import { RawNote, StrettoChainResult, StrettoSearchOptions, StrettoChainOption, StrettoConstraintMode, ScoreLog, StrettoSearchReport } from '../../types';
import { SCORING, INTERVALS } from './strettoConstants';
import { analyzeStrettoHarmony } from './strettoHarmonyAnalysis';
import { getVoiceLabel } from './midiVoices';

// --- StrettoGrid: High-Performance Spatial Indexing ---
// Uses a flat Int8Array to represent the score grid.
// -1 = Silence
// 0-127 = MIDI Pitch
class StrettoGrid {
    private buffer: Int8Array;
    private width: number;
    private voices: number;

    constructor(voices: number, duration: number) {
        this.voices = voices;
        this.width = duration;
        // Initialize with -1 (Silence)
        this.buffer = new Int8Array(voices * duration).fill(-1);
    }

    // Write notes to grid
    write(voiceIndex: number, notes: InternalSubjectNote[], offset: number, transposition: number) {
        const rowOffset = voiceIndex * this.width;
        for (let i = 0; i < notes.length; i++) {
            const n = notes[i];
            const val = n.pitch + transposition;
            const start = rowOffset + offset + n.relTick16;
            for (let t = 0; t < n.dur16; t++) {
                if (start + t < this.buffer.length) {
                    this.buffer[start + t] = val;
                }
            }
        }
    }

    // Clear notes (for backtracking)
    clear(voiceIndex: number, notes: InternalSubjectNote[], offset: number) {
        const rowOffset = voiceIndex * this.width;
        for (let i = 0; i < notes.length; i++) {
            const n = notes[i];
            const start = rowOffset + offset + n.relTick16;
            for (let t = 0; t < n.dur16; t++) {
                if (start + t < this.buffer.length) {
                    this.buffer[start + t] = -1;
                }
            }
        }
    }

    // Perform Parallel Perfect check against all other active voices
    // Optimized to only check motion points (start of new notes)
    hasParallelErrors(voiceIndex: number, notes: InternalSubjectNote[], offset: number, transposition: number): boolean {
        const rowOffset = voiceIndex * this.width;

        for (let i = 0; i < notes.length; i++) {
            const n = notes[i];
            const t = offset + n.relTick16;

            if (t <= 0) continue; // Start of piece, no parallel possible
            if (t >= this.width) break;

            const p1Curr = n.pitch + transposition;

            // Get previous pitch of THIS voice from the grid (t-1)
            // If grid at t-1 is empty (-1) or same pitch, there is no melodic motion, so no parallel error possible.
            const prevIdx = rowOffset + t - 1;
            const p1Prev = this.buffer[prevIdx];

            if (p1Prev === -1 || p1Prev === p1Curr) continue; 

            // Check against all other voices
            for (let v = 0; v < this.voices; v++) {
                if (v === voiceIndex) continue;

                const otherRow = v * this.width;
                const p2Curr = this.buffer[otherRow + t];
                const p2Prev = this.buffer[otherRow + t - 1];

                if (p2Curr === -1 || p2Prev === -1) continue; // Other voice silent
                if (p2Curr === p2Prev) continue; // Other voice Oblique (static)

                // Both voices moved. Check Intervals.
                const loCurr = Math.min(p1Curr, p2Curr);
                const hiCurr = Math.max(p1Curr, p2Curr);

                const sCurr = (hiCurr - loCurr) % 12;

                // Only care if destination is Perfect Unison(0) or Perfect 5th(7)
                // (Octaves map to 0 mod 12)
                if (sCurr === 0 || sCurr === 7) {
                    const loPrev = Math.min(p1Prev, p2Prev);
                    const hiPrev = Math.max(p1Prev, p2Prev);
                    const sPrev = (hiPrev - loPrev) % 12;

                    if (sPrev === sCurr) return true; // Fatal Parallel
                }
            }
        }
        return false;
    }
}

// --- Helper Functions ---

function isDissonant(lo: number, hi: number, lowerIsBass: boolean): boolean {
    const s = (hi - lo) % 12;
    if (INTERVALS.DISSONANT_SIMPLE.has(s)) return true;
    if (s === 5 && lowerIsBass) return true; // P4 against bass is dissonant
    return false;
}

function isParallelPerfect(lo: number, hi: number): boolean {
    const s = (hi - lo) % 12;
    return s === 0 || s === 7;
}

// Inversion Logic
const SCALE_INTERVALS = [0, 2, 4, 5, 7, 9, 11];

function invertPitch(pitch: number, pivot: number): number | null {
    const diff = pitch - pivot;
    const octaves = Math.floor(diff / 12);
    const semitone = (diff % 12 + 12) % 12;
    const scaleIndex = SCALE_INTERVALS.indexOf(semitone);
    if (scaleIndex === -1) return pivot - diff; 
    const absStep = (octaves * 7) + scaleIndex;
    const invStep = -absStep;
    const invOctaves = Math.floor(invStep / 7);
    const invRem = (invStep % 7 + 7) % 7;
    const invSemitone = SCALE_INTERVALS[invRem];
    return pivot + (invOctaves * 12) + invSemitone;
}

function getVoiceName(index: number, total: number, names?: Record<number, string>): string {
    if (names && names[index]) return names[index];
    return getVoiceLabel(index, total);
}

// --- Timeline & Validation ---

interface Timeline {
    // tick -> voice -> { pitch, dur16 (total duration of note in 16ths) }
    [tick16: number]: { [voiceIdx: number]: { pitch: number, dur16: number } }; 
}

interface InternalSubjectNote {
    relTick16: number; // 16th note grid relative to start
    dur16: number;
    pitch: number;
}

function normalizeSubject(notes: RawNote[], ppq: number): InternalSubjectNote[] {
    const sorted = [...notes].sort((a,b) => a.ticks - b.ticks);
    if (sorted.length === 0) return [];
    const startTick = sorted[0].ticks;
    const ticksPer16 = ppq / 4;

    return sorted.map(n => ({
        relTick16: Math.round((n.ticks - startTick) / ticksPer16),
        dur16: Math.max(1, Math.round(n.durationTicks / ticksPer16)),
        pitch: n.midi
    }));
}

function getEffectiveSubjectLength16(notes: InternalSubjectNote[]): number {
    if (notes.length === 0) return 0;
    let maxEnd = 0;
    notes.forEach(n => {
        const end = n.relTick16 + n.dur16;
        if (end > maxEnd) maxEnd = end;
    });
    // This represents the strict duration from start to the absolute last note-off.
    // Trailing rests are thus naturally excluded from the availability block.
    return maxEnd;
}

function getSubjectNotes(
    type: 'N' | 'I', 
    baseSubject: InternalSubjectNote[], 
    invertedSubject: InternalSubjectNote[], 
    length16: number
): InternalSubjectNote[] {
    const source = type === 'N' ? baseSubject : invertedSubject;
    return source.filter(n => n.relTick16 < length16).map(n => ({
        ...n,
        dur16: Math.min(n.dur16, length16 - n.relTick16)
    }));
}

function buildTimeline(
    specs: StrettoChainOption[], 
    baseSubject: InternalSubjectNote[], 
    invertedSubject: InternalSubjectNote[]
): Timeline {
    const tl: Timeline = {};

    specs.forEach((spec) => {
        const notes = getSubjectNotes(spec.type, baseSubject, invertedSubject, spec.length);
        const start16 = Math.round(spec.startBeat * 4); // beats to 16ths

        notes.forEach(n => {
            for (let t = 0; t < n.dur16; t++) {
                const absTick = start16 + n.relTick16 + t;
                if (!tl[absTick]) tl[absTick] = {};
                tl[absTick][spec.voiceIndex] = { 
                    pitch: n.pitch + spec.transposition,
                    dur16: n.dur16 // Storing full duration for harmony filter
                };
            }
        });
    });

    return tl;
}

interface ValidationResult {
    isValid: boolean;
    errors: string[];
    warnings: string[];
    polyphonyIntegral: number;
    totalDuration: number;
    polyphonicDuration: number;
    bassDissDuration: number;
    upperDissDuration: number;
    harmonicReward: number;
    harmonicPenalty: number;
    detectedChords: string[];
}

function checkRulesAndStats(
    specs: StrettoChainOption[], 
    baseSubject: InternalSubjectNote[], 
    invertedSubject: InternalSubjectNote[],
    requireConsonantEnd: boolean,
    totalVoices: number,
    voiceNames?: Record<number, string>
): ValidationResult {

    const tl = buildTimeline(specs, baseSubject, invertedSubject);
    const ticks = Object.keys(tl).map(Number).sort((a,b) => a-b);
    const errors: string[] = [];
    const warnings: string[] = [];

    const usedVoices = new Set<number>();
    specs.forEach(s => usedVoices.add(s.voiceIndex));
    const voices = Array.from(usedVoices).sort((a,b) => a-b);

    let polyphonyIntegral = 0;
    let totalDuration = 0;
    let polyphonicDuration = 0;
    let bassDissDuration = 0;
    let upperDissDuration = 0;

    // 1. Calculate Polyphony and Dissonance
    if (ticks.length > 0) {
        const minT = ticks[0];
        const maxT = ticks[ticks.length - 1];
        totalDuration = maxT - minT + 1;

        for (let t = minT; t <= maxT; t++) {
            const activeVoiceMap = tl[t];
            if (!activeVoiceMap) continue; 

            const activeCount = Object.keys(activeVoiceMap).length;

            if (activeCount > 0) {
                polyphonyIntegral += (activeCount - SCORING.POLYPHONY_OFFSET);
            }

            if (activeCount < 2) continue; 

            polyphonicDuration += 1;

            const pitches: number[] = [];
            const activeIndices = Object.keys(activeVoiceMap).map(Number);

            activeIndices.forEach(v => pitches.push(activeVoiceMap[v].pitch));
            pitches.sort((a,b) => a-b);

            const bassPitch = pitches[0];
            const bassVoiceIdx = parseInt(Object.keys(activeVoiceMap).find(k => activeVoiceMap[parseInt(k)].pitch === bassPitch) || "-1");

            // Check Intervals
            for (let i = 0; i < activeIndices.length; i++) {
                for (let j = i + 1; j < activeIndices.length; j++) {
                    const vA = activeIndices[i];
                    const vB = activeIndices[j];
                    const p1 = activeVoiceMap[vA].pitch;
                    const p2 = activeVoiceMap[vB].pitch;

                    const lo = Math.min(p1, p2);
                    const hi = Math.max(p1, p2);
                    const isBassPair = (vA === bassVoiceIdx || vB === bassVoiceIdx);

                    if (isDissonant(lo, hi, isBassPair)) {
                        if (isBassPair) bassDissDuration += 1; 
                        else upperDissDuration += 1;
                    }
                }
            }
        }
    }

    // 2. Delegate Harmonic Analysis
    const { reward, penalty, chords } = analyzeStrettoHarmony(tl, ticks);

    // 3. Validation Checks (Parallel/Runs)
    for (let i = 0; i < voices.length; i++) {
        for (let j = i + 1; j < voices.length; j++) {
            const vA = voices[i];
            const vB = voices[j];

            const sounding: { t: number, lo: number, hi: number, lowerIsBass: boolean, p1: number, p2: number }[] = [];

            ticks.forEach(t => {
                const v = tl[t];
                if (v[vA] !== undefined && v[vB] !== undefined) {
                    const minAll = Math.min(...Object.values(v).map(d => d.pitch));
                    const p1 = v[vA].pitch;
                    const p2 = v[vB].pitch;
                    const lo = Math.min(p1, p2);
                    const hi = Math.max(p1, p2);
                    sounding.push({ t, lo, hi, lowerIsBass: lo === minAll, p1, p2 });
                }
            });

            if (sounding.length < 2) continue;

            // RULE 1: Parallel Perfect
            for (let k = 1; k < sounding.length; k++) {
                const prev = sounding[k-1];
                const curr = sounding[k];

                // Allow static intervals (no motion)
                if (prev.p1 === curr.p1 && prev.p2 === curr.p2) continue;

                // Allow Oblique Motion (One voice static, other moving)
                const p1Moved = prev.p1 !== curr.p1;
                const p2Moved = prev.p2 !== curr.p2;
                if (!p1Moved || !p2Moved) continue; 

                // Check for Parallel Perfects (Both voices moving into a perfect interval)
                if (isParallelPerfect(curr.lo, curr.hi)) {
                    // Previous must also be perfect
                    if (isParallelPerfect(prev.lo, prev.hi)) {
                        const int1 = (prev.hi - prev.lo) % 12;
                        const int2 = (curr.hi - curr.lo) % 12;
                        if (int1 === int2) {
                            errors.push(`Parallel ${int1 === 7 ? '5th' : '8ve'} (${getVoiceName(vA, totalVoices, voiceNames)}, ${getVoiceName(vB, totalVoices, voiceNames)})`);
                        }
                    }
                }
            }

            // RULE 2: Dissonance Runs
            let k = 0;
            while (k < sounding.length) {
                const startEv = sounding[k];
                if (!isDissonant(startEv.lo, startEv.hi, startEv.lowerIsBass)) {
                    k++; continue;
                }

                let segStart = k;
                while (k < sounding.length) {
                    const curr = sounding[k];
                    if (!isDissonant(curr.lo, curr.hi, curr.lowerIsBass)) break;

                    if ((curr.t - sounding[segStart].t + 1) >= 4) { // 1 Beat threshold
                        const distinctPitches = new Set<string>();
                        for(let m = segStart; m <= k; m++) distinctPitches.add(`${sounding[m].p1}-${sounding[m].p2}`);
                        if (distinctPitches.size > 1) {
                            errors.push(`Unresolved Dissonance Run (${getVoiceName(vA, totalVoices, voiceNames)}, ${getVoiceName(vB, totalVoices, voiceNames)})`);
                            break; // Stop checking this run
                        }
                    }
                    k++;
                }
            }
        }
    }

    // 4. Consonant Termination
    if (requireConsonantEnd) {
        for (const spec of specs) {
            const start16 = Math.round(spec.startBeat * 4);
            const end16 = start16 + spec.length; 
            const checkTick = end16 - 1;
            const activeVoices = tl[checkTick];
            if (!activeVoices || Object.keys(activeVoices).length < 2) continue;

            const myData = activeVoices[spec.voiceIndex];
            if (!myData) continue;
            const myPitch = myData.pitch;

            // Find Bass
            const activePitches = Object.values(activeVoices).map(v => v.pitch);
            const bassPitch = Math.min(...activePitches);

            let hasConsonance = false;
            for (const otherVStr in activeVoices) {
                const otherV = parseInt(otherVStr);
                if (otherV === spec.voiceIndex) continue;
                const otherPitch = activeVoices[otherV].pitch;
                const interval = Math.abs(myPitch - otherPitch) % 12;

                if (INTERVALS.CONSONANT.has(interval)) {
                    hasConsonance = true;
                    break;
                }
                // Special Rule for 4ths: If the lower note isn't the bass, a P4 is allowed as consonant
                if (interval === 5) {
                    const pairLower = Math.min(myPitch, otherPitch);
                    if (pairLower > bassPitch) {
                        hasConsonance = true;
                        break;
                    }
                }
            }
            if (!hasConsonance) {
                errors.push(`Non-Consonant Ending (${getVoiceName(spec.voiceIndex, totalVoices, voiceNames)})`);
            }
        }
    }

    return { 
        isValid: errors.length === 0, 
        errors,
        warnings, 
        polyphonyIntegral, 
        totalDuration, 
        polyphonicDuration,
        bassDissDuration,
        upperDissDuration,
        harmonicReward: reward,
        harmonicPenalty: penalty,
        detectedChords: chords
    };
}

// --- Pre-Pass Discovery ---

interface EntryCandidate {
    transposition: number;
    delayBeats: number;
    type: 'N' | 'I';
    score: number;
}

function findValidPairwiseCandidates(
    baseSubject: InternalSubjectNote[], 
    invertedSubject: InternalSubjectNote[], 
    options: StrettoSearchOptions, 
    validTranspositions: number[],
    effectiveLen16: number,
    subjectDurationBeats: number
): EntryCandidate[] {
    const candidates: EntryCandidate[] = [];

    // We check Subject (Voice 0) vs Candidate (Voice 1)
    // Candidate enters at `delay` with `transposition`
    const voice0: StrettoChainOption = {
        startBeat: 0, transposition: 0, type: 'N', length: effectiveLen16, voiceIndex: 0
    };

    const delays: number[] = [];
    // UPDATED: Allow delays up to 2/3 of length (Subject + Entry 1,2,3 are allowed to be wide)
    const maxDelay = Math.max(0.5, subjectDurationBeats * (2/3));
    for(let d = 0.5; d <= maxDelay; d += 0.5) delays.push(d);

    const types: {type: 'N'|'I', source: InternalSubjectNote[]}[] = [];
    types.push({ type: 'N', source: baseSubject });
    if (options.inversionMode !== 'None' && invertedSubject.length > 0) {
        types.push({ type: 'I', source: invertedSubject });
    }

    // Optimization: Check every combination
    for (const d of delays) {
        for (const t of validTranspositions) {
            for (const typeObj of types) {

                // DISALLOW COMPLEX EXCEPTIONS
                // If Inverted, restrict to Perfect Intervals (0, 5, 7, 12)
                if (options.disallowComplexExceptions && typeObj.type === 'I') {
                    const intervalClass = Math.abs(t % 12);
                    const isPerfect = [0, 5, 7].includes(intervalClass);
                    if (!isPerfect) continue; // Skip 3rds/6ths for inversions
                }

                // Construct pairwise check
                const voice1: StrettoChainOption = {
                    startBeat: d,
                    transposition: t,
                    type: typeObj.type,
                    length: effectiveLen16, // Use full length for check
                    voiceIndex: 1
                };

                // NOTE: Pairwise validation still uses the slow checkRulesAndStats for depth 2,
                // but this runs once at start. The recursive solver will use the fast StrettoGrid.
                const res = checkRulesAndStats([voice0, voice1], baseSubject, invertedSubject, options.requireConsonantEnd, options.ensembleTotal, options.voiceNames);

                if (res.isValid) {
                    // Heuristic scoring for sorting
                    // Prefer: High polyphony, Sweet Dissonance, Consonant End
                    let score = res.polyphonyIntegral;
                    if (res.bassDissDuration === 0) score += 50; 

                    candidates.push({
                        transposition: t,
                        delayBeats: d,
                        type: typeObj.type,
                        score: score
                    });
                }
            }
        }
    }

    // Sort by best score first, then by smallest absolute transposition (Compactness preference)
    return candidates.sort((a,b) => {
        if (b.score !== a.score) return b.score - a.score;
        return Math.abs(a.transposition) - Math.abs(b.transposition);
    });
}

// --- Search Algorithm ---

export async function searchStrettoChains(
    rawSubject: RawNote[],
    options: StrettoSearchOptions,
    ppq: number
): Promise<StrettoSearchReport> {

    // Safety Break
    const START_TIME = Date.now();
    const TIME_LIMIT_MS = 30000; 
    const MAX_VISITED_NODES = 500000; 
    let nodesVisited = 0;
    let stopReason: 'Success' | 'Timeout' | 'NodeLimit' | 'Exhausted' = 'Exhausted';
    let maxDepthReached = 0;

    const baseSubject = normalizeSubject(rawSubject, ppq);
    if (baseSubject.length === 0) {
        return { results: [], stats: { nodesVisited: 0, timeMs: 0, stopReason: 'Exhausted', maxDepthReached: 0 } };
    }

    // Ensure effective length captures the last Note-Off, not just the abstract end
    // NOTE: This intentionally excludes trailing rests from the subject definition.
    const effectiveLen16 = getEffectiveSubjectLength16(baseSubject);
    const subjectDurationBeats = effectiveLen16 / 4;

    // Create Grid
    const maxChainDuration16 = Math.ceil((options.targetChainLength * subjectDurationBeats * 4) * 2); // Buffer
    const grid = new StrettoGrid(options.ensembleTotal, maxChainDuration16);

    const invertedSubject: InternalSubjectNote[] = [];
    if (options.inversionMode !== 'None') {
        baseSubject.forEach(n => {
            const inv = invertPitch(n.pitch, options.pivotMidi);
            if (inv !== null) invertedSubject.push({ ...n, pitch: inv });
        });
    }

    const validResults: StrettoChainResult[] = [];
    const invalidResults: StrettoChainResult[] = [];
    const partialResults: StrettoChainResult[] = [];

    const MAX_VALID_RESULTS = 200; 
    const MAX_INVALID_BUFFER = 50; 

    const ensembleTotal = options.ensembleTotal;
    const targetChainLength = options.targetChainLength;

    const validTranspositions = Array.from(INTERVALS.TRAD_TRANSPOSITIONS);
    if (options.thirdSixthMode !== 'None') {
        INTERVALS.THIRD_SIXTH_TRANSPOSITIONS.forEach(t => {
            if (!validTranspositions.includes(t)) validTranspositions.push(t);
        });
    }

    // 1. Perform Pairwise Pre-Pass
    const potentialCandidates = findValidPairwiseCandidates(baseSubject, invertedSubject, options, validTranspositions, effectiveLen16, subjectDurationBeats);

    const isBudgetAvailable = (mode: StrettoConstraintMode, currentUsage: number) => {
        if (mode === 'None') return false;
        if (mode === 'Max 1') return currentUsage < 1;
        return true; 
    };

    function processChain(chain: StrettoChainOption[], validation: ValidationResult, targetList: StrettoChainResult[]) {
        const log: ScoreLog = { base: 0, penalties: [], bonuses: [], total: 0 };
        let score = 0; 

        // 1. Polyphony
        if (validation.totalDuration > 0) {
            const avgScore = validation.polyphonyIntegral / validation.totalDuration;
            const polyScore = SCORING.POLYPHONY_BASE_MULT * avgScore;
            score += polyScore;
            log.bonuses.push({ reason: `Polyphony Density`, points: Math.round(polyScore) });
        }

        // 2. Dissonance (Proportional)
        if (validation.polyphonicDuration > 0) {
            const weightedDiss = (SCORING.DISS_WEIGHT_BASS * validation.bassDissDuration) + (SCORING.DISS_WEIGHT_UPPER * validation.upperDissDuration);
            const ratio = weightedDiss / validation.polyphonicDuration;

            if (ratio > SCORING.DISS_PENALTY_START) {
                const excess = ratio - SCORING.DISS_PENALTY_START;
                const penalty = excess * SCORING.DISS_PENALTY_SLOPE;
                score -= penalty;
                log.penalties.push({ reason: `Dissonance ${(ratio*100).toFixed(0)}%`, points: Math.round(penalty) });
            } else if (ratio >= SCORING.BUCKET_SWEET_MIN && ratio <= SCORING.BUCKET_SWEET_MAX) {
                score += SCORING.BUCKET_SWEET_SCORE;
                log.bonuses.push({ reason: `Rich Harmony (${(ratio*100).toFixed(0)}%)`, points: SCORING.BUCKET_SWEET_SCORE });
            }
        }

        // 3. Harmonic Quality
        if (validation.harmonicReward > 0) {
            score += validation.harmonicReward;
            log.bonuses.push({ reason: "Harmonic Quality", points: Math.round(validation.harmonicReward) });
        }
        if (validation.harmonicPenalty > 0) {
            score -= validation.harmonicPenalty;
            log.penalties.push({ reason: "NCT Clashing", points: Math.round(validation.harmonicPenalty) });
        }

        // 4. Distance/Structure Scoring (For remaining valid chains)
        const distanceCounts: Record<string, number> = {};
        chain.forEach((e, i) => {
            if (i === 0) return;
            const prev = chain[i-1];
            const dist = e.startBeat - prev.startBeat;
            const distStr = dist.toFixed(2);
            distanceCounts[distStr] = (distanceCounts[distStr] || 0) + 1;

            const ratio = dist / subjectDurationBeats;
            if (ratio <= SCORING.COMPACT_HYPER_THRESH) {
                score += SCORING.COMPACT_HYPER_BONUS;
                log.bonuses.push({ reason: `Hyper-Stretto (V${i+1})`, points: SCORING.COMPACT_HYPER_BONUS });
            } else if (ratio <= SCORING.COMPACT_TIGHT_THRESH) {
                score += SCORING.COMPACT_TIGHT_BONUS;
                log.bonuses.push({ reason: `Tight Stretto (V${i+1})`, points: SCORING.COMPACT_TIGHT_BONUS });
            }

            const absInt = e.transposition;
            const absSemi = Math.abs(absInt % 12);
            if ([3,4,8,9].includes(absSemi)) {
                score += SCORING.IMPERFECT_CONS_BONUS;
                log.bonuses.push({ reason: `3rd/6th Entry`, points: SCORING.IMPERFECT_CONS_BONUS });
            }
        });

        const uniqueDistances = Object.keys(distanceCounts).length;
        if (uniqueDistances > 1) {
            const b = (uniqueDistances - 1) * SCORING.DIST_VARIETY_BONUS;
            score += b;
            log.bonuses.push({ reason: `Distance Variety`, points: b });
        }

        // --- Invalidity Penalties ---
        if (!validation.isValid) {
            const fatalPenalty = validation.errors.length * 1000;
            score -= fatalPenalty;
            log.penalties.push({ reason: `${validation.errors.length} Fatal Rules Broken`, points: fatalPenalty });
        }

        // Length Bonus (for partials)
        if (chain.length < targetChainLength) {
            const missing = targetChainLength - chain.length;
            score -= (missing * 50); // Penalty for shortness
        }

        log.total = Math.max(0, score);

        const resultObj: StrettoChainResult = {
            id: `chain-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
            entries: [...chain],
            warnings: [...validation.errors, ...validation.warnings],
            score: log.total,
            scoreLog: log,
            detectedChords: validation.detectedChords
        };

        targetList.push(resultObj);
        targetList.sort((a,b) => b.score - a.score);
        if (targetList.length > MAX_INVALID_BUFFER) {
            targetList.pop();
        }
    }

    // Recursive Solver
    async function solve(
        chain: StrettoChainOption[], 
        nInv: number, n3rd: number, nTrunc: number,
        voiceEndTimes16: number[] 
    ) {
        nodesVisited++;
        if (chain.length > maxDepthReached) maxDepthReached = chain.length;

        if (validResults.length >= MAX_VALID_RESULTS) {
            stopReason = 'Success';
            return;
        }
        if (Date.now() - START_TIME > TIME_LIMIT_MS) {
            stopReason = 'Timeout';
            if (chain.length >= 3) {
                 const validation = checkRulesAndStats(chain, baseSubject, invertedSubject, options.requireConsonantEnd, options.ensembleTotal, options.voiceNames);
                 processChain(chain, validation, partialResults);
            }
            return;
        }
        if (nodesVisited > MAX_VISITED_NODES) {
            stopReason = 'NodeLimit';
            if (chain.length >= 3) {
                 const validation = checkRulesAndStats(chain, baseSubject, invertedSubject, options.requireConsonantEnd, options.ensembleTotal, options.voiceNames);
                 processChain(chain, validation, partialResults);
            }
            return;
        }

        // Leaf / Termination Check
        if (chain.length === targetChainLength) {
            const validation = checkRulesAndStats(chain, baseSubject, invertedSubject, options.requireConsonantEnd, options.ensembleTotal, options.voiceNames);
            if (validation.isValid) processChain(chain, validation, validResults);
            else processChain(chain, validation, invalidResults);
            return;
        }

        const lastEntry = chain[chain.length - 1];
        let extensionsFound = false;

        // --- Active Voice Transposition Map ---
        const lastTranspositions = new Map<number, number>();
        chain.forEach(entry => {
            lastTranspositions.set(entry.voiceIndex, entry.transposition);
        });

        // --- PRUNING OPTIMIZATION: "Redundancy Filter" ---
        // Scope: Restricted to OUTER VOICES ONLY (Voice 0 and Voice N-1).
        // Rationale: Inner voices have complex neighbor interactions; octave displacement matters.
        // Outer voices have free space above/below, so compact intervals are preferred if they fit.
        const triedFunctions = new Set<string>();

        for (const cand of potentialCandidates) {
            if (stopReason !== 'Exhausted') break;

            const harmonicKey = `${cand.delayBeats.toFixed(2)}-${cand.type}-${(cand.transposition % 12 + 12) % 12}`;

            const newStart = lastEntry.startBeat + cand.delayBeats;

            // --- DISTANCE LOGIC & CONSTRAINTS ---
            if (chain.length >= 2) {
                const prevDist = lastEntry.startBeat - chain[chain.length - 2].startBeat;
                const newDist = cand.delayBeats;

                // 1. HARD: Global Uniqueness of Distance
                let isUnique = true;
                for (let k = 1; k < chain.length; k++) {
                    const existingDist = chain[k].startBeat - chain[k-1].startBeat;
                    if (Math.abs(existingDist - newDist) < 0.01) {
                        isUnique = false;
                        break;
                    }
                }
                if (!isUnique) continue;

                // 2. HARD: Elasticity Limit (Max +1.0)
                if (newDist > prevDist + 1.0 + 0.01) continue;

                // 3. HARD: Expansion Reaction
                if (chain.length >= 3) {
                    const prevPrevDist = chain[chain.length - 2].startBeat - chain[chain.length - 3].startBeat;
                    if (prevDist > prevPrevDist + 0.01) {
                        if (newDist > prevPrevDist - 1.0 + 0.01) continue;
                    }
                }
            }

            const entryIndex = chain.length + 1;
            const constraintThreshold = Math.floor(targetChainLength / 2) + 1;
            const maxDelayEarly = subjectDurationBeats * (2/3);
            const maxDelayLate = subjectDurationBeats * 0.5;
            const limit = entryIndex >= constraintThreshold ? maxDelayLate : maxDelayEarly;

            if (cand.delayBeats > limit) continue;

            const absTrans = cand.transposition; 
            if (absTrans === lastEntry.transposition) continue;

            const start16 = Math.round(newStart * 4);
            let assignedVoice = -1;

            // --- STRICT VOICE ASSIGNMENT LOOP ---
            for (let v = 0; v < ensembleTotal; v++) {
                // 1. Time Availability Check (Linear tracker)
                // Rule: "A voice is not free from start of entry to start of entry + length of entry - 1 beat."

                const lastEnd16 = voiceEndTimes16[v];
                const allowedStart16 = Math.max(0, lastEnd16 - 4); // 4 ticks = 1 beat overlap allowed

                if (start16 < allowedStart16) continue; // Busy

                // 2. Transposition Envelope Constraints (Crossing Check)
                // "A voice should not be transposed up/down by more than the voice above/beneath it."

                // Voice Above (v-1)
                if (lastTranspositions.has(v - 1)) {
                    const tAbove = lastTranspositions.get(v - 1)!;
                    // Current T must be <= T_Above (cannot be transposed higher than the voice above)
                    if (absTrans > tAbove) continue;
                }

                // Voice Below (v+1)
                if (lastTranspositions.has(v + 1)) {
                    const tBelow = lastTranspositions.get(v + 1)!;
                    // Current T must be >= T_Below (cannot be transposed lower than the voice below)
                    if (absTrans < tBelow) continue;
                }

                assignedVoice = v;
                break; 
            }

            if (assignedVoice === -1) continue; 

            // --- OUTER VOICE PRUNING CHECK ---
            const isOuterVoice = (assignedVoice === 0 || assignedVoice === ensembleTotal - 1);
            if (isOuterVoice && triedFunctions.has(harmonicKey)) {
                // We already successfully placed this harmonic function in this outer voice slot.
                // Since candidates are sorted by compactness, we have used the tightest version.
                // Prune the wider versions.
                continue;
            }

            // Budget Checks
            const absSemi = Math.abs(absTrans % 12);
            const is3rd = [3,4,8,9].includes(absSemi);
            if (is3rd) {
                // "Disallow Complex Exceptions": If 3rd/6th, we cannot truncate OR invert (already filtered in pre-pass)
                if (options.disallowComplexExceptions && options.truncationMode !== 'None') {
                    // Force full length if using 3rds
                }
                if (!isBudgetAvailable(options.thirdSixthMode, n3rd)) continue;
            }

            const costInv = cand.type === 'I' ? 1 : 0;
            if (costInv > 0 && !isBudgetAvailable(options.inversionMode, nInv)) continue;

            // --- ACCELERATION: GRID VALIDATION (Cross-Voice Polyphony Only) ---
            // We use the grid here ONLY to check for Parallel 5ths/8ves against OTHER voices.
            const sourceNotes = cand.type === 'N' ? baseSubject : invertedSubject;

            // Write to Grid
            grid.write(assignedVoice, sourceNotes, start16, absTrans);

            // Check for Fatal Parallel Errors immediately
            const hasParallel = grid.hasParallelErrors(assignedVoice, sourceNotes, start16, absTrans);

            if (hasParallel) {
                // Backtrack Grid immediately
                grid.clear(assignedVoice, sourceNotes, start16);
                // Note: Do NOT prune here. If +7 failed, +19 might work.
                continue;
            }

            // SUCCESS! We found a valid slot.
            // If this was an Outer Voice, lock this harmonic function to prune redundant intervals later.
            if (isOuterVoice) {
                triedFunctions.add(harmonicKey);
            }

            const newEntry: StrettoChainOption = {
                startBeat: newStart,
                transposition: absTrans,
                type: cand.type,
                length: effectiveLen16,
                voiceIndex: assignedVoice
            };

            const testChain = [...chain, newEntry];
            const newVoiceState = [...voiceEndTimes16];
            const entryEnd16 = start16 + effectiveLen16;
            // Update end time tracking. 
            newVoiceState[assignedVoice] = Math.max(newVoiceState[assignedVoice], entryEnd16);

            extensionsFound = true;

            await solve(
                testChain, 
                nInv + costInv, 
                n3rd + (is3rd?1:0), 
                nTrunc, 
                newVoiceState
            );

            // Backtrack Grid
            grid.clear(assignedVoice, sourceNotes, start16);

            if (validResults.length >= MAX_VALID_RESULTS) return;
        }

        // Partial Chain Fallback
        if (!extensionsFound && chain.length >= 3) {
             const validation = checkRulesAndStats(chain, baseSubject, invertedSubject, options.requireConsonantEnd, options.ensembleTotal, options.voiceNames);
             processChain(chain, validation, partialResults);
        }
    }

    const initialVoiceState = new Array(ensembleTotal).fill(0);
    initialVoiceState[options.subjectVoiceIndex] = effectiveLen16;

    // Initialize Grid with Subject
    grid.write(options.subjectVoiceIndex, baseSubject, 0, 0);

    await solve([{
        startBeat: 0,
        transposition: 0,
        type: 'N',
        length: effectiveLen16,
        voiceIndex: options.subjectVoiceIndex
    }], 0, 0, 0, initialVoiceState);

    // Decision Logic: Valid > Partial > Invalid
    let rawResults = validResults;
    if (rawResults.length === 0) rawResults = partialResults;
    if (rawResults.length === 0) rawResults = invalidResults;

    // --- DEDUPLICATION LOGIC ---
    // Filter out results that are "Harmonically Identical" (same interval classes)
    const uniqueChains = new Map<string, StrettoChainResult>();

    rawResults.forEach(res => {
        // Create signature: IntervalClass sequence
        const signature = res.entries.map(e => {
            const pc = (e.transposition % 12 + 12) % 12;
            const dist = e.startBeat.toFixed(2);
            return `${pc}@${dist}`;
        }).join('|');

        if (!uniqueChains.has(signature)) {
            uniqueChains.set(signature, res);
        } else {
            const existing = uniqueChains.get(signature)!;
            if (res.score > existing.score) {
                uniqueChains.set(signature, res);
            }
        }
    });

    let resultsToReturn = Array.from(uniqueChains.values());

    const groups = new Map<string, StrettoChainResult[]>();

    const sortStrategy = (a: StrettoChainResult, b: StrettoChainResult) => {
        if (a.entries.length !== b.entries.length) {
            return b.entries.length - a.entries.length;
        }
        return b.score - a.score;
    };

    resultsToReturn.forEach(res => {
        const rhythmKey = res.entries.map(e => e.startBeat.toFixed(2)).join('|');
        if (!groups.has(rhythmKey)) groups.set(rhythmKey, []);
        groups.get(rhythmKey)!.push(res);
    });

    const finalResults: StrettoChainResult[] = [];

    groups.forEach((group) => {
        group.sort(sortStrategy);
        const leader = group[0];
        if (group.length > 1) leader.variations = group.slice(1);
        finalResults.push(leader);
    });

    return {
        results: finalResults.sort(sortStrategy).slice(0, 50),
        stats: {
            nodesVisited,
            timeMs: Date.now() - START_TIME,
            stopReason: validResults.length > 0 ? 'Success' : stopReason,
            maxDepthReached
        }
    };
}

import React from 'react';
import { StrettoSearchOptions, StrettoChainResult, StrettoCandidate, RawNote, StrettoSearchReport } from '../../types';
import StrettoSearchPanel from './StrettoSearchPanel';
import StrettoResultsList from './StrettoResultsList';
import StrettoInspector from './StrettoInspector';
import { DownloadIcon } from '../Icons';

interface StrettoChainViewProps {
    searchOptions: StrettoSearchOptions;
    setSearchOptions: (opt: StrettoSearchOptions) => void;
    onSearch: () => void;
    isSearching: boolean;
    chainResults: StrettoChainResult[];
    selectedChain: StrettoChainResult | null;
    setSelectedChain: (res: StrettoChainResult | null) => void;
    voiceNames?: Record<number, string>;

    // Inspector Props
    chainToCandidate: StrettoCandidate | null;
    ppq: number;
    ts: { num: number, den: number };
    isPlaying: boolean;
    onPlay: (notes: RawNote[]) => void;
    onDownloadChain: () => void;
    searchReport?: StrettoSearchReport | null;
}

export default function StrettoChainView({
    searchOptions, setSearchOptions, onSearch, isSearching,
    chainResults, selectedChain, setSelectedChain, voiceNames,
    chainToCandidate, ppq, ts, isPlaying, onPlay, onDownloadChain,
    searchReport
}: StrettoChainViewProps) {
    return (
        <>
            <StrettoSearchPanel 
                options={searchOptions} 
                setOptions={setSearchOptions}
                onSearch={onSearch}
                isSearching={isSearching}
            />

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8">
                <div className="lg:col-span-1 bg-gray-900 border border-gray-700 rounded shadow-inner">
                    <div className="p-3 border-b border-gray-700 bg-gray-800 flex justify-between items-center">
                        <h3 className="text-xs font-bold text-gray-400">FOUND CHAINS ({chainResults.length})</h3>
                        {searchReport && (
                            <div className="text-[9px] text-gray-500 text-right">
                                {searchReport.stats.nodesVisited.toLocaleString()} nodes in {searchReport.stats.timeMs}ms
                            </div>
                        )}
                    </div>
                    {searchReport && searchReport.stats.stopReason !== 'Success' && (
                        <div className="bg-yellow-900/30 border-b border-yellow-800 p-2 text-[10px] text-yellow-300">
                            <strong>Search {searchReport.stats.stopReason}:</strong> No valid chains of length {searchOptions.targetChainLength} found.
                            Showing partial chains (Max Depth: {searchReport.stats.maxDepthReached}).
                        </div>
                    )}
                    <StrettoResultsList 
                        results={chainResults}
                        selectedId={selectedChain?.id || null}
                        onSelect={setSelectedChain}
                        voiceNames={voiceNames}
                    />
                </div>
                <div className="lg:col-span-2">
                    <StrettoInspector 
                        candidate={chainToCandidate}
                        ppq={ppq}
                        ts={ts}
                        isPlaying={isPlaying}
                        onPlay={onPlay}
                        assemblyResult={""}
                        assemblyLog={[]}
                        onClearAssembly={() => {}}
                        onDownloadChain={onDownloadChain}
                    />

                    {chainToCandidate && (
                        <div className="mt-4 flex justify-end">
                            <button 
                                onClick={onDownloadChain}
                                className="flex items-center gap-2 px-4 py-2 bg-brand-primary text-white font-bold rounded shadow-lg hover:bg-brand-secondary transition-colors"
                            >
                                <DownloadIcon className="w-4 h-4" /> Download Chain MIDI
                            </button>
                        </div>
                    )}
                </div>
            </div>
        </>
    );
}

import { RawNote, StrettoChainResult, StrettoSearchOptions, StrettoChainOption, StrettoConstraintMode, ScoreLog, StrettoSearchReport } from '../../types';
import { SCORING, INTERVALS } from './strettoConstants';
import { analyzeStrettoHarmony } from './strettoHarmonyAnalysis';
import { getVoiceLabel } from './midiVoices';

// --- StrettoGrid: High-Performance Spatial Indexing ---
// Uses a flat Int8Array to represent the score grid.
// -1 = Silence
// 0-127 = MIDI Pitch
class StrettoGrid {
    private buffer: Int8Array;
    private width: number;
    private voices: number;

    constructor(voices: number, duration: number) {
        this.voices = voices;
        this.width = duration;
        // Initialize with -1 (Silence)
        this.buffer = new Int8Array(voices * duration).fill(-1);
    }

    // Write notes to grid
    write(voiceIndex: number, notes: InternalSubjectNote[], offset: number, transposition: number) {
        const rowOffset = voiceIndex * this.width;
        for (let i = 0; i < notes.length; i++) {
            const n = notes[i];
            const val = n.pitch + transposition;
            const start = rowOffset + offset + n.relTick16;
            for (let t = 0; t < n.dur16; t++) {
                if (start + t < this.buffer.length) {
                    this.buffer[start + t] = val;
                }
            }
        }
    }

    // Clear notes (for backtracking)
    clear(voiceIndex: number, notes: InternalSubjectNote[], offset: number) {
        const rowOffset = voiceIndex * this.width;
        for (let i = 0; i < notes.length; i++) {
            const n = notes[i];
            const start = rowOffset + offset + n.relTick16;
            for (let t = 0; t < n.dur16; t++) {
                if (start + t < this.buffer.length) {
                    this.buffer[start + t] = -1;
                }
            }
        }
    }

    // Perform Parallel Perfect check against all other active voices
    // Optimized to only check motion points (start of new notes)
    hasParallelErrors(voiceIndex: number, notes: InternalSubjectNote[], offset: number, transposition: number): boolean {
        const rowOffset = voiceIndex * this.width;

        for (let i = 0; i < notes.length; i++) {
            const n = notes[i];
            const t = offset + n.relTick16;

            if (t <= 0) continue; // Start of piece, no parallel possible
            if (t >= this.width) break;

            const p1Curr = n.pitch + transposition;

            // Get previous pitch of THIS voice from the grid (t-1)
            // If grid at t-1 is empty (-1) or same pitch, there is no melodic motion, so no parallel error possible.
            const prevIdx = rowOffset + t - 1;
            const p1Prev = this.buffer[prevIdx];

            if (p1Prev === -1 || p1Prev === p1Curr) continue; 

            // Check against all other voices
            for (let v = 0; v < this.voices; v++) {
                if (v === voiceIndex) continue;

                const otherRow = v * this.width;
                const p2Curr = this.buffer[otherRow + t];
                const p2Prev = this.buffer[otherRow + t - 1];

                if (p2Curr === -1 || p2Prev === -1) continue; // Other voice silent
                if (p2Curr === p2Prev) continue; // Other voice Oblique (static)

                // Both voices moved. Check Intervals.
                const loCurr = Math.min(p1Curr, p2Curr);
                const hiCurr = Math.max(p1Curr, p2Curr);

                const sCurr = (hiCurr - loCurr) % 12;

                // Only care if destination is Perfect Unison(0) or Perfect 5th(7)
                // (Octaves map to 0 mod 12)
                if (sCurr === 0 || sCurr === 7) {
                    const loPrev = Math.min(p1Prev, p2Prev);
                    const hiPrev = Math.max(p1Prev, p2Prev);
                    const sPrev = (hiPrev - loPrev) % 12;

                    if (sPrev === sCurr) return true; // Fatal Parallel
                }
            }
        }
        return false;
    }
}

// --- Helper Functions ---

function isDissonant(lo: number, hi: number, lowerIsBass: boolean): boolean {
    const s = (hi - lo) % 12;
    if (INTERVALS.DISSONANT_SIMPLE.has(s)) return true;
    if (s === 5 && lowerIsBass) return true; // P4 against bass is dissonant
    return false;
}

function isParallelPerfect(lo: number, hi: number): boolean {
    const s = (hi - lo) % 12;
    return s === 0 || s === 7;
}

// Inversion Logic
const SCALE_INTERVALS = [0, 2, 4, 5, 7, 9, 11];

function invertPitch(pitch: number, pivot: number): number | null {
    const diff = pitch - pivot;
    const octaves = Math.floor(diff / 12);
    const semitone = (diff % 12 + 12) % 12;
    const scaleIndex = SCALE_INTERVALS.indexOf(semitone);
    if (scaleIndex === -1) return pivot - diff; 
    const absStep = (octaves * 7) + scaleIndex;
    const invStep = -absStep;
    const invOctaves = Math.floor(invStep / 7);
    const invRem = (invStep % 7 + 7) % 7;
    const invSemitone = SCALE_INTERVALS[invRem];
    return pivot + (invOctaves * 12) + invSemitone;
}

function getVoiceName(index: number, total: number, names?: Record<number, string>): string {
    if (names && names[index]) return names[index];
    return getVoiceLabel(index, total);
}

// --- Timeline & Validation ---

interface Timeline {
    // tick -> voice -> { pitch, dur16 (total duration of note in 16ths) }
    [tick16: number]: { [voiceIdx: number]: { pitch: number, dur16: number } }; 
}

interface InternalSubjectNote {
    relTick16: number; // 16th note grid relative to start
    dur16: number;
    pitch: number;
}

function normalizeSubject(notes: RawNote[], ppq: number): InternalSubjectNote[] {
    // FIX: Filter out null/undefined notes before sorting to prevent "Cannot read properties of undefined (reading 'ticks')"
    const validNotes = notes.filter(n => !!n);
    const sorted = [...validNotes].sort((a,b) => a.ticks - b.ticks);

    if (sorted.length === 0) return [];
    const startTick = sorted[0].ticks;
    const ticksPer16 = ppq / 4;

    return sorted.map(n => ({
        relTick16: Math.round((n.ticks - startTick) / ticksPer16),
        dur16: Math.max(1, Math.round(n.durationTicks / ticksPer16)),
        pitch: n.midi
    }));
}

function getEffectiveSubjectLength16(notes: InternalSubjectNote[]): number {
    if (notes.length === 0) return 0;
    let maxEnd = 0;
    notes.forEach(n => {
        const end = n.relTick16 + n.dur16;
        if (end > maxEnd) maxEnd = end;
    });
    // This represents the strict duration from start to the absolute last note-off.
    // Trailing rests are thus naturally excluded from the availability block.
    return maxEnd;
}

function getSubjectNotes(
    type: 'N' | 'I', 
    baseSubject: InternalSubjectNote[], 
    invertedSubject: InternalSubjectNote[], 
    length16: number
): InternalSubjectNote[] {
    const source = type === 'N' ? baseSubject : invertedSubject;
    return source.filter(n => n.relTick16 < length16).map(n => ({
        ...n,
        dur16: Math.min(n.dur16, length16 - n.relTick16)
    }));
}

function buildTimeline(
    specs: StrettoChainOption[], 
    baseSubject: InternalSubjectNote[], 
    invertedSubject: InternalSubjectNote[]
): Timeline {
    const tl: Timeline = {};

    specs.forEach((spec) => {
        const notes = getSubjectNotes(spec.type, baseSubject, invertedSubject, spec.length);
        const start16 = Math.round(spec.startBeat * 4); // beats to 16ths

        notes.forEach(n => {
            for (let t = 0; t < n.dur16; t++) {
                const absTick = start16 + n.relTick16 + t;
                if (!tl[absTick]) tl[absTick] = {};
                tl[absTick][spec.voiceIndex] = { 
                    pitch: n.pitch + spec.transposition,
                    dur16: n.dur16 // Storing full duration for harmony filter
                };
            }
        });
    });

    return tl;
}

interface ValidationResult {
    isValid: boolean;
    errors: string[];
    warnings: string[];
    polyphonyIntegral: number;
    totalDuration: number;
    polyphonicDuration: number;
    bassDissDuration: number;
    upperDissDuration: number;
    harmonicReward: number;
    harmonicPenalty: number;
    detectedChords: string[];
}

function checkRulesAndStats(
    specs: StrettoChainOption[], 
    baseSubject: InternalSubjectNote[], 
    invertedSubject: InternalSubjectNote[],
    requireConsonantEnd: boolean,
    totalVoices: number,
    voiceNames?: Record<number, string>
): ValidationResult {

    const tl = buildTimeline(specs, baseSubject, invertedSubject);
    const ticks = Object.keys(tl).map(Number).sort((a,b) => a-b);
    const errors: string[] = [];
    const warnings: string[] = [];

    const usedVoices = new Set<number>();
    specs.forEach(s => usedVoices.add(s.voiceIndex));
    const voices = Array.from(usedVoices).sort((a,b) => a-b);

    let polyphonyIntegral = 0;
    let totalDuration = 0;
    let polyphonicDuration = 0;
    let bassDissDuration = 0;
    let upperDissDuration = 0;

    // 1. Calculate Polyphony and Dissonance
    if (ticks.length > 0) {
        const minT = ticks[0];
        const maxT = ticks[ticks.length - 1];
        totalDuration = maxT - minT + 1;

        for (let t = minT; t <= maxT; t++) {
            const activeVoiceMap = tl[t];
            if (!activeVoiceMap) continue; 

            const activeCount = Object.keys(activeVoiceMap).length;

            if (activeCount > 0) {
                polyphonyIntegral += (activeCount - SCORING.POLYPHONY_OFFSET);
            }

            if (activeCount < 2) continue; 

            polyphonicDuration += 1;

            const pitches: number[] = [];
            const activeIndices = Object.keys(activeVoiceMap).map(Number);

            activeIndices.forEach(v => pitches.push(activeVoiceMap[v].pitch));
            pitches.sort((a,b) => a-b);

            const bassPitch = pitches[0];
            const bassVoiceIdx = parseInt(Object.keys(activeVoiceMap).find(k => activeVoiceMap[parseInt(k)].pitch === bassPitch) || "-1");

            // Check Intervals
            for (let i = 0; i < activeIndices.length; i++) {
                for (let j = i + 1; j < activeIndices.length; j++) {
                    const vA = activeIndices[i];
                    const vB = activeIndices[j];
                    const p1 = activeVoiceMap[vA].pitch;
                    const p2 = activeVoiceMap[vB].pitch;

                    const lo = Math.min(p1, p2);
                    const hi = Math.max(p1, p2);
                    const isBassPair = (vA === bassVoiceIdx || vB === bassVoiceIdx);

                    if (isDissonant(lo, hi, isBassPair)) {
                        if (isBassPair) bassDissDuration += 1; 
                        else upperDissDuration += 1;
                    }
                }
            }
        }
    }

    // 2. Delegate Harmonic Analysis
    const { reward, penalty, chords } = analyzeStrettoHarmony(tl, ticks);

    // 3. Validation Checks (Parallel/Runs)
    for (let i = 0; i < voices.length; i++) {
        for (let j = i + 1; j < voices.length; j++) {
            const vA = voices[i];
            const vB = voices[j];

            const sounding: { t: number, lo: number, hi: number, lowerIsBass: boolean, p1: number, p2: number }[] = [];

            ticks.forEach(t => {
                const v = tl[t];
                if (v[vA] !== undefined && v[vB] !== undefined) {
                    const minAll = Math.min(...Object.values(v).map(d => d.pitch));
                    const p1 = v[vA].pitch;
                    const p2 = v[vB].pitch;
                    const lo = Math.min(p1, p2);
                    const hi = Math.max(p1, p2);
                    sounding.push({ t, lo, hi, lowerIsBass: lo === minAll, p1, p2 });
                }
            });

            if (sounding.length < 2) continue;

            // RULE 1: Parallel Perfect
            for (let k = 1; k < sounding.length; k++) {
                const prev = sounding[k-1];
                const curr = sounding[k];

                // Allow static intervals (no motion)
                if (prev.p1 === curr.p1 && prev.p2 === curr.p2) continue;

                // Allow Oblique Motion (One voice static, other moving)
                const p1Moved = prev.p1 !== curr.p1;
                const p2Moved = prev.p2 !== curr.p2;
                if (!p1Moved || !p2Moved) continue; 

                // Check for Parallel Perfects (Both voices moving into a perfect interval)
                if (isParallelPerfect(curr.lo, curr.hi)) {
                    // Previous must also be perfect
                    if (isParallelPerfect(prev.lo, prev.hi)) {
                        const int1 = (prev.hi - prev.lo) % 12;
                        const int2 = (curr.hi - curr.lo) % 12;
                        if (int1 === int2) {
                            errors.push(`Parallel ${int1 === 7 ? '5th' : '8ve'} (${getVoiceName(vA, totalVoices, voiceNames)}, ${getVoiceName(vB, totalVoices, voiceNames)})`);
                        }
                    }
                }
            }

            // RULE 2: Dissonance Runs
            let k = 0;
            while (k < sounding.length) {
                const startEv = sounding[k];
                if (!isDissonant(startEv.lo, startEv.hi, startEv.lowerIsBass)) {
                    k++; continue;
                }

                let segStart = k;
                while (k < sounding.length) {
                    const curr = sounding[k];
                    if (!isDissonant(curr.lo, curr.hi, curr.lowerIsBass)) break;

                    if ((curr.t - sounding[segStart].t + 1) >= 4) { // 1 Beat threshold
                        const distinctPitches = new Set<string>();
                        for(let m = segStart; m <= k; m++) distinctPitches.add(`${sounding[m].p1}-${sounding[m].p2}`);
                        if (distinctPitches.size > 1) {
                            errors.push(`Unresolved Dissonance Run (${getVoiceName(vA, totalVoices, voiceNames)}, ${getVoiceName(vB, totalVoices, voiceNames)})`);
                            break; // Stop checking this run
                        }
                    }
                    k++;
                }
            }
        }
    }

    // 4. Consonant Termination
    if (requireConsonantEnd) {
        for (const spec of specs) {
            const start16 = Math.round(spec.startBeat * 4);
            const end16 = start16 + spec.length; 
            const checkTick = end16 - 1;
            const activeVoices = tl[checkTick];
            if (!activeVoices || Object.keys(activeVoices).length < 2) continue;

            const myData = activeVoices[spec.voiceIndex];
            if (!myData) continue;
            const myPitch = myData.pitch;

            // Find Bass
            const activePitches = Object.values(activeVoices).map(v => v.pitch);
            const bassPitch = Math.min(...activePitches);

            let hasConsonance = false;
            for (const otherVStr in activeVoices) {
                const otherV = parseInt(otherVStr);
                if (otherV === spec.voiceIndex) continue;
                const otherPitch = activeVoices[otherV].pitch;
                const interval = Math.abs(myPitch - otherPitch) % 12;

                if (INTERVALS.CONSONANT.has(interval)) {
                    hasConsonance = true;
                    break;
                }
                // Special Rule for 4ths: If the lower note isn't the bass, a P4 is allowed as consonant
                if (interval === 5) {
                    const pairLower = Math.min(myPitch, otherPitch);
                    if (pairLower > bassPitch) {
                        hasConsonance = true;
                        break;
                    }
                }
            }
            if (!hasConsonance) {
                errors.push(`Non-Consonant Ending (${getVoiceName(spec.voiceIndex, totalVoices, voiceNames)})`);
            }
        }
    }

    return { 
        isValid: errors.length === 0, 
        errors,
        warnings, 
        polyphonyIntegral, 
        totalDuration, 
        polyphonicDuration,
        bassDissDuration,
        upperDissDuration,
        harmonicReward: reward,
        harmonicPenalty: penalty,
        detectedChords: chords
    };
}

// --- Pre-Pass Discovery ---

interface EntryCandidate {
    transposition: number;
    delayBeats: number;
    type: 'N' | 'I';
    score: number;
}

function findValidPairwiseCandidates(
    baseSubject: InternalSubjectNote[], 
    invertedSubject: InternalSubjectNote[], 
    options: StrettoSearchOptions, 
    validTranspositions: number[],
    effectiveLen16: number,
    subjectDurationBeats: number
): EntryCandidate[] {
    const candidates: EntryCandidate[] = [];

    // We check Subject (Voice 0) vs Candidate (Voice 1)
    // Candidate enters at `delay` with `transposition`
    const voice0: StrettoChainOption = {
        startBeat: 0, transposition: 0, type: 'N', length: effectiveLen16, voiceIndex: 0
    };

    const delays: number[] = [];
    // UPDATED: Allow delays up to 2/3 of length (Subject + Entry 1,2,3 are allowed to be wide)
    const maxDelay = Math.max(0.5, subjectDurationBeats * (2/3));
    for(let d = 0.5; d <= maxDelay; d += 0.5) delays.push(d);

    const types: {type: 'N'|'I', source: InternalSubjectNote[]}[] = [];
    types.push({ type: 'N', source: baseSubject });
    if (options.inversionMode !== 'None' && invertedSubject.length > 0) {
        types.push({ type: 'I', source: invertedSubject });
    }

    // Optimization: Check every combination
    for (const d of delays) {
        for (const t of validTranspositions) {
            for (const typeObj of types) {

                // DISALLOW COMPLEX EXCEPTIONS
                // If Inverted, restrict to Perfect Intervals (0, 5, 7, 12)
                if (options.disallowComplexExceptions && typeObj.type === 'I') {
                    const intervalClass = Math.abs(t % 12);
                    const isPerfect = [0, 5, 7].includes(intervalClass);
                    if (!isPerfect) continue; // Skip 3rds/6ths for inversions
                }

                // Construct pairwise check
                const voice1: StrettoChainOption = {
                    startBeat: d,
                    transposition: t,
                    type: typeObj.type,
                    length: effectiveLen16, // Use full length for check
                    voiceIndex: 1
                };

                // NOTE: Pairwise validation still uses the slow checkRulesAndStats for depth 2,
                // but this runs once at start. The recursive solver will use the fast StrettoGrid.
                const res = checkRulesAndStats([voice0, voice1], baseSubject, invertedSubject, options.requireConsonantEnd, options.ensembleTotal, options.voiceNames);

                if (res.isValid) {
                    // Heuristic scoring for sorting
                    // Prefer: High polyphony, Sweet Dissonance, Consonant End
                    let score = res.polyphonyIntegral;
                    if (res.bassDissDuration === 0) score += 50; 

                    candidates.push({
                        transposition: t,
                        delayBeats: d,
                        type: typeObj.type,
                        score: score
                    });
                }
            }
        }
    }

    // Sort by best score first, then by smallest absolute transposition (Compactness preference)
    return candidates.sort((a,b) => {
        if (b.score !== a.score) return b.score - a.score;
        return Math.abs(a.transposition) - Math.abs(b.transposition);
    });
}

// --- Search Algorithm ---

export async function searchStrettoChains(
    rawSubject: RawNote[],
    options: StrettoSearchOptions,
    ppq: number
): Promise<StrettoSearchReport> {

    // Safety Break
    const START_TIME = Date.now();
    const TIME_LIMIT_MS = 30000; 
    const MAX_VISITED_NODES = 500000; 
    let nodesVisited = 0;
    let stopReason: 'Success' | 'Timeout' | 'NodeLimit' | 'Exhausted' = 'Exhausted';
    let maxDepthReached = 0;

    const baseSubject = normalizeSubject(rawSubject, ppq);
    if (baseSubject.length === 0) {
        return { results: [], stats: { nodesVisited: 0, timeMs: 0, stopReason: 'Exhausted', maxDepthReached: 0 } };
    }

    // Ensure effective length captures the last Note-Off, not just the abstract end
    // NOTE: This intentionally excludes trailing rests from the subject definition.
    const effectiveLen16 = getEffectiveSubjectLength16(baseSubject);
    const subjectDurationBeats = effectiveLen16 / 4;

    // Create Grid
    const maxChainDuration16 = Math.ceil((options.targetChainLength * subjectDurationBeats * 4) * 2); // Buffer
    const grid = new StrettoGrid(options.ensembleTotal, maxChainDuration16);

    const invertedSubject: InternalSubjectNote[] = [];
    if (options.inversionMode !== 'None') {
        baseSubject.forEach(n => {
            const inv = invertPitch(n.pitch, options.pivotMidi);
            if (inv !== null) invertedSubject.push({ ...n, pitch: inv });
        });
    }

    const validResults: StrettoChainResult[] = [];
    const invalidResults: StrettoChainResult[] = [];
    const partialResults: StrettoChainResult[] = [];

    const MAX_VALID_RESULTS = 200; 
    const MAX_INVALID_BUFFER = 50; 

    const ensembleTotal = options.ensembleTotal;
    const targetChainLength = options.targetChainLength;

    const validTranspositions = Array.from(INTERVALS.TRAD_TRANSPOSITIONS);
    if (options.thirdSixthMode !== 'None') {
        INTERVALS.THIRD_SIXTH_TRANSPOSITIONS.forEach(t => {
            if (!validTranspositions.includes(t)) validTranspositions.push(t);
        });
    }

    // 1. Perform Pairwise Pre-Pass
    const potentialCandidates = findValidPairwiseCandidates(baseSubject, invertedSubject, options, validTranspositions, effectiveLen16, subjectDurationBeats);

    const isBudgetAvailable = (mode: StrettoConstraintMode, currentUsage: number) => {
        if (mode === 'None') return false;
        if (mode === 'Max 1') return currentUsage < 1;
        return true; 
    };

    function processChain(chain: StrettoChainOption[], validation: ValidationResult, targetList: StrettoChainResult[]) {
        const log: ScoreLog = { base: 0, penalties: [], bonuses: [], total: 0 };
        let score = 0; 

        // 1. Polyphony
        if (validation.totalDuration > 0) {
            const avgScore = validation.polyphonyIntegral / validation.totalDuration;
            const polyScore = SCORING.POLYPHONY_BASE_MULT * avgScore;
            score += polyScore;
            log.bonuses.push({ reason: `Polyphony Density`, points: Math.round(polyScore) });
        }

        // 2. Dissonance (Proportional)
        if (validation.polyphonicDuration > 0) {
            const weightedDiss = (SCORING.DISS_WEIGHT_BASS * validation.bassDissDuration) + (SCORING.DISS_WEIGHT_UPPER * validation.upperDissDuration);
            const ratio = weightedDiss / validation.polyphonicDuration;

            if (ratio > SCORING.DISS_PENALTY_START) {
                const excess = ratio - SCORING.DISS_PENALTY_START;
                const penalty = excess * SCORING.DISS_PENALTY_SLOPE;
                score -= penalty;
                log.penalties.push({ reason: `Dissonance ${(ratio*100).toFixed(0)}%`, points: Math.round(penalty) });
            } else if (ratio >= SCORING.BUCKET_SWEET_MIN && ratio <= SCORING.BUCKET_SWEET_MAX) {
                score += SCORING.BUCKET_SWEET_SCORE;
                log.bonuses.push({ reason: `Rich Harmony (${(ratio*100).toFixed(0)}%)`, points: SCORING.BUCKET_SWEET_SCORE });
            }
        }

        // 3. Harmonic Quality
        if (validation.harmonicReward > 0) {
            score += validation.harmonicReward;
            log.bonuses.push({ reason: "Harmonic Quality", points: Math.round(validation.harmonicReward) });
        }
        if (validation.harmonicPenalty > 0) {
            score -= validation.harmonicPenalty;
            log.penalties.push({ reason: "NCT Clashing", points: Math.round(validation.harmonicPenalty) });
        }

        // 4. Distance/Structure Scoring (For remaining valid chains)
        const distanceCounts: Record<string, number> = {};
        chain.forEach((e, i) => {
            if (i === 0) return;
            const prev = chain[i-1];
            const dist = e.startBeat - prev.startBeat;
            const distStr = dist.toFixed(2);
            distanceCounts[distStr] = (distanceCounts[distStr] || 0) + 1;

            const ratio = dist / subjectDurationBeats;
            if (ratio <= SCORING.COMPACT_HYPER_THRESH) {
                score += SCORING.COMPACT_HYPER_BONUS;
                log.bonuses.push({ reason: `Hyper-Stretto (V${i+1})`, points: SCORING.COMPACT_HYPER_BONUS });
            } else if (ratio <= SCORING.COMPACT_TIGHT_THRESH) {
                score += SCORING.COMPACT_TIGHT_BONUS;
                log.bonuses.push({ reason: `Tight Stretto (V${i+1})`, points: SCORING.COMPACT_TIGHT_BONUS });
            }

            const absInt = e.transposition;
            const absSemi = Math.abs(absInt % 12);
            if ([3,4,8,9].includes(absSemi)) {
                score += SCORING.IMPERFECT_CONS_BONUS;
                log.bonuses.push({ reason: `3rd/6th Entry`, points: SCORING.IMPERFECT_CONS_BONUS });
            }
        });

        const uniqueDistances = Object.keys(distanceCounts).length;
        if (uniqueDistances > 1) {
            const b = (uniqueDistances - 1) * SCORING.DIST_VARIETY_BONUS;
            score += b;
            log.bonuses.push({ reason: `Distance Variety`, points: b });
        }

        // --- Invalidity Penalties ---
        if (!validation.isValid) {
            const fatalPenalty = validation.errors.length * 1000;
            score -= fatalPenalty;
            log.penalties.push({ reason: `${validation.errors.length} Fatal Rules Broken`, points: fatalPenalty });
        }

        // Length Bonus (for partials)
        if (chain.length < targetChainLength) {
            const missing = targetChainLength - chain.length;
            score -= (missing * 50); // Penalty for shortness
        }

        log.total = Math.max(0, score);

        const resultObj: StrettoChainResult = {
            id: `chain-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
            entries: [...chain],
            warnings: [...validation.errors, ...validation.warnings],
            score: log.total,
            scoreLog: log,
            detectedChords: validation.detectedChords
        };

        targetList.push(resultObj);
        targetList.sort((a,b) => b.score - a.score);
        if (targetList.length > MAX_INVALID_BUFFER) {
            targetList.pop();
        }
    }

    // Recursive Solver
    async function solve(
        chain: StrettoChainOption[], 
        nInv: number, n3rd: number, nTrunc: number,
        voiceEndTimes16: number[] 
    ) {
        nodesVisited++;
        if (chain.length > maxDepthReached) maxDepthReached = chain.length;

        if (validResults.length >= MAX_VALID_RESULTS) {
            stopReason = 'Success';
            return;
        }
        if (Date.now() - START_TIME > TIME_LIMIT_MS) {
            stopReason = 'Timeout';
            if (chain.length >= 3) {
                 const validation = checkRulesAndStats(chain, baseSubject, invertedSubject, options.requireConsonantEnd, options.ensembleTotal, options.voiceNames);
                 processChain(chain, validation, partialResults);
            }
            return;
        }
        if (nodesVisited > MAX_VISITED_NODES) {
            stopReason = 'NodeLimit';
            if (chain.length >= 3) {
                 const validation = checkRulesAndStats(chain, baseSubject, invertedSubject, options.requireConsonantEnd, options.ensembleTotal, options.voiceNames);
                 processChain(chain, validation, partialResults);
            }
            return;
        }

        // Leaf / Termination Check
        if (chain.length === targetChainLength) {
            const validation = checkRulesAndStats(chain, baseSubject, invertedSubject, options.requireConsonantEnd, options.ensembleTotal, options.voiceNames);
            if (validation.isValid) processChain(chain, validation, validResults);
            else processChain(chain, validation, invalidResults);
            return;
        }

        const lastEntry = chain[chain.length - 1];
        let extensionsFound = false;

        // --- Active Voice Transposition Map ---
        const lastTranspositions = new Map<number, number>();
        chain.forEach(entry => {
            lastTranspositions.set(entry.voiceIndex, entry.transposition);
        });

        // --- PRUNING OPTIMIZATION: "Redundancy Filter" ---
        // Scope: Restricted to OUTER VOICES ONLY (Voice 0 and Voice N-1).
        // Rationale: Inner voices have complex neighbor interactions; octave displacement matters.
        // Outer voices have free space above/below, so compact intervals are preferred if they fit.
        const triedFunctions = new Set<string>();

        for (const cand of potentialCandidates) {
            if (stopReason !== 'Exhausted') break;

            const harmonicKey = `${cand.delayBeats.toFixed(2)}-${cand.type}-${(cand.transposition % 12 + 12) % 12}`;

            const newStart = lastEntry.startBeat + cand.delayBeats;

            // --- DISTANCE LOGIC & CONSTRAINTS ---
            if (chain.length >= 2) {
                const prevDist = lastEntry.startBeat - chain[chain.length - 2].startBeat;
                const newDist = cand.delayBeats;

                // 1. HARD: Global Uniqueness of Distance
                let isUnique = true;
                for (let k = 1; k < chain.length; k++) {
                    const existingDist = chain[k].startBeat - chain[k-1].startBeat;
                    if (Math.abs(existingDist - newDist) < 0.01) {
                        isUnique = false;
                        break;
                    }
                }
                if (!isUnique) continue;

                // 2. HARD: Elasticity Limit (Max +1.0)
                if (newDist > prevDist + 1.0 + 0.01) continue;

                // 3. HARD: Expansion Reaction
                if (chain.length >= 3) {
                    const prevPrevDist = chain[chain.length - 2].startBeat - chain[chain.length - 3].startBeat;
                    if (prevDist > prevPrevDist + 0.01) {
                        if (newDist > prevPrevDist - 1.0 + 0.01) continue;
                    }
                }
            }

            const entryIndex = chain.length + 1;
            const constraintThreshold = Math.floor(targetChainLength / 2) + 1;
            const maxDelayEarly = subjectDurationBeats * (2/3);
            const maxDelayLate = subjectDurationBeats * 0.5;
            const limit = entryIndex >= constraintThreshold ? maxDelayLate : maxDelayEarly;

            if (cand.delayBeats > limit) continue;

            const absTrans = cand.transposition; 
            if (absTrans === lastEntry.transposition) continue;

            const start16 = Math.round(newStart * 4);
            let assignedVoice = -1;

            // --- STRICT VOICE ASSIGNMENT LOOP ---
            for (let v = 0; v < ensembleTotal; v++) {
                // 1. Time Availability Check (Linear tracker)
                // Rule: "A voice is not free from start of entry to start of entry + length of entry - 1 beat."

                const lastEnd16 = voiceEndTimes16[v];
                const allowedStart16 = Math.max(0, lastEnd16 - 4); // 4 ticks = 1 beat overlap allowed

                if (start16 < allowedStart16) continue; // Busy

                // 2. Transposition Envelope Constraints (Crossing Check)
                // "A voice should not be transposed up/down by more than the voice above/beneath it."

                // Voice Above (v-1)
                if (lastTranspositions.has(v - 1)) {
                    const tAbove = lastTranspositions.get(v - 1)!;
                    // Current T must be <= T_Above (cannot be transposed higher than the voice above)
                    if (absTrans > tAbove) continue;
                }

                // Voice Below (v+1)
                if (lastTranspositions.has(v + 1)) {
                    const tBelow = lastTranspositions.get(v + 1)!;
                    // Current T must be >= T_Below (cannot be transposed lower than the voice below)
                    if (absTrans < tBelow) continue;
                }

                assignedVoice = v;
                break; 
            }

            if (assignedVoice === -1) continue; 

            // --- OUTER VOICE PRUNING CHECK ---
            const isOuterVoice = (assignedVoice === 0 || assignedVoice === ensembleTotal - 1);
            if (isOuterVoice && triedFunctions.has(harmonicKey)) {
                // We already successfully placed this harmonic function in this outer voice slot.
                // Since candidates are sorted by compactness, we have used the tightest version.
                // Prune the wider versions.
                continue;
            }

            // Budget Checks
            const absSemi = Math.abs(absTrans % 12);
            const is3rd = [3,4,8,9].includes(absSemi);
            if (is3rd) {
                // "Disallow Complex Exceptions": If 3rd/6th, we cannot truncate OR invert (already filtered in pre-pass)
                if (options.disallowComplexExceptions && options.truncationMode !== 'None') {
                    // Force full length if using 3rds
                }
                if (!isBudgetAvailable(options.thirdSixthMode, n3rd)) continue;
            }

            const costInv = cand.type === 'I' ? 1 : 0;
            if (costInv > 0 && !isBudgetAvailable(options.inversionMode, nInv)) continue;

            // --- ACCELERATION: GRID VALIDATION (Cross-Voice Polyphony Only) ---
            // We use the grid here ONLY to check for Parallel 5ths/8ves against OTHER voices.
            const sourceNotes = cand.type === 'N' ? baseSubject : invertedSubject;

            // Write to Grid
            grid.write(assignedVoice, sourceNotes, start16, absTrans);

            // Check for Fatal Parallel Errors immediately
            const hasParallel = grid.hasParallelErrors(assignedVoice, sourceNotes, start16, absTrans);

            if (hasParallel) {
                // Backtrack Grid immediately
                grid.clear(assignedVoice, sourceNotes, start16);
                // Note: Do NOT prune here. If +7 failed, +19 might work.
                continue;
            }

            // SUCCESS! We found a valid slot.
            // If this was an Outer Voice, lock this harmonic function to prune redundant intervals later.
            if (isOuterVoice) {
                triedFunctions.add(harmonicKey);
            }

            const newEntry: StrettoChainOption = {
                startBeat: newStart,
                transposition: absTrans,
                type: cand.type,
                length: effectiveLen16,
                voiceIndex: assignedVoice
            };

            const testChain = [...chain, newEntry];
            const newVoiceState = [...voiceEndTimes16];
            const entryEnd16 = start16 + effectiveLen16;
            // Update end time tracking. 
            newVoiceState[assignedVoice] = Math.max(newVoiceState[assignedVoice], entryEnd16);

            extensionsFound = true;

            await solve(
                testChain, 
                nInv + costInv, 
                n3rd + (is3rd?1:0), 
                nTrunc, 
                newVoiceState
            );

            // Backtrack Grid
            grid.clear(assignedVoice, sourceNotes, start16);

            if (validResults.length >= MAX_VALID_RESULTS) return;
        }

        // Partial Chain Fallback
        if (!extensionsFound && chain.length >= 3) {
             const validation = checkRulesAndStats(chain, baseSubject, invertedSubject, options.requireConsonantEnd, options.ensembleTotal, options.voiceNames);
             processChain(chain, validation, partialResults);
        }
    }

    const initialVoiceState = new Array(ensembleTotal).fill(0);
    initialVoiceState[options.subjectVoiceIndex] = effectiveLen16;

    // Initialize Grid with Subject
    grid.write(options.subjectVoiceIndex, baseSubject, 0, 0);

    await solve([{
        startBeat: 0,
        transposition: 0,
        type: 'N',
        length: effectiveLen16,
        voiceIndex: options.subjectVoiceIndex
    }], 0, 0, 0, initialVoiceState);

    // Decision Logic: Valid > Partial > Invalid
    let rawResults = validResults;
    if (rawResults.length === 0) rawResults = partialResults;
    if (rawResults.length === 0) rawResults = invalidResults;

    // --- DEDUPLICATION LOGIC ---
    // Filter out results that are "Harmonically Identical" (same interval classes)
    const uniqueChains = new Map<string, StrettoChainResult>();

    rawResults.forEach(res => {
        // Create signature: IntervalClass sequence
        const signature = res.entries.map(e => {
            const pc = (e.transposition % 12 + 12) % 12;
            const dist = e.startBeat.toFixed(2);
            return `${pc}@${dist}`;
        }).join('|');

        if (!uniqueChains.has(signature)) {
            uniqueChains.set(signature, res);
        } else {
            const existing = uniqueChains.get(signature)!;
            if (res.score > existing.score) {
                uniqueChains.set(signature, res);
            }
        }
    });

    let resultsToReturn = Array.from(uniqueChains.values());

    const groups = new Map<string, StrettoChainResult[]>();

    const sortStrategy = (a: StrettoChainResult, b: StrettoChainResult) => {
        if (a.entries.length !== b.entries.length) {
            return b.entries.length - a.entries.length;
        }
        return b.score - a.score;
    };

    resultsToReturn.forEach(res => {
        const rhythmKey = res.entries.map(e => e.startBeat.toFixed(2)).join('|');
        if (!groups.has(rhythmKey)) groups.set(rhythmKey, []);
        groups.get(rhythmKey)!.push(res);
    });

    const finalResults: StrettoChainResult[] = [];

    groups.forEach((group) => {
        group.sort(sortStrategy);
        const leader = group[0];
        if (group.length > 1) leader.variations = group.slice(1);
        finalResults.push(leader);
    });

    return {
        results: finalResults.sort(sortStrategy).slice(0, 50),
        stats: {
            nodesVisited,
            timeMs: Date.now() - START_TIME,
            stopReason: validResults.length > 0 ? 'Success' : stopReason,
            maxDepthReached
        }
    };
}

import { RawNote, StrettoCandidate, StrettoError, StrettoGrade, HarmonicRegion, StrettoChainOption } from '../../types';
import { getFormattedTime } from './midiHarmony';
import { getStrictPitchName, getIntervalLabel } from './midiSpelling';
import { analyzeStrettoHarmony } from './strettoHarmonyAnalysis';

const SEMIS_P8 = 12;
const SEMIS_P5 = 7;
const SEMIS_P4 = 5;

// Strict counterpoint intervals
const DISSONANT_INTERVALS = [1, 2, 6, 10, 11]; // m2, M2, TT, m7, M7
const PERFECT_CONSONANCES = [0, 7]; // P1, P5 (P8 is 0 mod 12)
const IMPERFECT_CONSONANCES = [3, 4, 8, 9]; // m3, M3, m6, M6

export interface VoiceEvent {
    tick: number;
    endTick: number; // New field for exact duration tracking
    pitch1: number; // Subject
    pitch2: number; // Answer (Transposed Subject)
    hasAttack1: boolean;
    hasAttack2: boolean;
}

export function getVerticalIntervals(subject: RawNote[], answer: RawNote[]): VoiceEvent[] {
    const timePoints = new Set<number>();
    [...subject, ...answer].forEach(n => {
        if (!n) return; // FIX: Ensure note exists
        timePoints.add(n.ticks);
        timePoints.add(n.ticks + n.durationTicks); // Also check release points
    });

    const sortedPoints = Array.from(timePoints).sort((a,b) => a-b);
    const events: VoiceEvent[] = [];

    // Filter points that are just releases of the very last note
    const endOfMusic = Math.max(0, ...[...subject, ...answer].map(n => n ? n.ticks + n.durationTicks : 0));

    for (let i = 0; i < sortedPoints.length - 1; i++) {
        const t = sortedPoints[i];
        if (t >= endOfMusic) break;

        // Check active notes at this time segment (t to nextPoint)
        // We use t + epsilon to check inside the window
        const checkTime = t; 

        const n1 = subject.find(n => n && n.ticks <= checkTime && (n.ticks + n.durationTicks) > checkTime);
        const n2 = answer.find(n => n && n.ticks <= checkTime && (n.ticks + n.durationTicks) > checkTime);

        if (n1 && n2) {
            events.push({
                tick: t,
                endTick: sortedPoints[i+1], // The state is valid until the next timeline event
                pitch1: n1.midi,
                pitch2: n2.midi,
                hasAttack1: n1.ticks === t,
                hasAttack2: n2.ticks === t
            });
        }
    }

    return events;
}

function isStrongBeat(tick: number, ppq: number, tsNum: number, tsDenom: number): boolean {
    const ticksPerMeasure = ppq * tsNum * (4 / tsDenom);
    const pos = tick % ticksPerMeasure;
    if (pos === 0) return true; // Downbeat
    if (tsNum === 4 && tsDenom === 4 && pos === (ticksPerMeasure / 2)) return true;
    return false; 
}

export function generateHarmonicRegions(events: VoiceEvent[]): HarmonicRegion[] {
    const regions: HarmonicRegion[] = [];
    let previousState: 'consonance' | 'dissonance' = 'consonance';

    // For Motion checking
    let prevP1: number | null = null;
    let prevP2: number | null = null;

    for (let i = 0; i < events.length; i++) {
        const ev = events[i];
        const duration = ev.endTick - ev.tick;

        if (duration <= 0) continue;

        const p1 = ev.pitch1;
        const p2 = ev.pitch2;
        const interval = Math.abs(p1 - p2);
        const intervalClass = interval % 12;
        const isBass1 = p1 < p2;
        const upperPitch = isBass1 ? p2 : p1;
        const prevUpperPitch = isBass1 ? (prevP2) : (prevP1);

        // Determine Interval Type
        const isP4 = intervalClass === 5; // P4 dissonant in 2-part if no bass support (strict: always diss)
        const isDiss = DISSONANT_INTERVALS.includes(intervalClass) || isP4;

        let regionType: HarmonicRegion['type'];

        if (isDiss) {
            if (previousState === 'consonance') {
                regionType = 'dissonance_1'; // Deep Blueish Purple
            } else {
                regionType = 'dissonance_consecutive'; // Reddish Purple
            }
            previousState = 'dissonance';
        } else {
            if (PERFECT_CONSONANCES.includes(intervalClass)) {
                regionType = 'perfect_consonance'; // Turquoise
            } else {
                regionType = 'imperfect_consonance'; // Lime Green
            }
            previousState = 'consonance';
        }

        // Determine Error Overlay (Parallel/Direct)
        let errorType: HarmonicRegion['errorType'] = null;

        if (prevP1 !== null && prevP2 !== null) {
            // Oblique check: If either voice stayed the same, it's NOT parallel
            const p1Moved = prevP1 !== p1;
            const p2Moved = prevP2 !== p2;

            // Only check for parallel if BOTH voices moved
            if (p1Moved && p2Moved) {
                const isParallelMotion = (p1 - prevP1) * (p2 - prevP2) > 0;
                const isPerfect = intervalClass === 0 || intervalClass === 7;

                // Check Parallel
                if (isPerfect && isParallelMotion) {
                    const prevInterval = Math.abs(prevP1 - prevP2);
                    const prevClass = prevInterval % 12;
                    if (prevClass === intervalClass) {
                        errorType = 'parallel';
                    }
                }

                // Check Direct (Hidden) Perfects
                // Definition: Similar motion into a perfect interval, where the upper voice leaps
                if (!errorType && isPerfect && isParallelMotion) {
                    // Check leap size of upper voice
                    if (prevUpperPitch !== null) {
                        const upperMove = Math.abs(upperPitch - prevUpperPitch);
                        if (upperMove > 2) { // Leap > Major 2nd
                            errorType = 'direct';
                        }
                    }
                }
            }
        }

        const name1 = getStrictPitchName(p1);
        const name2 = getStrictPitchName(p2);
        const label = getIntervalLabel(interval);

        regions.push({
            startTick: ev.tick,
            endTick: ev.endTick, 
            type: regionType,
            errorType: errorType,
            intervalLabel: label,
            description: `${label}: ${name1}, ${name2}`
        });

        // Only update 'prev' state if there was an attack (motion event boundary)
        prevP1 = p1;
        prevP2 = p2;
    }

    return regions;
}

// Inversion Logic
const SCALE_INTERVALS = [0, 2, 4, 5, 7, 9, 11];

function invertPitch(pitch: number, pivot: number): number | null {
    const diff = pitch - pivot;
    const octaves = Math.floor(diff / 12);
    const semitone = (diff % 12 + 12) % 12;
    const scaleIndex = SCALE_INTERVALS.indexOf(semitone);
    if (scaleIndex === -1) return pivot - diff; 
    const absStep = (octaves * 7) + scaleIndex;
    const invStep = -absStep;
    const invOctaves = Math.floor(invStep / 7);
    const invRem = (invStep % 7 + 7) % 7;
    const invSemitone = SCALE_INTERVALS[invRem];
    return pivot + (invOctaves * 12) + invSemitone;
}

export function analyzeStrettoCandidate(
    subject: RawNote[], 
    intervalSemis: number, 
    delayTicks: number, 
    ppq: number,
    ts: { num: number, den: number },
    isInverted: boolean = false,
    pivotMidi: number = 60
): StrettoCandidate {

    const answer: RawNote[] = subject.map(n => {
        if (!n) return null as any;
        let newMidi = n.midi;
        if (isInverted) {
            const inv = invertPitch(n.midi, pivotMidi);
            newMidi = inv !== null ? inv : n.midi; // Fallback?
        }
        newMidi += intervalSemis;

        return {
            ...n,
            ticks: n.ticks + delayTicks,
            midi: newMidi,
            name: getStrictPitchName(newMidi),
            voiceIndex: 1
        };
    }).filter(n => !!n);

    const startOverlap = delayTicks; 
    const subjectEnd = Math.max(0, ...subject.map(n => n ? n.ticks + n.durationTicks : 0));
    const endOverlap = subjectEnd;

    if (startOverlap >= endOverlap) {
        return {
            id: `invalid_gap`,
            intervalSemis, intervalLabel: 'N/A', delayBeats: 0, delayTicks,
            grade: 'INVALID', errors: [{ tick: 0, timeFormatted: '-', type: 'Consecutive Dissonance', details: 'No overlap', severity: 'fatal' }],
            notes: []
        };
    }

    const events = getVerticalIntervals(subject, answer).filter(e => e.tick >= startOverlap);

    // Generate Visualization Regions
    const harmonicRegions = generateHarmonicRegions(events);

    // Generate Standard Errors (Filtering from regions for text report)
    const errors: StrettoError[] = [];

    harmonicRegions.forEach(r => {
        const timeStr = getFormattedTime(r.startTick, ppq, ts.num, ts.den);
        const onStrong = isStrongBeat(r.startTick, ppq, ts.num, ts.den);

        if (r.errorType === 'parallel') {
            errors.push({
                tick: r.startTick, timeFormatted: timeStr,
                type: r.intervalLabel.includes('P5') ? 'Parallel 5th' : 'Parallel 8ve',
                details: `Parallel motion into ${r.intervalLabel}`,
                severity: onStrong ? 'fatal' : 'warning'
            });
        }
        if (r.errorType === 'direct') {
             errors.push({
                tick: r.startTick, timeFormatted: timeStr,
                type: r.intervalLabel.includes('P5') ? 'Direct 5th' : 'Direct 8ve',
                details: `Direct motion into ${r.intervalLabel} (Upper leap)`,
                severity: 'warning'
            });
        }
        if (r.type === 'dissonance_consecutive' && onStrong) {
             // Rule Update: P4 consecutive dissonances are not fatal (can be used in upper voices later)
             const isP4Run = r.intervalLabel.includes('P4');
             errors.push({
                 tick: r.startTick, timeFormatted: timeStr,
                 type: 'Consecutive Dissonance',
                 details: 'Consecutive dissonance',
                 severity: isP4Run ? 'warning' : 'fatal'
             });
        }
    });

    // Run Harmonic Analysis on the candidate pair (2 voices)
    const tl: any = {};
    const ticks: number[] = [];
    const allNotes = [...subject, ...answer];
    const uniqueTicks = new Set<number>();
    allNotes.forEach(n => { if (n) uniqueTicks.add(n.ticks); });
    Array.from(uniqueTicks).sort((a,b)=>a-b).forEach(t => ticks.push(t));

    ticks.forEach(t => {
        const active = allNotes.filter(n => n && n.ticks <= t && (n.ticks + n.durationTicks) > t);
        if (active.length > 0) {
            tl[t] = {};
            active.forEach(n => {
                const dur16 = Math.max(1, Math.round(n.durationTicks / (ppq/4)));
                tl[t][n.voiceIndex ?? 0] = { pitch: n.midi, dur16 };
            });
        }
    });

    const harmonyResult = analyzeStrettoHarmony(tl, ticks);

    let grade: StrettoGrade = 'STRONG';
    if (errors.some(e => e.severity === 'fatal')) grade = 'INVALID';
    else if (errors.length > 0) grade = 'VIABLE';

    let intLabel = getIntervalLabel(Math.abs(intervalSemis));
    if (intervalSemis < 0) intLabel = '-' + intLabel;
    else if (intervalSemis > 0) intLabel = '+' + intLabel;

    if (isInverted) intLabel += " (Inv)";

    const delayBeats = delayTicks / (ppq * (4 / ts.den));

    return {
        id: `${intLabel}@${delayBeats.toFixed(1)}${isInverted?'i':''}`,
        intervalSemis,
        intervalLabel: intLabel,
        delayBeats: parseFloat(delayBeats.toFixed(2)),
        delayTicks,
        grade,
        errors,
        notes: allNotes,
        regions: harmonicRegions,
        detectedChords: harmonyResult.chords
    };
}

