export interface StrettoConfig {
    intervals: {
        unison: boolean;
        octave: boolean; // +/- 1 & 2
        fifth: boolean; // +/- P5
        fourth: boolean; // +/- P4
    };
    maxDistanceBeats: number; // calculated limit
}

export interface StrettoChainOption {
    startBeat: number; // Relative to start of piece (or previous entry if chained logic, but logic usually normalized to 0)
    transposition: number;
    type: 'N' | 'I'; // Normal or Inverted
    length: number; // Full or Truncated length in ticks
    voiceIndex: number;
}

export interface ScoreLogItem {
    reason: string;
    points: number;
}

export interface ScoreLog {
    base: number;
    penalties: ScoreLogItem[];
    bonuses: ScoreLogItem[];
    total: number;
}

export interface StrettoChainResult {
    id: string;
    entries: StrettoChainOption[];
    warnings: string[];
    score: number; // Higher is better (variety of distances, lack of errors)
    scoreLog?: ScoreLog;
    variations?: StrettoChainResult[]; // Variations with same rhythmic structure but different intervals
    detectedChords?: string[]; // For UI reporting
}

export interface StrettoSearchReport {
    results: StrettoChainResult[];
    stats: {
        nodesVisited: number;
        timeMs: number;
        stopReason: 'Success' | 'Timeout' | 'NodeLimit' | 'Exhausted';
        maxDepthReached: number;
    };
}

export type StrettoConstraintMode = 'None' | 'Max 1' | 'Unlimited';

export interface StrettoSearchOptions {
    ensembleTotal: number;
    targetChainLength: number;
    subjectVoiceIndex: number;
    truncationMode: StrettoConstraintMode;
    truncationMusicalValue: string; // e.g., '1/2', '1/1' - replacing percent
    inversionMode: StrettoConstraintMode;
    thirdSixthMode: StrettoConstraintMode;
    pivotMidi: number; // For inversion
    requireConsonantEnd: boolean;
    disallowComplexExceptions: boolean;
    voiceNames?: Record<number, string>;
}

import { StrettoCandidate } from '../../types';
import { Midi } from '@tonejs/midi';

export function downloadStrettoCandidate(candidate: StrettoCandidate, sourcePpq: number) {
    const midi = new Midi();

    // The default PPQ for a new Tone.js Midi instance is 480.
    // The 'ppq' property on the header is a getter-only in some environments, so we cannot assign it directly.
    // Instead, we scale the ticks from the source resolution to the target resolution (480).
    const TARGET_PPQ = 480; 
    const scaleFactor = TARGET_PPQ / sourcePpq;

    // Set default tempo and time signature to ensure players recognize the file
    midi.header.setTempo(120);
    midi.header.timeSignatures.push({
        timeSignature: [4, 4],
        ticks: 0,
    });

    // Group notes by voice index to create separate tracks
    const notesByVoice: Record<number, any[]> = {};
    candidate.notes.forEach(n => {
        const v = n.voiceIndex ?? 0;
        if (!notesByVoice[v]) notesByVoice[v] = [];
        notesByVoice[v].push(n);
    });

    Object.keys(notesByVoice).map(Number).sort((a,b) => a-b).forEach(vIdx => {
        const track = midi.addTrack();
        track.name = `Voice ${vIdx + 1}`;
        track.channel = vIdx; // Assign channel for separation

        // Add instrument (Piano default)
        track.instrument.number = 0;

        notesByVoice[vIdx].forEach(n => {
            track.addNote({
                midi: n.midi,
                ticks: Math.round(n.ticks * scaleFactor),
                durationTicks: Math.round(n.durationTicks * scaleFactor),
                velocity: n.velocity
            });
        });
    });

    const midiBytes = midi.toArray();
    const blob = new Blob([midiBytes], { type: 'audio/midi' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `Stretto_${candidate.intervalLabel}_${candidate.delayBeats}beats.mid`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
}

import { StrettoCandidate } from '../../types';
import { Midi } from '@tonejs/midi';
import { getVoiceLabel } from './midiVoices';

/**
 * Generates and downloads a multi-track MIDI file representing the Stretto result.
 * Fixes "Cannot set property ppq" error by scaling ticks instead of modifying read-only header.
 */
export function downloadStrettoCandidate(candidate: StrettoCandidate, sourcePpq: number, voiceNames?: Record<number, string>) {
    const midi = new Midi();

    // Tone.js MIDI instances default to 480 PPQ. 
    // We scale incoming ticks to this resolution to avoid modifying read-only header properties.
    const TARGET_PPQ = 480; 
    const scaleFactor = TARGET_PPQ / sourcePpq;

    // Set basic metadata
    midi.header.setTempo(120);
    midi.header.timeSignatures.push({
        timeSignature: [4, 4],
        ticks: 0,
    });

    // Group notes by voice index
    const notesByVoice: Record<number, any[]> = {};
    candidate.notes.forEach(n => {
        const v = n.voiceIndex ?? 0;
        if (!notesByVoice[v]) notesByVoice[v] = [];
        notesByVoice[v].push(n);
    });

    const voiceIndices = Object.keys(notesByVoice).map(Number).sort((a,b) => a-b);

    // Determine total count for fallback labels
    const maxIdx = voiceIndices.length > 0 ? Math.max(...voiceIndices) : 0;
    const totalVoicesForLabeling = maxIdx + 1;

    voiceIndices.forEach(vIdx => {
        const track = midi.addTrack();

        // Use user-assigned voice name if available, else fallback to algorithmic label
        const nameFromConfig = voiceNames?.[vIdx];
        track.name = nameFromConfig || getVoiceLabel(vIdx, totalVoicesForLabeling);

        // Standard channel assignment (0-15)
        track.channel = vIdx % 16;
        track.instrument.number = 0; // Acoustic Grand Piano default

        const voiceNotes = notesByVoice[vIdx];
        voiceNotes.forEach(n => {
            track.addNote({
                midi: n.midi,
                ticks: Math.round(n.ticks * scaleFactor),
                durationTicks: Math.round(n.durationTicks * scaleFactor),
                velocity: n.velocity
            });
        });
    });

    // Prepare and trigger download
    const midiBytes = midi.toArray();
    const blob = new Blob([midiBytes], { type: 'audio/midi' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;

    // Descriptive filename
    const safeLabel = candidate.intervalLabel.replace(/[^a-z0-9]/gi, '_');
    a.download = `Stretto_${safeLabel}_${candidate.delayBeats}beats.mid`;

    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
}

import React, { useState, useMemo, useEffect } from 'react';
import { RawNote, StrettoCandidate, StrettoSearchOptions, StrettoChainResult, HarmonicRegion, StrettoSearchReport } from '../types';
import { parseSimpleAbc } from './services/abcBridge';
import { analyzeStrettoCandidate, getVerticalIntervals, generateHarmonicRegions } from './services/strettoCore';
import { searchStrettoChains } from './services/strettoGenerator'; 
import { getStrictPitchName } from './services/midiSpelling';
import { downloadStrettoCandidate } from './services/strettoExport';
import { Spinner, DocumentTextIcon } from './Icons';
import { playSequence, stopPlayback } from './midiPlaybackService';
import { useStrettoAssembly } from '../hooks/useStrettoAssembly';

import StrettoConfig, { SearchResolution } from './stretto/StrettoConfig';
import StrettoList from './stretto/StrettoList';
import StrettoInspector from './stretto/StrettoInspector';
import StrettoFooter from './stretto/StrettoFooter';
import StrettoChainView from './stretto/StrettoChainView'; 

interface StrettoViewProps {
    notes: RawNote[]; 
    ppq: number;
    ts: { num: number, den: number };
    voiceNames?: Record<number, string>;
}

interface SavedSubject {
    id: string;
    name: string;
    data: string;
}

export default function StrettoView({ notes: initialNotes, ppq, ts, voiceNames }: StrettoViewProps) {
    // Default to ABC mode if no MIDI notes were passed in
    const [mode, setMode] = useState<'midi' | 'abc'>(initialNotes.length > 0 ? 'midi' : 'abc');
    const [abcInput, setAbcInput] = useState<string>("M:4/4\nL:1/4\nQ:120\nK:C\nc2 G c d e f g3 a b c'2");

    // Default to Chain view
    const [viewMode, setViewMode] = useState<'pairwise' | 'chain'>('chain'); 

    // -- Library State --
    const [savedSubjects, setSavedSubjects] = useState<SavedSubject[]>([]);
    const [saveName, setSaveName] = useState('');
    const [showLibrary, setShowLibrary] = useState(false);

    // -- Pairwise State --
    const [configIntervals, setConfigIntervals] = useState<number[]>([0, 12, -12, 7, -5]);
    const [includeExtensions, setIncludeExtensions] = useState(false);
    const [includeInversions, setIncludeInversions] = useState(false);
    const [searchRes, setSearchRes] = useState<SearchResolution>('full');
    const [selectedCandidate, setSelectedCandidate] = useState<StrettoCandidate | null>(null);
    const [checkedIds, setCheckedIds] = useState<Set<string>>(new Set());

    // -- Chain Search State --
    const [searchOptions, setSearchOptions] = useState<StrettoSearchOptions>({
        ensembleTotal: 4,
        targetChainLength: 8,
        subjectVoiceIndex: 2, 
        truncationMode: 'Max 1',
        truncationMusicalValue: '1/2',
        inversionMode: 'None',
        thirdSixthMode: 'None',
        pivotMidi: 65, 
        requireConsonantEnd: true,
        disallowComplexExceptions: false
    });
    const [chainResults, setChainResults] = useState<StrettoChainResult[]>([]);
    const [searchReport, setSearchReport] = useState<StrettoSearchReport | null>(null);
    const [isSearching, setIsSearching] = useState(false);
    const [selectedChain, setSelectedChain] = useState<StrettoChainResult | null>(null);

    const [isPlaying, setIsPlaying] = useState(false);

    // Load Library on Mount
    useEffect(() => {
        const saved = localStorage.getItem('stretto_subject_library');
        if (saved) {
            try {
                setSavedSubjects(JSON.parse(saved));
            } catch (e) {
                console.error("Failed to load library", e);
            }
        }
    }, []);

    // Save Library Logic
    const handleSaveSubject = () => {
        if (!saveName.trim() || !abcInput.trim()) return;
        const newSubject: SavedSubject = {
            id: Date.now().toString(),
            name: saveName.trim(),
            data: abcInput
        };
        const updated = [...savedSubjects, newSubject];
        setSavedSubjects(updated);
        localStorage.setItem('stretto_subject_library', JSON.stringify(updated));
        setSaveName('');
    };

    const handleDeleteSubject = (id: string) => {
        const updated = savedSubjects.filter(s => s.id !== id);
        setSavedSubjects(updated);
        localStorage.setItem('stretto_subject_library', JSON.stringify(updated));
    };

    const handleLoadSubject = (data: string) => {
        setAbcInput(data);
    };

    // Data Preparation
    const subjectNotes = useMemo(() => {
        if (mode === 'abc') return parseSimpleAbc(abcInput, ppq);
        return initialNotes; 
    }, [mode, abcInput, initialNotes, ppq]);

    const { 
        isAssembling, assemblyStatus, assemblyResult, assemblyLog, 
        setAssemblyResult, runAssembly 
    } = useStrettoAssembly({ notes: subjectNotes, ppq, ts });

    // -- Pairwise Core Loop --
    const pairwiseResults = useMemo(() => {
        if (subjectNotes.length === 0 || viewMode !== 'pairwise') return [];
        const candidates: StrettoCandidate[] = [];
        // Handle undefined notes
        const validNotes = subjectNotes.filter(n => !!n);
        if (validNotes.length === 0) return [];

        const durationTicks = Math.max(...validNotes.map(n => n.ticks + n.durationTicks));
        const maxDelay = durationTicks * 0.75; 
        let stepTicks = ppq; 
        if (searchRes === 'half') stepTicks = ppq / 2;
        else if (searchRes === 'double') stepTicks = ppq * 2;

        let intervalsToCheck = [...configIntervals];
        if (includeExtensions) {
            const exts = [3, 4, 8, 9, -3, -4, -8, -9];
            exts.forEach(e => { if (!intervalsToCheck.includes(e)) intervalsToCheck.push(e); });
        }

        intervalsToCheck.forEach(interval => {
            for (let d = stepTicks; d <= maxDelay; d += stepTicks) {
                // Normal
                candidates.push(analyzeStrettoCandidate(validNotes, interval, Math.round(d), ppq, ts, false, 60));
                // Inverted
                if (includeInversions) {
                    candidates.push(analyzeStrettoCandidate(validNotes, interval, Math.round(d), ppq, ts, true, searchOptions.pivotMidi));
                }
            }
        });
        return candidates;
    }, [subjectNotes, configIntervals, includeExtensions, includeInversions, ppq, ts, searchRes, viewMode, searchOptions.pivotMidi]);

    const getSelectedCandidates = () => {
        return pairwiseResults.filter(r => checkedIds.has(r.id));
    };

    // -- Chain Search Action --
    const handleChainSearch = async () => {
        setIsSearching(true);
        setChainResults([]);
        setSearchReport(null);
        setSelectedChain(null);

        setTimeout(async () => {
            try {
                // Merge voiceNames into searchOptions
                const optionsWithNames = { ...searchOptions, voiceNames };
                const validNotes = subjectNotes.filter(n => !!n);
                const report = await searchStrettoChains(validNotes, optionsWithNames, ppq);
                setChainResults(report.results);
                setSearchReport(report);
            } catch (e) {
                console.error(e);
                alert("Search failed.");
            } finally {
                setIsSearching(false);
            }
        }, 100);
    };

    // -- Selection Logic for Chains --
    const chainToCandidate = useMemo((): StrettoCandidate | null => {
        if (!selectedChain) return null;

        let allNotes: RawNote[] = [];
        const voices: RawNote[][] = [];

        // FIX: Handle potential undefined notes in subjectNotes
        const validSubjectNotes = subjectNotes.filter(n => !!n);
        const sortedSubj = [...validSubjectNotes].sort((a,b)=>a.ticks-b.ticks);

        if (sortedSubj.length === 0) return null;

        const startTick = sortedSubj[0].ticks;

        selectedChain.entries.forEach((entry, idx) => {
            const entryStartTick = Math.round(entry.startBeat * ppq);
            const transformed = sortedSubj.map(n => {
                let pitch = n.midi;
                if (entry.type === 'I') {
                    const diff = pitch - searchOptions.pivotMidi;
                    pitch = searchOptions.pivotMidi - diff; 
                }
                pitch += entry.transposition;

                return {
                    ...n,
                    ticks: (n.ticks - startTick) + entryStartTick, 
                    midi: pitch,
                    name: getStrictPitchName(pitch),
                    voiceIndex: entry.voiceIndex,
                    durationTicks: n.durationTicks 
                };
            });

            // Apply truncation
            const entryDuration16 = entry.length; 
            const entryDurationTicks = entryDuration16 * (ppq/4);
            const entryEnd = entryStartTick + entryDurationTicks;

            const clipped = transformed.filter(n => n.ticks < entryEnd).map(n => ({
                ...n,
                durationTicks: Math.min(n.durationTicks, entryEnd - n.ticks)
            }));

            voices.push(clipped);
            allNotes = [...allNotes, ...clipped];
        });

        let chainRegions: HarmonicRegion[] = [];
        for (let i = 0; i < voices.length - 1; i++) {
            const vA = voices[i];
            const vB = voices[i+1];
            const events = getVerticalIntervals(vA, vB);
            const regions = generateHarmonicRegions(events);
            chainRegions = [...chainRegions, ...regions];
        }

        return {
            id: selectedChain.id,
            intervalLabel: "Chain",
            intervalSemis: 0,
            delayBeats: 0,
            delayTicks: 0,
            grade: 'STRONG',
            errors: [], 
            notes: allNotes,
            regions: chainRegions 
        };
    }, [selectedChain, subjectNotes, ppq, searchOptions.pivotMidi]);


    // Actions
    const handlePlay = (notes: RawNote[]) => {
        if (isPlaying) {
            stopPlayback();
            setIsPlaying(false);
            return;
        }
        const seq = notes.filter(n => !!n).map(n => ({
            name: n.name, 
            time: n.ticks * (0.5 / ppq), 
            duration: n.durationTicks * (0.5 / ppq),
            velocity: n.velocity
        }));
        setIsPlaying(true);
        playSequence(seq, () => setIsPlaying(false));
    };

    const toggleCheck = (id: string) => {
        setCheckedIds(prev => {
            const next = new Set(prev);
            if (next.has(id)) next.delete(id);
            else next.add(id);
            const candidate = pairwiseResults.find(r => r.id === id);
            if (candidate) setSelectedCandidate(candidate);
            return next;
        });
    };

    const triggerAssembly = () => {
        const activeCandidates = checkedIds.size > 0 ? getSelectedCandidates() : (selectedCandidate ? [selectedCandidate] : []);
        runAssembly(activeCandidates, abcInput);
    };

    const handleDownloadChain = () => {
        if (chainToCandidate) {
            downloadStrettoCandidate(chainToCandidate, ppq, voiceNames);
        } else {
            alert("No chain selected.");
        }
    };

    const handleDownloadPairwise = () => {
        if (selectedCandidate) {
            downloadStrettoCandidate(selectedCandidate, ppq, voiceNames);
        }
    };

    return (
        <div className="w-full bg-gray-dark p-6 rounded-2xl border border-gray-medium animate-slide-up pb-32 relative">
            <div className="flex justify-between items-center mb-6">
                <h2 className="text-2xl font-bold text-gray-light">Stretto Assembly Lab</h2>
                {isAssembling && (
                    <div className="flex items-center gap-2 bg-brand-primary/20 px-4 py-2 rounded-full border border-brand-primary/40 animate-pulse">
                        <Spinner className="w-4 h-4 text-brand-primary" />
                        <span className="text-xs font-bold text-brand-primary">{assemblyStatus}</span>
                    </div>
                )}
            </div>

            {/* Top Toolbar */}
            <div className="flex flex-col md:flex-row gap-4 mb-6 p-4 bg-gray-800 rounded-lg border border-gray-700 justify-between">
                <div className="flex gap-2 items-center">
                    <span className="text-xs font-bold text-gray-500 mr-2">INPUT:</span>
                    <button onClick={() => setMode('midi')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${mode === 'midi' ? 'bg-brand-primary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Selected MIDI</button>
                    <button onClick={() => setMode('abc')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${mode === 'abc' ? 'bg-brand-primary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>ABC Notation</button>
                </div>

                <div className="flex gap-2 items-center border-l border-gray-600 pl-4">
                    <span className="text-xs font-bold text-gray-500 mr-2">MODE:</span>
                    <button onClick={() => setViewMode('pairwise')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${viewMode === 'pairwise' ? 'bg-brand-secondary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Pairwise Discovery</button>
                    <button onClick={() => setViewMode('chain')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${viewMode === 'chain' ? 'bg-brand-secondary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Algorithmic Chain</button>
                </div>
            </div>

            {mode === 'abc' && (
                <div className="mb-6 space-y-4">
                    <div className="flex justify-between items-center">
                        <div className="flex items-center gap-2">
                            <label className="block text-sm text-gray-400 font-bold uppercase tracking-wider">Subject ABC</label>
                            <span className="text-[10px] text-gray-500 font-mono hidden sm:inline">Supports M: (Meter), L: (Length), Q: (Tempo), K: (Key)</span>
                        </div>
                        <button 
                            onClick={() => setShowLibrary(!showLibrary)}
                            className="text-xs bg-gray-800 hover:bg-gray-700 text-brand-primary border border-brand-primary/30 px-3 py-1 rounded flex items-center gap-2 transition-colors"
                        >
                            <DocumentTextIcon className="w-3 h-3" />
                            {showLibrary ? "Hide Library" : "Subject Library"}
                        </button>
                    </div>

                    {showLibrary && (
                        <div className="bg-gray-800 p-4 rounded-lg border border-gray-700 animate-fade-in">
                            <div className="flex gap-2 mb-4 border-b border-gray-700 pb-4">
                                <input 
                                    type="text" 
                                    placeholder="Subject Name..." 
                                    value={saveName}
                                    onChange={(e) => setSaveName(e.target.value)}
                                    className="flex-grow bg-gray-900 border border-gray-600 rounded px-3 py-1 text-sm text-white focus:border-brand-primary outline-none"
                                />
                                <button 
                                    onClick={handleSaveSubject}
                                    disabled={!saveName.trim()}
                                    className="bg-brand-primary hover:bg-brand-secondary disabled:bg-gray-600 text-white px-4 py-1 rounded text-sm font-bold transition-colors"
                                >
                                    Save
                                </button>
                            </div>

                            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-2 max-h-48 overflow-y-auto">
                                {savedSubjects.length === 0 ? (
                                    <p className="text-xs text-gray-500 col-span-full text-center py-2">No saved subjects yet.</p>
                                ) : (
                                    savedSubjects.map(s => (
                                        <div key={s.id} className="flex justify-between items-center bg-gray-900 p-2 rounded border border-gray-700 group">
                                            <span className="text-sm font-bold text-gray-300 truncate mr-2" title={s.name}>{s.name}</span>
                                            <div className="flex gap-1 opacity-50 group-hover:opacity-100 transition-opacity">
                                                <button 
                                                    onClick={() => handleLoadSubject(s.data)}
                                                    className="text-[10px] bg-brand-secondary/50 hover:bg-brand-secondary text-white px-2 py-0.5 rounded"
                                                >
                                                    Load
                                                </button>
                                                <button 
                                                    onClick={() => handleDeleteSubject(s.id)}
                                                    className="text-[10px] bg-red-900/50 hover:bg-red-700 text-red-200 px-2 py-0.5 rounded"
                                                >
                                                    ×
                                                </button>
                                            </div>
                                        </div>
                                    ))
                                )}
                            </div>
                        </div>
                    )}

                    <textarea 
                        value={abcInput} 
                        onChange={e => setAbcInput(e.target.value)}
                        placeholder="M:4/4\nL:1/4\nK:C\nc2 G c d e f g"
                        className="w-full bg-gray-900 border border-gray-700 rounded p-3 text-white font-mono h-24 focus:border-brand-primary outline-none transition-colors shadow-inner"
                    />
                </div>
            )}

            {viewMode === 'pairwise' ? (
                <>
                    <StrettoConfig 
                        selectedIntervals={configIntervals} 
                        setSelectedIntervals={setConfigIntervals} 
                        searchRes={searchRes} 
                        setSearchRes={setSearchRes} 
                        includeInversions={includeInversions}
                        setIncludeInversions={setIncludeInversions}
                        includeExtensions={includeExtensions}
                        setIncludeExtensions={setIncludeExtensions}
                    />

                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
                        <StrettoList 
                            candidates={pairwiseResults} 
                            selectedId={selectedCandidate?.id || null}
                            onSelect={setSelectedCandidate}
                            checkedIds={checkedIds}
                            onToggleCheck={toggleCheck}
                        />

                        <StrettoInspector 
                            candidate={selectedCandidate}
                            ppq={ppq}
                            ts={ts}
                            isPlaying={isPlaying}
                            onPlay={handlePlay}
                            assemblyResult={assemblyResult}
                            assemblyLog={assemblyLog}
                            onClearAssembly={() => setAssemblyResult('')}
                            onDownloadChain={handleDownloadPairwise} 
                        />
                    </div>

                    <StrettoFooter 
                        selectedCandidates={getSelectedCandidates()}
                        onDownloadMidi={() => {}}
                        onAssemble={triggerAssembly}
                        isAssembling={isAssembling}
                        onRemoveCandidate={toggleCheck}
                    />
                </>
            ) : (
                <StrettoChainView 
                    searchOptions={searchOptions}
                    setSearchOptions={setSearchOptions}
                    onSearch={handleChainSearch}
                    isSearching={isSearching}
                    chainResults={chainResults}
                    selectedChain={selectedChain}
                    setSelectedChain={setSelectedChain}
                    voiceNames={voiceNames}
                    chainToCandidate={chainToCandidate}
                    ppq={ppq}
                    ts={ts}
                    isPlaying={isPlaying}
                    onPlay={handlePlay}
                    onDownloadChain={handleDownloadChain}
                    searchReport={searchReport}
                />
            )}
        </div>
    );
}

import { RawNote } from '../../types';

// Standard ABC Pitch Mapping
// C = 48 (C below middle C)
// c = 60 (Middle C)
const BASE_PITCHES: Record<string, number> = {
    'C': 48, 'D': 50, 'E': 52, 'F': 53, 'G': 55, 'A': 57, 'B': 59,
    'c': 60, 'd': 62, 'e': 64, 'f': 65, 'g': 67, 'a': 69, 'b': 71
};

// Key Signature Definitions (Sharps/Flats to apply)
const KEY_SIGNATURES: Record<string, Record<string, number>> = {
    'C': {}, 'AM': {},
    'G': { 'f': 1, 'F': 1 }, 'EM': { 'f': 1, 'F': 1 },
    'D': { 'f': 1, 'F': 1, 'c': 1, 'C': 1 }, 'BM': { 'f': 1, 'F': 1, 'c': 1, 'C': 1 },
    'A': { 'f': 1, 'F': 1, 'c': 1, 'C': 1, 'g': 1, 'G': 1 }, 'F#M': { 'f': 1, 'F': 1, 'c': 1, 'C': 1, 'g': 1, 'G': 1 },
    'E': { 'f': 1, 'F': 1, 'c': 1, 'C': 1, 'g': 1, 'G': 1, 'd': 1, 'D': 1 }, 'C#M': { 'f': 1, 'F': 1, 'c': 1, 'C': 1, 'g': 1, 'G': 1, 'd': 1, 'D': 1 },
    'B': { 'f': 1, 'F': 1, 'c': 1, 'C': 1, 'g': 1, 'G': 1, 'd': 1, 'D': 1, 'a': 1, 'A': 1 },
    'F': { 'b': -1, 'B': -1 }, 'DM': { 'b': -1, 'B': -1 },
    'BB': { 'b': -1, 'B': -1, 'e': -1, 'E': -1 }, 'GM': { 'b': -1, 'B': -1, 'e': -1, 'E': -1 },
    'EB': { 'b': -1, 'B': -1, 'e': -1, 'E': -1, 'a': -1, 'A': -1 }, 'CM': { 'b': -1, 'B': -1, 'e': -1, 'E': -1, 'a': -1, 'A': -1 },
    'AB': { 'b': -1, 'B': -1, 'e': -1, 'E': -1, 'a': -1, 'A': -1, 'd': -1, 'D': -1 }, 'FM': { 'b': -1, 'B': -1, 'e': -1, 'E': -1, 'a': -1, 'A': -1, 'd': -1, 'D': -1 },
};

function getBaseMidi(char: string): number {
    return BASE_PITCHES[char] || 60;
}

export function parseSimpleAbc(abcString: string, ppq: number = 480): RawNote[] {
    const lines = abcString.split(/\r?\n/);

    // Default Context
    let keyAccidentals: Record<string, number> = {};
    let measureAccidentals: Record<string, number> = {}; // Persistence within measure
    let defaultNoteLength = 1/8; 
    let tempo = 120;

    const notes: RawNote[] = [];
    let currentTick = 0;

    // 1. Parse Headers
    let bodyStartLine = 0;
    for (let i = 0; i < lines.length; i++) {
        const line = lines[i].trim();
        if (line.length === 0) continue;

        const headerMatch = line.match(/^([A-Za-z]):\s*(.*)/);
        if (headerMatch) {
            const field = headerMatch[1].toUpperCase();
            const value = headerMatch[2].trim();

            if (field === 'K') {
                const keyClean = value.toUpperCase().replace('MAJ', '').split(' ')[0]; 
                if (KEY_SIGNATURES[keyClean]) {
                    keyAccidentals = { ...KEY_SIGNATURES[keyClean] };
                }
            } else if (field === 'L') {
                const parts = value.split('/');
                if (parts.length === 2) {
                    const num = parseFloat(parts[0]);
                    const den = parseFloat(parts[1]);
                    if (!isNaN(num) && !isNaN(den) && den !== 0) defaultNoteLength = num / den;
                }
            } else if (field === 'Q') {
                if (value.includes('=')) tempo = parseFloat(value.split('=')[1]);
                else tempo = parseFloat(value);
            }
        } else {
            bodyStartLine = i;
            break;
        }
    }

    // 2. Parse Notes and Measure resets
    const bodyText = lines.slice(bodyStartLine).join(' ');
    // Added barline | to regex
    const regex = /(\||\[|\])|([\^=_]*)?([a-gA-GzZxX])([,']*)?([0-9]*\/?[0-9]*)?/g;

    let match;
    const wholeNoteTicks = ppq * 4;

    while ((match = regex.exec(bodyText)) !== null) {
        if (match[0] === '') continue;

        // Check for Barline (Reset measure-based accidentals)
        if (match[1] === '|') {
            measureAccidentals = {};
            continue;
        }

        const accStr = match[2] || '';
        const letter = match[3];
        const octStr = match[4] || '';
        const lenStr = match[5] || '';

        if (!letter) continue;

        // Calculate Duration
        let durMult = 1.0;
        if (lenStr) {
            if (lenStr === '/') durMult = 0.5;
            else if (lenStr === '//') durMult = 0.25;
            else if (lenStr.startsWith('/')) {
                durMult = 1 / parseFloat(lenStr.substring(1));
            } else if (lenStr.includes('/')) {
                const [n, d] = lenStr.split('/');
                const num = n === '' ? 1 : parseFloat(n);
                const den = d === '' ? 1 : parseFloat(d); 
                durMult = num / den;
            } else {
                durMult = parseFloat(lenStr);
            }
        }

        const durationTicks = Math.round(wholeNoteTicks * defaultNoteLength * durMult);

        if (['z', 'Z', 'x', 'X'].includes(letter)) {
            currentTick += durationTicks;
            continue;
        }

        let midi = getBaseMidi(letter);
        let accidentalOffset = 0;

        // --- Accidental Logic ---
        // 1. Explicit note accidental overrides everything and sticks for measure
        if (accStr !== '') {
            if (accStr.includes('^^')) accidentalOffset = 2;
            else if (accStr.includes('^')) accidentalOffset = 1;
            else if (accStr.includes('__')) accidentalOffset = -2;
            else if (accStr.includes('_')) accidentalOffset = -1;
            else if (accStr.includes('=')) accidentalOffset = 0; 

            // Persist for measure
            measureAccidentals[letter] = accidentalOffset;
        } 
        // 2. Measure-persistent accidental check
        else if (measureAccidentals[letter] !== undefined) {
            accidentalOffset = measureAccidentals[letter];
        }
        // 3. Key Signature check
        else if (keyAccidentals[letter] !== undefined) {
            accidentalOffset = keyAccidentals[letter];
        }

        midi += accidentalOffset;

        // Octaves
        if (octStr) {
            const up = (octStr.match(/'/g) || []).length;
            const down = (octStr.match(/,/g) || []).length;
            midi += (up * 12) - (down * 12);
        }

        notes.push({
            midi,
            ticks: currentTick,
            durationTicks,
            velocity: 0.8,
            name: `${accStr}${letter}${octStr}`,
            isOrnament: false
        });

        currentTick += durationTicks;
    }

    return notes;
}

import React, { useState } from 'react';
import { AppState } from './types';
import { useMidiController } from './hooks/useMidiController';
import Header from './components/Header';
import FileUpload from './components/FileUpload';
import TrackList from './components/TrackList';
import Modal from './components/Modal';
import PianoRoll from './components/PianoRoll';
import TrackAnalysis from './components/TrackAnalysis';
import Notification from './components/Notification';
import ConversionSettings from './components/ConversionSettings';
import AnalysisSettings from './components/AnalysisSettings'; 
import ActionPanel from './components/ActionPanel';
import StrettoView from './components/StrettoView'; // Import Stretto View
import { DownloadIcon } from './components/Icons';

export default function App() {
  const { state, settings, setters, actions } = useMidiController();
  const { 
    appState, errorMessage, successMessage, fileName, trackInfo, selectedTracks, 
    playingTrackId, eventCounts, quantizationWarning, midiData,
    isPianoRollVisible, pianoRollTrackData, generatedScore, auditLog, isLoadedState,
    analyzedTrackData, isAnalysisModalOpen
  } = state;

  const [currentView, setCurrentView] = useState<'analysis' | 'stretto'>('analysis');

  // Helper to get notes for Stretto View (using first selected track or empty)
  const getStrettoNotes = () => {
      if (!midiData) return [];
      // Prefer selected track
      if (selectedTracks.size > 0) {
          const id = Array.from(selectedTracks)[0];
          return midiData.tracks[id]?.notes.map(n => ({...n} as any)) || [];
      }
      // Fallback to first track with notes
      const t = midiData.tracks.find(t => t.notes.length > 0);
      return t ? t.notes.map(n => ({...n} as any)) : [];
  };

  const ppq = midiData?.header.ppq || 480;
  const ts = midiData?.header.timeSignatures[0]?.timeSignature || [4, 4];

  // Logic to determine what to render in the main area
  const renderMainContent = () => {
      if (currentView === 'stretto') {
          return (
              <StrettoView 
                  notes={getStrettoNotes()} 
                  ppq={ppq} 
                  ts={{ num: ts[0], den: ts[1] }} 
                  voiceNames={settings.voiceNames}
                  setVoiceNames={setters.setVoiceNames}
              />
          );
      }

      // Analysis View Logic
      if (!isLoadedState) {
          return (
              <div className="w-full max-w-lg text-center">
                  <FileUpload onFileUpload={actions.handleFileUpload} isLoading={appState === AppState.LOADING} />
                  {appState === AppState.ERROR && (
                      <div className="mt-4 p-4 bg-red-900/50 border border-red-700 text-red-300 rounded-lg animate-fade-in">
                          <p className="font-bold">An Error Occurred</p>
                          <p>{errorMessage}</p>
                      </div>
                  )}
              </div>
          );
      }

      return (
          <>
              <TrackList
                tracks={trackInfo}
                selectedTracks={selectedTracks}
                onTrackSelect={actions.handleTrackSelect}
                onSelectAll={actions.handleSelectAllTracks}
                onReset={actions.handleReset}
                fileName={fileName}
                playingTrackId={playingTrackId}
                onPreviewTrack={actions.handlePreviewTrack}
                onShowPianoRoll={actions.handleShowPianoRoll}
                onAnalyzeTrack={actions.handleAnalyzeTrack}
              />

              {/* Data Preparation Settings */}
              <ConversionSettings 
                settings={settings}
                setters={setters}
                eventCounts={eventCounts}
                onEventFilterToggle={actions.handleEventFilterToggle}
                quantizationWarning={quantizationWarning}
              />

              {/* Analysis Context & Range */}
              <AnalysisSettings 
                sections={settings.analysisSections}
                setSections={setters.setAnalysisSections}
                contextText={settings.contextText}
                setContextText={setters.setContextText}
                voiceNames={settings.voiceNames}
                setVoiceNames={setters.setVoiceNames}
                voiceCountEstimate={settings.maxVoices || 4}
                midiData={midiData}
                trackInfo={trackInfo}
                selectedTracks={selectedTracks}
                voiceAssignmentMode={settings.voiceAssignmentMode}
              />

              {(successMessage || errorMessage) && (
                  <div className="my-4">
                    <Notification 
                        message={successMessage || errorMessage || ''} 
                        type={successMessage ? 'success' : 'error'} 
                        onDismiss={actions.clearMessages} 
                    />
                  </div>
              )}

              <ActionPanel 
                 onGenerateScore={actions.handleGenerateScore}
                 onDownloadScore={actions.handleDownloadScore}
                 onDownloadAudit={actions.handleDownloadAuditLog}
                 isGenerating={appState === AppState.GENERATING}
                 canProcess={selectedTracks.size >= 1}
                 selectedCount={selectedTracks.size}
                 hasResult={!!generatedScore}
                 hasAudit={!!auditLog}
              />

              {/* Score Output */}
              {generatedScore && (
                  <div className="w-full bg-gray-dark p-6 rounded-2xl shadow-2xl border border-gray-medium mt-6 animate-slide-up">
                      <div className="flex justify-between items-center mb-4">
                          <h3 className="text-xl font-bold text-gray-light">Generated Analysis & Score</h3>
                          <div className="flex gap-2">
                              <button 
                                onClick={actions.handleDownloadScore}
                                className="flex items-center gap-2 text-sm bg-gray-700 hover:bg-gray-600 text-white px-3 py-1 rounded transition-colors"
                              >
                                  <DownloadIcon className="w-4 h-4" /> Download
                              </button>
                              <button 
                                onClick={() => navigator.clipboard.writeText(generatedScore)}
                                className="text-sm bg-brand-primary hover:bg-brand-secondary text-white px-3 py-1 rounded transition-colors"
                              >
                                  Copy to Clipboard
                              </button>
                          </div>
                      </div>
                      <textarea 
                        readOnly 
                        value={generatedScore} 
                        className="w-full h-96 bg-black border border-gray-700 text-gray-300 font-mono text-xs p-4 rounded-lg focus:outline-none"
                      />
                  </div>
              )}

              {/* Separate Audit Log Panel */}
              {auditLog && (
                  <div className="w-full bg-gray-900/80 p-6 rounded-2xl shadow-2xl border-2 border-amber-600/50 mt-6 animate-slide-up">
                      <div className="flex justify-between items-center mb-4">
                          <div className="flex flex-col">
                              <h3 className="text-xl font-bold text-amber-500">HIA v2.2 Deep Audit Log</h3>
                              <p className="text-xs text-gray-400">Technical decision trace for Harmonic Implication Algorithm.</p>
                          </div>
                          <div className="flex gap-2">
                              <button 
                                onClick={actions.handleDownloadAuditLog}
                                className="flex items-center gap-2 text-sm bg-amber-800 hover:bg-amber-700 text-white px-3 py-1 rounded transition-colors"
                              >
                                  <DownloadIcon className="w-4 h-4" /> Download Audit
                              </button>
                              <button 
                                onClick={() => navigator.clipboard.writeText(auditLog)}
                                className="text-sm bg-gray-700 hover:bg-gray-600 text-white px-3 py-1 rounded transition-colors"
                              >
                                  Copy Log
                              </button>
                          </div>
                      </div>
                      <textarea 
                        readOnly 
                        value={auditLog} 
                        className="w-full h-64 bg-black border border-amber-900/50 text-amber-200/80 font-mono text-xs p-4 rounded-lg focus:outline-none"
                      />
                  </div>
              )}
          </>
      );
  };

  return (
    <>
      <div className="min-h-screen bg-gray-darker flex flex-col items-center p-4 sm:p-6 lg:p-8 font-sans">
        <Header currentView={currentView} onViewChange={setCurrentView} />

        <main className="w-full max-w-4xl mx-auto flex-grow flex flex-col items-center justify-center">
            <div className="w-full animate-fade-in pb-12">
                {renderMainContent()}
            </div>
        </main>
        <footer className="w-full max-w-4xl mx-auto text-center py-4 mt-8 border-t border-gray-medium text-gray-medium">
          <p>Built with React, Tailwind CSS, and @tonejs/midi</p>
        </footer>
      </div>

      {isPianoRollVisible && pianoRollTrackData && (
        <Modal
          isOpen={isPianoRollVisible}
          onClose={() => setters.setIsPianoRollVisible(false)}
          title={`Piano Roll: ${pianoRollTrackData.name}`}
        >
          <PianoRoll trackData={pianoRollTrackData} />
        </Modal>
      )}

      {isAnalysisModalOpen && analyzedTrackData && (
        <Modal
          isOpen={isAnalysisModalOpen}
          onClose={() => setters.setIsAnalysisModalOpen(false)}
          title={`Track Analysis: ${analyzedTrackData.trackName}`}
        >
          <TrackAnalysis data={analyzedTrackData} />
        </Modal>
      )}
    </>
  );
}

import React, { useState, useMemo, useEffect } from 'react';
import { RawNote, StrettoCandidate, StrettoSearchOptions, StrettoChainResult, HarmonicRegion, StrettoSearchReport } from '../types';
import { parseSimpleAbc } from './services/abcBridge';
import { analyzeStrettoCandidate, getVerticalIntervals, generateHarmonicRegions } from './services/strettoCore';
import { searchStrettoChains } from './services/strettoGenerator'; 
import { getStrictPitchName } from './services/midiSpelling';
import { downloadStrettoCandidate } from './services/strettoExport';
import { Spinner, DocumentTextIcon } from './Icons';
import { playSequence, stopPlayback } from './midiPlaybackService';
import { useStrettoAssembly } from '../hooks/useStrettoAssembly';

import StrettoConfig, { SearchResolution } from './stretto/StrettoConfig';
import StrettoList from './stretto/StrettoList';
import StrettoInspector from './stretto/StrettoInspector';
import StrettoFooter from './stretto/StrettoFooter';
import StrettoChainView from './stretto/StrettoChainView'; 

interface StrettoViewProps {
    notes: RawNote[]; 
    ppq: number;
    ts: { num: number, den: number };
    voiceNames?: Record<number, string>;
    setVoiceNames?: (names: Record<number, string>) => void;
}

interface SavedSubject {
    id: string;
    name: string;
    data: string;
}

export default function StrettoView({ notes: initialNotes, ppq, ts, voiceNames, setVoiceNames }: StrettoViewProps) {
    // Default to ABC mode if no MIDI notes were passed in
    const [mode, setMode] = useState<'midi' | 'abc'>(initialNotes.length > 0 ? 'midi' : 'abc');
    const [abcInput, setAbcInput] = useState<string>("M:4/4\nL:1/4\nQ:120\nK:C\nc2 G c d e f g3 a b c'2");

    // Default to Chain view
    const [viewMode, setViewMode] = useState<'pairwise' | 'chain'>('chain'); 

    // -- Library State --
    const [savedSubjects, setSavedSubjects] = useState<SavedSubject[]>([]);
    const [saveName, setSaveName] = useState('');
    const [showLibrary, setShowLibrary] = useState(false);

    // -- Pairwise State --
    const [configIntervals, setConfigIntervals] = useState<number[]>([0, 12, -12, 7, -5]);
    const [includeExtensions, setIncludeExtensions] = useState(false);
    const [includeInversions, setIncludeInversions] = useState(false);
    const [searchRes, setSearchRes] = useState<SearchResolution>('full');
    const [selectedCandidate, setSelectedCandidate] = useState<StrettoCandidate | null>(null);
    const [checkedIds, setCheckedIds] = useState<Set<string>>(new Set());

    // -- Chain Search State --
    const [searchOptions, setSearchOptions] = useState<StrettoSearchOptions>({
        ensembleTotal: 4,
        targetChainLength: 8,
        subjectVoiceIndex: 2, 
        truncationMode: 'Max 1',
        truncationMusicalValue: '1/2',
        inversionMode: 'None',
        thirdSixthMode: 'None',
        pivotMidi: 65, 
        requireConsonantEnd: true,
        disallowComplexExceptions: false
    });
    const [chainResults, setChainResults] = useState<StrettoChainResult[]>([]);
    const [searchReport, setSearchReport] = useState<StrettoSearchReport | null>(null);
    const [isSearching, setIsSearching] = useState(false);
    const [selectedChain, setSelectedChain] = useState<StrettoChainResult | null>(null);

    const [isPlaying, setIsPlaying] = useState(false);

    // Load Library on Mount
    useEffect(() => {
        const saved = localStorage.getItem('stretto_subject_library');
        if (saved) {
            try {
                setSavedSubjects(JSON.parse(saved));
            } catch (e) {
                console.error("Failed to load library", e);
            }
        }
    }, []);

    // Save Library Logic
    const handleSaveSubject = () => {
        if (!saveName.trim() || !abcInput.trim()) return;
        const newSubject: SavedSubject = {
            id: Date.now().toString(),
            name: saveName.trim(),
            data: abcInput
        };
        const updated = [...savedSubjects, newSubject];
        setSavedSubjects(updated);
        localStorage.setItem('stretto_subject_library', JSON.stringify(updated));
        setSaveName('');
    };

    const handleDeleteSubject = (id: string) => {
        const updated = savedSubjects.filter(s => s.id !== id);
        setSavedSubjects(updated);
        localStorage.setItem('stretto_subject_library', JSON.stringify(updated));
    };

    const handleLoadSubject = (data: string) => {
        setAbcInput(data);
    };

    // Data Preparation
    const subjectNotes = useMemo(() => {
        if (mode === 'abc') return parseSimpleAbc(abcInput, ppq);
        return initialNotes; 
    }, [mode, abcInput, initialNotes, ppq]);

    const { 
        isAssembling, assemblyStatus, assemblyResult, assemblyLog, 
        setAssemblyResult, runAssembly 
    } = useStrettoAssembly({ notes: subjectNotes, ppq, ts });

    // -- Pairwise Core Loop --
    const pairwiseResults = useMemo(() => {
        if (subjectNotes.length === 0 || viewMode !== 'pairwise') return [];
        const candidates: StrettoCandidate[] = [];
        // Handle undefined notes
        const validNotes = subjectNotes.filter(n => !!n);
        if (validNotes.length === 0) return [];

        const durationTicks = Math.max(...validNotes.map(n => n.ticks + n.durationTicks));
        const maxDelay = durationTicks * 0.75; 
        let stepTicks = ppq; 
        if (searchRes === 'half') stepTicks = ppq / 2;
        else if (searchRes === 'double') stepTicks = ppq * 2;

        let intervalsToCheck = [...configIntervals];
        if (includeExtensions) {
            const exts = [3, 4, 8, 9, -3, -4, -8, -9];
            exts.forEach(e => { if (!intervalsToCheck.includes(e)) intervalsToCheck.push(e); });
        }

        intervalsToCheck.forEach(interval => {
            for (let d = stepTicks; d <= maxDelay; d += stepTicks) {
                // Normal
                candidates.push(analyzeStrettoCandidate(validNotes, interval, Math.round(d), ppq, ts, false, 60));
                // Inverted
                if (includeInversions) {
                    candidates.push(analyzeStrettoCandidate(validNotes, interval, Math.round(d), ppq, ts, true, searchOptions.pivotMidi));
                }
            }
        });
        return candidates;
    }, [subjectNotes, configIntervals, includeExtensions, includeInversions, ppq, ts, searchRes, viewMode, searchOptions.pivotMidi]);

    const getSelectedCandidates = () => {
        return pairwiseResults.filter(r => checkedIds.has(r.id));
    };

    // -- Chain Search Action --
    const handleChainSearch = async () => {
        setIsSearching(true);
        setChainResults([]);
        setSearchReport(null);
        setSelectedChain(null);

        setTimeout(async () => {
            try {
                // Merge voiceNames into searchOptions
                const optionsWithNames = { ...searchOptions, voiceNames };
                const validNotes = subjectNotes.filter(n => !!n);
                const report = await searchStrettoChains(validNotes, optionsWithNames, ppq);
                setChainResults(report.results);
                setSearchReport(report);
            } catch (e) {
                console.error(e);
                alert("Search failed.");
            } finally {
                setIsSearching(false);
            }
        }, 100);
    };

    // -- Selection Logic for Chains --
    const chainToCandidate = useMemo((): StrettoCandidate | null => {
        if (!selectedChain) return null;

        let allNotes: RawNote[] = [];
        const voices: RawNote[][] = [];

        // FIX: Handle potential undefined notes in subjectNotes
        const validSubjectNotes = subjectNotes.filter(n => !!n);
        const sortedSubj = [...validSubjectNotes].sort((a,b)=>a.ticks-b.ticks);

        if (sortedSubj.length === 0) return null;

        const startTick = sortedSubj[0].ticks;

        selectedChain.entries.forEach((entry, idx) => {
            const entryStartTick = Math.round(entry.startBeat * ppq);
            const transformed = sortedSubj.map(n => {
                let pitch = n.midi;
                if (entry.type === 'I') {
                    const diff = pitch - searchOptions.pivotMidi;
                    pitch = searchOptions.pivotMidi - diff; 
                }
                pitch += entry.transposition;

                return {
                    ...n,
                    ticks: (n.ticks - startTick) + entryStartTick, 
                    midi: pitch,
                    name: getStrictPitchName(pitch),
                    voiceIndex: entry.voiceIndex,
                    durationTicks: n.durationTicks 
                };
            });

            // Apply truncation
            const entryDuration16 = entry.length; 
            const entryDurationTicks = entryDuration16 * (ppq/4);
            const entryEnd = entryStartTick + entryDurationTicks;

            const clipped = transformed.filter(n => n.ticks < entryEnd).map(n => ({
                ...n,
                durationTicks: Math.min(n.durationTicks, entryEnd - n.ticks)
            }));

            voices.push(clipped);
            allNotes = [...allNotes, ...clipped];
        });

        let chainRegions: HarmonicRegion[] = [];
        for (let i = 0; i < voices.length - 1; i++) {
            const vA = voices[i];
            const vB = voices[i+1];
            const events = getVerticalIntervals(vA, vB);
            const regions = generateHarmonicRegions(events);
            chainRegions = [...chainRegions, ...regions];
        }

        return {
            id: selectedChain.id,
            intervalLabel: "Chain",
            intervalSemis: 0,
            delayBeats: 0,
            delayTicks: 0,
            grade: 'STRONG',
            errors: [], 
            notes: allNotes,
            regions: chainRegions 
        };
    }, [selectedChain, subjectNotes, ppq, searchOptions.pivotMidi]);


    // Actions
    const handlePlay = (notes: RawNote[]) => {
        if (isPlaying) {
            stopPlayback();
            setIsPlaying(false);
            return;
        }
        const seq = notes.filter(n => !!n).map(n => ({
            name: n.name, 
            time: n.ticks * (0.5 / ppq), 
            duration: n.durationTicks * (0.5 / ppq),
            velocity: n.velocity
        }));
        setIsPlaying(true);
        playSequence(seq, () => setIsPlaying(false));
    };

    const toggleCheck = (id: string) => {
        setCheckedIds(prev => {
            const next = new Set(prev);
            if (next.has(id)) next.delete(id);
            else next.add(id);
            const candidate = pairwiseResults.find(r => r.id === id);
            if (candidate) setSelectedCandidate(candidate);
            return next;
        });
    };

    const triggerAssembly = () => {
        const activeCandidates = checkedIds.size > 0 ? getSelectedCandidates() : (selectedCandidate ? [selectedCandidate] : []);
        runAssembly(activeCandidates, abcInput);
