import { getFormattedTime } from './midiHarmony';
import { getStrictPitchName, getIntervalLabel } from './midiSpelling';
import { analyzeStrettoHarmony } from './strettoHarmonyAnalysis';

const SEMIS_P8 = 12;
const SEMIS_P5 = 7;
const SEMIS_P4 = 5;

// Strict counterpoint intervals
const DISSONANT_INTERVALS = [1, 2, 6, 10, 11]; // m2, M2, TT, m7, M7
const PERFECT_CONSONANCES = [0, 7]; // P1, P5 (P8 is 0 mod 12)
const IMPERFECT_CONSONANCES = [3, 4, 8, 9]; // m3, M3, m6, M6

export interface VoiceEvent {
    tick: number;
    endTick: number; // New field for exact duration tracking
    pitch1: number; // Subject
    pitch2: number; // Answer (Transposed Subject)
    hasAttack1: boolean;
    hasAttack2: boolean;
}

export function getVerticalIntervals(subject: RawNote[], answer: RawNote[]): VoiceEvent[] {
    const timePoints = new Set<number>();
    [...subject, ...answer].forEach(n => {
        if (!n) return; // FIX: Ensure note exists
        timePoints.add(n.ticks);
        timePoints.add(n.ticks + n.durationTicks); // Also check release points
    });

    const sortedPoints = Array.from(timePoints).sort((a,b) => a-b);
    const events: VoiceEvent[] = [];

    // Filter points that are just releases of the very last note
    const endOfMusic = Math.max(0, ...[...subject, ...answer].map(n => n ? n.ticks + n.durationTicks : 0));

    for (let i = 0; i < sortedPoints.length - 1; i++) {
        const t = sortedPoints[i];
        if (t >= endOfMusic) break;

        // Check active notes at this time segment (t to nextPoint)
        // We use t + epsilon to check inside the window
        const checkTime = t; 

        const n1 = subject.find(n => n && n.ticks <= checkTime && (n.ticks + n.durationTicks) > checkTime);
        const n2 = answer.find(n => n && n.ticks <= checkTime && (n.ticks + n.durationTicks) > checkTime);

        if (n1 && n2) {
            events.push({
                tick: t,
                endTick: sortedPoints[i+1], // The state is valid until the next timeline event
                pitch1: n1.midi,
                pitch2: n2.midi,
                hasAttack1: n1.ticks === t,
                hasAttack2: n2.ticks === t
            });
        }
    }

    return events;
}

function isStrongBeat(tick: number, ppq: number, tsNum: number, tsDenom: number): boolean {
    const ticksPerMeasure = ppq * tsNum * (4 / tsDenom);
    const pos = tick % ticksPerMeasure;
    if (pos === 0) return true; // Downbeat
    if (tsNum === 4 && tsDenom === 4 && pos === (ticksPerMeasure / 2)) return true;
    return false; 
}

export function generateHarmonicRegions(events: VoiceEvent[]): HarmonicRegion[] {
    const regions: HarmonicRegion[] = [];
    let previousState: 'consonance' | 'dissonance' = 'consonance';

    // For Motion checking
    let prevP1: number | null = null;
    let prevP2: number | null = null;

    for (let i = 0; i < events.length; i++) {
        const ev = events[i];
        const duration = ev.endTick - ev.tick;

        if (duration <= 0) continue;

        const p1 = ev.pitch1;
        const p2 = ev.pitch2;
        const interval = Math.abs(p1 - p2);
        const intervalClass = interval % 12;
        const isBass1 = p1 < p2;
        const upperPitch = isBass1 ? p2 : p1;
        const prevUpperPitch = isBass1 ? (prevP2) : (prevP1);

        // Determine Interval Type
        const isP4 = intervalClass === 5; // P4 dissonant in 2-part if no bass support (strict: always diss)
        const isDiss = DISSONANT_INTERVALS.includes(intervalClass) || isP4;

        let regionType: HarmonicRegion['type'];

        if (isDiss) {
            if (previousState === 'consonance') {
                regionType = 'dissonance_1'; // Deep Blueish Purple
            } else {
                regionType = 'dissonance_consecutive'; // Reddish Purple
            }
            previousState = 'dissonance';
        } else {
            if (PERFECT_CONSONANCES.includes(intervalClass)) {
                regionType = 'perfect_consonance'; // Turquoise
            } else {
                regionType = 'imperfect_consonance'; // Lime Green
            }
            previousState = 'consonance';
        }

        // Determine Error Overlay (Parallel/Direct)
        let errorType: HarmonicRegion['errorType'] = null;

        if (prevP1 !== null && prevP2 !== null) {
            // Oblique check: If either voice stayed the same, it's NOT parallel
            const p1Moved = prevP1 !== p1;
            const p2Moved = prevP2 !== p2;

            // Only check for parallel if BOTH voices moved
            if (p1Moved && p2Moved) {
                const isParallelMotion = (p1 - prevP1) * (p2 - prevP2) > 0;
                const isPerfect = intervalClass === 0 || intervalClass === 7;

                // Check Parallel
                if (isPerfect && isParallelMotion) {
                    const prevInterval = Math.abs(prevP1 - prevP2);
                    const prevClass = prevInterval % 12;
                    if (prevClass === intervalClass) {
                        errorType = 'parallel';
                    }
                }

                // Check Direct (Hidden) Perfects
                // Definition: Similar motion into a perfect interval, where the upper voice leaps
                if (!errorType && isPerfect && isParallelMotion) {
                    // Check leap size of upper voice
                    if (prevUpperPitch !== null) {
                        const upperMove = Math.abs(upperPitch - prevUpperPitch);
                        if (upperMove > 2) { // Leap > Major 2nd
                            errorType = 'direct';
                        }
                    }
                }
            }
        }

        const name1 = getStrictPitchName(p1);
        const name2 = getStrictPitchName(p2);
        const label = getIntervalLabel(interval);

        regions.push({
            startTick: ev.tick,
            endTick: ev.endTick, 
            type: regionType,
            errorType: errorType,
            intervalLabel: label,
            description: `${label}: ${name1}, ${name2}`
        });

        // Only update 'prev' state if there was an attack (motion event boundary)
        prevP1 = p1;
        prevP2 = p2;
    }

    return regions;
}

// Inversion Logic
const SCALE_INTERVALS = [0, 2, 4, 5, 7, 9, 11];

function invertPitch(pitch: number, pivot: number): number | null {
    const diff = pitch - pivot;
    const octaves = Math.floor(diff / 12);
    const semitone = (diff % 12 + 12) % 12;
    const scaleIndex = SCALE_INTERVALS.indexOf(semitone);
    if (scaleIndex === -1) return pivot - diff; 
    const absStep = (octaves * 7) + scaleIndex;
    const invStep = -absStep;
    const invOctaves = Math.floor(invStep / 7);
    const invRem = (invStep % 7 + 7) % 7;
    const invSemitone = SCALE_INTERVALS[invRem];
    return pivot + (invOctaves * 12) + invSemitone;
}

export function analyzeStrettoCandidate(
    subject: RawNote[], 
    intervalSemis: number, 
    delayTicks: number, 
    ppq: number,
    ts: { num: number, den: number },
    isInverted: boolean = false,
    pivotMidi: number = 60
): StrettoCandidate {

    const answer: RawNote[] = subject.map(n => {
        if (!n) return null as any;
        let newMidi = n.midi;
        if (isInverted) {
            const inv = invertPitch(n.midi, pivotMidi);
            newMidi = inv !== null ? inv : n.midi; // Fallback?
        }
        newMidi += intervalSemis;

        return {
            ...n,
            ticks: n.ticks + delayTicks,
            midi: newMidi,
            name: getStrictPitchName(newMidi),
            voiceIndex: 1
        };
    }).filter(n => !!n);

    const startOverlap = delayTicks; 
    const subjectEnd = Math.max(0, ...subject.map(n => n ? n.ticks + n.durationTicks : 0));
    const endOverlap = subjectEnd;

    if (startOverlap >= endOverlap) {
        return {
            id: `invalid_gap`,
            intervalSemis, intervalLabel: 'N/A', delayBeats: 0, delayTicks,
            grade: 'INVALID', errors: [{ tick: 0, timeFormatted: '-', type: 'Consecutive Dissonance', details: 'No overlap', severity: 'fatal' }],
            notes: [], dissonanceRatio: 0, endsOnDissonance: true
        };
    }

    const events = getVerticalIntervals(subject, answer).filter(e => e.tick >= startOverlap);

    // Generate Visualization Regions
    const harmonicRegions = generateHarmonicRegions(events);

    // Dissonance Calculations
    let totalOverlapTicks = 0;
    let dissonantTicks = 0;
    let endsOnDissonance = false;

    harmonicRegions.forEach((r, idx) => {
        const dur = r.endTick - r.startTick;
        totalOverlapTicks += dur;
        if (r.type === 'dissonance_1' || r.type === 'dissonance_consecutive') {
            dissonantTicks += dur;
            if (idx === harmonicRegions.length - 1) endsOnDissonance = true;
        }
    });

    const dissonanceRatio = totalOverlapTicks > 0 ? (dissonantTicks / totalOverlapTicks) : 0;

    // Generate Standard Errors (Filtering from regions for text report)
    const errors: StrettoError[] = [];

    harmonicRegions.forEach(r => {
        const timeStr = getFormattedTime(r.startTick, ppq, ts.num, ts.den);
        const onStrong = isStrongBeat(r.startTick, ppq, ts.num, ts.den);

        if (r.errorType === 'parallel') {
            errors.push({
                tick: r.startTick, timeFormatted: timeStr,
                type: r.intervalLabel.includes('P5') ? 'Parallel 5th' : 'Parallel 8ve',
                details: `Parallel motion into ${r.intervalLabel}`,
                severity: onStrong ? 'fatal' : 'warning'
            });
        }
        if (r.errorType === 'direct') {
             errors.push({
                tick: r.startTick, timeFormatted: timeStr,
                type: r.intervalLabel.includes('P5') ? 'Direct 5th' : 'Direct 8ve',
                details: `Direct motion into ${r.intervalLabel} (Upper leap)`,
                severity: 'warning'
            });
        }
        if (r.type === 'dissonance_consecutive' && onStrong) {
             // Rule Update: P4 consecutive dissonances are not fatal (can be used in upper voices later)
             const isP4Run = r.intervalLabel.includes('P4');
             errors.push({
                 tick: r.startTick, timeFormatted: timeStr,
                 type: 'Consecutive Dissonance',
                 details: 'Consecutive dissonance',
                 severity: isP4Run ? 'warning' : 'fatal'
             });
        }
    });

    // Run Harmonic Analysis on the candidate pair (2 voices)
    const tl: any = {};
    const ticks: number[] = [];
    const allNotes = [...subject, ...answer];
    const uniqueTicks = new Set<number>();
    allNotes.forEach(n => { if (n) uniqueTicks.add(n.ticks); });
    Array.from(uniqueTicks).sort((a,b)=>a-b).forEach(t => ticks.push(t));

    ticks.forEach(t => {
        const active = allNotes.filter(n => n && n.ticks <= t && (n.ticks + n.durationTicks) > t);
        if (active.length > 0) {
            tl[t] = {};
            active.forEach(n => {
                const dur16 = Math.max(1, Math.round(n.durationTicks / (ppq/4)));
                tl[t][n.voiceIndex ?? 0] = { pitch: n.midi, dur16 };
            });
        }
    });

    const harmonyResult = analyzeStrettoHarmony(tl, ticks);

    let grade: StrettoGrade = 'STRONG';
    if (errors.some(e => e.severity === 'fatal')) grade = 'INVALID';
    else if (errors.length > 0) grade = 'VIABLE';

    // Build Interval Label
    let intLabel = getIntervalLabel(intervalSemis);
    // getIntervalLabel handles signedness implicitly via abs, but transposition can be negative
    // Actually the new getIntervalLabel uses abs, so we check sign here
    if (intervalSemis < 0 && !intLabel.startsWith('-')) intLabel = '-' + intLabel;
    else if (intervalSemis > 0 && !intLabel.startsWith('+')) intLabel = '+' + intLabel;

    if (isInverted) intLabel += " (Inv)";

    const delayBeats = delayTicks / (ppq * (4 / ts.den));

    return {
        id: `${intLabel}@${delayBeats.toFixed(1)}${isInverted?'i':''}`,
        intervalSemis,
        intervalLabel: intLabel,
        delayBeats: parseFloat(delayBeats.toFixed(2)),
        delayTicks,
        grade,
        errors,
        notes: allNotes,
        regions: harmonicRegions,
        detectedChords: harmonyResult.chords,
        dissonanceRatio,
        endsOnDissonance
    };
}

import { StrettoCandidate } from '../../types';
import { Midi } from '@tonejs/midi';
import { getVoiceLabel } from './midiVoices';

/**
 * Generates and downloads a multi-track MIDI file representing the Stretto result.
 * Fixes "Cannot set property ppq" error by scaling ticks instead of modifying read-only header.
 */
export function downloadStrettoCandidate(candidate: StrettoCandidate, sourcePpq: number, voiceNames?: Record<number, string>) {
    const midi = new Midi();

    // Tone.js MIDI instances default to 480 PPQ. 
    // We scale incoming ticks to this resolution to avoid modifying read-only header properties.
    const TARGET_PPQ = 480; 
    const scaleFactor = TARGET_PPQ / sourcePpq;

    // Set basic metadata
    midi.header.setTempo(120);
    midi.header.timeSignatures.push({
        timeSignature: [4, 4],
        ticks: 0,
    });

    // Group notes by voice index
    const notesByVoice: Record<number, any[]> = {};
    candidate.notes.forEach(n => {
        const v = n.voiceIndex ?? 0;
        if (!notesByVoice[v]) notesByVoice[v] = [];
        notesByVoice[v].push(n);
    });

    const voiceIndices = Object.keys(notesByVoice).map(Number).sort((a,b) => a-b);

    // Determine total count for fallback labels
    const maxIdx = voiceIndices.length > 0 ? Math.max(...voiceIndices) : 0;
    const totalVoicesForLabeling = maxIdx + 1;

    voiceIndices.forEach(vIdx => {
        const track = midi.addTrack();

        // Use user-assigned voice name if available, else fallback to algorithmic label
        const nameFromConfig = voiceNames?.[vIdx];
        track.name = nameFromConfig || getVoiceLabel(vIdx, totalVoicesForLabeling);

        // Standard channel assignment (0-15)
        track.channel = vIdx % 16;
        track.instrument.number = 0; // Acoustic Grand Piano default

        const voiceNotes = notesByVoice[vIdx];
        voiceNotes.forEach(n => {
            track.addNote({
                midi: n.midi,
                ticks: Math.round(n.ticks * scaleFactor),
                durationTicks: Math.round(n.durationTicks * scaleFactor),
                velocity: n.velocity
            });
        });
    });

    // Prepare and trigger download
    const midiBytes = midi.toArray();
    const blob = new Blob([midiBytes], { type: 'audio/midi' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;

    // Descriptive filename
    const safeLabel = candidate.intervalLabel.replace(/[^a-z0-9]/gi, '_');
    a.download = `Stretto_${safeLabel}_${candidate.delayBeats}beats.mid`;

    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
}

/**
 * Bundles multiple candidates into a single multi-track MIDI file.
 */
export function downloadStrettoSelection(candidates: StrettoCandidate[], sourcePpq: number, voiceNames?: Record<number, string>) {
    if (candidates.length === 0) return;

    const midi = new Midi();
    const TARGET_PPQ = 480; 
    const scaleFactor = TARGET_PPQ / sourcePpq;

    midi.header.setTempo(120);
    midi.header.timeSignatures.push({ timeSignature: [4, 4], ticks: 0 });

    candidates.forEach((candidate, cIdx) => {
        // Group notes by voice index
        const notesByVoice: Record<number, any[]> = {};
        candidate.notes.forEach(n => {
            const v = n.voiceIndex ?? 0;
            if (!notesByVoice[v]) notesByVoice[v] = [];
            notesByVoice[v].push(n);
        });

        const voiceIndices = Object.keys(notesByVoice).map(Number).sort((a,b) => a-b);
        const totalInCand = Math.max(...voiceIndices) + 1;

        voiceIndices.forEach(vIdx => {
            const track = midi.addTrack();
            const baseName = voiceNames?.[vIdx] || getVoiceLabel(vIdx, totalInCand);
            track.name = `S${cIdx+1} - ${baseName} (${candidate.intervalLabel})`;

            // Channel offset per candidate to avoid cross-talk if possible
            track.channel = (cIdx * 2 + vIdx) % 16;

            const voiceNotes = notesByVoice[vIdx];
            voiceNotes.forEach(n => {
                track.addNote({
                    midi: n.midi,
                    ticks: Math.round(n.ticks * scaleFactor),
                    durationTicks: Math.round(n.durationTicks * scaleFactor),
                    velocity: n.velocity
                });
            });
        });
    });

    const midiBytes = midi.toArray();
    const blob = new Blob([midiBytes], { type: 'audio/midi' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `Stretto_Selection_Export_${candidates.length}_items.mid`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
}

import React, { useState, useMemo, useEffect } from 'react';
import { RawNote, StrettoCandidate, StrettoSearchOptions, StrettoChainResult, HarmonicRegion, StrettoSearchReport } from '../types';
import { parseSimpleAbc } from './services/abcBridge';
import { analyzeStrettoCandidate, getVerticalIntervals, generateHarmonicRegions } from './services/strettoCore';
import { searchStrettoChains } from './services/strettoGenerator'; 
import { getStrictPitchName } from './services/midiSpelling';
import { downloadStrettoCandidate, downloadStrettoSelection } from './services/strettoExport';
import { Spinner, DocumentTextIcon } from './Icons';
import { playSequence, stopPlayback } from './midiPlaybackService';
import { useStrettoAssembly } from '../hooks/useStrettoAssembly';

import StrettoConfig, { SearchResolution } from './stretto/StrettoConfig';
import StrettoList from './stretto/StrettoList';
import StrettoInspector from './stretto/StrettoInspector';
import StrettoFooter from './stretto/StrettoFooter';
import StrettoChainView from './stretto/StrettoChainView'; 

interface StrettoViewProps {
    notes: RawNote[]; 
    ppq: number;
    ts: { num: number, den: number };
    voiceNames?: Record<number, string>;
    setVoiceNames?: (names: Record<number, string>) => void;
}

interface SavedSubject {
    id: string;
    name: string;
    data: string;
}

export default function StrettoView({ notes: initialNotes, ppq, ts, voiceNames, setVoiceNames }: StrettoViewProps) {
    // Default to ABC mode if no MIDI notes were passed in
    const [mode, setMode] = useState<'midi' | 'abc'>(initialNotes.length > 0 ? 'midi' : 'abc');
    const [abcInput, setAbcInput] = useState<string>("M:4/4\nL:1/4\nQ:120\nK:C\nc2 G c d e f g3 a b c'2");

    // Default to Chain view
    const [viewMode, setViewMode] = useState<'pairwise' | 'chain'>('chain'); 

    // -- Library State --
    const [savedSubjects, setSavedSubjects] = useState<SavedSubject[]>([]);
    const [saveName, setSaveName] = useState('');
    const [showLibrary, setShowLibrary] = useState(false);

    // -- Pairwise State --
    const [configIntervals, setConfigIntervals] = useState<number[]>([0, 12, -12, 7, -5]);
    const [includeExtensions, setIncludeExtensions] = useState(false);
    const [includeInversions, setIncludeInversions] = useState(false);
    const [searchRes, setSearchRes] = useState<SearchResolution>('full');
    const [selectedCandidate, setSelectedCandidate] = useState<StrettoCandidate | null>(null);
    const [checkedIds, setCheckedIds] = useState<Set<string>>(new Set());

    // -- Chain Search State --
    const [searchOptions, setSearchOptions] = useState<StrettoSearchOptions>({
        ensembleTotal: 4,
        targetChainLength: 8,
        subjectVoiceIndex: 2, 
        truncationMode: 'Max 1',
        truncationMusicalValue: '1/2',
        inversionMode: 'None',
        thirdSixthMode: 'None',
        pivotMidi: 65, 
        requireConsonantEnd: true,
        disallowComplexExceptions: false
    });
    const [chainResults, setChainResults] = useState<StrettoChainResult[]>([]);
    const [searchReport, setSearchReport] = useState<StrettoSearchReport | null>(null);
    const [isSearching, setIsSearching] = useState(false);
    const [selectedChain, setSelectedChain] = useState<StrettoChainResult | null>(null);

    const [isPlaying, setIsPlaying] = useState(false);

    // Load Library on Mount
    useEffect(() => {
        const saved = localStorage.getItem('stretto_subject_library');
        if (saved) {
            try {
                setSavedSubjects(JSON.parse(saved));
            } catch (e) {
                console.error("Failed to load library", e);
            }
        }
    }, []);

    // Save Library Logic
    const handleSaveSubject = () => {
        if (!saveName.trim() || !abcInput.trim()) return;
        const newSubject: SavedSubject = {
            id: Date.now().toString(),
            name: saveName.trim(),
            data: abcInput
        };
        const updated = [...savedSubjects, newSubject];
        setSavedSubjects(updated);
        localStorage.setItem('stretto_subject_library', JSON.stringify(updated));
        setSaveName('');
    };

    const handleDeleteSubject = (id: string) => {
        const updated = savedSubjects.filter(s => s.id !== id);
        setSavedSubjects(updated);
        localStorage.setItem('stretto_subject_library', JSON.stringify(updated));
    };

    const handleLoadSubject = (data: string) => {
        setAbcInput(data);
    };

    // Data Preparation
    const subjectNotes = useMemo(() => {
        if (mode === 'abc') return parseSimpleAbc(abcInput, ppq);
        return initialNotes; 
    }, [mode, abcInput, initialNotes, ppq]);

    const { 
        isAssembling, assemblyStatus, assemblyResult, assemblyLog, 
        setAssemblyResult, runAssembly 
    } = useStrettoAssembly({ notes: subjectNotes, ppq, ts });

    // -- Pairwise Core Loop --
    const pairwiseResults = useMemo(() => {
        if (subjectNotes.length === 0 || viewMode !== 'pairwise') return [];
        const candidates: StrettoCandidate[] = [];
        // Handle undefined notes
        const validNotes = subjectNotes.filter(n => !!n);
        if (validNotes.length === 0) return [];

        const durationTicks = Math.max(...validNotes.map(n => n.ticks + n.durationTicks));
        const maxDelay = durationTicks * 0.75; 
        let stepTicks = ppq; 
        if (searchRes === 'half') stepTicks = ppq / 2;
        else if (searchRes === 'double') stepTicks = ppq * 2;

        let intervalsToCheck = [...configIntervals];
        if (includeExtensions) {
            const exts = [3, 4, 8, 9, -3, -4, -8, -9];
            exts.forEach(e => { if (!intervalsToCheck.includes(e)) intervalsToCheck.push(e); });
        }

        intervalsToCheck.forEach(interval => {
            for (let d = stepTicks; d <= maxDelay; d += stepTicks) {
                // Normal
                candidates.push(analyzeStrettoCandidate(validNotes, interval, Math.round(d), ppq, ts, false, 60));
                // Inverted
                if (includeInversions) {
                    candidates.push(analyzeStrettoCandidate(validNotes, interval, Math.round(d), ppq, ts, true, searchOptions.pivotMidi));
                }
            }
        });
        return candidates;
    }, [subjectNotes, configIntervals, includeExtensions, includeInversions, ppq, ts, searchRes, viewMode, searchOptions.pivotMidi]);

    const getSelectedCandidates = () => {
        return pairwiseResults.filter(r => checkedIds.has(r.id));
    };

    // -- Chain Search Action --
    const handleChainSearch = async () => {
        setIsSearching(true);
        setChainResults([]);
        setSearchReport(null);
        setSelectedChain(null);

        setTimeout(async () => {
            try {
                // Merge voiceNames into searchOptions
                const optionsWithNames = { ...searchOptions, voiceNames };
                const validNotes = subjectNotes.filter(n => !!n);
                const report = await searchStrettoChains(validNotes, optionsWithNames, ppq);
                setChainResults(report.results);
                setSearchReport(report);
            } catch (e) {
                console.error(e);
                alert("Search failed.");
            } finally {
                setIsSearching(false);
            }
        }, 100);
    };

    // -- Selection Logic for Chains --
    const chainToCandidate = useMemo((): StrettoCandidate | null => {
        if (!selectedChain) return null;

        let allNotes: RawNote[] = [];
        const voices: RawNote[][] = [];

        // FIX: Handle potential undefined notes in subjectNotes
        const validSubjectNotes = subjectNotes.filter(n => !!n);
        const sortedSubj = [...validSubjectNotes].sort((a,b)=>a.ticks-b.ticks);

        if (sortedSubj.length === 0) return null;

        const startTick = sortedSubj[0].ticks;

        selectedChain.entries.forEach((entry, idx) => {
            const entryStartTick = Math.round(entry.startBeat * ppq);
            const transformed = sortedSubj.map(n => {
                let pitch = n.midi;
                if (entry.type === 'I') {
                    const diff = pitch - searchOptions.pivotMidi;
                    pitch = searchOptions.pivotMidi - diff; 
                }
                pitch += entry.transposition;

                return {
                    ...n,
                    ticks: (n.ticks - startTick) + entryStartTick, 
                    midi: pitch,
                    name: getStrictPitchName(pitch),
                    voiceIndex: entry.voiceIndex,
                    durationTicks: n.durationTicks 
                };
            });

            // Apply truncation
            const entryDuration16 = entry.length; 
            const entryDurationTicks = entryDuration16 * (ppq/4);
            const entryEnd = entryStartTick + entryDurationTicks;

            const clipped = transformed.filter(n => n.ticks < entryEnd).map(n => ({
                ...n,
                durationTicks: Math.min(n.durationTicks, entryEnd - n.ticks)
            }));

            voices.push(clipped);
            allNotes = [...allNotes, ...clipped];
        });

        let chainRegions: HarmonicRegion[] = [];
        for (let i = 0; i < voices.length - 1; i++) {
            const vA = voices[i];
            const vB = voices[i+1];
            const events = getVerticalIntervals(vA, vB);
            const regions = generateHarmonicRegions(events);
            chainRegions = [...chainRegions, ...regions];
        }

        return {
            id: selectedChain.id,
            intervalLabel: "Chain",
            intervalSemis: 0,
            delayBeats: 0,
            delayTicks: 0,
            grade: 'STRONG',
            errors: [], 
            notes: allNotes,
            regions: chainRegions,
            dissonanceRatio: 0, 
            endsOnDissonance: false
        };
    }, [selectedChain, subjectNotes, ppq, searchOptions.pivotMidi]);


    // Actions
    const handlePlay = (notes: RawNote[]) => {
        if (isPlaying) {
            stopPlayback();
            setIsPlaying(false);
            return;
        }
        const seq = notes.filter(n => !!n).map(n => ({
            name: n.name, 
            time: n.ticks * (0.5 / ppq), 
            duration: n.durationTicks * (0.5 / ppq),
            velocity: n.velocity
        }));
        setIsPlaying(true);
        playSequence(seq, () => setIsPlaying(false));
    };

    const toggleCheck = (id: string) => {
        setCheckedIds(prev => {
            const next = new Set(prev);
            if (next.has(id)) next.delete(id);
            else next.add(id);
            const candidate = pairwiseResults.find(r => r.id === id);
            if (candidate) setSelectedCandidate(candidate);
            return next;
        });
    };

    const triggerAssembly = () => {
        const activeCandidates = checkedIds.size > 0 ? getSelectedCandidates() : (selectedCandidate ? [selectedCandidate] : []);
        runAssembly(activeCandidates, abcInput);
    };

    const handleDownloadChain = () => {
        if (chainToCandidate) {
            downloadStrettoCandidate(chainToCandidate, ppq, voiceNames);
        } else {
            alert("No chain selected.");
        }
    };

    const handleDownloadPairwise = () => {
        if (selectedCandidate) {
            downloadStrettoCandidate(selectedCandidate, ppq, voiceNames);
        }
    };

    const handleDownloadSelection = () => {
        const selected = getSelectedCandidates();
        if (selected.length > 0) {
            downloadStrettoSelection(selected, ppq, voiceNames);
        } else {
            alert("No candidates selected in the list. Check the boxes to export multiple.");
        }
    };

    return (
        <div className="w-full bg-gray-dark p-6 rounded-2xl border border-gray-medium animate-slide-up pb-32 relative">
            <div className="flex justify-between items-center mb-6">
                <h2 className="text-2xl font-bold text-gray-light">Stretto Assembly Lab</h2>
                {isAssembling && (
                    <div className="flex items-center gap-2 bg-brand-primary/20 px-4 py-2 rounded-full border border-brand-primary/40 animate-pulse">
                        <Spinner className="w-4 h-4 text-brand-primary" />
                        <span className="text-xs font-bold text-brand-primary">{assemblyStatus}</span>
                    </div>
                )}
            </div>

            {/* Top Toolbar */}
            <div className="flex flex-col md:flex-row gap-4 mb-6 p-4 bg-gray-800 rounded-lg border border-gray-700 justify-between">
                <div className="flex gap-2 items-center">
                    <span className="text-xs font-bold text-gray-500 mr-2">INPUT:</span>
                    <button onClick={() => setMode('midi')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${mode === 'midi' ? 'bg-brand-primary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Selected MIDI</button>
                    <button onClick={() => setMode('abc')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${mode === 'abc' ? 'bg-brand-primary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>ABC Notation</button>
                </div>

                <div className="flex gap-2 items-center border-l border-gray-600 pl-4">
                    <span className="text-xs font-bold text-gray-500 mr-2">MODE:</span>
                    <button onClick={() => setViewMode('pairwise')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${viewMode === 'pairwise' ? 'bg-brand-secondary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Pairwise Discovery</button>
                    <button onClick={() => setViewMode('chain')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${viewMode === 'chain' ? 'bg-brand-secondary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Algorithmic Chain</button>
                </div>
            </div>

            {mode === 'abc' && (
                <div className="mb-6 space-y-4">
                    <div className="flex justify-between items-center">
                        <div className="flex items-center gap-2">
                            <label className="block text-sm text-gray-400 font-bold uppercase tracking-wider">Subject ABC</label>
                            <span className="text-[10px] text-gray-500 font-mono hidden sm:inline">Supports M: (Meter), L: (Length), Q: (Tempo), K: (Key)</span>
                        </div>
                        <button 
                            onClick={() => setShowLibrary(!showLibrary)}
                            className="text-xs bg-gray-800 hover:bg-gray-700 text-brand-primary border border-brand-primary/30 px-3 py-1 rounded flex items-center gap-2 transition-colors"
                        >
                            <DocumentTextIcon className="w-3 h-3" />
                            {showLibrary ? "Hide Library" : "Subject Library"}
                        </button>
                    </div>

                    {showLibrary && (
                        <div className="bg-gray-800 p-4 rounded-lg border border-gray-700 animate-fade-in">
                            <div className="flex gap-2 mb-4 border-b border-gray-700 pb-4">
                                <input 
                                    type="text" 
                                    placeholder="Subject Name..." 
                                    value={saveName}
                                    onChange={(e) => setSaveName(e.target.value)}
                                    className="flex-grow bg-gray-900 border border-gray-600 rounded px-3 py-1 text-sm text-white focus:border-brand-primary outline-none"
                                />
                                <button 
                                    onClick={handleSaveSubject}
                                    disabled={!saveName.trim()}
                                    className="bg-brand-primary hover:bg-brand-secondary disabled:bg-gray-600 text-white px-4 py-1 rounded text-sm font-bold transition-colors"
                                >
                                    Save
                                </button>
                            </div>

                            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-2 max-h-48 overflow-y-auto">
                                {savedSubjects.length === 0 ? (
                                    <p className="text-xs text-gray-500 col-span-full text-center py-2">No saved subjects yet.</p>
                                ) : (
                                    savedSubjects.map(s => (
                                        <div key={s.id} className="flex justify-between items-center bg-gray-900 p-2 rounded border border-gray-700 group">
