        });
        prevP1 = p1; prevP2 = p2;
    }
    return regions;
}

const SCALE_INTERVALS = [0, 2, 4, 5, 7, 9, 11];
function invertPitch(pitch: number, pivot: number): number | null {
    const diff = pitch - pivot;
    const octaves = Math.floor(diff / 12);
    const semitone = (diff % 12 + 12) % 12;
    const scaleIndex = SCALE_INTERVALS.indexOf(semitone);
    if (scaleIndex === -1) return pivot - diff; 
    const absStep = (octaves * 7) + scaleIndex;
    const invStep = -absStep;
    const invOctaves = Math.floor(invStep / 7);
    const invRem = (invStep % 7 + 7) % 7;
    const invSemitone = SCALE_INTERVALS[invRem];
    return pivot + (invOctaves * 12) + invSemitone;
}

export function analyzeStrettoCandidate(
    subject: RawNote[], 
    intervalSemis: number, 
    delayTicks: number, 
    ppq: number,
    ts: { num: number, den: number },
    isInverted: boolean = false,
    pivotMidi: number = 60
): StrettoCandidate {

    // Smart Inversion Pivot: The pivot point now shifts based on the transposition.
    // If the answer is transposed up, the pivot for inversion should shift to keep the inverted answer in the same register.
    const octaveShift = Math.floor(intervalSemis / 12) * 12;
    const smartPivot = pivotMidi + octaveShift;

    const answer: RawNote[] = subject.map(n => {
        if (!n) return null as any;
        let newMidi = n.midi;
        if (isInverted) {
            const inv = invertPitch(n.midi, smartPivot);
            newMidi = inv !== null ? inv : n.midi;
        }
        newMidi += intervalSemis;
        return {
            ...n,
            ticks: n.ticks + delayTicks,
            midi: newMidi,
            name: getStrictPitchName(newMidi),
            voiceIndex: 1
        };
    }).filter(n => !!n);

    const startOverlap = delayTicks; 
    const subjectEnd = Math.max(0, ...subject.map(n => n ? n.ticks + n.durationTicks : 0));
    const endOverlap = subjectEnd;

    if (startOverlap >= endOverlap) {
        return {
            id: `invalid_gap`,
            intervalSemis, intervalLabel: 'N/A', delayBeats: 0, delayTicks,
            grade: 'INVALID', errors: [], notes: [], dissonanceRatio: 0, endsOnDissonance: true
        };
    }

    const events = getVerticalIntervals(subject, answer).filter(e => e.tick >= startOverlap);
    const harmonicRegions = generateHarmonicRegions(events);

    let totalOverlapTicks = 0;
    let dissonantTicks = 0;
    let endsOnDissonance = false;

    harmonicRegions.forEach((r, idx) => {
        const dur = r.endTick - r.startTick;
        totalOverlapTicks += dur;
        if (r.type === 'dissonance_1' || r.type === 'dissonance_consecutive') {
            dissonantTicks += dur;
            if (idx === harmonicRegions.length - 1) endsOnDissonance = true;
        }
    });

    const dissonanceRatio = totalOverlapTicks > 0 ? (dissonantTicks / totalOverlapTicks) : 0;
    const errors: StrettoError[] = [];

    harmonicRegions.forEach(r => {
        const timeStr = getFormattedTime(r.startTick, ppq, ts.num, ts.den);
        const onStrong = isStrongBeat(r.startTick, ppq, ts.num, ts.den);
        if (r.errorType === 'parallel') {
            errors.push({
                tick: r.startTick, timeFormatted: timeStr,
                type: r.intervalLabel.includes('P5') ? 'Parallel 5th' : 'Parallel 8ve',
                details: `Parallel motion into ${r.intervalLabel}`,
                severity: onStrong ? 'fatal' : 'warning'
            });
        }
        if (r.errorType === 'direct') {
             errors.push({
                tick: r.startTick, timeFormatted: timeStr,
                type: r.intervalLabel.includes('P5') ? 'Direct 5th' : 'Direct 8ve',
                details: `Direct motion into ${r.intervalLabel} (Upper leap)`,
                severity: 'warning'
            });
        }
        if (r.type === 'dissonance_consecutive' && onStrong) {
             const isP4Run = r.intervalLabel.includes('P4');
             errors.push({
                 tick: r.startTick, timeFormatted: timeStr,
                 type: 'Consecutive Dissonance',
                 details: 'Consecutive dissonance',
                 severity: isP4Run ? 'warning' : 'fatal'
             });
        }
    });

    let grade: StrettoGrade = 'STRONG';
    if (errors.some(e => e.severity === 'fatal')) grade = 'INVALID';
    else if (errors.length > 0) grade = 'VIABLE';

    let intLabel = getIntervalLabel(intervalSemis);
    if (intervalSemis < 0 && !intLabel.startsWith('-')) intLabel = '-' + intLabel;
    else if (intervalSemis > 0 && !intLabel.startsWith('+')) intLabel = '+' + intLabel;
    if (isInverted) intLabel += " (Inv)";

    const delayBeats = delayTicks / (ppq * (4 / ts.den));

    return {
        id: `${intLabel}@${delayBeats.toFixed(1)}${isInverted?'i':''}`,
        intervalSemis,
        intervalLabel: intLabel,
        delayBeats: parseFloat(delayBeats.toFixed(2)),
        delayTicks,
        grade,
        errors,
        notes: [...subject, ...answer],
        regions: harmonicRegions,
        dissonanceRatio,
        endsOnDissonance
    };
}

import React from 'react';

const INTERVAL_OPTIONS = [
    { label: 'Unison (P1)', val: 0 },
    { label: '+ Perf 5th', val: 7 },
    { label: '- Perf 5th', val: -7 },
    { label: '+ Perf 4th', val: 5 },
    { label: '- Perf 4th', val: -5 },
    { label: '+1 Octave (P8)', val: 12 },
    { label: '-1 Octave (P8)', val: -12 },
    { label: '+2 Octaves (P15)', val: 24 },
    { label: '-2 Octaves (P15)', val: -24 },
];

export type SearchResolution = 'half' | 'full' | 'double';

interface StrettoConfigProps {
    selectedIntervals: number[];
    setSelectedIntervals: (vals: number[]) => void;
    searchRes: SearchResolution;
    setSearchRes: (res: SearchResolution) => void;
    includeInversions: boolean;
    setIncludeInversions: (val: boolean) => void;
    includeExtensions: boolean;
    setIncludeExtensions: (val: boolean) => void;
}

export default function StrettoConfig({ 
    selectedIntervals, setSelectedIntervals, 
    searchRes, setSearchRes,
    includeInversions, setIncludeInversions,
    includeExtensions, setIncludeExtensions
}: StrettoConfigProps) {

    const toggleInterval = (val: number, checked: boolean) => {
        if (checked) {
            if (!selectedIntervals.includes(val)) setSelectedIntervals([...selectedIntervals, val]);
        } else {
            setSelectedIntervals(selectedIntervals.filter(c => c !== val));
        }
    };

    return (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
            <div className="p-4 bg-gray-800 rounded border border-gray-700 shadow-sm">
                <h3 className="text-xs font-bold text-gray-400 mb-3 uppercase tracking-widest text-brand-primary">Functional Search Intervals</h3>
                <div className="grid grid-cols-3 gap-2 mb-3">
                    {INTERVAL_OPTIONS.map(opt => (
                        <label key={opt.val} className={`flex items-center justify-center px-2 py-1.5 rounded cursor-pointer border transition-all ${selectedIntervals.includes(opt.val) ? 'bg-brand-primary/20 border-brand-primary text-brand-primary' : 'bg-gray-900 border-gray-700 text-gray-400 hover:border-gray-500'}`}>
                            <input 
                                type="checkbox" 
                                checked={selectedIntervals.includes(opt.val)}
                                onChange={e => toggleInterval(opt.val, e.target.checked)}
                                className="sr-only"
                            />
                            <span className="text-[10px] font-bold text-center">{opt.label}</span>
                        </label>
                    ))}
                </div>
                <div className="flex flex-wrap gap-2 border-t border-gray-700 pt-3">
                     <label className={`flex items-center px-3 py-1.5 rounded cursor-pointer border transition-all ${includeExtensions ? 'bg-brand-secondary/20 border-brand-secondary text-brand-secondary' : 'bg-gray-900 border-gray-700 text-gray-400 hover:border-gray-500'}`}>
                        <input 
                            type="checkbox" 
                            checked={includeExtensions}
                            onChange={e => setIncludeExtensions(e.target.checked)}
                            className="sr-only"
                        />
                        <span className="text-xs font-bold">+ 3rds & 6ths</span>
                    </label>
                    <label className={`flex items-center px-3 py-1.5 rounded cursor-pointer border transition-all ${includeInversions ? 'bg-blue-900/30 border-blue-500 text-blue-300' : 'bg-gray-900 border-gray-700 text-gray-400 hover:border-gray-500'}`}>
                        <input 
                            type="checkbox" 
                            checked={includeInversions}
                            onChange={e => setIncludeInversions(e.target.checked)}
                            className="sr-only"
                        />
                        <span className="text-xs font-bold">+ Inversions</span>
                    </label>
                </div>
            </div>

            <div className="p-4 bg-gray-800 rounded border border-gray-700 shadow-sm">
                <h3 className="text-xs font-bold text-gray-400 mb-3 uppercase tracking-widest">Search Frequency</h3>
                <div className="grid grid-cols-3 gap-2">
                    {(['half', 'full', 'double'] as SearchResolution[]).map(res => (
                        <button 
                            key={res}
                            onClick={() => setSearchRes(res)}
                            className={`px-2 py-2 rounded text-xs font-bold border transition-all ${searchRes === res ? 'bg-brand-primary text-white border-brand-primary shadow-lg' : 'bg-gray-900 border-gray-700 text-gray-500 hover:bg-gray-800'}`}
                        >
                            {res === 'half' ? '1/2 Beat' : res === 'full' ? 'Beat' : '2 Beats'}
                        </button>
                    ))}
                </div>
                <p className="text-[10px] text-gray-500 mt-2">
                    Finer resolution checks more entry points but takes longer to process.
                </p>
            </div>
        </div>
    );
}

import React, { useState, useMemo, useEffect } from 'react';
import { RawNote, StrettoCandidate, StrettoSearchOptions, StrettoChainResult, HarmonicRegion, StrettoSearchReport, StrettoGrade } from '../types';
import { parseSimpleAbc } from './services/abcBridge';
import { analyzeStrettoCandidate, getVerticalIntervals, generateHarmonicRegions } from './services/strettoCore';
import { searchStrettoChains } from './services/strettoGenerator'; 
import { getStrictPitchName } from './services/midiSpelling';
import { downloadStrettoCandidate, downloadStrettoSelection } from './services/strettoExport';
import { Spinner, DocumentTextIcon, DownloadIcon } from './Icons';
import { playSequence, stopPlayback } from './midiPlaybackService';
import { useStrettoAssembly } from '../hooks/useStrettoAssembly';

import StrettoConfig, { SearchResolution } from './stretto/StrettoConfig';
import StrettoList from './stretto/StrettoList';
import StrettoInspector from './stretto/StrettoInspector';
import StrettoFooter from './stretto/StrettoFooter';
import StrettoChainView from './stretto/StrettoChainView'; 

interface StrettoViewProps {
    notes: RawNote[]; 
    ppq: number;
    ts: { num: number, den: number };
    voiceNames?: Record<number, string>;
    setVoiceNames?: (names: Record<number, string>) => void;
}

interface SavedSubject {
    id: string;
    name: string;
    data: string;
}

export default function StrettoView({ notes: initialNotes, ppq, ts, voiceNames, setVoiceNames }: StrettoViewProps) {
    const [mode, setMode] = useState<'midi' | 'abc'>(initialNotes.length > 0 ? 'midi' : 'abc');
    const [abcInput, setAbcInput] = useState<string>("M:4/4\nL:1/4\nQ:120\nK:C\nc2 G c d e f g3 a b c'2");
    const [viewMode, setViewMode] = useState<'pairwise' | 'chain'>('chain'); 

    // Discovery Filters
    const [gradeFilter, setGradeFilter] = useState<Record<StrettoGrade, boolean>>({
        'STRONG': true,
        'VIABLE': true,
        'INVALID': false
    });

    const [savedSubjects, setSavedSubjects] = useState<SavedSubject[]>([]);
    const [saveName, setSaveName] = useState('');
    const [showLibrary, setShowLibrary] = useState(false);

    const [configIntervals, setConfigIntervals] = useState<number[]>([0, 12, -12, 7, -5]);
    const [includeExtensions, setIncludeExtensions] = useState(false);
    const [includeInversions, setIncludeInversions] = useState(false);
    const [searchRes, setSearchRes] = useState<SearchResolution>('full');
    const [selectedCandidate, setSelectedCandidate] = useState<StrettoCandidate | null>(null);
    const [checkedIds, setCheckedIds] = useState<Set<string>>(new Set());

    const [searchOptions, setSearchOptions] = useState<StrettoSearchOptions>({
        ensembleTotal: 4,
        targetChainLength: 8,
        subjectVoiceIndex: 2, 
        truncationMode: 'Max 1',
        truncationMusicalValue: '1/2',
        inversionMode: 'None',
        thirdSixthMode: 'None',
        pivotMidi: 65, 
        requireConsonantEnd: true,
        disallowComplexExceptions: false
    });
    const [chainResults, setChainResults] = useState<StrettoChainResult[]>([]);
    const [searchReport, setSearchReport] = useState<StrettoSearchReport | null>(null);
    const [isSearching, setIsSearching] = useState(false);
    const [selectedChain, setSelectedChain] = useState<StrettoChainResult | null>(null);

    const [isPlaying, setIsPlaying] = useState(false);

    useEffect(() => {
        const saved = localStorage.getItem('stretto_subject_library');
        if (saved) {
            try { setSavedSubjects(JSON.parse(saved)); } catch (e) { console.error(e); }
        }
    }, []);

    const handleSaveSubject = () => {
        if (!saveName.trim() || !abcInput.trim()) return;
        const newSubject: SavedSubject = { id: Date.now().toString(), name: saveName.trim(), data: abcInput };
        const updated = [...savedSubjects, newSubject];
        setSavedSubjects(updated);
        localStorage.setItem('stretto_subject_library', JSON.stringify(updated));
        setSaveName('');
    };

    const handleDeleteSubject = (id: string) => {
        const updated = savedSubjects.filter(s => s.id !== id);
        setSavedSubjects(updated);
        localStorage.setItem('stretto_subject_library', JSON.stringify(updated));
    };

    const handleLoadSubject = (data: string) => { setAbcInput(data); };

    const subjectNotes = useMemo(() => {
        if (mode === 'abc') return parseSimpleAbc(abcInput, ppq);
        return initialNotes; 
    }, [mode, abcInput, initialNotes, ppq]);

    const { 
        isAssembling, assemblyStatus, assemblyResult, assemblyLog, 
        setAssemblyResult, runAssembly 
    } = useStrettoAssembly({ notes: subjectNotes, ppq, ts });

    const pairwiseResults = useMemo(() => {
        if (subjectNotes.length === 0 || viewMode !== 'pairwise') return [];
        const candidates: StrettoCandidate[] = [];
        const validNotes = subjectNotes.filter(n => !!n);
        if (validNotes.length === 0) return [];

        const durationTicks = Math.max(...validNotes.map(n => n.ticks + n.durationTicks));
        const maxDelay = durationTicks * 0.75; 
        let stepTicks = ppq; 
        if (searchRes === 'half') stepTicks = ppq / 2;
        else if (searchRes === 'double') stepTicks = ppq * 2;

        let intervalsToCheck = [...configIntervals];
        if (includeExtensions) {
            const exts = [3, 4, 8, 9, -3, -4, -8, -9];
            exts.forEach(e => { if (!intervalsToCheck.includes(e)) intervalsToCheck.push(e); });
        }

        intervalsToCheck.forEach(interval => {
            for (let d = stepTicks; d <= maxDelay; d += stepTicks) {
                candidates.push(analyzeStrettoCandidate(validNotes, interval, Math.round(d), ppq, ts, false, 60));
                if (includeInversions) {
                    candidates.push(analyzeStrettoCandidate(validNotes, interval, Math.round(d), ppq, ts, true, searchOptions.pivotMidi));
                }
            }
        });
        return candidates;
    }, [subjectNotes, configIntervals, includeExtensions, includeInversions, ppq, ts, searchRes, viewMode, searchOptions.pivotMidi]);

    const processedDiscoveryResults = useMemo(() => {
        return pairwiseResults.filter(r => gradeFilter[r.grade]);
    }, [pairwiseResults, gradeFilter]);

    const handleExportDiscoveryText = () => {
        if (processedDiscoveryResults.length === 0) {
            alert("No results to export with current filters.");
            return;
        }

        let report = `# Stretto Pairwise Discovery Report\n`;
        report += `Generated: ${new Date().toLocaleString()}\n`;
        report += `Active Filters: ${Object.entries(gradeFilter).filter(([_, v]) => v).map(([k]) => k).join(', ')}\n\n`;

        report += `| Interval | Delay | Quality | Dissonance % | Resolution | Errors |\n`;
        report += `| :--- | :--- | :--- | :--- | :--- | :--- |\n`;

        processedDiscoveryResults.forEach(r => {
            const diss = Math.round(r.dissonanceRatio * 100);
            const res = r.endsOnDissonance ? "Unresolved (!)" : "Resolved (✓)";
            const errs = r.errors.length > 0 ? r.errors.map(e => e.type).join(', ') : '-';
            report += `| ${r.intervalLabel} | ${r.delayBeats}B | ${r.grade} | ${diss}% | ${res} | ${errs} |\n`;
        });

        const blob = new Blob([report], { type: 'text/plain' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `Stretto_Discovery_Report_${Date.now()}.md`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
    };

    const getSelectedCandidates = () => pairwiseResults.filter(r => checkedIds.has(r.id));

    const handleChainSearch = async () => {
        setIsSearching(true); setChainResults([]); setSearchReport(null); setSelectedChain(null);
        setTimeout(async () => {
            try {
                const report = await searchStrettoChains(subjectNotes.filter(n => !!n), { ...searchOptions, voiceNames }, ppq);
                setChainResults(report.results); setSearchReport(report);
            } catch (e) { alert("Search failed."); } finally { setIsSearching(false); }
        }, 100);
    };

    const chainToCandidate = useMemo((): StrettoCandidate | null => {
        if (!selectedChain) return null;
        let allNotes: RawNote[] = [];
        const voices: RawNote[][] = [];
        const validSubjectNotes = subjectNotes.filter(n => !!n);
        if (validSubjectNotes.length === 0) return null;
        const sortedSubj = [...validSubjectNotes].sort((a,b)=>a.ticks-b.ticks);
        const startTick = sortedSubj[0].ticks;

        selectedChain.entries.forEach((entry) => {
            const entryStartTick = Math.round(entry.startBeat * ppq);
            const transformed = sortedSubj.map(n => {
                let pitch = n.midi;
                if (entry.type === 'I') pitch = searchOptions.pivotMidi - (pitch - searchOptions.pivotMidi); 
                pitch += entry.transposition;
                return { ...n, ticks: (n.ticks - startTick) + entryStartTick, midi: pitch, name: getStrictPitchName(pitch), voiceIndex: entry.voiceIndex };
            });
            const entryEnd = entryStartTick + (entry.length * (ppq/4));
            const clipped = transformed.filter(n => n.ticks < entryEnd).map(n => ({ ...n, durationTicks: Math.min(n.durationTicks, entryEnd - n.ticks) }));
            voices.push(clipped); allNotes = [...allNotes, ...clipped];
        });

        let chainRegions: HarmonicRegion[] = [];
        for (let i = 0; i < voices.length - 1; i++) {
            const regions = generateHarmonicRegions(getVerticalIntervals(voices[i], voices[i+1]));
            chainRegions = [...chainRegions, ...regions];
        }

        return { id: selectedChain.id, intervalLabel: "Chain", intervalSemis: 0, delayBeats: 0, delayTicks: 0, grade: 'STRONG', errors: [], notes: allNotes, regions: chainRegions, dissonanceRatio: 0, endsOnDissonance: false };
    }, [selectedChain, subjectNotes, ppq, searchOptions.pivotMidi]);

    const handlePlay = (notes: RawNote[]) => {
        if (isPlaying) { stopPlayback(); setIsPlaying(false); return; }
        setIsPlaying(true);
        playSequence(notes.filter(n => !!n).map(n => ({ name: n.name, time: n.ticks * (0.5 / ppq), duration: n.durationTicks * (0.5 / ppq), velocity: n.velocity })), () => setIsPlaying(false));
    };

    const toggleCheck = (id: string) => {
        setCheckedIds(prev => {
            const next = new Set(prev);
            if (next.has(id)) next.delete(id); else next.add(id);
            const cand = pairwiseResults.find(r => r.id === id);
            if (cand) setSelectedCandidate(cand);
            return next;
        });
    };

    return (
        <div className="w-full bg-gray-dark p-6 rounded-2xl border border-gray-medium animate-slide-up pb-32 relative">
            <div className="flex justify-between items-center mb-6">
                <h2 className="text-2xl font-bold text-gray-light">Stretto Assembly Lab</h2>
                {isAssembling && (
                    <div className="flex items-center gap-2 bg-brand-primary/20 px-4 py-2 rounded-full border border-brand-primary/40 animate-pulse">
                        <Spinner className="w-4 h-4 text-brand-primary" />
                        <span className="text-xs font-bold text-brand-primary">{assemblyStatus}</span>
                    </div>
                )}
            </div>

            <div className="flex flex-col md:flex-row gap-4 mb-6 p-4 bg-gray-800 rounded-lg border border-gray-700 justify-between">
                <div className="flex gap-2 items-center">
                    <span className="text-xs font-bold text-gray-500 mr-2">INPUT:</span>
                    <button onClick={() => setMode('midi')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${mode === 'midi' ? 'bg-brand-primary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Selected MIDI</button>
                    <button onClick={() => setMode('abc')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${mode === 'abc' ? 'bg-brand-primary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>ABC Notation</button>
                </div>
                <div className="flex gap-2 items-center border-l border-gray-600 pl-4">
                    <span className="text-xs font-bold text-gray-500 mr-2">MODE:</span>
                    <button onClick={() => setViewMode('pairwise')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${viewMode === 'pairwise' ? 'bg-brand-secondary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Pairwise Discovery</button>
                    <button onClick={() => setViewMode('chain')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${viewMode === 'chain' ? 'bg-brand-secondary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Algorithmic Chain</button>
                </div>
            </div>

            {mode === 'abc' && (
                <div className="mb-6 space-y-4">
                    <div className="flex justify-between items-center">
                        <label className="block text-sm text-gray-400 font-bold uppercase tracking-wider">Subject ABC</label>
                        <button onClick={() => setShowLibrary(!showLibrary)} className="text-xs bg-gray-800 hover:bg-gray-700 text-brand-primary border border-brand-primary/30 px-3 py-1 rounded flex items-center gap-2 transition-colors">
                            <DocumentTextIcon className="w-3 h-3" /> {showLibrary ? "Hide Library" : "Subject Library"}
                        </button>
                    </div>
                    {showLibrary && (
                        <div className="bg-gray-800 p-4 rounded-lg border border-gray-700 animate-fade-in">
                            <div className="flex gap-2 mb-4 border-b border-gray-700 pb-4">
                                <input type="text" placeholder="Subject Name..." value={saveName} onChange={(e) => setSaveName(e.target.value)} className="flex-grow bg-gray-900 border border-gray-600 rounded px-3 py-1 text-sm text-white outline-none" />
                                <button onClick={handleSaveSubject} disabled={!saveName.trim()} className="bg-brand-primary hover:bg-brand-secondary text-white px-4 py-1 rounded text-sm font-bold transition-colors disabled:bg-gray-600">Save</button>
                            </div>
                            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-2 max-h-48 overflow-y-auto">
                                {savedSubjects.length > 0 ? savedSubjects.map(s => (
                                    <div key={s.id} className="flex justify-between items-center bg-gray-900 p-2 rounded border border-gray-700 group">
                                        <span className="text-sm font-bold text-gray-300 truncate mr-2">{s.name}</span>
                                        <div className="flex gap-1 opacity-50 group-hover:opacity-100">
                                            <button onClick={() => handleLoadSubject(s.data)} className="text-[10px] bg-brand-secondary/50 px-2 py-0.5 rounded">Load</button>
                                            <button onClick={() => handleDeleteSubject(s.id)} className="text-[10px] bg-red-900/50 px-2 py-0.5 rounded">×</button>
                                        </div>
                                    </div>
                                )) : <p className="text-xs text-gray-500 col-span-full text-center py-2">Library empty.</p>}
                            </div>
                        </div>
                    )}
                    <textarea value={abcInput} onChange={e => setAbcInput(e.target.value)} className="w-full bg-gray-900 border border-gray-700 rounded p-3 text-white font-mono h-24 outline-none focus:border-brand-primary" />
                </div>
            )}

            {viewMode === 'pairwise' ? (
                <>
                    <StrettoConfig selectedIntervals={configIntervals} setSelectedIntervals={setConfigIntervals} searchRes={searchRes} setSearchRes={setSearchRes} includeInversions={includeInversions} setIncludeInversions={setIncludeInversions} includeExtensions={includeExtensions} setIncludeExtensions={setIncludeExtensions} />
                    <div className="flex justify-end mb-2">
                        <button 
                            onClick={handleExportDiscoveryText}
                            className="flex items-center gap-2 text-xs bg-gray-800 hover:bg-gray-700 text-gray-300 px-3 py-1.5 rounded border border-gray-600 transition-colors"
                        >
                            <DocumentTextIcon className="w-4 h-4" /> Export Text Report
                        </button>
                    </div>
                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
                        <StrettoList 
                            candidates={pairwiseResults} 
                            processedResults={processedDiscoveryResults}
                            gradeFilter={gradeFilter}
                            setGradeFilter={setGradeFilter}
                            selectedId={selectedCandidate?.id || null} 
                            onSelect={setSelectedCandidate} 
                            checkedIds={checkedIds} 
                            onToggleCheck={toggleCheck} 
                        />
                        <StrettoInspector candidate={selectedCandidate} ppq={ppq} ts={ts} isPlaying={isPlaying} onPlay={handlePlay} assemblyResult={assemblyResult} assemblyLog={assemblyLog} onClearAssembly={() => setAssemblyResult('')} onDownloadChain={() => selectedCandidate && downloadStrettoCandidate(selectedCandidate, ppq, voiceNames)} />
                    </div>
                    <StrettoFooter selectedCandidates={getSelectedCandidates()} onDownloadMidi={() => downloadStrettoSelection(getSelectedCandidates(), ppq, voiceNames)} onAssemble={() => runAssembly(checkedIds.size > 0 ? getSelectedCandidates() : (selectedCandidate ? [selectedCandidate] : []), abcInput)} isAssembling={isAssembling} onRemoveCandidate={toggleCheck} />
                </>
            ) : (
                <StrettoChainView searchOptions={searchOptions} setSearchOptions={setSearchOptions} onSearch={handleChainSearch} isSearching={isSearching} chainResults={chainResults} selectedChain={selectedChain} setSelectedChain={setSelectedChain} voiceNames={voiceNames} setVoiceNames={setVoiceNames} chainToCandidate={chainToCandidate} ppq={ppq} ts={ts} isPlaying={isPlaying} onPlay={handlePlay} onDownloadChain={() => chainToCandidate && downloadStrettoCandidate(chainToCandidate, ppq, voiceNames)} searchReport={searchReport} />
            )}
        </div>
    );
}

import React, { useState, useMemo } from 'react';
import { StrettoCandidate, StrettoGrade } from '../../types';

interface StrettoListProps {
    candidates: StrettoCandidate[];
    processedResults: StrettoCandidate[];
    gradeFilter: Record<StrettoGrade, boolean>;
    setGradeFilter: (val: Record<StrettoGrade, boolean>) => void;
    selectedId: string | null;
    onSelect: (candidate: StrettoCandidate) => void;
    checkedIds: Set<string>;
    onToggleCheck: (id: string) => void;
}

type SortKey = 'grade' | 'delay' | 'interval' | 'dissonance';

export default function StrettoList({ 
    candidates, processedResults, gradeFilter, setGradeFilter, 
    selectedId, onSelect, checkedIds, onToggleCheck 
}: StrettoListProps) {
    const [sortKey, setSortKey] = useState<SortKey>('grade');
    const [sortDir, setSortDir] = useState<'asc' | 'desc'>('desc');

    const toggleGradeFilter = (g: StrettoGrade) => {
        setGradeFilter({ ...gradeFilter, [g]: !gradeFilter[g] });
    };

    const handleSort = (key: SortKey) => {
        if (sortKey === key) {
            setSortDir(prev => prev === 'asc' ? 'desc' : 'asc');
        } else {
            setSortKey(key);
            setSortDir(key === 'grade' || key === 'dissonance' ? 'desc' : 'asc');
        }
    };

    const sortedResults = useMemo(() => {
        const res = [...processedResults];
        res.sort((a, b) => {
            let diff = 0;
            if (sortKey === 'grade') {
                const score = { 'STRONG': 3, 'VIABLE': 2, 'INVALID': 1 };
                diff = score[a.grade] - score[b.grade];
            } else if (sortKey === 'delay') {
                diff = a.delayTicks - b.delayTicks;
            } else if (sortKey === 'interval') {
                diff = Math.abs(a.intervalSemis) - Math.abs(b.intervalSemis);
            } else if (sortKey === 'dissonance') {
                diff = a.dissonanceRatio - b.dissonanceRatio;
            }
            return sortDir === 'asc' ? diff : -diff;
        });
        return res;
    }, [processedResults, sortKey, sortDir]);

    return (
        <div className="bg-gray-900 border border-gray-700 rounded h-[600px] flex flex-col shadow-inner relative">
            <div className="p-2 border-b border-gray-700 bg-gray-800 flex flex-col gap-2">
                <div className="flex justify-between items-center">
                    <div className="flex gap-2">
                        <button onClick={() => toggleGradeFilter('STRONG')} className={`px-2 py-1 text-[10px] rounded font-bold transition-colors ${gradeFilter.STRONG ? 'bg-green-900 text-green-300 border border-green-700' : 'bg-gray-900 text-gray-500 border border-gray-700'}`}>Strong</button>
                        <button onClick={() => toggleGradeFilter('VIABLE')} className={`px-2 py-1 text-[10px] rounded font-bold transition-colors ${gradeFilter.VIABLE ? 'bg-yellow-900 text-yellow-300 border border-yellow-700' : 'bg-gray-900 text-gray-500 border border-gray-700'}`}>Viable</button>
                        <button onClick={() => toggleGradeFilter('INVALID')} className={`px-2 py-1 text-[10px] rounded font-bold transition-colors ${gradeFilter.INVALID ? 'bg-red-900 text-red-300 border border-red-700' : 'bg-gray-900 text-gray-500 border border-gray-700'}`}>Invalid</button>
                    </div>
                    <div className="text-[10px] text-gray-400">
                        {sortedResults.length} / {candidates.length}
                    </div>
                </div>
                <div className="flex gap-1 bg-gray-900 p-1 rounded">
                    {(['grade', 'delay', 'interval', 'dissonance'] as SortKey[]).map(key => (
                        <button key={key} onClick={() => handleSort(key)} className={`flex-1 text-[10px] py-1 rounded transition-colors ${sortKey === key ? 'bg-gray-700 text-white font-bold' : 'text-gray-500 hover:text-gray-300'}`}>
                            {key.charAt(0).toUpperCase() + key.slice(1)} {sortKey === key && (sortDir === 'asc' ? '↑' : '↓')}
                        </button>
                    ))}
                </div>
            </div>

            <div className="overflow-y-auto flex-grow p-2">
                <div className="grid grid-cols-12 gap-2 px-2 py-1 text-[9px] font-bold text-gray-500 uppercase border-b border-gray-800">
                    <div className="col-span-1"></div>
                    <div className="col-span-2">Int</div>
                    <div className="col-span-2">Delay</div>
                    <div className="col-span-2">Verdict</div>
                    <div className="col-span-2">Diss %</div>
                    <div className="col-span-1">End</div>
                    <div className="col-span-2 text-right">Err</div>
                </div>

                {sortedResults.length === 0 ? (
                    <div className="py-20 text-center text-gray-600 text-sm italic">Filter result empty.</div>
                ) : (
                    sortedResults.map((r) => (
                        <div key={r.id} onClick={() => onSelect(r)} className={`grid grid-cols-12 gap-2 p-2 rounded cursor-pointer border-b border-gray-800 hover:bg-gray-800 items-center transition-colors ${selectedId === r.id ? 'bg-gray-800 border-l-4 border-l-brand-primary' : ''}`}>
                            <div className="col-span-1 flex justify-center" onClick={(e) => e.stopPropagation()}>
                                <input type="checkbox" checked={checkedIds.has(r.id)} onChange={() => onToggleCheck(r.id)} className="rounded bg-gray-700 border-gray-600 text-brand-primary w-4 h-4" />
                            </div>
                            <span className="col-span-2 font-bold text-brand-primary text-xs truncate">{r.intervalLabel}</span>
                            <span className="col-span-2 text-gray-300 text-xs">{r.delayBeats}B</span>
                            <div className="col-span-2">
                                <span className={`text-[9px] font-bold px-1 py-0.5 rounded ${r.grade === 'STRONG' ? 'bg-green-900 text-green-300' : r.grade === 'VIABLE' ? 'bg-yellow-900 text-yellow-300' : 'bg-red-900 text-red-300'}`}>{r.grade.charAt(0)}</span>
                            </div>
                            <span className={`col-span-2 text-xs font-mono font-bold ${r.dissonanceRatio > 0.5 ? 'text-red-400' : r.dissonanceRatio > 0.3 ? 'text-yellow-400' : 'text-green-400'}`}>{Math.round(r.dissonanceRatio * 100)}%</span>
                            <div className="col-span-1 flex justify-center">{r.endsOnDissonance ? <span className="text-red-500 font-bold">!</span> : <span className="text-green-500 font-bold">✓</span>}</div>
                            <span className="col-span-2 text-[10px] text-gray-500 text-right">{r.errors.length > 0 ? r.errors.length : '-'}</span>
                        </div>
                    ))
                )}
            </div>
        </div>
    );
}

import { RawNote, StrettoCandidate, StrettoError, StrettoGrade, HarmonicRegion } from '../../types';
import { getFormattedTime } from './midiHarmony';
import { getStrictPitchName, getIntervalLabel } from './midiSpelling';

// Strict counterpoint intervals
const DISSONANT_INTERVALS = [1, 2, 6, 10, 11]; // m2, M2, TT, m7, M7
const PERFECT_CONSONANCES = [0, 7]; // P1, P5 (P8 is 0 mod 12)

export interface VoiceEvent {
    tick: number;
    endTick: number; 
    pitch1: number; // Subject
    pitch2: number; // Answer (Transposed Subject)
    hasAttack1: boolean;
    hasAttack2: boolean;
}

export function getVerticalIntervals(subject: RawNote[], answer: RawNote[]): VoiceEvent[] {
    const timePoints = new Set<number>();
    [...subject, ...answer].forEach(n => {
        if (!n) return;
        timePoints.add(n.ticks);
        timePoints.add(n.ticks + n.durationTicks);
    });

    const sortedPoints = Array.from(timePoints).sort((a,b) => a-b);
    const events: VoiceEvent[] = [];
    const endOfMusic = Math.max(0, ...[...subject, ...answer].map(n => n ? n.ticks + n.durationTicks : 0));

    for (let i = 0; i < sortedPoints.length - 1; i++) {
        const t = sortedPoints[i];
        if (t >= endOfMusic) break;

        const checkTime = t; 
        const n1 = subject.find(n => n && n.ticks <= checkTime && (n.ticks + n.durationTicks) > checkTime);
        const n2 = answer.find(n => n && n.ticks <= checkTime && (n.ticks + n.durationTicks) > checkTime);

        if (n1 && n2) {
            events.push({
                tick: t,
                endTick: sortedPoints[i+1],
                pitch1: n1.midi,
                pitch2: n2.midi,
                hasAttack1: n1.ticks === t,
                hasAttack2: n2.ticks === t
            });
        }
    }
    return events;
}

function isStrongBeat(tick: number, ppq: number, tsNum: number, tsDenom: number): boolean {
    const ticksPerMeasure = ppq * tsNum * (4 / tsDenom);
    const pos = tick % ticksPerMeasure;
    if (pos === 0) return true; 
    if (tsNum === 4 && tsDenom === 4 && pos === (ticksPerMeasure / 2)) return true;
    return false; 
}

export function generateHarmonicRegions(events: VoiceEvent[]): HarmonicRegion[] {
    const regions: HarmonicRegion[] = [];
    let previousState: 'consonance' | 'dissonance' = 'consonance';
    let prevP1: number | null = null;
    let prevP2: number | null = null;

    for (let i = 0; i < events.length; i++) {
        const ev = events[i];
        const duration = ev.endTick - ev.tick;
        if (duration <= 0) continue;

        const p1 = ev.pitch1;
        const p2 = ev.pitch2;
        const interval = Math.abs(p1 - p2);
        const intervalClass = interval % 12;
        const isBass1 = p1 < p2;
        const upperPitch = isBass1 ? p2 : p1;
        const prevUpperPitch = isBass1 ? (prevP2) : (prevP1);

        const isP4 = intervalClass === 5; 
        const isDiss = DISSONANT_INTERVALS.includes(intervalClass) || isP4;
        let regionType: HarmonicRegion['type'];

        if (isDiss) {
            regionType = (previousState === 'consonance') ? 'dissonance_1' : 'dissonance_consecutive';
            previousState = 'dissonance';
        } else {
            regionType = (PERFECT_CONSONANCES.includes(intervalClass)) ? 'perfect_consonance' : 'imperfect_consonance';
            previousState = 'consonance';
        }

        let errorType: HarmonicRegion['errorType'] = null;
        if (prevP1 !== null && prevP2 !== null) {
            const p1Moved = prevP1 !== p1;
            const p2Moved = prevP2 !== p2;
            if (p1Moved && p2Moved) {
                const isParallelMotion = (p1 - prevP1) * (p2 - prevP2) > 0;
                const isPerfect = intervalClass === 0 || intervalClass === 7;
                if (isPerfect && isParallelMotion) {
                    const prevInterval = Math.abs(prevP1 - prevP2);
                    if (prevInterval % 12 === intervalClass) errorType = 'parallel';
                }
                if (!errorType && isPerfect && isParallelMotion && prevUpperPitch !== null) {
                    if (Math.abs(upperPitch - prevUpperPitch) > 2) errorType = 'direct';
                }
            }
        }

        regions.push({
            startTick: ev.tick,
            endTick: ev.endTick, 
            type: regionType,
            errorType: errorType,
            intervalLabel: getIntervalLabel(interval),
            description: `${getIntervalLabel(interval)}: ${getStrictPitchName(p1)}, ${getStrictPitchName(p2)}`
        });
        prevP1 = p1; prevP2 = p2;
    }
    return regions;
}

const SCALE_INTERVALS = [0, 2, 4, 5, 7, 9, 11];
function invertPitch(pitch: number, pivot: number): number | null {
    const diff = pitch - pivot;
    const octaves = Math.floor(diff / 12);
    const semitone = (diff % 12 + 12) % 12;
    const scaleIndex = SCALE_INTERVALS.indexOf(semitone);
    if (scaleIndex === -1) return pivot - diff; 
    const absStep = (octaves * 7) + scaleIndex;
    const invStep = -absStep;
    const invOctaves = Math.floor(invStep / 7);
    const invRem = (invStep % 7 + 7) % 7;
    const invSemitone = SCALE_INTERVALS[invRem];
    return pivot + (invOctaves * 12) + invSemitone;
}

export function analyzeStrettoCandidate(
    subject: RawNote[], 
    intervalSemis: number, 
    delayTicks: number, 
    ppq: number,
    ts: { num: number, den: number },
    isInverted: boolean = false,
    pivotMidi: number = 60
): StrettoCandidate {

    // Stable Pivot Correction: As requested, keep inversion around the same note (Middle C).
    // The transposition is then applied on top of the inverted form.
    const answer: RawNote[] = subject.map(n => {
        if (!n) return null as any;
        let newMidi = n.midi;
        if (isInverted) {
            const inv = invertPitch(n.midi, pivotMidi);
            newMidi = inv !== null ? inv : n.midi;
        }
        newMidi += intervalSemis;
        return {
            ...n,
            ticks: n.ticks + delayTicks,
            midi: newMidi,
            name: getStrictPitchName(newMidi),
            voiceIndex: 1
        };
    }).filter(n => !!n);

    const startOverlap = delayTicks; 
    const subjectEnd = Math.max(0, ...subject.map(n => n ? n.ticks + n.durationTicks : 0));
    const endOverlap = subjectEnd;

    if (startOverlap >= endOverlap) {
        return {
            id: `invalid_gap`,
            intervalSemis, intervalLabel: 'N/A', delayBeats: 0, delayTicks,
            grade: 'INVALID', errors: [], notes: [], dissonanceRatio: 0, endsOnDissonance: true
        };
    }

    const events = getVerticalIntervals(subject, answer).filter(e => e.tick >= startOverlap);
    const harmonicRegions = generateHarmonicRegions(events);

    let totalOverlapTicks = 0;
    let dissonantTicks = 0;
    let endsOnDissonance = false;

    harmonicRegions.forEach((r, idx) => {
        const dur = r.endTick - r.startTick;
        totalOverlapTicks += dur;
        if (r.type === 'dissonance_1' || r.type === 'dissonance_consecutive') {
            dissonantTicks += dur;
            if (idx === harmonicRegions.length - 1) endsOnDissonance = true;
        }
    });

    const dissonanceRatio = totalOverlapTicks > 0 ? (dissonantTicks / totalOverlapTicks) : 0;
    const errors: StrettoError[] = [];

    harmonicRegions.forEach(r => {
        const timeStr = getFormattedTime(r.startTick, ppq, ts.num, ts.den);
        const onStrong = isStrongBeat(r.startTick, ppq, ts.num, ts.den);
        if (r.errorType === 'parallel') {
            errors.push({
                tick: r.startTick, timeFormatted: timeStr,
                type: r.intervalLabel.includes('P5') ? 'Parallel 5th' : 'Parallel 8ve',
                details: `Parallel motion into ${r.intervalLabel}`,
                severity: onStrong ? 'fatal' : 'warning'
            });
        }
        if (r.errorType === 'direct') {
             errors.push({
                tick: r.startTick, timeFormatted: timeStr,
                type: r.intervalLabel.includes('P5') ? 'Direct 5th' : 'Direct 8ve',
                details: `Direct motion into ${r.intervalLabel} (Upper leap)`,
                severity: 'warning'
            });
        }
        if (r.type === 'dissonance_consecutive' && onStrong) {
             const isP4Run = r.intervalLabel.includes('P4');
             errors.push({
                 tick: r.startTick, timeFormatted: timeStr,
                 type: 'Consecutive Dissonance',
                 details: 'Consecutive dissonance',
                 severity: isP4Run ? 'warning' : 'fatal'
             });
        }
    });

    let grade: StrettoGrade = 'STRONG';
    if (errors.some(e => e.severity === 'fatal')) grade = 'INVALID';
    else if (errors.length > 0) grade = 'VIABLE';

    let intLabel = getIntervalLabel(intervalSemis);
    if (intervalSemis < 0 && !intLabel.startsWith('-')) intLabel = '-' + intLabel;
    else if (intervalSemis > 0 && !intLabel.startsWith('+')) intLabel = '+' + intLabel;
    if (isInverted) intLabel += " (Inv)";

    const delayBeats = delayTicks / (ppq * (4 / ts.den));

    return {
        id: `${intLabel}@${delayBeats.toFixed(1)}${isInverted?'i':''}`,
        intervalSemis,
        intervalLabel: intLabel,
        delayBeats: parseFloat(delayBeats.toFixed(2)),
        delayTicks,
        grade,
        errors,
        notes: [...subject, ...answer],
        regions: harmonicRegions,
        dissonanceRatio,
        endsOnDissonance
    };
}

import React from 'react';

const INTERVAL_OPTIONS = [
    { label: 'Unison (P1)', val: 0 },
    { label: '+ Perf 5th', val: 7 },
    { label: '- Perf 5th', val: -7 },
    { label: '+ Perf 4th', val: 5 },
    { label: '- Perf 4th', val: -5 },
    { label: '+1 Octave (P8)', val: 12 },
    { label: '-1 Octave (P8)', val: -12 },
    { label: '+2 Octaves (P15)', val: 24 },
    { label: '-2 Octaves (P15)', val: -24 },
];

export type SearchResolution = 'half' | 'full' | 'double';

interface StrettoConfigProps {
    selectedIntervals: number[];
    setSelectedIntervals: (vals: number[]) => void;
    searchRes: SearchResolution;
    setSearchRes: (res: SearchResolution) => void;
    includeInversions: boolean;
    setIncludeInversions: (val: boolean) => void;
    includeExtensions: boolean;
    setIncludeExtensions: (val: boolean) => void;
}

export default function StrettoConfig({ 
    selectedIntervals, setSelectedIntervals, 
    searchRes, setSearchRes,
    includeInversions, setIncludeInversions,
    includeExtensions, setIncludeExtensions
}: StrettoConfigProps) {

    const toggleInterval = (val: number, checked: boolean) => {
        if (checked) {
            if (!selectedIntervals.includes(val)) setSelectedIntervals([...selectedIntervals, val]);
        } else {
            setSelectedIntervals(selectedIntervals.filter(c => c !== val));
        }
    };

    return (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
            <div className="p-4 bg-gray-800 rounded border border-gray-700 shadow-sm">
                <h3 className="text-xs font-bold text-gray-400 mb-3 uppercase tracking-widest text-brand-primary">Functional Discovery Intervals</h3>
                <div className="grid grid-cols-3 gap-2 mb-3">
                    {INTERVAL_OPTIONS.map(opt => (
                        <label key={opt.val} className={`flex items-center justify-center px-2 py-1.5 rounded cursor-pointer border transition-all ${selectedIntervals.includes(opt.val) ? 'bg-brand-primary/20 border-brand-primary text-brand-primary' : 'bg-gray-900 border-gray-700 text-gray-400 hover:border-gray-500'}`}>
                            <input 
                                type="checkbox" 
                                checked={selectedIntervals.includes(opt.val)}
                                onChange={e => toggleInterval(opt.val, e.target.checked)}
                                className="sr-only"
                            />
                            <span className="text-[10px] font-bold text-center">{opt.label}</span>
                        </label>
                    ))}
                </div>
                <div className="flex flex-wrap gap-2 border-t border-gray-700 pt-3">
                     <label className={`flex items-center px-3 py-1.5 rounded cursor-pointer border transition-all ${includeExtensions ? 'bg-brand-secondary/20 border-brand-secondary text-brand-secondary' : 'bg-gray-900 border-gray-700 text-gray-400 hover:border-gray-500'}`}>
                        <input 
                            type="checkbox" 
                            checked={includeExtensions}
                            onChange={e => setIncludeExtensions(e.target.checked)}
                            className="sr-only"
                        />
                        <span className="text-xs font-bold">+ 3rds & 6ths</span>
                    </label>
                    <label className={`flex items-center px-3 py-1.5 rounded cursor-pointer border transition-all ${includeInversions ? 'bg-blue-900/30 border-blue-500 text-blue-300' : 'bg-gray-900 border-gray-700 text-gray-400 hover:border-gray-500'}`}>
                        <input 
                            type="checkbox" 
                            checked={includeInversions}
                            onChange={e => setIncludeInversions(e.target.checked)}
                            className="sr-only"
                        />
                        <span className="text-xs font-bold">+ Inversions</span>
                    </label>
                </div>
            </div>

            <div className="p-4 bg-gray-800 rounded border border-gray-700 shadow-sm">
                <h3 className="text-xs font-bold text-gray-400 mb-3 uppercase tracking-widest">Entry Resolution</h3>
                <div className="grid grid-cols-3 gap-2">
                    {(['half', 'full', 'double'] as SearchResolution[]).map(res => (
                        <button 
                            key={res}
                            onClick={() => setSearchRes(res)}
                            className={`px-2 py-2 rounded text-xs font-bold border transition-all ${searchRes === res ? 'bg-brand-primary text-white border-brand-primary shadow-lg' : 'bg-gray-900 border-gray-700 text-gray-500 hover:bg-gray-800'}`}
                        >
                            {res === 'half' ? '1/2 Beat' : res === 'full' ? 'Beat' : '2 Beats'}
                        </button>
                    ))}
                </div>
                <p className="text-[10px] text-gray-500 mt-2">
                    Defines how frequently the algorithm checks for entry points.
                </p>
            </div>
        </div>
    );
}

import React, { useState, useMemo } from 'react';
import { StrettoCandidate, StrettoGrade } from '../../types';

interface StrettoListProps {
    candidates: StrettoCandidate[];
    processedResults: StrettoCandidate[];
    gradeFilter: Record<StrettoGrade, boolean>;
    setGradeFilter: (val: Record<StrettoGrade, boolean>) => void;
    selectedId: string | null;
    onSelect: (candidate: StrettoCandidate) => void;
    checkedIds: Set<string>;
    onToggleCheck: (id: string) => void;
}

type SortKey = 'grade' | 'delay' | 'interval' | 'dissonance';

export default function StrettoList({ 
    candidates, processedResults, gradeFilter, setGradeFilter, 
    selectedId, onSelect, checkedIds, onToggleCheck 
}: StrettoListProps) {
    const [sortKey, setSortKey] = useState<SortKey>('grade');
    const [sortDir, setSortDir] = useState<'asc' | 'desc'>('desc');

    const toggleGradeFilter = (g: StrettoGrade) => {
        setGradeFilter({ ...gradeFilter, [g]: !gradeFilter[g] });
    };

    const handleSort = (key: SortKey) => {
        if (sortKey === key) {
            setSortDir(prev => prev === 'asc' ? 'desc' : 'asc');
        } else {
            setSortKey(key);
            setSortDir(key === 'grade' || key === 'dissonance' ? 'desc' : 'asc');
        }
    };

    const sortedResults = useMemo(() => {
        const res = [...processedResults];
        res.sort((a, b) => {
            let diff = 0;
            if (sortKey === 'grade') {
                const score = { 'STRONG': 3, 'VIABLE': 2, 'INVALID': 1 };
                diff = score[a.grade] - score[b.grade];
            } else if (sortKey === 'delay') {
                diff = a.delayTicks - b.delayTicks;
            } else if (sortKey === 'interval') {
                diff = Math.abs(a.intervalSemis) - Math.abs(b.intervalSemis);
            } else if (sortKey === 'dissonance') {
                diff = a.dissonanceRatio - b.dissonanceRatio;
            }
            return sortDir === 'asc' ? diff : -diff;
        });
        return res;
    }, [processedResults, sortKey, sortDir]);

    return (
        <div className="bg-gray-900 border border-gray-700 rounded h-[600px] flex flex-col shadow-inner relative">
            <div className="p-3 border-b border-gray-700 bg-gray-800 flex flex-col gap-3">
                <div className="flex justify-between items-center">
                    <div className="flex gap-2 items-center">
                        <span className="text-[10px] font-bold text-gray-500 uppercase tracking-widest mr-1">Filter:</span>
                        <button onClick={() => toggleGradeFilter('STRONG')} className={`px-3 py-1 text-[10px] rounded font-bold border transition-all ${gradeFilter.STRONG ? 'bg-green-900 border-green-500 text-green-300' : 'bg-gray-900 border-gray-700 text-gray-500'}`}>Strong</button>
                        <button onClick={() => toggleGradeFilter('VIABLE')} className={`px-3 py-1 text-[10px] rounded font-bold border transition-all ${gradeFilter.VIABLE ? 'bg-yellow-900 border-yellow-500 text-yellow-300' : 'bg-gray-900 border-gray-700 text-gray-500'}`}>Viable</button>
                        <button onClick={() => toggleGradeFilter('INVALID')} className={`px-3 py-1 text-[10px] rounded font-bold border transition-all ${gradeFilter.INVALID ? 'bg-red-900 border-red-500 text-red-300' : 'bg-gray-900 border-gray-700 text-gray-500'}`}>Invalid</button>
                    </div>
                    <div className="text-[10px] font-mono text-gray-500">
                        {sortedResults.length} Visible
                    </div>
                </div>
                <div className="flex gap-1 bg-gray-900 p-1 rounded border border-gray-700">
                    {(['grade', 'delay', 'interval', 'dissonance'] as SortKey[]).map(key => (
                        <button key={key} onClick={() => handleSort(key)} className={`flex-1 text-[10px] py-1 rounded transition-colors ${sortKey === key ? 'bg-gray-700 text-white font-bold' : 'text-gray-500 hover:text-gray-300'}`}>
                            {key.charAt(0).toUpperCase() + key.slice(1)} {sortKey === key && (sortDir === 'asc' ? '↑' : '↓')}
                        </button>
                    ))}
                </div>
            </div>

            <div className="overflow-y-auto flex-grow p-2">
                <div className="grid grid-cols-12 gap-2 px-2 py-1 text-[9px] font-bold text-gray-500 uppercase border-b border-gray-800">
                    <div className="col-span-1"></div>
                    <div className="col-span-2">Int</div>
                    <div className="col-span-2">Delay</div>
                    <div className="col-span-2">Verdict</div>
                    <div className="col-span-2">Diss %</div>
                    <div className="col-span-1">End</div>
                    <div className="col-span-2 text-right">Err</div>
                </div>

                {sortedResults.length === 0 ? (
                    <div className="py-20 text-center text-gray-600 text-sm italic">No results match filters.</div>
                ) : (
                    sortedResults.map((r) => (
                        <div key={r.id} onClick={() => onSelect(r)} className={`grid grid-cols-12 gap-2 p-2 rounded cursor-pointer border-b border-gray-800 hover:bg-gray-800 items-center transition-colors ${selectedId === r.id ? 'bg-gray-800 border-l-4 border-l-brand-primary' : ''}`}>
                            <div className="col-span-1 flex justify-center" onClick={(e) => e.stopPropagation()}>
                                <input type="checkbox" checked={checkedIds.has(r.id)} onChange={() => onToggleCheck(r.id)} className="rounded bg-gray-700 border-gray-600 text-brand-primary w-4 h-4" />
                            </div>
                            <span className="col-span-2 font-bold text-brand-primary text-xs truncate">{r.intervalLabel}</span>
                            <span className="col-span-2 text-gray-300 text-xs">{r.delayBeats}B</span>
                            <div className="col-span-2">
                                <span className={`text-[9px] font-bold px-1 py-0.5 rounded ${r.grade === 'STRONG' ? 'bg-green-900 text-green-300' : r.grade === 'VIABLE' ? 'bg-yellow-900 text-yellow-300' : 'bg-red-900 text-red-300'}`}>{r.grade.charAt(0)}</span>
                            </div>
                            <span className={`col-span-2 text-xs font-mono font-bold ${r.dissonanceRatio > 0.5 ? 'text-red-400' : r.dissonanceRatio > 0.3 ? 'text-yellow-400' : 'text-green-400'}`}>{Math.round(r.dissonanceRatio * 100)}%</span>
                            <div className="col-span-1 flex justify-center">{r.endsOnDissonance ? <span className="text-red-500 font-bold">!</span> : <span className="text-green-500 font-bold">✓</span>}</div>
                            <span className="col-span-2 text-[10px] text-gray-500 text-right">{r.errors.length > 0 ? r.errors.length : '-'}</span>
                        </div>
                    ))
                )}
            </div>
        </div>
    );
}

import React, { useState, useMemo, useEffect } from 'react';
import { RawNote, StrettoCandidate, StrettoSearchOptions, StrettoChainResult, HarmonicRegion, StrettoSearchReport, StrettoGrade } from '../types';
import { parseSimpleAbc } from './services/abcBridge';
import { analyzeStrettoCandidate, getVerticalIntervals, generateHarmonicRegions } from './services/strettoCore';
import { searchStrettoChains } from './services/strettoGenerator'; 
import { getStrictPitchName } from './services/midiSpelling';
import { downloadStrettoCandidate, downloadStrettoSelection } from './services/strettoExport';
import { Spinner, DocumentTextIcon, DownloadIcon } from './Icons';
import { playSequence, stopPlayback } from './midiPlaybackService';
import { useStrettoAssembly } from '../hooks/useStrettoAssembly';

import StrettoConfig, { SearchResolution } from './stretto/StrettoConfig';
import StrettoList from './stretto/StrettoList';
import StrettoInspector from './stretto/StrettoInspector';
import StrettoFooter from './stretto/StrettoFooter';
import StrettoChainView from './stretto/StrettoChainView'; 

interface StrettoViewProps {
    notes: RawNote[]; 
    ppq: number;
    ts: { num: number, den: number };
    voiceNames?: Record<number, string>;
    setVoiceNames?: (names: Record<number, string>) => void;
}

interface SavedSubject {
    id: string;
    name: string;
    data: string;
}

export default function StrettoView({ notes: initialNotes, ppq, ts, voiceNames, setVoiceNames }: StrettoViewProps) {
    const [mode, setMode] = useState<'midi' | 'abc'>(initialNotes.length > 0 ? 'midi' : 'abc');
    const [abcInput, setAbcInput] = useState<string>("M:4/4\nL:1/4\nQ:120\nK:C\nc2 G c d e f g3 a b c'2");
    const [viewMode, setViewMode] = useState<'pairwise' | 'chain'>('chain'); 

    // Discovery Filters
    const [gradeFilter, setGradeFilter] = useState<Record<StrettoGrade, boolean>>({
        'STRONG': true,
        'VIABLE': true,
        'INVALID': false
    });

    const [savedSubjects, setSavedSubjects] = useState<SavedSubject[]>([]);
    const [saveName, setSaveName] = useState('');
    const [showLibrary, setShowLibrary] = useState(false);

    // Initial Functional Intervals: P1, +/-P4, +/-P5, +/-P8, +/-P15
    const [configIntervals, setConfigIntervals] = useState<number[]>([0, 12, -12, 7, -7, 5, -5, 24, -24]);
    const [includeExtensions, setIncludeExtensions] = useState(false);
    const [includeInversions, setIncludeInversions] = useState(false);
    const [searchRes, setSearchRes] = useState<SearchResolution>('full');
    const [selectedCandidate, setSelectedCandidate] = useState<StrettoCandidate | null>(null);
    const [checkedIds, setCheckedIds] = useState<Set<string>>(new Set());

    const [searchOptions, setSearchOptions] = useState<StrettoSearchOptions>({
        ensembleTotal: 4,
        targetChainLength: 8,
        subjectVoiceIndex: 2, 
        truncationMode: 'Max 1',
        truncationMusicalValue: '1/2',
        inversionMode: 'None',
        thirdSixthMode: 'None',
        pivotMidi: 65, 
        requireConsonantEnd: true,
        disallowComplexExceptions: false
    });
    const [chainResults, setChainResults] = useState<StrettoChainResult[]>([]);
    const [searchReport, setSearchReport] = useState<StrettoSearchReport | null>(null);
    const [isSearching, setIsSearching] = useState(false);
    const [selectedChain, setSelectedChain] = useState<StrettoChainResult | null>(null);

    const [isPlaying, setIsPlaying] = useState(false);

    useEffect(() => {
        const saved = localStorage.getItem('stretto_subject_library');
        if (saved) {
            try { setSavedSubjects(JSON.parse(saved)); } catch (e) { console.error(e); }
        }
    }, []);

    const handleSaveSubject = () => {
        if (!saveName.trim() || !abcInput.trim()) return;
        const newSubject: SavedSubject = { id: Date.now().toString(), name: saveName.trim(), data: abcInput };
        const updated = [...savedSubjects, newSubject];
        setSavedSubjects(updated);
        localStorage.setItem('stretto_subject_library', JSON.stringify(updated));
        setSaveName('');
    };

    const handleDeleteSubject = (id: string) => {
        const updated = savedSubjects.filter(s => s.id !== id);
        setSavedSubjects(updated);
        localStorage.setItem('stretto_subject_library', JSON.stringify(updated));
    };

    const handleLoadSubject = (data: string) => { setAbcInput(data); };

    const subjectNotes = useMemo(() => {
        if (mode === 'abc') return parseSimpleAbc(abcInput, ppq);
        return initialNotes; 
    }, [mode, abcInput, initialNotes, ppq]);

    const { 
        isAssembling, assemblyStatus, assemblyResult, assemblyLog, 
        setAssemblyResult, runAssembly 
    } = useStrettoAssembly({ notes: subjectNotes, ppq, ts });

    const pairwiseResults = useMemo(() => {
        if (subjectNotes.length === 0 || viewMode !== 'pairwise') return [];
        const candidates: StrettoCandidate[] = [];
        const validNotes = subjectNotes.filter(n => !!n);
        if (validNotes.length === 0) return [];

        const durationTicks = Math.max(...validNotes.map(n => n.ticks + n.durationTicks));
        const maxDelay = durationTicks * 0.75; 
        let stepTicks = ppq; 
        if (searchRes === 'half') stepTicks = ppq / 2;
        else if (searchRes === 'double') stepTicks = ppq * 2;

        let intervalsToCheck = [...configIntervals];
        if (includeExtensions) {
            const exts = [3, 4, 8, 9, -3, -4, -8, -9];
            exts.forEach(e => { if (!intervalsToCheck.includes(e)) intervalsToCheck.push(e); });
        }

        intervalsToCheck.forEach(interval => {
            for (let d = stepTicks; d <= maxDelay; d += stepTicks) {
                candidates.push(analyzeStrettoCandidate(validNotes, interval, Math.round(d), ppq, ts, false, 60));
                if (includeInversions) {
                    candidates.push(analyzeStrettoCandidate(validNotes, interval, Math.round(d), ppq, ts, true, 60));
                }
            }
        });
        return candidates;
    }, [subjectNotes, configIntervals, includeExtensions, includeInversions, ppq, ts, searchRes, viewMode]);

    const processedDiscoveryResults = useMemo(() => {
        return pairwiseResults.filter(r => gradeFilter[r.grade]);
    }, [pairwiseResults, gradeFilter]);

    const handleExportDiscoveryText = () => {
        if (processedDiscoveryResults.length === 0) {
            alert("No results to export with current filters.");
            return;
        }

        let report = `# Stretto Pairwise Discovery Report\n`;
        report += `Generated: ${new Date().toLocaleString()}\n`;
        report += `Active Filters: ${Object.entries(gradeFilter).filter(([_, v]) => v).map(([k]) => k).join(', ')}\n\n`;

        report += `| Interval | Delay | Verdict | Dissonance % | Resolution | Errors |\n`;
        report += `| :--- | :--- | :--- | :--- | :--- | :--- |\n`;

        processedDiscoveryResults.forEach(r => {
            const diss = Math.round(r.dissonanceRatio * 100);
            const res = r.endsOnDissonance ? "Unresolved (!)" : "Resolved (✓)";
            const errs = r.errors.length > 0 ? r.errors.map(e => e.type).join(', ') : '-';
            report += `| ${r.intervalLabel} | ${r.delayBeats}B | ${r.grade} | ${diss}% | ${res} | ${errs} |\n`;
        });

        const blob = new Blob([report], { type: 'text/markdown' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `Stretto_Discovery_Report_${Date.now()}.md`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
    };

    const getSelectedCandidates = () => pairwiseResults.filter(r => checkedIds.has(r.id));

    const handleChainSearch = async () => {
        setIsSearching(true); setChainResults([]); setSearchReport(null); setSelectedChain(null);
        setTimeout(async () => {
            try {
                const report = await searchStrettoChains(subjectNotes.filter(n => !!n), { ...searchOptions, voiceNames }, ppq);
                setChainResults(report.results); setSearchReport(report);
            } catch (e) { alert("Search failed."); } finally { setIsSearching(false); }
        }, 100);
    };

    const chainToCandidate = useMemo((): StrettoCandidate | null => {
        if (!selectedChain) return null;
        let allNotes: RawNote[] = [];
        const voices: RawNote[][] = [];
        const validSubjectNotes = subjectNotes.filter(n => !!n);
        if (validSubjectNotes.length === 0) return null;
        const sortedSubj = [...validSubjectNotes].sort((a,b)=>a.ticks-b.ticks);
        const startTick = sortedSubj[0].ticks;

        selectedChain.entries.forEach((entry) => {
            const entryStartTick = Math.round(entry.startBeat * ppq);
            const transformed = sortedSubj.map(n => {
                let pitch = n.midi;
                if (entry.type === 'I') pitch = searchOptions.pivotMidi - (pitch - searchOptions.pivotMidi); 
                pitch += entry.transposition;
                return { ...n, ticks: (n.ticks - startTick) + entryStartTick, midi: pitch, name: getStrictPitchName(pitch), voiceIndex: entry.voiceIndex };
            });
            const entryEnd = entryStartTick + (entry.length * (ppq/4));
            const clipped = transformed.filter(n => n.ticks < entryEnd).map(n => ({ ...n, durationTicks: Math.min(n.durationTicks, entryEnd - n.ticks) }));
            voices.push(clipped); allNotes = [...allNotes, ...clipped];
        });

        let chainRegions: HarmonicRegion[] = [];
        for (let i = 0; i < voices.length - 1; i++) {
            const regions = generateHarmonicRegions(getVerticalIntervals(voices[i], voices[i+1]));
            chainRegions = [...chainRegions, ...regions];
        }

        return { id: selectedChain.id, intervalLabel: "Chain", intervalSemis: 0, delayBeats: 0, delayTicks: 0, grade: 'STRONG', errors: [], notes: allNotes, regions: chainRegions, dissonanceRatio: 0, endsOnDissonance: false };
    }, [selectedChain, subjectNotes, ppq, searchOptions.pivotMidi]);

    const handlePlay = (notes: RawNote[]) => {
        if (isPlaying) { stopPlayback(); setIsPlaying(false); return; }
        setIsPlaying(true);
        playSequence(notes.filter(n => !!n).map(n => ({ name: n.name, time: n.ticks * (0.5 / ppq), duration: n.durationTicks * (0.5 / ppq), velocity: n.velocity })), () => setIsPlaying(false));
    };

    const toggleCheck = (id: string) => {
        setCheckedIds(prev => {
            const next = new Set(prev);
            if (next.has(id)) next.delete(id); else next.add(id);
            const cand = pairwiseResults.find(r => r.id === id);
            if (cand) setSelectedCandidate(cand);
            return next;
        });
    };

    return (
        <div className="w-full bg-gray-dark p-6 rounded-2xl border border-gray-medium animate-slide-up pb-32 relative">
            <div className="flex justify-between items-center mb-6">
                <h2 className="text-2xl font-bold text-gray-light">Stretto Assembly Lab</h2>
                {isAssembling && (
                    <div className="flex items-center gap-2 bg-brand-primary/20 px-4 py-2 rounded-full border border-brand-primary/40 animate-pulse">
                        <Spinner className="w-4 h-4 text-brand-primary" />
                        <span className="text-xs font-bold text-brand-primary">{assemblyStatus}</span>
                    </div>
                )}
            </div>

            <div className="flex flex-col md:flex-row gap-4 mb-6 p-4 bg-gray-800 rounded-lg border border-gray-700 justify-between">
                <div className="flex gap-2 items-center">
                    <span className="text-xs font-bold text-gray-500 mr-2">INPUT:</span>
                    <button onClick={() => setMode('midi')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${mode === 'midi' ? 'bg-brand-primary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Selected MIDI</button>
                    <button onClick={() => setMode('abc')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${mode === 'abc' ? 'bg-brand-primary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>ABC Notation</button>
                </div>
                <div className="flex gap-2 items-center border-l border-gray-600 pl-4">
                    <span className="text-xs font-bold text-gray-500 mr-2">MODE:</span>
                    <button onClick={() => setViewMode('pairwise')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${viewMode === 'pairwise' ? 'bg-brand-secondary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Pairwise Discovery</button>
                    <button onClick={() => setViewMode('chain')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${viewMode === 'chain' ? 'bg-brand-secondary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Algorithmic Chain</button>
                </div>
            </div>

            {mode === 'abc' && (
                <div className="mb-6 space-y-4">
                    <div className="flex justify-between items-center">
                        <label className="block text-sm text-gray-400 font-bold uppercase tracking-wider">Subject ABC</label>
                        <button onClick={() => setShowLibrary(!showLibrary)} className="text-xs bg-gray-800 hover:bg-gray-700 text-brand-primary border border-brand-primary/30 px-3 py-1 rounded flex items-center gap-2 transition-colors">
                            <DocumentTextIcon className="w-3 h-3" /> {showLibrary ? "Hide Library" : "Subject Library"}
                        </button>
                    </div>
                    {showLibrary && (
                        <div className="bg-gray-800 p-4 rounded-lg border border-gray-700 animate-fade-in">
                            <div className="flex gap-2 mb-4 border-b border-gray-700 pb-4">
                                <input type="text" placeholder="Subject Name..." value={saveName} onChange={(e) => setSaveName(e.target.value)} className="flex-grow bg-gray-900 border border-gray-600 rounded px-3 py-1 text-sm text-white outline-none" />
                                <button onClick={handleSaveSubject} disabled={!saveName.trim()} className="bg-brand-primary hover:bg-brand-secondary text-white px-4 py-1 rounded text-sm font-bold transition-colors disabled:bg-gray-600">Save</button>
                            </div>
                            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-2 max-h-48 overflow-y-auto">
                                {savedSubjects.length > 0 ? savedSubjects.map(s => (
                                    <div key={s.id} className="flex justify-between items-center bg-gray-900 p-2 rounded border border-gray-700 group">
                                        <span className="text-sm font-bold text-gray-300 truncate mr-2">{s.name}</span>
                                        <div className="flex gap-1 opacity-50 group-hover:opacity-100">
                                            <button onClick={() => handleLoadSubject(s.data)} className="text-[10px] bg-brand-secondary/50 px-2 py-0.5 rounded">Load</button>
                                            <button onClick={() => handleDeleteSubject(s.id)} className="text-[10px] bg-red-900/50 px-2 py-0.5 rounded">×</button>
                                        </div>
                                    </div>
                                )) : <p className="text-xs text-gray-500 col-span-full text-center py-2">Library empty.</p>}
                            </div>
                        </div>
                    )}
                    <textarea value={abcInput} onChange={e => setAbcInput(e.target.value)} className="w-full bg-gray-900 border border-gray-700 rounded p-3 text-white font-mono h-24 outline-none focus:border-brand-primary" />
                </div>
            )}

            {viewMode === 'pairwise' ? (
                <>
                    <StrettoConfig selectedIntervals={configIntervals} setSelectedIntervals={setConfigIntervals} searchRes={searchRes} setSearchRes={setSearchRes} includeInversions={includeInversions} setIncludeInversions={setIncludeInversions} includeExtensions={includeExtensions} setIncludeExtensions={setIncludeExtensions} />
                    <div className="flex justify-end mb-2">
                        <button 
                            onClick={handleExportDiscoveryText}
                            className="flex items-center gap-2 text-xs bg-gray-800 hover:bg-gray-700 text-gray-300 px-3 py-1.5 rounded border border-gray-600 transition-colors shadow-sm"
                        >
                            <DocumentTextIcon className="w-4 h-4" /> Export Table (.md)
                        </button>
                    </div>
                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
                        <StrettoList 
                            candidates={pairwiseResults} 
                            processedResults={processedDiscoveryResults}
                            gradeFilter={gradeFilter}
                            setGradeFilter={setGradeFilter}
                            selectedId={selectedCandidate?.id || null} 
                            onSelect={setSelectedCandidate} 
                            checkedIds={checkedIds} 
                            onToggleCheck={toggleCheck} 
                        />
                        <StrettoInspector candidate={selectedCandidate} ppq={ppq} ts={ts} isPlaying={isPlaying} onPlay={handlePlay} assemblyResult={assemblyResult} assemblyLog={assemblyLog} onClearAssembly={() => setAssemblyResult('')} onDownloadChain={() => selectedCandidate && downloadStrettoCandidate(selectedCandidate, ppq, voiceNames)} />
                    </div>
                    <StrettoFooter selectedCandidates={getSelectedCandidates()} onDownloadMidi={() => downloadStrettoSelection(getSelectedCandidates(), ppq, voiceNames)} onAssemble={() => runAssembly(checkedIds.size > 0 ? getSelectedCandidates() : (selectedCandidate ? [selectedCandidate] : []), abcInput)} isAssembling={isAssembling} onRemoveCandidate={toggleCheck} />
                </>
            ) : (
                <StrettoChainView searchOptions={searchOptions} setSearchOptions={setSearchOptions} onSearch={handleChainSearch} isSearching={isSearching} chainResults={chainResults} selectedChain={selectedChain} setSelectedChain={setSelectedChain} voiceNames={voiceNames} setVoiceNames={setVoiceNames} chainToCandidate={chainToCandidate} ppq={ppq} ts={ts} isPlaying={isPlaying} onPlay={handlePlay} onDownloadChain={() => chainToCandidate && downloadStrettoCandidate(chainToCandidate, ppq, voiceNames)} searchReport={searchReport} />
            )}
        </div>
    );
}

import * as Tone from 'tone';
import { Midi } from '@tonejs/midi';

let instrument: Tone.Sampler | Tone.PolySynth | null = null;
let currentPart: Tone.Part | null = null;

const PIANO_SAMPLES = {
    'A0': 'A0.mp3', 'C1': 'C1.mp3', 'D#1': 'Ds1.mp3', 'F#1': 'Fs1.mp3', 'A1': 'A1.mp3',
    'C2': 'C2.mp3', 'D#2': 'Ds2.mp3', 'F#2': 'Fs2.mp3', 'A2': 'A2.mp3',
    'C3': 'C3.mp3', 'D#3': 'Ds3.mp3', 'F#3': 'Fs3.mp3', 'A3': 'A3.mp3',
    'C4': 'C4.mp3', 'D#4': 'Ds4.mp3', 'F#4': 'Fs4.mp3', 'A4': 'A4.mp3',
    'C5': 'C5.mp3', 'D#5': 'Ds5.mp3', 'F#5': 'Fs5.mp3', 'A5': 'A5.mp3',
    'C6': 'C6.mp3', 'D#6': 'Ds6.mp3', 'F#6': 'Fs6.mp3', 'A6': 'A6.mp3',
    'C7': 'C7.mp3', 'D#7': 'Ds7.mp3', 'F#7': 'Fs7.mp3', 'A7': 'A7.mp3',
    'C8': 'C8.mp3'
};
const SAMPLE_BASE_URL = "https://tonejs.github.io/audio/salamander/";

async function initializeInstrument(): Promise<Tone.Sampler | Tone.PolySynth> {
  if (instrument) return instrument;

  return new Promise((resolve) => {
      const sampler = new Tone.Sampler({
          urls: PIANO_SAMPLES,
          baseUrl: SAMPLE_BASE_URL,
          onload: () => {
              sampler.toDestination();
              instrument = sampler;
              resolve(sampler);
          },
          onerror: () => {
              createFallbackSynth();
              resolve(instrument!);
          }
      });

      setTimeout(() => {
          if (!sampler.loaded) {
              createFallbackSynth();
              resolve(instrument!);
          }
      }, 3000);
  });
}

function createFallbackSynth() {
    if (instrument instanceof Tone.PolySynth) return;
    instrument = new Tone.PolySynth(Tone.Synth, {
        oscillator: { type: "triangle" },
        envelope: { attack: 0.005, decay: 0.3, sustain: 0.4, release: 1.2 },
        volume: -6
    }).toDestination();
}

export async function playTrack(processedMidi: Midi, onEnded: () => void): Promise<void> {
  stopPlayback();
  if (processedMidi.tracks.length === 0) { onEnded(); return; }
  const track = processedMidi.tracks[0];
  if (!track.notes || track.notes.length === 0) { onEnded(); return; }

  const inst = await initializeInstrument();
  await Tone.start();

  Tone.Transport.stop();
  Tone.Transport.position = 0;
  Tone.Transport.bpm.value = processedMidi.header.tempos[0]?.bpm || 120;

  currentPart = new Tone.Part(
    (time, note) => {
      // Use MIDI number for stability
      if (note.midi !== undefined && !isNaN(note.midi)) {
          inst.triggerAttackRelease(Tone.Frequency(note.midi, "midi").toNote(), note.duration, time, note.velocity);
      }
    },
    track.notes.map(note => ({
      time: note.time,
      midi: note.midi,
      duration: note.duration,
      velocity: note.velocity,
    }))
  );

  currentPart.loop = false;
  Tone.Transport.on('stop', () => {
    currentPart?.dispose();
    currentPart = null;
    onEnded();
  });

  currentPart.start(0);
  Tone.Transport.start();
  const lastNote = track.notes[track.notes.length - 1];
  const endTime = lastNote.time + lastNote.duration + 1;
  Tone.Transport.scheduleOnce(() => { Tone.Transport.stop(); }, endTime);
}

export async function playSequence(notes: { midi?: number, name?: string, time: number, duration: number, velocity: number }[], onEnded?: () => void) {
    stopPlayback();
    const inst = await initializeInstrument();
    await Tone.start();
    const now = Tone.now();
    let maxTime = 0;

    notes.forEach(n => {
        // Prefer MIDI number over name for stability
        const pitch = n.midi !== undefined ? Tone.Frequency(n.midi, "midi").toNote() : n.name;
        if (pitch && !pitch.includes('undefined')) {
            try {
                inst.triggerAttackRelease(pitch, n.duration, now + n.time, n.velocity);
                if ((n.time + n.duration) > maxTime) maxTime = n.time + n.duration;
            } catch (e) { console.warn(`Playback error for pitch: ${pitch}`, e); }
        }
    });

    if (onEnded) { setTimeout(onEnded, maxTime * 1000 + 500); }
}

export async function playSpecificNotes(notes: { midi?: number, name?: string, duration: number, velocity: number }[]) {
    const inst = await initializeInstrument();
    await Tone.start();
    const now = Tone.now();
    notes.forEach(n => {
        const pitch = n.midi !== undefined ? Tone.Frequency(n.midi, "midi").toNote() : n.name;
        if (pitch && !pitch.includes('undefined')) {
            try { inst.triggerAttackRelease(pitch, n.duration, now, n.velocity); } catch (e) { }
        }
    });
}

export function stopPlayback(): void {
  if (Tone.Transport.state === 'started') {
    Tone.Transport.stop();
    Tone.Transport.cancel(); 
  }
  if (currentPart) {
    currentPart.dispose();
    currentPart = null;
  }
  if (instrument) { instrument.releaseAll(); }
}

