import React, { useState, useMemo } from 'react';
import { StrettoCandidate, StrettoGrade } from '../../types';
import { getStrictPitchName } from '../services/midiSpelling';

interface StrettoListProps {
    candidates: StrettoCandidate[];
    processedResults: StrettoCandidate[];
    gradeFilter: Record<StrettoGrade, boolean>;
    setGradeFilter: (val: Record<StrettoGrade, boolean>) => void;
    selectedId: string | null;
    onSelect: (candidate: StrettoCandidate) => void;
    checkedIds: Set<string>;
    onToggleCheck: (id: string) => void;
}

type SortKey = 'grade' | 'delay' | 'interval' | 'dissonance';

export default function StrettoList({ 
    candidates, processedResults, gradeFilter, setGradeFilter, 
    selectedId, onSelect, checkedIds, onToggleCheck 
}: StrettoListProps) {
    const [sortKey, setSortKey] = useState<SortKey>('grade');
    const [sortDir, setSortDir] = useState<'asc' | 'desc'>('desc');
    const [entryPitchFilter, setEntryPitchFilter] = useState<string>('All');

    // Unique Entry Pitches for the filter dropdown
    const availablePitches = useMemo(() => {
        const pitches = new Set<string>();
        candidates.forEach(c => {
            const firstAnswerNote = c.notes.find(n => n.voiceIndex === 1);
            if (firstAnswerNote) {
                // Get note name without octave for filtering (e.g. C, G)
                pitches.add(getStrictPitchName(firstAnswerNote.midi).replace(/\d/g, ''));
            }
        });
        return ['All', ...Array.from(pitches).sort()];
    }, [candidates]);

    const filteredResults = useMemo(() => {
        return processedResults.filter(r => {
            if (entryPitchFilter === 'All') return true;
            const firstAnswerNote = r.notes.find(n => n.voiceIndex === 1);
            if (!firstAnswerNote) return false;
            const pName = getStrictPitchName(firstAnswerNote.midi).replace(/\d/g, '');
            return pName === entryPitchFilter;
        });
    }, [processedResults, entryPitchFilter]);

    const sortedResults = useMemo(() => {
        const res = [...filteredResults];
        res.sort((a, b) => {
            let diff = 0;
            if (sortKey === 'grade') {
                const score = { 'STRONG': 3, 'VIABLE': 2, 'INVALID': 1 };
                diff = score[a.grade] - score[b.grade];
            } else if (sortKey === 'delay') {
                diff = a.delayTicks - b.delayTicks;
            } else if (sortKey === 'interval') {
                diff = Math.abs(a.intervalSemis) - Math.abs(b.intervalSemis);
            } else if (sortKey === 'dissonance') {
                diff = a.dissonanceRatio - b.dissonanceRatio;
            }
            return sortDir === 'asc' ? diff : -diff;
        });
        return res;
    }, [filteredResults, sortKey, sortDir]);

    const handleSort = (key: SortKey) => {
        if (sortKey === key) setSortDir(prev => prev === 'asc' ? 'desc' : 'asc');
        else { setSortKey(key); setSortDir(key === 'grade' || key === 'dissonance' ? 'desc' : 'asc'); }
    };

    return (
        <div className="bg-gray-900 border border-gray-700 rounded h-[600px] flex flex-col shadow-inner relative">
            <div className="p-3 border-b border-gray-700 bg-gray-800 flex flex-col gap-3">
                <div className="flex flex-col gap-2">
                    <div className="flex justify-between items-center">
                        <span className="text-[10px] font-bold text-gray-500 uppercase tracking-widest">Verdict Visibility:</span>
                        <div className="flex gap-1">
                            <button onClick={() => setGradeFilter({ ...gradeFilter, STRONG: !gradeFilter.STRONG })} className={`px-2 py-0.5 text-[9px] rounded font-bold border transition-all ${gradeFilter.STRONG ? 'bg-green-900 border-green-500 text-green-300' : 'bg-gray-900 border-gray-700 text-gray-600'}`}>Strong</button>
                            <button onClick={() => setGradeFilter({ ...gradeFilter, VIABLE: !gradeFilter.VIABLE })} className={`px-2 py-0.5 text-[9px] rounded font-bold border transition-all ${gradeFilter.VIABLE ? 'bg-yellow-900 border-yellow-500 text-yellow-300' : 'bg-gray-900 border-gray-700 text-gray-600'}`}>Viable</button>
                            <button onClick={() => setGradeFilter({ ...gradeFilter, INVALID: !gradeFilter.INVALID })} className={`px-2 py-0.5 text-[9px] rounded font-bold border transition-all ${gradeFilter.INVALID ? 'bg-red-900 border-red-500 text-red-300' : 'bg-gray-900 border-gray-700 text-gray-600'}`}>Invalid</button>
                        </div>
                    </div>

                    <div className="flex justify-between items-center pt-2 border-t border-gray-700">
                        <span className="text-[10px] font-bold text-gray-500 uppercase tracking-widest">Filter by Entry:</span>
                        <select 
                            value={entryPitchFilter}
                            onChange={(e) => setEntryPitchFilter(e.target.value)}
                            className="bg-gray-900 border border-gray-600 text-[10px] rounded px-2 py-0.5 text-brand-primary font-bold outline-none"
                        >
                            {availablePitches.map(p => <option key={p} value={p}>{p === 'All' ? 'All Notes' : `Starts on ${p}`}</option>)}
                        </select>
                    </div>
                </div>

                <div className="flex gap-1 bg-gray-900 p-1 rounded border border-gray-700">
                    {(['grade', 'delay', 'interval', 'dissonance'] as SortKey[]).map(key => (
                        <button key={key} onClick={() => handleSort(key)} className={`flex-1 text-[9px] py-1 rounded transition-colors ${sortKey === key ? 'bg-gray-700 text-white font-bold' : 'text-gray-500 hover:text-gray-300'}`}>
                            {key.toUpperCase()} {sortKey === key && (sortDir === 'asc' ? '↑' : '↓')}
                        </button>
                    ))}
                </div>
            </div>

            <div className="overflow-y-auto flex-grow p-2">
                <div className="grid grid-cols-12 gap-2 px-2 py-1 text-[9px] font-bold text-gray-500 uppercase border-b border-gray-800">
                    <div className="col-span-1"></div>
                    <div className="col-span-2">Int</div>
                    <div className="col-span-2">Delay</div>
                    <div className="col-span-2">Entry</div>
                    <div className="col-span-2">Diss %</div>
                    <div className="col-span-1">End</div>
                    <div className="col-span-2 text-right">Err</div>
                </div>

                {sortedResults.length === 0 ? (
                    <div className="py-20 text-center text-gray-600 text-sm italic">No matching strettos.</div>
                ) : (
                    sortedResults.map((r) => {
                        const firstAnswerNote = r.notes.find(n => n.voiceIndex === 1);
                        const entryNote = firstAnswerNote ? getStrictPitchName(firstAnswerNote.midi) : '?';
                        return (
                            <div key={r.id} onClick={() => onSelect(r)} className={`grid grid-cols-12 gap-2 p-2 rounded cursor-pointer border-b border-gray-800 hover:bg-gray-800 items-center transition-colors ${selectedId === r.id ? 'bg-gray-800 border-l-4 border-l-brand-primary' : ''}`}>
                                <div className="col-span-1 flex justify-center" onClick={(e) => e.stopPropagation()}>
                                    <input type="checkbox" checked={checkedIds.has(r.id)} onChange={() => onToggleCheck(r.id)} className="rounded bg-gray-700 border-gray-600 text-brand-primary w-3 h-3" />
                                </div>
                                <span className="col-span-2 font-bold text-brand-primary text-[10px] truncate">{r.intervalLabel}</span>
                                <span className="col-span-2 text-gray-300 text-[10px]">{r.delayBeats}B</span>
                                <span className="col-span-2 text-gray-500 text-[10px] font-mono">{entryNote}</span>
                                <span className={`col-span-2 text-[10px] font-mono font-bold ${r.dissonanceRatio > 0.5 ? 'text-red-400' : r.dissonanceRatio > 0.3 ? 'text-yellow-400' : 'text-green-400'}`}>{Math.round(r.dissonanceRatio * 100)}%</span>
                                <div className="col-span-1 flex justify-center">{r.endsOnDissonance ? <span className="text-red-500 font-bold text-[10px]">!</span> : <span className="text-green-500 font-bold text-[10px]">✓</span>}</div>
                                <span className="col-span-2 text-[9px] text-gray-500 text-right">{r.errors.length > 0 ? r.errors.length : '-'}</span>
                            </div>
                        );
                    })
                )}
            </div>
        </div>
    );
}

import { RawNote, StrettoCandidate, StrettoError, StrettoGrade, HarmonicRegion } from '../../types';
import { getFormattedTime } from './midiHarmony';
import { getStrictPitchName, getIntervalLabel } from './midiSpelling';

// Strict counterpoint intervals
const DISSONANT_INTERVALS = [1, 2, 6, 10, 11]; // m2, M2, TT, m7, M7
const PERFECT_CONSONANCES = [0, 7]; // P1, P5 (P8 is 0 mod 12)

export interface VoiceEvent {
    tick: number;
    endTick: number; 
    pitch1: number; // Subject
    pitch2: number; // Answer (Transposed Subject)
    hasAttack1: boolean;
    hasAttack2: boolean;
}

export function getVerticalIntervals(subject: RawNote[], answer: RawNote[]): VoiceEvent[] {
    const timePoints = new Set<number>();
    [...subject, ...answer].forEach(n => {
        if (!n) return;
        timePoints.add(n.ticks);
        timePoints.add(n.ticks + n.durationTicks);
    });

    const sortedPoints = Array.from(timePoints).sort((a,b) => a-b);
    const events: VoiceEvent[] = [];
    const endOfMusic = Math.max(0, ...[...subject, ...answer].map(n => n ? n.ticks + n.durationTicks : 0));

    for (let i = 0; i < sortedPoints.length - 1; i++) {
        const t = sortedPoints[i];
        if (t >= endOfMusic) break;

        const checkTime = t; 
        const n1 = subject.find(n => n && n.ticks <= checkTime && (n.ticks + n.durationTicks) > checkTime);
        const n2 = answer.find(n => n && n.ticks <= checkTime && (n.ticks + n.durationTicks) > checkTime);

        if (n1 && n2) {
            events.push({
                tick: t,
                endTick: sortedPoints[i+1],
                pitch1: n1.midi,
                pitch2: n2.midi,
                hasAttack1: n1.ticks === t,
                hasAttack2: n2.ticks === t
            });
        }
    }
    return events;
}

function isStrongBeat(tick: number, ppq: number, tsNum: number, tsDenom: number): boolean {
    const ticksPerMeasure = ppq * tsNum * (4 / tsDenom);
    const pos = tick % ticksPerMeasure;
    if (pos === 0) return true; 
    if (tsNum === 4 && tsDenom === 4 && pos === (ticksPerMeasure / 2)) return true;
    return false; 
}

export function generateHarmonicRegions(events: VoiceEvent[]): HarmonicRegion[] {
    const regions: HarmonicRegion[] = [];
    let previousState: 'consonance' | 'dissonance' = 'consonance';
    let prevP1: number | null = null;
    let prevP2: number | null = null;

    for (let i = 0; i < events.length; i++) {
        const ev = events[i];
        const duration = ev.endTick - ev.tick;
        if (duration <= 0) continue;

        const p1 = ev.pitch1;
        const p2 = ev.pitch2;
        const interval = Math.abs(p1 - p2);
        const intervalClass = interval % 12;
        const isBass1 = p1 < p2;
        const upperPitch = isBass1 ? p2 : p1;
        const prevUpperPitch = isBass1 ? (prevP2) : (prevP1);

        const isP4 = intervalClass === 5; 
        const isDiss = DISSONANT_INTERVALS.includes(intervalClass) || isP4;
        let regionType: HarmonicRegion['type'];

        if (isDiss) {
            regionType = (previousState === 'consonance') ? 'dissonance_1' : 'dissonance_consecutive';
            previousState = 'dissonance';
        } else {
            regionType = (PERFECT_CONSONANCES.includes(intervalClass)) ? 'perfect_consonance' : 'imperfect_consonance';
            previousState = 'consonance';
        }

        let errorType: HarmonicRegion['errorType'] = null;
        if (prevP1 !== null && prevP2 !== null) {
            const p1Moved = prevP1 !== p1;
            const p2Moved = prevP2 !== p2;
            if (p1Moved && p2Moved) {
                const isParallelMotion = (p1 - prevP1) * (p2 - prevP2) > 0;
                const isPerfect = intervalClass === 0 || intervalClass === 7;
                if (isPerfect && isParallelMotion) {
                    const prevInterval = Math.abs(prevP1 - prevP2);
                    if (prevInterval % 12 === intervalClass) errorType = 'parallel';
                }
                if (!errorType && isPerfect && isParallelMotion && prevUpperPitch !== null) {
                    if (Math.abs(upperPitch - prevUpperPitch) > 2) errorType = 'direct';
                }
            }
        }

        regions.push({
            startTick: ev.tick,
            endTick: ev.endTick, 
            type: regionType,
            errorType: errorType,
            intervalLabel: getIntervalLabel(interval),
            description: `${getIntervalLabel(interval)}: ${getStrictPitchName(p1)}, ${getStrictPitchName(p2)}`
        });
        prevP1 = p1; prevP2 = p2;
    }
    return regions;
}

export function analyzeStrettoCandidate(
    subject: RawNote[], 
    intervalSemis: number, 
    delayTicks: number, 
    ppq: number,
    ts: { num: number, den: number },
    isInverted: boolean = false,
    pivotMidi: number = 60 // No longer used for fixed entry logic
): StrettoCandidate {

    // REQUIREMENT: "The filter must always be around the same note and transposed up or down by the full interval"
    // This implies anchoring the answer's entry pitch to (SubjectEntry + Transposition)
    if (subject.length === 0) throw new Error("Subject is empty.");

    const subjectEntryPitch = subject[0].midi;
    const targetEntryPitch = subjectEntryPitch + intervalSemis;

    const answer: RawNote[] = subject.map(n => {
        if (!n) return null as any;
        let newMidi: number;

        if (isInverted) {
            // Mirror around the subject entry pitch, then transpose to target
            // Pitch(n) -> Entry - (Pitch(n) - Entry) -> 2*Entry - Pitch(n)
            // Then move to target: (2*Entry - Pitch(n)) + (Target - Entry) = Entry + Target - Pitch(n)
            newMidi = subjectEntryPitch + targetEntryPitch - n.midi;
        } else {
            // Standard transposition
            newMidi = n.midi + intervalSemis;
        }

        return {
            ...n,
            ticks: n.ticks + delayTicks,
            midi: newMidi,
            name: getStrictPitchName(newMidi),
            voiceIndex: 1
        };
    }).filter(n => !!n);

    const startOverlap = delayTicks; 
    const subjectEnd = Math.max(0, ...subject.map(n => n ? n.ticks + n.durationTicks : 0));
    const endOverlap = subjectEnd;

    if (startOverlap >= endOverlap) {
        return {
            id: `invalid_gap`,
            intervalSemis, intervalLabel: 'N/A', delayBeats: 0, delayTicks,
            grade: 'INVALID', errors: [], notes: [], dissonanceRatio: 0, endsOnDissonance: true
        };
    }

    const events = getVerticalIntervals(subject, answer).filter(e => e.tick >= startOverlap);
    const harmonicRegions = generateHarmonicRegions(events);

    let totalOverlapTicks = 0;
    let dissonantTicks = 0;
    let endsOnDissonance = false;

    harmonicRegions.forEach((r, idx) => {
        const dur = r.endTick - r.startTick;
        totalOverlapTicks += dur;
        if (r.type === 'dissonance_1' || r.type === 'dissonance_consecutive') {
            dissonantTicks += dur;
            if (idx === harmonicRegions.length - 1) endsOnDissonance = true;
        }
    });

    const dissonanceRatio = totalOverlapTicks > 0 ? (dissonantTicks / totalOverlapTicks) : 0;
    const errors: StrettoError[] = [];

    harmonicRegions.forEach(r => {
        const timeStr = getFormattedTime(r.startTick, ppq, ts.num, ts.den);
        const onStrong = isStrongBeat(r.startTick, ppq, ts.num, ts.den);
        if (r.errorType === 'parallel') {
            errors.push({
                tick: r.startTick, timeFormatted: timeStr,
                type: r.intervalLabel.includes('P5') ? 'Parallel 5th' : 'Parallel 8ve',
                details: `Parallel motion into ${r.intervalLabel}`,
                severity: onStrong ? 'fatal' : 'warning'
            });
        }
        if (r.errorType === 'direct') {
             errors.push({
                tick: r.startTick, timeFormatted: timeStr,
                type: r.intervalLabel.includes('P5') ? 'Direct 5th' : 'Direct 8ve',
                details: `Direct motion into ${r.intervalLabel} (Upper leap)`,
                severity: 'warning'
            });
        }
        if (r.type === 'dissonance_consecutive' && onStrong) {
             const isP4Run = r.intervalLabel.includes('P4');
             errors.push({
                 tick: r.startTick, timeFormatted: timeStr,
                 type: 'Consecutive Dissonance',
                 details: 'Consecutive dissonance',
                 severity: isP4Run ? 'warning' : 'fatal'
             });
        }
    });

    let grade: StrettoGrade = 'STRONG';
    if (errors.some(e => e.severity === 'fatal')) grade = 'INVALID';
    else if (errors.length > 0) grade = 'VIABLE';

    let intLabel = getIntervalLabel(intervalSemis);
    if (intervalSemis < 0 && !intLabel.startsWith('-')) intLabel = '-' + intLabel;
    else if (intervalSemis > 0 && !intLabel.startsWith('+')) intLabel = '+' + intLabel;
    if (isInverted) intLabel += " (Inv)";

    const delayBeats = delayTicks / (ppq * (4 / ts.den));

    return {
        id: `${intLabel}@${delayBeats.toFixed(1)}${isInverted?'i':''}`,
        intervalSemis,
        intervalLabel: intLabel,
        delayBeats: parseFloat(delayBeats.toFixed(2)),
        delayTicks,
        grade,
        errors,
        notes: [...subject, ...answer],
        regions: harmonicRegions,
        dissonanceRatio,
        endsOnDissonance
    };
}

import React, { useState, useMemo } from 'react';
import { StrettoCandidate, StrettoGrade } from '../../types';
import { getStrictPitchName } from '../services/midiSpelling';

interface StrettoListProps {
    candidates: StrettoCandidate[];
    processedResults: StrettoCandidate[];
    gradeFilter: Record<StrettoGrade, boolean>;
    setGradeFilter: (val: Record<StrettoGrade, boolean>) => void;
    selectedId: string | null;
    onSelect: (candidate: StrettoCandidate) => void;
    checkedIds: Set<string>;
    onToggleCheck: (id: string) => void;
}

type SortKey = 'grade' | 'delay' | 'interval' | 'dissonance';

export default function StrettoList({ 
    candidates, processedResults, gradeFilter, setGradeFilter, 
    selectedId, onSelect, checkedIds, onToggleCheck 
}: StrettoListProps) {
    const [sortKey, setSortKey] = useState<SortKey>('grade');
    const [sortDir, setSortDir] = useState<'asc' | 'desc'>('desc');

    // Column Filters
    const [entryPitchFilter, setEntryPitchFilter] = useState<string>('All');
    const [intervalFilter, setIntervalFilter] = useState<string>('All');
    const [delayFilter, setDelayFilter] = useState<string>('All');

    // Extract unique values for filter dropdowns
    const { availablePitches, availableIntervals, availableDelays } = useMemo(() => {
        const pitches = new Set<string>();
        const intervals = new Set<string>();
        const delays = new Set<string>();

        candidates.forEach(c => {
            const firstAnswerNote = c.notes.find(n => n.voiceIndex === 1);
            if (firstAnswerNote) {
                pitches.add(getStrictPitchName(firstAnswerNote.midi).replace(/\d/g, ''));
            }
            intervals.add(c.intervalLabel);
            delays.add(c.delayBeats.toString());
        });

        return {
            availablePitches: ['All', ...Array.from(pitches).sort()],
            availableIntervals: ['All', ...Array.from(intervals).sort((a,b) => a.localeCompare(b, undefined, {numeric: true}))],
            availableDelays: ['All', ...Array.from(delays).sort((a,b) => parseFloat(a) - parseFloat(b))]
        };
    }, [candidates]);

    // Apply combined filters
    const filteredResults = useMemo(() => {
        return processedResults.filter(r => {
            // 1. Entry Note
            if (entryPitchFilter !== 'All') {
                const firstAnswerNote = r.notes.find(n => n.voiceIndex === 1);
                if (!firstAnswerNote) return false;
                const pName = getStrictPitchName(firstAnswerNote.midi).replace(/\d/g, '');
                if (pName !== entryPitchFilter) return false;
            }

            // 2. Interval
            if (intervalFilter !== 'All' && r.intervalLabel !== intervalFilter) return false;

            // 3. Delay
            if (delayFilter !== 'All' && r.delayBeats.toString() !== delayFilter) return false;

            return true;
        });
    }, [processedResults, entryPitchFilter, intervalFilter, delayFilter]);

    // Sort the final filtered set
    const sortedResults = useMemo(() => {
        const res = [...filteredResults];
        res.sort((a, b) => {
            let diff = 0;
            if (sortKey === 'grade') {
                const score = { 'STRONG': 3, 'VIABLE': 2, 'INVALID': 1 };
                diff = score[a.grade] - score[b.grade];
            } else if (sortKey === 'delay') {
                diff = a.delayTicks - b.delayTicks;
            } else if (sortKey === 'interval') {
                diff = Math.abs(a.intervalSemis) - Math.abs(b.intervalSemis);
            } else if (sortKey === 'dissonance') {
                diff = a.dissonanceRatio - b.dissonanceRatio;
            }
            return sortDir === 'asc' ? diff : -diff;
        });
        return res;
    }, [filteredResults, sortKey, sortDir]);

    const handleSort = (key: SortKey) => {
        if (sortKey === key) setSortDir(prev => prev === 'asc' ? 'desc' : 'asc');
        else { setSortKey(key); setSortDir(key === 'grade' || key === 'dissonance' ? 'desc' : 'asc'); }
    };

    return (
        <div className="bg-gray-900 border border-gray-700 rounded h-[600px] flex flex-col shadow-inner relative">
            <div className="p-3 border-b border-gray-700 bg-gray-800 flex flex-col gap-3">

                {/* Unified Filters Row */}
                <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
                    <div className="flex flex-col gap-1">
                        <label className="text-[9px] font-bold text-gray-500 uppercase tracking-widest">Grade</label>
                        <div className="flex gap-0.5">
                            <button onClick={() => setGradeFilter({ ...gradeFilter, STRONG: !gradeFilter.STRONG })} className={`flex-1 py-1 text-[9px] rounded font-bold border transition-all ${gradeFilter.STRONG ? 'bg-green-900 border-green-500 text-green-300' : 'bg-gray-900 border-gray-700 text-gray-600'}`}>S</button>
                            <button onClick={() => setGradeFilter({ ...gradeFilter, VIABLE: !gradeFilter.VIABLE })} className={`flex-1 py-1 text-[9px] rounded font-bold border transition-all ${gradeFilter.VIABLE ? 'bg-yellow-900 border-yellow-500 text-yellow-300' : 'bg-gray-900 border-gray-700 text-gray-600'}`}>V</button>
                            <button onClick={() => setGradeFilter({ ...gradeFilter, INVALID: !gradeFilter.INVALID })} className={`flex-1 py-1 text-[9px] rounded font-bold border transition-all ${gradeFilter.INVALID ? 'bg-red-900 border-red-500 text-red-300' : 'bg-gray-900 border-gray-700 text-gray-600'}`}>I</button>
                        </div>
                    </div>

                    <div className="flex flex-col gap-1">
                        <label className="text-[9px] font-bold text-gray-500 uppercase tracking-widest">Interval</label>
                        <select 
                            value={intervalFilter}
                            onChange={(e) => setIntervalFilter(e.target.value)}
                            className="bg-gray-900 border border-gray-700 text-[10px] rounded px-1.5 py-1 text-brand-primary outline-none"
                        >
                            {availableIntervals.map(i => <option key={i} value={i}>{i}</option>)}
                        </select>
                    </div>

                    <div className="flex flex-col gap-1">
                        <label className="text-[9px] font-bold text-gray-500 uppercase tracking-widest">Delay</label>
                        <select 
                            value={delayFilter}
                            onChange={(e) => setDelayFilter(e.target.value)}
                            className="bg-gray-900 border border-gray-700 text-[10px] rounded px-1.5 py-1 text-gray-300 outline-none"
                        >
                            {availableDelays.map(d => <option key={d} value={d}>{d === 'All' ? 'All' : `${d}B`}</option>)}
                        </select>
                    </div>

                    <div className="flex flex-col gap-1">
                        <label className="text-[9px] font-bold text-gray-500 uppercase tracking-widest">Entry Pitch</label>
                        <select 
                            value={entryPitchFilter}
                            onChange={(e) => setEntryPitchFilter(e.target.value)}
                            className="bg-gray-900 border border-gray-700 text-[10px] rounded px-1.5 py-1 text-gray-300 outline-none"
                        >
                            {availablePitches.map(p => <option key={p} value={p}>{p}</option>)}
                        </select>
                    </div>
                </div>

                {/* Sorting Controls */}
                <div className="flex gap-1 bg-gray-900 p-1 rounded border border-gray-700 mt-1">
                    {(['grade', 'delay', 'interval', 'dissonance'] as SortKey[]).map(key => (
                        <button key={key} onClick={() => handleSort(key)} className={`flex-1 text-[9px] py-1 rounded transition-colors ${sortKey === key ? 'bg-gray-700 text-white font-bold' : 'text-gray-500 hover:text-gray-300'}`}>
                            {key.toUpperCase()} {sortKey === key && (sortDir === 'asc' ? '↑' : '↓')}
                        </button>
                    ))}
                </div>
            </div>

            <div className="overflow-y-auto flex-grow p-2">
                <div className="grid grid-cols-12 gap-2 px-2 py-1 text-[9px] font-bold text-gray-500 uppercase border-b border-gray-800">
                    <div className="col-span-1"></div>
                    <div className="col-span-2">Int</div>
                    <div className="col-span-2">Delay</div>
                    <div className="col-span-2">Entry</div>
                    <div className="col-span-2">Diss %</div>
                    <div className="col-span-1">End</div>
                    <div className="col-span-2 text-right">Err</div>
                </div>

                {sortedResults.length === 0 ? (
                    <div className="py-20 text-center text-gray-600 text-sm italic">No matching strettos.</div>
                ) : (
                    sortedResults.map((r) => {
                        const firstAnswerNote = r.notes.find(n => n.voiceIndex === 1);
                        const entryNote = firstAnswerNote ? getStrictPitchName(firstAnswerNote.midi) : '?';
                        return (
                            <div key={r.id} onClick={() => onSelect(r)} className={`grid grid-cols-12 gap-2 p-2 rounded cursor-pointer border-b border-gray-800 hover:bg-gray-800 items-center transition-colors ${selectedId === r.id ? 'bg-gray-800 border-l-4 border-l-brand-primary' : ''}`}>
                                <div className="col-span-1 flex justify-center" onClick={(e) => e.stopPropagation()}>
                                    <input type="checkbox" checked={checkedIds.has(r.id)} onChange={() => onToggleCheck(r.id)} className="rounded bg-gray-700 border-gray-600 text-brand-primary w-3 h-3" />
                                </div>
                                <span className="col-span-2 font-bold text-brand-primary text-[10px] truncate">{r.intervalLabel}</span>
                                <span className="col-span-2 text-gray-300 text-[10px]">{r.delayBeats}B</span>
                                <span className="col-span-2 text-gray-500 text-[10px] font-mono">{entryNote}</span>
                                <span className={`col-span-2 text-[10px] font-mono font-bold ${r.dissonanceRatio > 0.5 ? 'text-red-400' : r.dissonanceRatio > 0.3 ? 'text-yellow-400' : 'text-green-400'}`}>{Math.round(r.dissonanceRatio * 100)}%</span>
                                <div className="col-span-1 flex justify-center">{r.endsOnDissonance ? <span className="text-red-500 font-bold text-[10px]">!</span> : <span className="text-green-500 font-bold text-[10px]">✓</span>}</div>
                                <span className="col-span-2 text-[9px] text-gray-500 text-right">{r.errors.length > 0 ? r.errors.length : '-'}</span>
                            </div>
                        );
                    })
                )}
            </div>

            <div className="p-2 border-t border-gray-800 bg-gray-800/50 flex justify-between items-center px-4">
                <span className="text-[10px] text-gray-500 italic">{sortedResults.length} Visible</span>
                <button 
                    onClick={() => { setIntervalFilter('All'); setDelayFilter('All'); setEntryPitchFilter('All'); setGradeFilter({STRONG: true, VIABLE: true, INVALID: true}) }}
                    className="text-[9px] text-brand-primary hover:text-white uppercase font-bold"
                >
                    Reset Filters
                </button>
            </div>
        </div>
    );
}

import * as Tone from 'tone';
import { Midi } from '@tonejs/midi';

let instrument: Tone.Sampler | Tone.PolySynth | null = null;
let currentPart: Tone.Part | null = null;

const PIANO_SAMPLES = {
    'A0': 'A0.mp3', 'C1': 'C1.mp3', 'D#1': 'Ds1.mp3', 'F#1': 'Fs1.mp3', 'A1': 'A1.mp3',
    'C2': 'C2.mp3', 'D#2': 'Ds2.mp3', 'F#2': 'Fs2.mp3', 'A2': 'A2.mp3',
    'C3': 'C3.mp3', 'D#3': 'Ds3.mp3', 'F#3': 'Fs3.mp3', 'A3': 'A3.mp3',
    'C4': 'C4.mp3', 'D#4': 'Ds4.mp3', 'F#4': 'Fs4.mp3', 'A4': 'A4.mp3',
    'C5': 'C5.mp3', 'D#5': 'Ds5.mp3', 'F#5': 'Fs5.mp3', 'A5': 'A5.mp3',
    'C6': 'C6.mp3', 'D#6': 'Ds6.mp3', 'F#6': 'Fs6.mp3', 'A6': 'A6.mp3',
    'C7': 'C7.mp3', 'D#7': 'Ds7.mp3', 'F#7': 'Fs7.mp3', 'A7': 'A7.mp3',
    'C8': 'C8.mp3'
};
const SAMPLE_BASE_URL = "https://tonejs.github.io/audio/salamander/";

async function initializeInstrument(): Promise<Tone.Sampler | Tone.PolySynth> {
  if (instrument) return instrument;

  return new Promise((resolve) => {
      const sampler = new Tone.Sampler({
          urls: PIANO_SAMPLES,
          baseUrl: SAMPLE_BASE_URL,
          onload: () => {
              sampler.toDestination();
              instrument = sampler;
              resolve(sampler);
          },
          onerror: () => {
              createFallbackSynth();
              resolve(instrument!);
          }
      });

      setTimeout(() => {
          if (!sampler.loaded) {
              createFallbackSynth();
              resolve(instrument!);
          }
      }, 3000);
  });
}

function createFallbackSynth() {
    if (instrument instanceof Tone.PolySynth) return;
    instrument = new Tone.PolySynth(Tone.Synth, {
        oscillator: { type: "triangle" },
        envelope: { attack: 0.005, decay: 0.3, sustain: 0.4, release: 1.2 },
        volume: -6
    }).toDestination();
}

export async function playTrack(processedMidi: Midi, onEnded: () => void): Promise<void> {
  stopPlayback();
  if (processedMidi.tracks.length === 0) { onEnded(); return; }
  const track = processedMidi.tracks[0];
  if (!track.notes || track.notes.length === 0) { onEnded(); return; }

  const inst = await initializeInstrument();
  await Tone.start();

  Tone.Transport.stop();
  Tone.Transport.position = 0;
  Tone.Transport.bpm.value = processedMidi.header.tempos[0]?.bpm || 120;

  currentPart = new Tone.Part(
    (time, note) => {
      // Use MIDI number for stability instead of names that might contain ABC characters
      if (note.midi !== undefined && !isNaN(note.midi)) {
          const pitch = Tone.Frequency(note.midi, "midi").toNote();
          inst.triggerAttackRelease(pitch, note.duration, time, note.velocity);
      }
    },
    track.notes.map(note => ({
      time: note.time,
      midi: note.midi,
      duration: note.duration,
      velocity: note.velocity,
    }))
  );

  currentPart.loop = false;
  Tone.Transport.on('stop', () => {
    currentPart?.dispose();
    currentPart = null;
    onEnded();
  });

  currentPart.start(0);
  Tone.Transport.start();
  const lastNote = track.notes[track.notes.length - 1];
  const endTime = lastNote.time + lastNote.duration + 1;
  Tone.Transport.scheduleOnce(() => { Tone.Transport.stop(); }, endTime);
}

export async function playSequence(notes: { midi?: number, name?: string, time: number, duration: number, velocity: number }[], onEnded?: () => void) {
    stopPlayback();
    const inst = await initializeInstrument();
    await Tone.start();
    const now = Tone.now();
    let maxTime = 0;

    notes.forEach(n => {
        // ALWAYS prefer MIDI number to avoid ABC comma/apostrophe name errors
        let pitch: string | null = null;
        if (n.midi !== undefined && !isNaN(n.midi)) {
            pitch = Tone.Frequency(n.midi, "midi").toNote();
        }

        if (pitch && !pitch.includes('undefined')) {
            try {
                inst.triggerAttackRelease(pitch, n.duration, now + n.time, n.velocity);
                if ((n.time + n.duration) > maxTime) maxTime = n.time + n.duration;
            } catch (e) { console.warn(`Playback error for pitch: ${pitch}`, e); }
        }
    });

    if (onEnded) { setTimeout(onEnded, maxTime * 1000 + 500); }
}

export async function playSpecificNotes(notes: { midi?: number, name?: string, duration: number, velocity: number }[]) {
    const inst = await initializeInstrument();
    await Tone.start();
    const now = Tone.now();
    notes.forEach(n => {
        let pitch: string | null = null;
        if (n.midi !== undefined && !isNaN(n.midi)) {
            pitch = Tone.Frequency(n.midi, "midi").toNote();
        }

        if (pitch && !pitch.includes('undefined')) {
            try { inst.triggerAttackRelease(pitch, n.duration, now, n.velocity); } catch (e) { }
        }
    });
}

export function stopPlayback(): void {
  if (Tone.Transport.state === 'started') {
    Tone.Transport.stop();
    Tone.Transport.cancel(); 
  }
  if (currentPart) {
    currentPart.dispose();
    currentPart = null;
  }
  if (instrument) { instrument.releaseAll(); }
}

import { RawNote, StrettoCandidate, StrettoError, StrettoGrade, HarmonicRegion } from '../../types';
import { getFormattedTime } from './midiHarmony';
import { getStrictPitchName, getIntervalLabel } from './midiSpelling';

const DISSONANT_INTERVALS = [1, 2, 6, 10, 11]; // m2, M2, TT, m7, M7
const PERFECT_CONSONANCES = [0, 7]; // P1, P5

export interface VoiceEvent {
    tick: number;
    endTick: number; 
    pitch1: number;
    pitch2: number;
    hasAttack1: boolean;
    hasAttack2: boolean;
}

export function getVerticalIntervals(subject: RawNote[], answer: RawNote[]): VoiceEvent[] {
    const timePoints = new Set<number>();
    [...subject, ...answer].forEach(n => {
        if (!n) return;
        timePoints.add(n.ticks);
        timePoints.add(n.ticks + n.durationTicks);
    });

    const sortedPoints = Array.from(timePoints).sort((a,b) => a-b);
    const events: VoiceEvent[] = [];
    const endOfMusic = Math.max(0, ...[...subject, ...answer].map(n => n ? n.ticks + n.durationTicks : 0));

    for (let i = 0; i < sortedPoints.length - 1; i++) {
        const t = sortedPoints[i];
        if (t >= endOfMusic) break;

        const checkTime = t; 
        const n1 = subject.find(n => n && n.ticks <= checkTime && (n.ticks + n.durationTicks) > checkTime);
        const n2 = answer.find(n => n && n.ticks <= checkTime && (n.ticks + n.durationTicks) > checkTime);

        if (n1 && n2) {
            events.push({
                tick: t,
                endTick: sortedPoints[i+1],
                pitch1: n1.midi,
                pitch2: n2.midi,
                hasAttack1: n1.ticks === t,
                hasAttack2: n2.ticks === t
            });
        }
    }
    return events;
}

function isStrongBeat(tick: number, ppq: number, tsNum: number, tsDenom: number): boolean {
    const ticksPerMeasure = ppq * tsNum * (4 / tsDenom);
    const pos = tick % ticksPerMeasure;
    if (pos === 0) return true; 
    if (tsNum === 4 && tsDenom === 4 && pos === (ticksPerMeasure / 2)) return true;
    return false; 
}

export function generateHarmonicRegions(events: VoiceEvent[]): HarmonicRegion[] {
    const regions: HarmonicRegion[] = [];
    let previousState: 'consonance' | 'dissonance' = 'consonance';
    let prevP1: number | null = null;
    let prevP2: number | null = null;

    for (let i = 0; i < events.length; i++) {
        const ev = events[i];
        const duration = ev.endTick - ev.tick;
        if (duration <= 0) continue;

        const p1 = ev.pitch1;
        const p2 = ev.pitch2;
        const interval = Math.abs(p1 - p2);
        const intervalClass = interval % 12;
        const isBass1 = p1 < p2;
        const upperPitch = isBass1 ? p2 : p1;
        const prevUpperPitch = isBass1 ? (prevP2) : (prevP1);

        const isP4 = intervalClass === 5; 
        const isDiss = DISSONANT_INTERVALS.includes(intervalClass) || isP4;
        let regionType: HarmonicRegion['type'];

        if (isDiss) {
            regionType = (previousState === 'consonance') ? 'dissonance_1' : 'dissonance_consecutive';
            previousState = 'dissonance';
        } else {
            regionType = (PERFECT_CONSONANCES.includes(intervalClass)) ? 'perfect_consonance' : 'imperfect_consonance';
            previousState = 'consonance';
        }

        let errorType: HarmonicRegion['errorType'] = null;
        if (prevP1 !== null && prevP2 !== null) {
            const p1Moved = prevP1 !== p1;
            const p2Moved = prevP2 !== p2;
            if (p1Moved && p2Moved) {
                const isParallelMotion = (p1 - prevP1) * (p2 - prevP2) > 0;
                const isPerfect = intervalClass === 0 || intervalClass === 7;
                if (isPerfect && isParallelMotion) {
                    const prevInterval = Math.abs(prevP1 - prevP2);
                    if (prevInterval % 12 === intervalClass) errorType = 'parallel';
                }
                if (!errorType && isPerfect && isParallelMotion && prevUpperPitch !== null) {
                    if (Math.abs(upperPitch - prevUpperPitch) > 2) errorType = 'direct';
                }
            }
        }

        regions.push({
            startTick: ev.tick,
            endTick: ev.endTick, 
            type: regionType,
            errorType: errorType,
            intervalLabel: getIntervalLabel(interval),
            description: `${getIntervalLabel(interval)}: ${getStrictPitchName(p1)}, ${getStrictPitchName(p2)}`
        });
        prevP1 = p1; prevP2 = p2;
    }
    return regions;
}

export function analyzeStrettoCandidate(
    subject: RawNote[], 
    intervalSemis: number, 
    delayTicks: number, 
    ppq: number,
    ts: { num: number, den: number },
    isInverted: boolean = false,
    pivotMidi: number = 60
): StrettoCandidate {

    if (subject.length === 0) {
        return {
            id: `empty`, intervalSemis, intervalLabel: 'N/A', delayBeats: 0, delayTicks,
            grade: 'INVALID', errors: [], notes: [], dissonanceRatio: 0, endsOnDissonance: true
        };
    }

    const subjectEntryPitch = subject[0].midi;
    const targetEntryPitch = subjectEntryPitch + intervalSemis;

    const answer: RawNote[] = subject.map(n => {
        if (!n) return null as any;
        let newMidi: number;

        if (isInverted) {
            // "The filter must always be around the same note"
            // Mirror subject around its entry pitch, then transpose to the target entry pitch.
            // This anchors the inverted answer to enter on the EXACT same transposed note.
            newMidi = subjectEntryPitch + targetEntryPitch - n.midi;
        } else {
            newMidi = n.midi + intervalSemis;
        }

        return {
            ...n,
            ticks: n.ticks + delayTicks,
            midi: newMidi,
            name: getStrictPitchName(newMidi),
            voiceIndex: 1
        };
    }).filter(n => !!n);

    const startOverlap = delayTicks; 
    const subjectEnd = Math.max(0, ...subject.map(n => n ? n.ticks + n.durationTicks : 0));

    if (startOverlap >= subjectEnd) {
        return {
            id: `invalid_gap`,
            intervalSemis, intervalLabel: 'N/A', delayBeats: 0, delayTicks,
            grade: 'INVALID', errors: [], notes: [], dissonanceRatio: 0, endsOnDissonance: true
        };
    }

    const events = getVerticalIntervals(subject, answer).filter(e => e.tick >= startOverlap);
    const harmonicRegions = generateHarmonicRegions(events);

    let totalOverlapTicks = 0;
    let dissonantTicks = 0;
    let endsOnDissonance = false;

    harmonicRegions.forEach((r, idx) => {
        const dur = r.endTick - r.startTick;
        totalOverlapTicks += dur;
        if (r.type === 'dissonance_1' || r.type === 'dissonance_consecutive') {
            dissonantTicks += dur;
            if (idx === harmonicRegions.length - 1) endsOnDissonance = true;
        }
    });

    const dissonanceRatio = totalOverlapTicks > 0 ? (dissonantTicks / totalOverlapTicks) : 0;
    const errors: StrettoError[] = [];

    harmonicRegions.forEach(r => {
        const timeStr = getFormattedTime(r.startTick, ppq, ts.num, ts.den);
        const onStrong = isStrongBeat(r.startTick, ppq, ts.num, ts.den);
        if (r.errorType === 'parallel') {
            errors.push({
                tick: r.startTick, timeFormatted: timeStr,
                type: r.intervalLabel.includes('P5') ? 'Parallel 5th' : 'Parallel 8ve',
                details: `Parallel motion into ${r.intervalLabel}`,
                severity: onStrong ? 'fatal' : 'warning'
            });
        }
        if (r.errorType === 'direct') {
             errors.push({
                tick: r.startTick, timeFormatted: timeStr,
                type: r.intervalLabel.includes('P5') ? 'Direct 5th' : 'Direct 8ve',
                details: `Direct motion into ${r.intervalLabel} (Upper leap)`,
                severity: 'warning'
            });
        }
        if (r.type === 'dissonance_consecutive' && onStrong) {
             const isP4Run = r.intervalLabel.includes('P4');
             errors.push({
                 tick: r.startTick, timeFormatted: timeStr,
                 type: 'Consecutive Dissonance',
                 details: 'Consecutive dissonance',
                 severity: isP4Run ? 'warning' : 'fatal'
             });
        }
    });

    let grade: StrettoGrade = 'STRONG';
    if (errors.some(e => e.severity === 'fatal')) grade = 'INVALID';
    else if (errors.length > 0) grade = 'VIABLE';

    let intLabel = getIntervalLabel(intervalSemis);
    if (intervalSemis < 0 && !intLabel.startsWith('-')) intLabel = '-' + intLabel;
    else if (intervalSemis > 0 && !intLabel.startsWith('+')) intLabel = '+' + intLabel;
    if (isInverted) intLabel += " (Inv)";

    const delayBeats = delayTicks / (ppq * (4 / ts.den));

    return {
        id: `${intLabel}@${delayBeats.toFixed(1)}${isInverted?'i':''}`,
        intervalSemis,
        intervalLabel: intLabel,
        delayBeats: parseFloat(delayBeats.toFixed(2)),
        delayTicks,
        grade,
        errors,
        notes: [...subject, ...answer],
        regions: harmonicRegions,
        dissonanceRatio,
        endsOnDissonance
    };
}

import React, { useState, useMemo } from 'react';
import { StrettoCandidate, StrettoGrade } from '../../types';
import { getStrictPitchName } from '../services/midiSpelling';

interface StrettoListProps {
    candidates: StrettoCandidate[];
    processedResults: StrettoCandidate[];
    gradeFilter: Record<StrettoGrade, boolean>;
    setGradeFilter: (val: Record<StrettoGrade, boolean>) => void;
    selectedId: string | null;
    onSelect: (candidate: StrettoCandidate) => void;
    checkedIds: Set<string>;
    onToggleCheck: (id: string) => void;
}

type SortKey = 'grade' | 'delay' | 'interval' | 'dissonance';

export default function StrettoList({ 
    candidates, processedResults, gradeFilter, setGradeFilter, 
    selectedId, onSelect, checkedIds, onToggleCheck 
}: StrettoListProps) {
    const [sortKey, setSortKey] = useState<SortKey>('grade');
    const [sortDir, setSortDir] = useState<'asc' | 'desc'>('desc');

    // Column Filters
    const [entryPitchFilter, setEntryPitchFilter] = useState<string>('All');
    const [intervalFilter, setIntervalFilter] = useState<string>('All');
    const [delayFilter, setDelayFilter] = useState<string>('All');

    // Extract unique values for filter dropdowns from the raw candidate list
    const { availablePitches, availableIntervals, availableDelays } = useMemo(() => {
        const pitches = new Set<string>();
        const intervals = new Set<string>();
        const delays = new Set<string>();

        candidates.forEach(c => {
            const firstAnswerNote = c.notes.find(n => n.voiceIndex === 1);
            if (firstAnswerNote) {
                // Remove octave digits for consistent pitch filtering (C, G, etc.)
                pitches.add(getStrictPitchName(firstAnswerNote.midi).replace(/\d/g, ''));
            }
            intervals.add(c.intervalLabel);
            delays.add(c.delayBeats.toString());
        });

        return {
            availablePitches: ['All', ...Array.from(pitches).sort()],
            availableIntervals: ['All', ...Array.from(intervals).sort((a,b) => a.localeCompare(b, undefined, {numeric: true}))],
            availableDelays: ['All', ...Array.from(delays).sort((a,b) => parseFloat(a) - parseFloat(b))]
        };
    }, [candidates]);

    // Apply combined filters
    const filteredResults = useMemo(() => {
        return processedResults.filter(r => {
            // 1. Grade (S/V/I)
            if (!gradeFilter[r.grade]) return false;

            // 2. Entry Note
            if (entryPitchFilter !== 'All') {
                const firstAnswerNote = r.notes.find(n => n.voiceIndex === 1);
                if (!firstAnswerNote) return false;
                const pName = getStrictPitchName(firstAnswerNote.midi).replace(/\d/g, '');
                if (pName !== entryPitchFilter) return false;
            }

            // 3. Interval
            if (intervalFilter !== 'All' && r.intervalLabel !== intervalFilter) return false;

            // 4. Delay
            if (delayFilter !== 'All' && r.delayBeats.toString() !== delayFilter) return false;

            return true;
        });
    }, [processedResults, gradeFilter, entryPitchFilter, intervalFilter, delayFilter]);

    // Sort the final filtered set
    const sortedResults = useMemo(() => {
        const res = [...filteredResults];
        res.sort((a, b) => {
            let diff = 0;
            if (sortKey === 'grade') {
                const score = { 'STRONG': 3, 'VIABLE': 2, 'INVALID': 1 };
                diff = score[a.grade] - score[b.grade];
            } else if (sortKey === 'delay') {
                diff = a.delayTicks - b.delayTicks;
            } else if (sortKey === 'interval') {
                diff = Math.abs(a.intervalSemis) - Math.abs(b.intervalSemis);
            } else if (sortKey === 'dissonance') {
                diff = a.dissonanceRatio - b.dissonanceRatio;
            }
            return sortDir === 'asc' ? diff : -diff;
        });
        return res;
    }, [filteredResults, sortKey, sortDir]);

    const handleSort = (key: SortKey) => {
        if (sortKey === key) setSortDir(prev => prev === 'asc' ? 'desc' : 'asc');
        else { setSortKey(key); setSortDir(key === 'grade' || key === 'dissonance' ? 'desc' : 'asc'); }
    };

    return (
        <div className="bg-gray-900 border border-gray-700 rounded h-[600px] flex flex-col shadow-inner relative">
            <div className="p-3 border-b border-gray-700 bg-gray-800 flex flex-col gap-3">

                {/* Unified Filters Row */}
                <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
                    <div className="flex flex-col gap-1">
                        <label className="text-[9px] font-bold text-gray-500 uppercase tracking-widest">Verdict</label>
                        <div className="flex gap-0.5">
                            <button onClick={() => setGradeFilter({ ...gradeFilter, STRONG: !gradeFilter.STRONG })} className={`flex-1 py-1 text-[9px] rounded font-bold border transition-all ${gradeFilter.STRONG ? 'bg-green-900 border-green-500 text-green-300' : 'bg-gray-900 border-gray-700 text-gray-600'}`}>S</button>
                            <button onClick={() => setGradeFilter({ ...gradeFilter, VIABLE: !gradeFilter.VIABLE })} className={`flex-1 py-1 text-[9px] rounded font-bold border transition-all ${gradeFilter.VIABLE ? 'bg-yellow-900 border-yellow-500 text-yellow-300' : 'bg-gray-900 border-gray-700 text-gray-600'}`}>V</button>
                            <button onClick={() => setGradeFilter({ ...gradeFilter, INVALID: !gradeFilter.INVALID })} className={`flex-1 py-1 text-[9px] rounded font-bold border transition-all ${gradeFilter.INVALID ? 'bg-red-900 border-red-500 text-red-300' : 'bg-gray-900 border-gray-700 text-gray-600'}`}>I</button>
                        </div>
                    </div>

                    <div className="flex flex-col gap-1">
                        <label className="text-[9px] font-bold text-gray-500 uppercase tracking-widest">Interval</label>
                        <select 
                            value={intervalFilter}
                            onChange={(e) => setIntervalFilter(e.target.value)}
                            className="bg-gray-900 border border-gray-700 text-[10px] rounded px-1.5 py-1 text-brand-primary outline-none"
                        >
                            {availableIntervals.map(i => <option key={i} value={i}>{i}</option>)}
                        </select>
                    </div>

                    <div className="flex flex-col gap-1">
                        <label className="text-[9px] font-bold text-gray-500 uppercase tracking-widest">Delay</label>
                        <select 
                            value={delayFilter}
                            onChange={(e) => setDelayFilter(e.target.value)}
                            className="bg-gray-900 border border-gray-700 text-[10px] rounded px-1.5 py-1 text-gray-300 outline-none"
                        >
                            {availableDelays.map(d => <option key={d} value={d}>{d === 'All' ? 'All' : `${d}B`}</option>)}
                        </select>
                    </div>

                    <div className="flex flex-col gap-1">
                        <label className="text-[9px] font-bold text-gray-500 uppercase tracking-widest">Entry Pitch</label>
                        <select 
                            value={entryPitchFilter}
                            onChange={(e) => setEntryPitchFilter(e.target.value)}
                            className="bg-gray-900 border border-gray-700 text-[10px] rounded px-1.5 py-1 text-gray-300 outline-none"
                        >
                            {availablePitches.map(p => <option key={p} value={p}>{p}</option>)}
                        </select>
                    </div>
                </div>

                {/* Sorting Controls */}
                <div className="flex gap-1 bg-gray-900 p-1 rounded border border-gray-700 mt-1 shadow-inner">
                    {(['grade', 'delay', 'interval', 'dissonance'] as SortKey[]).map(key => (
                        <button key={key} onClick={() => handleSort(key)} className={`flex-1 text-[9px] py-1 rounded transition-colors ${sortKey === key ? 'bg-gray-700 text-white font-bold' : 'text-gray-500 hover:text-gray-300'}`}>
                            {key.toUpperCase()} {sortKey === key && (sortDir === 'asc' ? '↑' : '↓')}
                        </button>
                    ))}
                </div>
            </div>

            <div className="overflow-y-auto flex-grow p-2">
                <div className="grid grid-cols-12 gap-2 px-2 py-1 text-[9px] font-bold text-gray-500 uppercase border-b border-gray-800">
                    <div className="col-span-1"></div>
                    <div className="col-span-2">Int</div>
                    <div className="col-span-2">Delay</div>
                    <div className="col-span-2">Entry</div>
                    <div className="col-span-2">Diss %</div>
                    <div className="col-span-1">End</div>
                    <div className="col-span-2 text-right">Err</div>
                </div>

                {sortedResults.length === 0 ? (
                    <div className="py-20 text-center text-gray-600 text-sm italic">No matching strettos.</div>
                ) : (
                    sortedResults.map((r) => {
                        const firstAnswerNote = r.notes.find(n => n.voiceIndex === 1);
                        const entryNote = firstAnswerNote ? getStrictPitchName(firstAnswerNote.midi) : '?';
                        return (
                            <div key={r.id} onClick={() => onSelect(r)} className={`grid grid-cols-12 gap-2 p-2 rounded cursor-pointer border-b border-gray-800 hover:bg-gray-800 items-center transition-colors ${selectedId === r.id ? 'bg-gray-800 border-l-4 border-l-brand-primary' : ''}`}>
                                <div className="col-span-1 flex justify-center" onClick={(e) => e.stopPropagation()}>
                                    <input type="checkbox" checked={checkedIds.has(r.id)} onChange={() => onToggleCheck(r.id)} className="rounded bg-gray-700 border-gray-600 text-brand-primary w-3 h-3" />
                                </div>
                                <span className="col-span-2 font-bold text-brand-primary text-[10px] truncate">{r.intervalLabel}</span>
                                <span className="col-span-2 text-gray-300 text-[10px]">{r.delayBeats}B</span>
                                <span className="col-span-2 text-gray-500 text-[10px] font-mono">{entryNote}</span>
                                <span className={`col-span-2 text-[10px] font-mono font-bold ${r.dissonanceRatio > 0.5 ? 'text-red-400' : r.dissonanceRatio > 0.3 ? 'text-yellow-400' : 'text-green-400'}`}>{Math.round(r.dissonanceRatio * 100)}%</span>
                                <div className="col-span-1 flex justify-center">{r.endsOnDissonance ? <span className="text-red-500 font-bold text-[10px]">!</span> : <span className="text-green-500 font-bold text-[10px]">✓</span>}</div>
                                <span className="col-span-2 text-[9px] text-gray-500 text-right">{r.errors.length > 0 ? r.errors.length : '-'}</span>
                            </div>
                        );
                    })
                )}
            </div>

            <div className="p-2 border-t border-gray-800 bg-gray-800/50 flex justify-between items-center px-4">
                <span className="text-[10px] text-gray-500 italic">{sortedResults.length} Visible</span>
                <button 
                    onClick={() => { setIntervalFilter('All'); setDelayFilter('All'); setEntryPitchFilter('All'); setGradeFilter({STRONG: true, VIABLE: true, INVALID: true}) }}
                    className="text-[9px] text-brand-primary hover:text-white uppercase font-bold"
                >
                    Reset Filters
                </button>
            </div>
        </div>
    );
}

import React, { useState, useMemo } from 'react';
import { StrettoCandidate, StrettoGrade } from '../../types';
import { getStrictPitchName } from '../services/midiSpelling';

interface StrettoListProps {
    candidates: StrettoCandidate[];
    processedResults: StrettoCandidate[]; // Results that passed the grade filter
    gradeFilter: Record<StrettoGrade, boolean>;
    setGradeFilter: (val: Record<StrettoGrade, boolean>) => void;
    selectedId: string | null;
    onSelect: (candidate: StrettoCandidate) => void;
    checkedIds: Set<string>;
    onToggleCheck: (id: string) => void;
}

type SortKey = 'grade' | 'delay' | 'interval' | 'dissonance' | 'entry' | 'errors';

export default function StrettoList({ 
    candidates, processedResults, gradeFilter, setGradeFilter, 
    selectedId, onSelect, checkedIds, onToggleCheck 
}: StrettoListProps) {
    const [sortKey, setSortKey] = useState<SortKey>('grade');
    const [sortDir, setSortDir] = useState<'asc' | 'desc'>('desc');

    // Multi-select Filters
    const [selectedPitches, setSelectedPitches] = useState<Set<string>>(new Set());
    const [selectedIntervals, setSelectedIntervals] = useState<Set<string>>(new Set());
    const [selectedDelays, setSelectedDelays] = useState<Set<string>>(new Set());

    // Logic Filters
    const [maxDissonance, setMaxDissonance] = useState<number>(100);
    const [onlyResolved, setOnlyResolved] = useState<boolean>(false);

    // Extract unique values for filter toggles
    const { availablePitches, availableIntervals, availableDelays } = useMemo(() => {
        const pitches = new Set<string>();
        const intervals = new Set<string>();
        const delays = new Set<string>();

        candidates.forEach(c => {
            const firstAnswerNote = c.notes.find(n => n.voiceIndex === 1);
            if (firstAnswerNote) {
                pitches.add(getStrictPitchName(firstAnswerNote.midi).replace(/\d/g, ''));
            }
            intervals.add(c.intervalLabel);
            delays.add(c.delayBeats.toString());
        });

        return {
            availablePitches: Array.from(pitches).sort(),
            availableIntervals: Array.from(intervals).sort((a,b) => a.localeCompare(b, undefined, {numeric: true})),
            availableDelays: Array.from(delays).sort((a,b) => parseFloat(a) - parseFloat(b))
        };
    }, [candidates]);

    // Combined Advanced Filtering
    const finalFilteredResults = useMemo(() => {
        return processedResults.filter(r => {
            // 1. Grade (Already handled by parent passing processedResults, but double check if needed)
            if (!gradeFilter[r.grade]) return false;

            // 2. Multi-select Entry Pitch
            if (selectedPitches.size > 0) {
                const firstAnswerNote = r.notes.find(n => n.voiceIndex === 1);
                if (!firstAnswerNote) return false;
                const pName = getStrictPitchName(firstAnswerNote.midi).replace(/\d/g, '');
                if (!selectedPitches.has(pName)) return false;
            }

            // 3. Multi-select Interval
            if (selectedIntervals.size > 0 && !selectedIntervals.has(r.intervalLabel)) return false;

            // 4. Multi-select Delay
            if (selectedDelays.size > 0 && !selectedDelays.has(r.delayBeats.toString())) return false;

            // 5. Numeric Dissonance
            if (Math.round(r.dissonanceRatio * 100) > maxDissonance) return false;

            // 6. End Resolution
            if (onlyResolved && r.endsOnDissonance) return false;

            return true;
        });
    }, [processedResults, gradeFilter, selectedPitches, selectedIntervals, selectedDelays, maxDissonance, onlyResolved]);

    // Sorting Logic
    const sortedResults = useMemo(() => {
        const res = [...finalFilteredResults];
        res.sort((a, b) => {
            let diff = 0;
            const firstA = a.notes.find(n => n.voiceIndex === 1);
            const firstB = b.notes.find(n => n.voiceIndex === 1);

            switch (sortKey) {
                case 'grade':
                    const score = { 'STRONG': 3, 'VIABLE': 2, 'INVALID': 1 };
                    diff = score[a.grade] - score[b.grade];
                    break;
                case 'delay':
                    diff = a.delayTicks - b.delayTicks;
                    break;
                case 'interval':
                    diff = Math.abs(a.intervalSemis) - Math.abs(b.intervalSemis);
                    break;
                case 'dissonance':
                    diff = a.dissonanceRatio - b.dissonanceRatio;
                    break;
                case 'entry':
                    diff = (firstA?.midi || 0) - (firstB?.midi || 0);
                    break;
                case 'errors':
                    diff = a.errors.length - b.errors.length;
                    break;
            }
            return sortDir === 'asc' ? diff : -diff;
        });
        return res;
    }, [finalFilteredResults, sortKey, sortDir]);

    const handleSort = (key: SortKey) => {
        if (sortKey === key) setSortDir(prev => prev === 'asc' ? 'desc' : 'asc');
        else { setSortKey(key); setSortDir(key === 'grade' || key === 'dissonance' ? 'desc' : 'asc'); }
    };

    const toggleFilterSet = (set: Set<string>, val: string) => {
        const next = new Set(set);
        if (next.has(val)) next.delete(val);
        else next.add(val);
        return next;
    };

    const renderToggleGroup = (label: string, items: string[], current: Set<string>, update: (s: Set<string>) => void) => (
        <div className="flex flex-col gap-1">
            <div className="flex justify-between items-center">
                <label className="text-[9px] font-bold text-gray-500 uppercase tracking-widest">{label}</label>
                <button 
                    onClick={() => update(new Set())}
                    className="text-[8px] text-brand-primary hover:underline"
                >
                    {current.size === 0 ? 'All' : 'Clear'}
                </button>
            </div>
            <div className="flex flex-wrap gap-1 max-h-12 overflow-y-auto bg-black/20 p-1 rounded border border-gray-700 shadow-inner">
                {items.map(item => (
                    <button
                        key={item}
                        onClick={() => update(toggleFilterSet(current, item))}
                        className={`px-1.5 py-0.5 text-[9px] font-bold rounded transition-all border ${current.has(item) ? 'bg-brand-primary border-brand-primary text-white shadow-sm' : 'bg-gray-800 border-gray-600 text-gray-500 hover:border-gray-400'}`}
                    >
                        {item}
                    </button>
                ))}
            </div>
        </div>
    );

    return (
        <div className="bg-gray-900 border border-gray-700 rounded h-[600px] flex flex-col shadow-inner relative">
            <div className="p-3 border-b border-gray-700 bg-gray-800 flex flex-col gap-4">

                {/* Advanced Multi-Select Filters */}
                <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
                    {renderToggleGroup("Intervals", availableIntervals, selectedIntervals, setSelectedIntervals)}
                    {renderToggleGroup("Delays", availableDelays, selectedDelays, setSelectedDelays)}
                    {renderToggleGroup("Entry Pitches", availablePitches, selectedPitches, setSelectedPitches)}
                </div>

                {/* Metric & Verdict Row */}
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4 border-t border-gray-700 pt-3">
                    <div className="flex flex-col gap-1">
                        <label className="text-[9px] font-bold text-gray-500 uppercase tracking-widest">Verdict</label>
                        <div className="flex gap-1">
                            {(['STRONG', 'VIABLE', 'INVALID'] as StrettoGrade[]).map(g => (
                                <button 
                                    key={g}
                                    onClick={() => setGradeFilter({ ...gradeFilter, [g]: !gradeFilter[g] })} 
                                    className={`flex-1 py-1 text-[9px] rounded font-bold border transition-all ${gradeFilter[g] ? 'bg-brand-primary/20 border-brand-primary text-brand-primary' : 'bg-gray-900 border-gray-700 text-gray-600'}`}
                                >
                                    {g.charAt(0)}
                                </button>
                            ))}
                        </div>
                    </div>

                    <div className="flex flex-col gap-1">
                        <div className="flex justify-between">
                            <label className="text-[9px] font-bold text-gray-500 uppercase tracking-widest">Max Dissonance</label>
                            <span className="text-[9px] font-mono text-brand-primary font-bold">{maxDissonance}%</span>
                        </div>
                        <input 
                            type="range" min="0" max="100" step="1" 
                            value={maxDissonance} 
                            onChange={(e) => setMaxDissonance(parseInt(e.target.value))}
                            className="w-full h-1 bg-gray-700 rounded-lg appearance-none cursor-pointer accent-brand-primary"
                        />
                    </div>

                    <div className="flex flex-col justify-end">
                        <label className={`flex items-center gap-2 p-2 bg-gray-900/50 rounded border cursor-pointer transition-all ${onlyResolved ? 'border-green-500/50 bg-green-900/10' : 'border-gray-700'}`}>
                            <input 
                                type="checkbox" 
                                checked={onlyResolved} 
                                onChange={(e) => setOnlyResolved(e.target.checked)}
                                className="w-3 h-3 rounded bg-gray-800 border-gray-600 text-brand-primary"
                            />
                            <span className={`text-[10px] font-bold uppercase tracking-tight ${onlyResolved ? 'text-green-400' : 'text-gray-500'}`}>Resolved End Only</span>
                        </label>
                    </div>
                </div>
            </div>

            {/* Redesigned Table with Integrated Sorting */}
            <div className="overflow-y-auto flex-grow p-1">
                <div className="sticky top-0 bg-gray-900 z-10 grid grid-cols-12 gap-1 px-2 py-2 text-[9px] font-bold text-gray-500 uppercase border-b border-gray-800">
                    <div className="col-span-1"></div>
                    <button onClick={() => handleSort('interval')} className={`col-span-2 text-left hover:text-white transition-colors ${sortKey === 'interval' ? 'text-brand-primary' : ''}`}>
                        Int {sortKey === 'interval' && (sortDir === 'asc' ? '↑' : '↓')}
                    </button>
                    <button onClick={() => handleSort('delay')} className={`col-span-2 text-left hover:text-white transition-colors ${sortKey === 'delay' ? 'text-brand-primary' : ''}`}>
                        Delay {sortKey === 'delay' && (sortDir === 'asc' ? '↑' : '↓')}
                    </button>
                    <button onClick={() => handleSort('entry')} className={`col-span-2 text-left hover:text-white transition-colors ${sortKey === 'entry' ? 'text-brand-primary' : ''}`}>
                        Entry {sortKey === 'entry' && (sortDir === 'asc' ? '↑' : '↓')}
                    </button>
                    <button onClick={() => handleSort('dissonance')} className={`col-span-2 text-left hover:text-white transition-colors ${sortKey === 'dissonance' ? 'text-brand-primary' : ''}`}>
                        Diss % {sortKey === 'dissonance' && (sortDir === 'asc' ? '↑' : '↓')}
                    </button>
                    <div className="col-span-1 text-center">End</div>
                    <button onClick={() => handleSort('errors')} className={`col-span-2 text-right hover:text-white transition-colors ${sortKey === 'errors' ? 'text-brand-primary' : ''}`}>
                        Err {sortKey === 'errors' && (sortDir === 'asc' ? '↑' : '↓')}
                    </button>
                </div>

                {sortedResults.length === 0 ? (
                    <div className="py-20 text-center text-gray-600 text-sm italic">No matching strettos. Try widening filters.</div>
                ) : (
                    sortedResults.map((r) => {
                        const firstAnswerNote = r.notes.find(n => n.voiceIndex === 1);
                        const entryNote = firstAnswerNote ? getStrictPitchName(firstAnswerNote.midi) : '?';
                        return (
                            <div 
                                key={r.id} 
                                onClick={() => onSelect(r)} 
                                className={`grid grid-cols-12 gap-1 p-2 rounded cursor-pointer border-b border-gray-800 items-center transition-all ${selectedId === r.id ? 'bg-gray-800 ring-1 ring-brand-primary/50' : 'hover:bg-gray-800/50'}`}
                            >
                                <div className="col-span-1 flex justify-center" onClick={(e) => e.stopPropagation()}>
                                    <input 
                                        type="checkbox" 
                                        checked={checkedIds.has(r.id)} 
                                        onChange={() => onToggleCheck(r.id)} 
