        return {
            availablePitches: Array.from(pitches).sort(),
            availableIntervals: Array.from(intervals).sort((a,b) => a.localeCompare(b, undefined, {numeric: true})),
            availableDelays: Array.from(delays).sort((a,b) => parseFloat(a) - parseFloat(b))
        };
    }, [candidates]);

    const finalFilteredResults = useMemo(() => {
        return processedResults.filter(r => {
            if (!gradeFilter[r.grade]) return false;

            if (selectedPitches.size > 0) {
                const firstAnswerNote = r.notes.find(n => n.voiceIndex === 1);
                if (!firstAnswerNote) return false;
                const pName = getStrictPitchName(firstAnswerNote.midi).replace(/\d/g, '');
                if (!selectedPitches.has(pName)) return false;
            }

            if (selectedIntervals.size > 0 && !selectedIntervals.has(r.intervalLabel)) return false;

            if (selectedDelays.size > 0 && !selectedDelays.has(r.delayBeats.toString())) return false;

            if (Math.round(r.dissonanceRatio * 100) > maxDissonance) return false;

            if (onlyResolved && r.endsOnDissonance) return false;

            return true;
        });
    }, [processedResults, gradeFilter, selectedPitches, selectedIntervals, selectedDelays, maxDissonance, onlyResolved]);

    const sortedResults = useMemo(() => {
        const res = [...finalFilteredResults];
        res.sort((a, b) => {
            let diff = 0;
            const firstA = a.notes.find(n => n.voiceIndex === 1);
            const firstB = b.notes.find(n => n.voiceIndex === 1);

            switch (sortKey) {
                case 'grade':
                    const score = { 'STRONG': 3, 'VIABLE': 2, 'INVALID': 1 };
                    diff = score[a.grade] - score[b.grade];
                    break;
                case 'delay':
                    diff = a.delayTicks - b.delayTicks;
                    break;
                case 'interval':
                    diff = Math.abs(a.intervalSemis) - Math.abs(b.intervalSemis);
                    break;
                case 'dissonance':
                    diff = a.dissonanceRatio - b.dissonanceRatio;
                    break;
                case 'entry':
                    diff = (firstA?.midi || 0) - (firstB?.midi || 0);
                    break;
                case 'errors':
                    diff = a.errors.length - b.errors.length;
                    break;
            }
            return sortDir === 'asc' ? diff : -diff;
        });
        return res;
    }, [finalFilteredResults, sortKey, sortDir]);

    const handleSort = (key: SortKey) => {
        if (sortKey === key) setSortDir(prev => prev === 'asc' ? 'desc' : 'asc');
        else { setSortKey(key); setSortDir(key === 'grade' || key === 'dissonance' ? 'desc' : 'asc'); }
    };

    const toggleFilterSet = (set: Set<string>, val: string) => {
        const next = new Set(set);
        if (next.has(val)) next.delete(val);
        else next.add(val);
        return next;
    };

    const renderToggleGroup = (label: string, items: string[], current: Set<string>, update: (s: Set<string>) => void) => (
        <div className="flex flex-col gap-1">
            <div className="flex justify-between items-center">
                <label className="text-[9px] font-bold text-gray-500 uppercase tracking-widest">{label}</label>
                <button 
                    onClick={() => update(new Set())}
                    className="text-[8px] text-brand-primary hover:underline"
                >
                    {current.size === 0 ? 'All' : 'Clear'}
                </button>
            </div>
            <div className="flex flex-wrap gap-1 max-h-12 overflow-y-auto bg-black/20 p-1 rounded border border-gray-700 shadow-inner">
                {items.map(item => (
                    <button
                        key={item}
                        onClick={() => update(toggleFilterSet(current, item))}
                        className={`px-1.5 py-0.5 text-[9px] font-bold rounded transition-all border ${current.has(item) ? 'bg-brand-primary border-brand-primary text-white shadow-sm' : 'bg-gray-800 border-gray-600 text-gray-500 hover:border-gray-400'}`}
                    >
                        {item}
                    </button>
                ))}
            </div>
        </div>
    );

    return (
        <div className="bg-gray-900 border border-gray-700 rounded h-[600px] flex flex-col shadow-inner relative">
            <div className="p-3 border-b border-gray-700 bg-gray-800 flex flex-col gap-4">

                <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
                    {renderToggleGroup("Intervals", availableIntervals, selectedIntervals, setSelectedIntervals)}
                    {renderToggleGroup("Delays", availableDelays, selectedDelays, setSelectedDelays)}
                    {renderToggleGroup("Entry Pitches", availablePitches, selectedPitches, setSelectedPitches)}
                </div>

                <div className="grid grid-cols-1 md:grid-cols-3 gap-4 border-t border-gray-700 pt-3">
                    <div className="flex flex-col gap-1">
                        <label className="text-[9px] font-bold text-gray-500 uppercase tracking-widest">Verdict</label>
                        <div className="flex gap-1">
                            {(['STRONG', 'VIABLE', 'INVALID'] as StrettoGrade[]).map(g => (
                                <button 
                                    key={g}
                                    onClick={() => setGradeFilter({ ...gradeFilter, [g]: !gradeFilter[g] })} 
                                    className={`flex-1 py-1 text-[9px] rounded font-bold border transition-all ${gradeFilter[g] ? 'bg-brand-primary/20 border-brand-primary text-brand-primary' : 'bg-gray-900 border-gray-700 text-gray-600'}`}
                                >
                                    {g.charAt(0)}
                                </button>
                            ))}
                        </div>
                    </div>

                    <div className="flex flex-col gap-1">
                        <div className="flex justify-between">
                            <label className="text-[9px] font-bold text-gray-500 uppercase tracking-widest">Max Dissonance</label>
                            <span className="text-[9px] font-mono text-brand-primary font-bold">{maxDissonance}%</span>
                        </div>
                        <input 
                            type="range" min="0" max="100" step="1" 
                            value={maxDissonance} 
                            onChange={(e) => setMaxDissonance(parseInt(e.target.value))}
                            className="w-full h-1 bg-gray-700 rounded-lg appearance-none cursor-pointer accent-brand-primary"
                        />
                    </div>

                    <div className="flex flex-col justify-end">
                        <label className={`flex items-center gap-2 p-2 bg-gray-900/50 rounded border cursor-pointer transition-all ${onlyResolved ? 'border-green-500/50 bg-green-900/10' : 'border-gray-700'}`}>
                            <input 
                                type="checkbox" 
                                checked={onlyResolved} 
                                onChange={(e) => setOnlyResolved(e.target.checked)}
                                className="w-3 h-3 rounded bg-gray-800 border-gray-600 text-brand-primary"
                            />
                            <span className={`text-[10px] font-bold uppercase tracking-tight ${onlyResolved ? 'text-green-400' : 'text-gray-500'}`}>Resolved End Only</span>
                        </label>
                    </div>
                </div>
            </div>

            <div className="overflow-y-auto flex-grow p-1">
                <div className="sticky top-0 bg-gray-900 z-10 grid grid-cols-12 gap-1 px-2 py-2 text-[9px] font-bold text-gray-500 uppercase border-b border-gray-800">
                    <div className="col-span-1"></div>
                    <button onClick={() => handleSort('interval')} className={`col-span-2 text-left hover:text-white transition-colors ${sortKey === 'interval' ? 'text-brand-primary' : ''}`}>
                        Int {sortKey === 'interval' && (sortDir === 'asc' ? '↑' : '↓')}
                    </button>
                    <button onClick={() => handleSort('delay')} className={`col-span-2 text-left hover:text-white transition-colors ${sortKey === 'delay' ? 'text-brand-primary' : ''}`}>
                        Delay {sortKey === 'delay' && (sortDir === 'asc' ? '↑' : '↓')}
                    </button>
                    <button onClick={() => handleSort('entry')} className={`col-span-2 text-left hover:text-white transition-colors ${sortKey === 'entry' ? 'text-brand-primary' : ''}`}>
                        Entry {sortKey === 'entry' && (sortDir === 'asc' ? '↑' : '↓')}
                    </button>
                    <button onClick={() => handleSort('dissonance')} className={`col-span-2 text-left hover:text-white transition-colors ${sortKey === 'dissonance' ? 'text-brand-primary' : ''}`}>
                        Diss % {sortKey === 'dissonance' && (sortDir === 'asc' ? '↑' : '↓')}
                    </button>
                    <div className="col-span-1 text-center">End</div>
                    <button onClick={() => handleSort('errors')} className={`col-span-2 text-right hover:text-white transition-colors ${sortKey === 'errors' ? 'text-brand-primary' : ''}`}>
                        Err {sortKey === 'errors' && (sortDir === 'asc' ? '↑' : '↓')}
                    </button>
                </div>

                {sortedResults.length === 0 ? (
                    <div className="py-20 text-center text-gray-600 text-sm italic">No matching strettos. Try widening filters.</div>
                ) : (
                    sortedResults.map((r) => {
                        const firstAnswerNote = r.notes.find(n => n.voiceIndex === 1);
                        const entryNote = firstAnswerNote ? getStrictPitchName(firstAnswerNote.midi) : '?';
                        return (
                            <div 
                                key={r.id} 
                                onClick={() => onSelect(r)} 
                                className={`grid grid-cols-12 gap-1 p-2 rounded cursor-pointer border-b border-gray-800 items-center transition-all ${selectedId === r.id ? 'bg-gray-800 ring-1 ring-brand-primary/50' : 'hover:bg-gray-800/50'}`}
                            >
                                <div className="col-span-1 flex justify-center" onClick={(e) => e.stopPropagation()}>
                                    <input 
                                        type="checkbox" 
                                        checked={checkedIds.has(r.id)} 
                                        onChange={() => onToggleCheck(r.id)} 
                                        className="rounded bg-gray-700 border-gray-600 text-brand-primary w-3 h-3" 
                                    />
                                </div>
                                <span className={`col-span-2 font-bold text-[10px] truncate ${r.intervalLabel.includes('Inv') ? 'text-blue-400' : 'text-brand-primary'}`}>
                                    {r.intervalLabel}
                                </span>
                                <span className="col-span-2 text-gray-300 text-[10px]">{r.delayBeats}B</span>
                                <span className="col-span-2 text-gray-500 text-[10px] font-mono">{entryNote}</span>
                                <span className={`col-span-2 text-[10px] font-mono font-bold ${r.dissonanceRatio > 0.4 ? 'text-red-400' : r.dissonanceRatio > 0.2 ? 'text-yellow-400' : 'text-green-400'}`}>
                                    {Math.round(r.dissonanceRatio * 100)}%
                                </span>
                                <div className="col-span-1 flex justify-center">
                                    {r.endsOnDissonance ? <span className="text-red-500 font-bold text-[11px]">!</span> : <span className="text-green-500 font-bold text-[11px]">✓</span>}
                                </div>
                                <span className="col-span-2 text-[9px] text-gray-500 text-right">
                                    {r.errors.length > 0 ? (
                                        <span className="bg-red-900/30 text-red-400 px-1 rounded border border-red-900/50">{r.errors.length}</span>
                                    ) : '-'}
                                </span>
                            </div>
                        );
                    })
                )}
            </div>

            <div className="p-2 border-t border-gray-800 bg-gray-800/50 flex justify-between items-center px-4">
                <div className="flex items-center gap-3">
                    <span className="text-[10px] text-gray-500 italic">{sortedResults.length} Visible</span>
                    <span className="text-[10px] text-gray-700">|</span>
                    <span className="text-[10px] text-gray-500">{checkedIds.size} Selected</span>
                </div>
                <button 
                    onClick={() => { 
                        setSelectedIntervals(new Set()); 
                        setSelectedDelays(new Set()); 
                        setSelectedPitches(new Set()); 
                        setMaxDissonance(100); 
                        setOnlyResolved(false);
                        setGradeFilter({STRONG: true, VIABLE: true, INVALID: true}) 
                    }}
                    className="text-[9px] text-brand-primary hover:text-white uppercase font-bold tracking-wider"
                >
                    Reset Power Filter
                </button>
            </div>
        </div>
    );
}

import React, { useState, useMemo, useEffect } from 'react';
import { RawNote, StrettoCandidate, StrettoSearchOptions, StrettoChainResult, HarmonicRegion, StrettoSearchReport, StrettoGrade } from '../types';
import { parseSimpleAbc } from './services/abcBridge';
import { analyzeStrettoCandidate, getVerticalIntervals, generateHarmonicRegions } from './services/strettoCore';
import { searchStrettoChains } from './services/strettoGenerator'; 
import { getStrictPitchName } from './services/midiSpelling';
import { downloadStrettoCandidate, downloadStrettoSelection } from './services/strettoExport';
import { Spinner, DocumentTextIcon, DownloadIcon } from './Icons';
import { playSequence, stopPlayback } from './midiPlaybackService';
import { useStrettoAssembly } from '../hooks/useStrettoAssembly';

import StrettoConfig, { SearchResolution } from './stretto/StrettoConfig';
import StrettoList from './stretto/StrettoList';
import StrettoInspector from './stretto/StrettoInspector';
import StrettoFooter from './stretto/StrettoFooter';
import StrettoChainView from './stretto/StrettoChainView'; 

interface StrettoViewProps {
    notes: RawNote[]; 
    ppq: number;
    ts: { num: number, den: number };
    voiceNames?: Record<number, string>;
    setVoiceNames?: (names: Record<number, string>) => void;
}

interface SavedSubject {
    id: string;
    name: string;
    data: string;
}

export default function StrettoView({ notes: initialNotes, ppq, ts, voiceNames, setVoiceNames }: StrettoViewProps) {
    const [mode, setMode] = useState<'midi' | 'abc'>(initialNotes.length > 0 ? 'midi' : 'abc');
    const [abcInput, setAbcInput] = useState<string>("M:4/4\nL:1/4\nQ:120\nK:C\nc2 G c d e f g3 a b c'2");
    const [viewMode, setViewMode] = useState<'pairwise' | 'chain'>('chain'); 

    const [gradeFilter, setGradeFilter] = useState<Record<StrettoGrade, boolean>>({
        'STRONG': true,
        'VIABLE': true,
        'INVALID': false
    });

    const [savedSubjects, setSavedSubjects] = useState<SavedSubject[]>([]);
    const [saveName, setSaveName] = useState('');
    const [showLibrary, setShowLibrary] = useState(false);

    const [configIntervals, setConfigIntervals] = useState<number[]>([0, 12, -12, 7, -7, 5, -5, 24, -24]);
    const [includeExtensions, setIncludeExtensions] = useState(false);
    const [includeInversions, setIncludeInversions] = useState(false);
    const [searchRes, setSearchRes] = useState<SearchResolution>('full');
    const [selectedCandidate, setSelectedCandidate] = useState<StrettoCandidate | null>(null);
    const [checkedIds, setCheckedIds] = useState<Set<string>>(new Set());

    const [searchOptions, setSearchOptions] = useState<StrettoSearchOptions>({
        ensembleTotal: 4,
        targetChainLength: 8,
        subjectVoiceIndex: 2, 
        truncationMode: 'Max 1',
        truncationMusicalValue: '1/2',
        inversionMode: 'None',
        thirdSixthMode: 'None',
        pivotMidi: 65, 
        requireConsonantEnd: true,
        disallowComplexExceptions: false
    });
    const [chainResults, setChainResults] = useState<StrettoChainResult[]>([]);
    const [searchReport, setSearchReport] = useState<StrettoSearchReport | null>(null);
    const [isSearching, setIsSearching] = useState(false);
    const [selectedChain, setSelectedChain] = useState<StrettoChainResult | null>(null);

    const [isPlaying, setIsPlaying] = useState(false);

    useEffect(() => {
        const saved = localStorage.getItem('stretto_subject_library');
        if (saved) {
            try { setSavedSubjects(JSON.parse(saved)); } catch (e) { console.error(e); }
        }
    }, []);

    const handleSaveSubject = () => {
        if (!saveName.trim() || !abcInput.trim()) return;
        const newSubject: SavedSubject = { id: Date.now().toString(), name: saveName.trim(), data: abcInput };
        const updated = [...savedSubjects, newSubject];
        setSavedSubjects(updated);
        localStorage.setItem('stretto_subject_library', JSON.stringify(updated));
        setSaveName('');
    };

    const handleDeleteSubject = (id: string) => {
        const updated = savedSubjects.filter(s => s.id !== id);
        setSavedSubjects(updated);
        localStorage.setItem('stretto_subject_library', JSON.stringify(updated));
    };

    const handleLoadSubject = (data: string) => { setAbcInput(data); };

    const subjectNotes = useMemo(() => {
        if (mode === 'abc') return parseSimpleAbc(abcInput, ppq || 480);
        return initialNotes; 
    }, [mode, abcInput, initialNotes, ppq]);

    const { 
        isAssembling, assemblyStatus, assemblyResult, assemblyLog, 
        setAssemblyResult, runAssembly 
    } = useStrettoAssembly({ notes: subjectNotes, ppq: ppq || 480, ts });

    const pairwiseResults = useMemo(() => {
        if (subjectNotes.length === 0 || viewMode !== 'pairwise') return [];
        const candidates: StrettoCandidate[] = [];
        const validNotes = subjectNotes.filter(n => !!n);
        if (validNotes.length === 0) return [];

        const durationTicks = Math.max(...validNotes.map(n => n.ticks + n.durationTicks));
        const maxDelay = durationTicks * 0.75; 
        const currentPpq = ppq || 480;
        let stepTicks = currentPpq; 
        if (searchRes === 'half') stepTicks = currentPpq / 2;
        else if (searchRes === 'double') stepTicks = currentPpq * 2;

        let intervalsToCheck = [...configIntervals];
        if (includeExtensions) {
            const exts = [3, 4, 8, 9, -3, -4, -8, -9];
            exts.forEach(e => { if (!intervalsToCheck.includes(e)) intervalsToCheck.push(e); });
        }

        intervalsToCheck.forEach(interval => {
            for (let d = stepTicks; d <= maxDelay; d += stepTicks) {
                candidates.push(analyzeStrettoCandidate(validNotes, interval, Math.round(d), currentPpq, ts, false, 60));
                if (includeInversions) {
                    candidates.push(analyzeStrettoCandidate(validNotes, interval, Math.round(d), currentPpq, ts, true, 60));
                }
            }
        });
        return candidates;
    }, [subjectNotes, configIntervals, includeExtensions, includeInversions, ppq, ts, searchRes, viewMode]);

    const processedDiscoveryResults = useMemo(() => {
        return pairwiseResults.filter(r => gradeFilter[r.grade]);
    }, [pairwiseResults, gradeFilter]);

    const handleExportDiscoveryText = () => {
        if (processedDiscoveryResults.length === 0) {
            alert("No results to export with current filters.");
            return;
        }

        let report = `# Stretto Pairwise Discovery Report\n`;
        report += `Generated: ${new Date().toLocaleString()}\n`;
        report += `Active Filters: ${Object.entries(gradeFilter).filter(([_, v]) => v).map(([k]) => k).join(', ')}\n\n`;

        report += `| Interval | Delay | Verdict | Dissonance % | Resolution | Errors |\n`;
        report += `| :--- | :--- | :--- | :--- | :--- | :--- |\n`;

        processedDiscoveryResults.forEach(r => {
            const diss = Math.round(r.dissonanceRatio * 100);
            const res = r.endsOnDissonance ? "Unresolved (!)" : "Resolved (✓)";
            const errs = r.errors.length > 0 ? r.errors.map(e => e.type).join(', ') : '-';
            report += `| ${r.intervalLabel} | ${r.delayBeats}B | ${r.grade} | ${diss}% | ${res} | ${errs} |\n`;
        });

        const blob = new Blob([report], { type: 'text/markdown' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `Stretto_Discovery_Report_${Date.now()}.md`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
    };

    const getSelectedCandidates = () => pairwiseResults.filter(r => checkedIds.has(r.id));

    const handleChainSearch = async () => {
        setIsSearching(true); setChainResults([]); setSearchReport(null); setSelectedChain(null);
        setTimeout(async () => {
            try {
                const report = await searchStrettoChains(subjectNotes.filter(n => !!n), { ...searchOptions, voiceNames }, ppq || 480);
                setChainResults(report.results); setSearchReport(report);
            } catch (e) { alert("Search failed."); } finally { setIsSearching(false); }
        }, 100);
    };

    const chainToCandidate = useMemo((): StrettoCandidate | null => {
        if (!selectedChain) return null;
        let allNotes: RawNote[] = [];
        const voices: RawNote[][] = [];
        const validSubjectNotes = subjectNotes.filter(n => !!n);
        const currentPpq = ppq || 480;
        if (validSubjectNotes.length === 0) return null;
        const sortedSubj = [...validSubjectNotes].sort((a,b)=>a.ticks-b.ticks);
        const startTick = sortedSubj[0].ticks;

        selectedChain.entries.forEach((entry) => {
            const entryStartTick = Math.round(entry.startBeat * currentPpq);
            const transformed = sortedSubj.map(n => {
                let pitch = n.midi;
                if (entry.type === 'I') {
                    // Anchor inversion entry pitch
                    const subjEntry = sortedSubj[0].midi;
                    const targetEntry = subjEntry + entry.transposition;
                    pitch = subjEntry + targetEntry - n.midi;
                } else {
                    pitch += entry.transposition;
                }
                return { ...n, ticks: (n.ticks - startTick) + entryStartTick, midi: pitch, name: getStrictPitchName(pitch), voiceIndex: entry.voiceIndex };
            });
            const entryEnd = entryStartTick + (entry.length * (currentPpq/4));
            const clipped = transformed.filter(n => n.ticks < entryEnd).map(n => ({ ...n, durationTicks: Math.min(n.durationTicks, entryEnd - n.ticks) }));
            voices.push(clipped); allNotes = [...allNotes, ...clipped];
        });

        let chainRegions: HarmonicRegion[] = [];
        for (let i = 0; i < voices.length - 1; i++) {
            const regions = generateHarmonicRegions(getVerticalIntervals(voices[i], voices[i+1]));
            chainRegions = [...chainRegions, ...regions];
        }

        return { id: selectedChain.id, intervalLabel: "Chain", intervalSemis: 0, delayBeats: 0, delayTicks: 0, grade: 'STRONG', errors: [], notes: allNotes, regions: chainRegions, dissonanceRatio: 0, endsOnDissonance: false };
    }, [selectedChain, subjectNotes, ppq, searchOptions.pivotMidi]);

    const handlePlay = (notes: RawNote[]) => {
        if (isPlaying) { stopPlayback(); setIsPlaying(false); return; }
        setIsPlaying(true);
        const currentPpq = ppq || 480;
        playSequence(notes.filter(n => !!n).map(n => ({ 
            midi: n.midi, 
            name: n.name, 
            time: n.ticks * (0.5 / currentPpq), 
            duration: n.durationTicks * (0.5 / currentPpq), 
            velocity: n.velocity 
        })), () => setIsPlaying(false));
    };

    const toggleCheck = (id: string) => {
        setCheckedIds(prev => {
            const next = new Set(prev);
            if (next.has(id)) next.delete(id); else next.add(id);
            const cand = pairwiseResults.find(r => r.id === id);
            if (cand) setSelectedCandidate(cand);
            return next;
        });
    };

    return (
        <div className="w-full bg-gray-dark p-6 rounded-2xl border border-gray-medium animate-slide-up pb-32 relative">
            <div className="flex justify-between items-center mb-6">
                <h2 className="text-2xl font-bold text-gray-light">Stretto Assembly Lab</h2>
                {isAssembling && (
                    <div className="flex items-center gap-2 bg-brand-primary/20 px-4 py-2 rounded-full border border-brand-primary/40 animate-pulse">
                        <Spinner className="w-4 h-4 text-brand-primary" />
                        <span className="text-xs font-bold text-brand-primary">{assemblyStatus}</span>
                    </div>
                )}
            </div>

            <div className="flex flex-col md:flex-row gap-4 mb-6 p-4 bg-gray-800 rounded-lg border border-gray-700 justify-between">
                <div className="flex gap-2 items-center">
                    <span className="text-xs font-bold text-gray-500 mr-2">INPUT:</span>
                    <button onClick={() => setMode('midi')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${mode === 'midi' ? 'bg-brand-primary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Selected MIDI</button>
                    <button onClick={() => setMode('abc')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${mode === 'abc' ? 'bg-brand-primary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>ABC Notation</button>
                </div>
                <div className="flex gap-2 items-center border-l border-gray-600 pl-4">
                    <span className="text-xs font-bold text-gray-500 mr-2">MODE:</span>
                    <button onClick={() => setViewMode('pairwise')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${viewMode === 'pairwise' ? 'bg-brand-secondary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Pairwise Discovery</button>
                    <button onClick={() => setViewMode('chain')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${viewMode === 'chain' ? 'bg-brand-secondary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Algorithmic Chain</button>
                </div>
            </div>

            {mode === 'abc' && (
                <div className="mb-6 space-y-4">
                    <div className="flex justify-between items-center">
                        <label className="block text-sm text-gray-400 font-bold uppercase tracking-wider">Subject ABC</label>
                        <button onClick={() => setShowLibrary(!showLibrary)} className="text-xs bg-gray-800 hover:bg-gray-700 text-brand-primary border border-brand-primary/30 px-3 py-1 rounded flex items-center gap-2 transition-colors">
                            <DocumentTextIcon className="w-3 h-3" /> {showLibrary ? "Hide Library" : "Subject Library"}
                        </button>
                    </div>
                    {showLibrary && (
                        <div className="bg-gray-800 p-4 rounded-lg border border-gray-700 animate-fade-in">
                            <div className="flex gap-2 mb-4 border-b border-gray-700 pb-4">
                                <input type="text" placeholder="Subject Name..." value={saveName} onChange={(e) => setSaveName(e.target.value)} className="flex-grow bg-gray-900 border border-gray-600 rounded px-3 py-1 text-sm text-white outline-none" />
                                <button onClick={handleSaveSubject} disabled={!saveName.trim()} className="bg-brand-primary hover:bg-brand-secondary text-white px-4 py-1 rounded text-sm font-bold transition-colors disabled:bg-gray-600">Save</button>
                            </div>
                            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-2 max-h-48 overflow-y-auto">
                                {savedSubjects.length > 0 ? savedSubjects.map(s => (
                                    <div key={s.id} className="flex justify-between items-center bg-gray-900 p-2 rounded border border-gray-700 group">
                                        <span className="text-sm font-bold text-gray-300 truncate mr-2">{s.name}</span>
                                        <div className="flex gap-1 opacity-50 group-hover:opacity-100">
                                            <button onClick={() => handleLoadSubject(s.data)} className="text-[10px] bg-brand-secondary/50 px-2 py-0.5 rounded">Load</button>
                                            <button onClick={() => handleDeleteSubject(s.id)} className="text-[10px] bg-red-900/50 px-2 py-0.5 rounded">×</button>
                                        </div>
                                    </div>
                                )) : <p className="text-xs text-gray-500 col-span-full text-center py-2">Library empty.</p>}
                            </div>
                        </div>
                    )}
                    <textarea value={abcInput} onChange={e => setAbcInput(e.target.value)} className="w-full bg-gray-900 border border-gray-700 rounded p-3 text-white font-mono h-24 outline-none focus:border-brand-primary" />
                </div>
            )}

            {viewMode === 'pairwise' ? (
                <>
                    <StrettoConfig selectedIntervals={configIntervals} setSelectedIntervals={setConfigIntervals} searchRes={searchRes} setSearchRes={setSearchRes} includeInversions={includeInversions} setIncludeInversions={setIncludeInversions} includeExtensions={includeExtensions} setIncludeExtensions={setIncludeExtensions} />
                    <div className="flex justify-end mb-2">
                        <button 
                            onClick={handleExportDiscoveryText}
                            className="flex items-center gap-2 text-xs bg-gray-800 hover:bg-gray-700 text-gray-300 px-3 py-1.5 rounded border border-gray-600 transition-colors shadow-sm"
                        >
                            <DocumentTextIcon className="w-4 h-4" /> Export Table (.md)
                        </button>
                    </div>
                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
                        <StrettoList 
                            candidates={pairwiseResults} 
                            processedResults={processedDiscoveryResults}
                            gradeFilter={gradeFilter}
                            setGradeFilter={setGradeFilter}
                            selectedId={selectedCandidate?.id || null} 
                            onSelect={setSelectedCandidate} 
                            checkedIds={checkedIds} 
                            onToggleCheck={toggleCheck} 
                        />
                        <StrettoInspector candidate={selectedCandidate} ppq={ppq || 480} ts={ts} isPlaying={isPlaying} onPlay={handlePlay} assemblyResult={assemblyResult} assemblyLog={assemblyLog} onClearAssembly={() => setAssemblyResult('')} onDownloadChain={() => selectedCandidate && downloadStrettoCandidate(selectedCandidate, ppq || 480, voiceNames)} />
                    </div>
                    <StrettoFooter selectedCandidates={getSelectedCandidates()} onDownloadMidi={() => downloadStrettoSelection(getSelectedCandidates(), ppq || 480, voiceNames)} onAssemble={() => runAssembly(checkedIds.size > 0 ? getSelectedCandidates() : (selectedCandidate ? [selectedCandidate] : []), abcInput)} isAssembling={isAssembling} onRemoveCandidate={toggleCheck} />
                </>
            ) : (
                <StrettoChainView searchOptions={searchOptions} setSearchOptions={setSearchOptions} onSearch={handleChainSearch} isSearching={isSearching} chainResults={chainResults} selectedChain={selectedChain} setSelectedChain={setSelectedChain} voiceNames={voiceNames} setVoiceNames={setVoiceNames} chainToCandidate={chainToCandidate} ppq={ppq || 480} ts={ts} isPlaying={isPlaying} onPlay={handlePlay} onDownloadChain={() => chainToCandidate && downloadStrettoCandidate(chainToCandidate, ppq || 480, voiceNames)} searchReport={searchReport} />
            )}
        </div>
    );
}

import React, { useState, useMemo } from 'react';
import { StrettoCandidate, StrettoGrade } from '../../types';
import { getStrictPitchName } from '../services/midiSpelling';
import { DocumentTextIcon } from '../Icons';

interface StrettoListProps {
    candidates: StrettoCandidate[];
    processedResults: StrettoCandidate[]; // Results that passed the grade filter
    gradeFilter: Record<StrettoGrade, boolean>;
    setGradeFilter: (val: Record<StrettoGrade, boolean>) => void;
    selectedId: string | null;
    onSelect: (candidate: StrettoCandidate) => void;
    checkedIds: Set<string>;
    onToggleCheck: (id: string) => void;
}

type SortKey = 'grade' | 'delay' | 'interval' | 'dissonance' | 'entry' | 'errors';

export default function StrettoList({ 
    candidates, processedResults, gradeFilter, setGradeFilter, 
    selectedId, onSelect, checkedIds, onToggleCheck 
}: StrettoListProps) {
    const [sortKey, setSortKey] = useState<SortKey>('grade');
    const [sortDir, setSortDir] = useState<'asc' | 'desc'>('desc');

    // Multi-select Filters
    const [selectedPitches, setSelectedPitches] = useState<Set<string>>(new Set());
    const [selectedIntervals, setSelectedIntervals] = useState<Set<string>>(new Set());
    const [selectedDelays, setSelectedDelays] = useState<Set<string>>(new Set());

    // Logic Filters
    const [maxDissonance, setMaxDissonance] = useState<number>(100);
    const [onlyResolved, setOnlyResolved] = useState<boolean>(false);

    // Extract unique values for filter toggles
    const { availablePitches, availableIntervals, availableDelays } = useMemo(() => {
        const pitches = new Set<string>();
        const intervals = new Set<string>();
        const delays = new Set<string>();

        candidates.forEach(c => {
            const firstAnswerNote = c.notes.find(n => n.voiceIndex === 1);
            if (firstAnswerNote) {
                pitches.add(getStrictPitchName(firstAnswerNote.midi).replace(/\d/g, ''));
            }
            intervals.add(c.intervalLabel);
            delays.add(c.delayBeats.toString());
        });

        return {
            availablePitches: Array.from(pitches).sort(),
            availableIntervals: Array.from(intervals).sort((a,b) => a.localeCompare(b, undefined, {numeric: true})),
            availableDelays: Array.from(delays).sort((a,b) => parseFloat(a) - parseFloat(b))
        };
    }, [candidates]);

    // Combined Advanced Filtering
    const finalFilteredResults = useMemo(() => {
        return processedResults.filter(r => {
            if (!gradeFilter[r.grade]) return false;

            if (selectedPitches.size > 0) {
                const firstAnswerNote = r.notes.find(n => n.voiceIndex === 1);
                if (!firstAnswerNote) return false;
                const pName = getStrictPitchName(firstAnswerNote.midi).replace(/\d/g, '');
                if (!selectedPitches.has(pName)) return false;
            }

            if (selectedIntervals.size > 0 && !selectedIntervals.has(r.intervalLabel)) return false;

            if (selectedDelays.size > 0 && !selectedDelays.has(r.delayBeats.toString())) return false;

            if (Math.round(r.dissonanceRatio * 100) > maxDissonance) return false;

            if (onlyResolved && r.endsOnDissonance) return false;

            return true;
        });
    }, [processedResults, gradeFilter, selectedPitches, selectedIntervals, selectedDelays, maxDissonance, onlyResolved]);

    // Sorting Logic
    const sortedResults = useMemo(() => {
        const res = [...finalFilteredResults];
        res.sort((a, b) => {
            let diff = 0;
            const firstA = a.notes.find(n => n.voiceIndex === 1);
            const firstB = b.notes.find(n => n.voiceIndex === 1);

            switch (sortKey) {
                case 'grade':
                    const score = { 'STRONG': 3, 'VIABLE': 2, 'INVALID': 1 };
                    diff = score[a.grade] - score[b.grade];
                    break;
                case 'delay':
                    diff = a.delayTicks - b.delayTicks;
                    break;
                case 'interval':
                    diff = Math.abs(a.intervalSemis) - Math.abs(b.intervalSemis);
                    break;
                case 'dissonance':
                    diff = a.dissonanceRatio - b.dissonanceRatio;
                    break;
                case 'entry':
                    diff = (firstA?.midi || 0) - (firstB?.midi || 0);
                    break;
                case 'errors':
                    diff = a.errors.length - b.errors.length;
                    break;
            }
            return sortDir === 'asc' ? diff : -diff;
        });
        return res;
    }, [finalFilteredResults, sortKey, sortDir]);

    const handleSort = (key: SortKey) => {
        if (sortKey === key) setSortDir(prev => prev === 'asc' ? 'desc' : 'asc');
        else { setSortKey(key); setSortDir(key === 'grade' || key === 'dissonance' ? 'desc' : 'asc'); }
    };

    const handleExport = () => {
        if (sortedResults.length === 0) return;

        let md = `| Interval | Delay | Entry Note | Dissonance % | Errors |\n`;
        md += `| :--- | :--- | :--- | :--- | :--- |\n`;

        sortedResults.forEach(r => {
            const firstAnswerNote = r.notes.find(n => n.voiceIndex === 1);
            const entryNote = firstAnswerNote ? getStrictPitchName(firstAnswerNote.midi) : '?';
            const diss = `${Math.round(r.dissonanceRatio * 100)}%`;
            const errs = r.errors.length > 0 ? r.errors.map(e => e.type).join(', ') : '-';

            md += `| ${r.intervalLabel} | ${r.delayBeats}B | ${entryNote} | ${diss} | ${errs} |\n`;
        });

        const blob = new Blob([md], { type: 'text/markdown' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `Stretto_Lab_Export_${Date.now()}.md`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
    };

    const toggleFilterSet = (set: Set<string>, val: string) => {
        const next = new Set(set);
        if (next.has(val)) next.delete(val);
        else next.add(val);
        return next;
    };

    const renderToggleGroup = (label: string, items: string[], current: Set<string>, update: (s: Set<string>) => void) => (
        <div className="flex flex-col gap-1">
            <div className="flex justify-between items-center">
                <label className="text-[9px] font-bold text-gray-500 uppercase tracking-widest">{label}</label>
                <button onClick={() => update(new Set())} className="text-[8px] text-brand-primary hover:underline">{current.size === 0 ? 'All' : 'Clear'}</button>
            </div>
            <div className="flex flex-wrap gap-1 max-h-12 overflow-y-auto bg-black/20 p-1 rounded border border-gray-700 shadow-inner">
                {items.map(item => (
                    <button
                        key={item}
                        onClick={() => update(toggleFilterSet(current, item))}
                        className={`px-1.5 py-0.5 text-[9px] font-bold rounded transition-all border ${current.has(item) ? 'bg-brand-primary border-brand-primary text-white shadow-sm' : 'bg-gray-800 border-gray-600 text-gray-500 hover:border-gray-400'}`}
                    >
                        {item}
                    </button>
                ))}
            </div>
        </div>
    );

    return (
        <div className="bg-gray-900 border border-gray-700 rounded h-[600px] flex flex-col shadow-inner relative">
            <div className="p-3 border-b border-gray-700 bg-gray-800 flex flex-col gap-4">
                <div className="flex justify-between items-center -mb-2">
                    <h3 className="text-[10px] font-bold text-brand-primary uppercase tracking-tighter">Power Filter</h3>
                    <button 
                        onClick={handleExport}
                        className="flex items-center gap-1.5 px-2 py-1 bg-gray-700 hover:bg-gray-600 text-[9px] text-gray-300 rounded border border-gray-600 transition-colors"
                    >
                        <DocumentTextIcon className="w-3.5 h-3.5" /> Export Grid
                    </button>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
                    {renderToggleGroup("Intervals", availableIntervals, selectedIntervals, setSelectedIntervals)}
                    {renderToggleGroup("Delays", availableDelays, selectedDelays, setSelectedDelays)}
                    {renderToggleGroup("Entry Pitches", availablePitches, selectedPitches, setSelectedPitches)}
                </div>

                <div className="grid grid-cols-1 md:grid-cols-3 gap-4 border-t border-gray-700 pt-3">
                    <div className="flex flex-col gap-1">
                        <label className="text-[9px] font-bold text-gray-500 uppercase tracking-widest">Verdict</label>
                        <div className="flex gap-1">
                            {(['STRONG', 'VIABLE', 'INVALID'] as StrettoGrade[]).map(g => (
                                <button 
                                    key={g}
                                    onClick={() => setGradeFilter({ ...gradeFilter, [g]: !gradeFilter[g] })} 
                                    className={`flex-1 py-1 text-[9px] rounded font-bold border transition-all ${gradeFilter[g] ? 'bg-brand-primary/20 border-brand-primary text-brand-primary' : 'bg-gray-900 border-gray-700 text-gray-600'}`}
                                >
                                    {g.charAt(0)}
                                </button>
                            ))}
                        </div>
                    </div>

                    <div className="flex flex-col gap-1">
                        <div className="flex justify-between">
                            <label className="text-[9px] font-bold text-gray-500 uppercase tracking-widest">Max Dissonance</label>
                            <span className="text-[9px] font-mono text-brand-primary font-bold">{maxDissonance}%</span>
                        </div>
                        <input 
                            type="range" min="0" max="100" step="1" 
                            value={maxDissonance} 
                            onChange={(e) => setMaxDissonance(parseInt(e.target.value))}
                            className="w-full h-1 bg-gray-700 rounded-lg appearance-none cursor-pointer accent-brand-primary"
                        />
                    </div>

                    <div className="flex flex-col justify-end">
                        <label className={`flex items-center gap-2 p-2 bg-gray-900/50 rounded border cursor-pointer transition-all ${onlyResolved ? 'border-green-500/50 bg-green-900/10' : 'border-gray-700'}`}>
                            <input 
                                type="checkbox" 
                                checked={onlyResolved} 
                                onChange={(e) => setOnlyResolved(e.target.checked)}
                                className="w-3 h-3 rounded bg-gray-800 border-gray-600 text-brand-primary"
                            />
                            <span className={`text-[10px] font-bold uppercase tracking-tight ${onlyResolved ? 'text-green-400' : 'text-gray-500'}`}>Resolved End Only</span>
                        </label>
                    </div>
                </div>
            </div>

            <div className="overflow-y-auto flex-grow p-1">
                <div className="sticky top-0 bg-gray-900 z-10 grid grid-cols-12 gap-1 px-2 py-2 text-[9px] font-bold text-gray-500 uppercase border-b border-gray-800">
                    <div className="col-span-1"></div>
                    <button onClick={() => handleSort('interval')} className={`col-span-2 text-left hover:text-white transition-colors ${sortKey === 'interval' ? 'text-brand-primary' : ''}`}>
                        Int {sortKey === 'interval' && (sortDir === 'asc' ? '↑' : '↓')}
                    </button>
                    <button onClick={() => handleSort('delay')} className={`col-span-2 text-left hover:text-white transition-colors ${sortKey === 'delay' ? 'text-brand-primary' : ''}`}>
                        Delay {sortKey === 'delay' && (sortDir === 'asc' ? '↑' : '↓')}
                    </button>
                    <button onClick={() => handleSort('entry')} className={`col-span-2 text-left hover:text-white transition-colors ${sortKey === 'entry' ? 'text-brand-primary' : ''}`}>
                        Entry {sortKey === 'entry' && (sortDir === 'asc' ? '↑' : '↓')}
                    </button>
                    <button onClick={() => handleSort('dissonance')} className={`col-span-2 text-left hover:text-white transition-colors ${sortKey === 'dissonance' ? 'text-brand-primary' : ''}`}>
                        Diss % {sortKey === 'dissonance' && (sortDir === 'asc' ? '↑' : '↓')}
                    </button>
                    <div className="col-span-1 text-center">End</div>
                    <button onClick={() => handleSort('errors')} className={`col-span-2 text-right hover:text-white transition-colors ${sortKey === 'errors' ? 'text-brand-primary' : ''}`}>
                        Err {sortKey === 'errors' && (sortDir === 'asc' ? '↑' : '↓')}
                    </button>
                </div>

                {sortedResults.length === 0 ? (
                    <div className="py-20 text-center text-gray-600 text-sm italic">No matching strettos. Try widening filters.</div>
                ) : (
                    sortedResults.map((r) => {
                        const firstAnswerNote = r.notes.find(n => n.voiceIndex === 1);
                        const entryNote = firstAnswerNote ? getStrictPitchName(firstAnswerNote.midi) : '?';
                        return (
                            <div 
                                key={r.id} 
                                onClick={() => onSelect(r)} 
                                className={`grid grid-cols-12 gap-1 p-2 rounded cursor-pointer border-b border-gray-800 items-center transition-all ${selectedId === r.id ? 'bg-gray-800 ring-1 ring-brand-primary/50' : 'hover:bg-gray-800/50'}`}
                            >
                                <div className="col-span-1 flex justify-center" onClick={(e) => e.stopPropagation()}>
                                    <input 
                                        type="checkbox" 
                                        checked={checkedIds.has(r.id)} 
                                        onChange={() => onToggleCheck(r.id)} 
                                        className="rounded bg-gray-700 border-gray-600 text-brand-primary w-3 h-3" 
                                    />
                                </div>
                                <span className={`col-span-2 font-bold text-[10px] truncate ${r.intervalLabel.includes('Inv') ? 'text-blue-400' : 'text-brand-primary'}`}>
                                    {r.intervalLabel}
                                </span>
                                <span className="col-span-2 text-gray-300 text-[10px]">{r.delayBeats}B</span>
                                <span className="col-span-2 text-gray-500 text-[10px] font-mono">{entryNote}</span>
                                <span className={`col-span-2 text-[10px] font-mono font-bold ${r.dissonanceRatio > 0.4 ? 'text-red-400' : r.dissonanceRatio > 0.2 ? 'text-yellow-400' : 'text-green-400'}`}>
                                    {Math.round(r.dissonanceRatio * 100)}%
                                </span>
                                <div className="col-span-1 flex justify-center">
                                    {r.endsOnDissonance ? <span className="text-red-500 font-bold text-[11px]">!</span> : <span className="text-green-500 font-bold text-[11px]">✓</span>}
                                </div>
                                <span className="col-span-2 text-[9px] text-gray-500 text-right">
                                    {r.errors.length > 0 ? (
                                        <span className="bg-red-900/30 text-red-400 px-1 rounded border border-red-900/50">{r.errors.length}</span>
                                    ) : '-'}
                                </span>
                            </div>
                        );
                    })
                )}
            </div>

            <div className="p-2 border-t border-gray-800 bg-gray-800/50 flex justify-between items-center px-4">
                <div className="flex items-center gap-3">
                    <span className="text-[10px] text-gray-500 italic">{sortedResults.length} Visible</span>
                    <span className="text-[10px] text-gray-700">|</span>
                    <span className="text-[10px] text-gray-500">{checkedIds.size} Selected</span>
                </div>
                <button 
                    onClick={() => { 
                        setSelectedIntervals(new Set()); 
                        setSelectedDelays(new Set()); 
                        setSelectedPitches(new Set()); 
                        setMaxDissonance(100); 
                        setOnlyResolved(false);
                        setGradeFilter({STRONG: true, VIABLE: true, INVALID: true}) 
                    }}
                    className="text-[9px] text-brand-primary hover:text-white uppercase font-bold tracking-wider"
                >
                    Reset Power Filter
                </button>
            </div>
        </div>
    );
}

import React, { useState, useMemo, useEffect } from 'react';
import { RawNote, StrettoCandidate, StrettoSearchOptions, StrettoChainResult, HarmonicRegion, StrettoSearchReport, StrettoGrade } from '../types';
import { parseSimpleAbc } from './services/abcBridge';
import { analyzeStrettoCandidate, getVerticalIntervals, generateHarmonicRegions } from './services/strettoCore';
import { searchStrettoChains } from './services/strettoGenerator'; 
import { getStrictPitchName } from './services/midiSpelling';
import { downloadStrettoCandidate, downloadStrettoSelection } from './services/strettoExport';
import { Spinner, DocumentTextIcon } from './Icons';
import { playSequence, stopPlayback } from './midiPlaybackService';
import { useStrettoAssembly } from '../hooks/useStrettoAssembly';

import StrettoConfig, { SearchResolution } from './stretto/StrettoConfig';
import StrettoList from './stretto/StrettoList';
import StrettoInspector from './stretto/StrettoInspector';
import StrettoFooter from './stretto/StrettoFooter';
import StrettoChainView from './stretto/StrettoChainView'; 

interface StrettoViewProps {
    notes: RawNote[]; 
    ppq: number;
    ts: { num: number, den: number };
    voiceNames?: Record<number, string>;
    setVoiceNames?: (names: Record<number, string>) => void;
}

interface SavedSubject {
    id: string;
    name: string;
    data: string;
}

export default function StrettoView({ notes: initialNotes, ppq, ts, voiceNames, setVoiceNames }: StrettoViewProps) {
    const [mode, setMode] = useState<'midi' | 'abc'>(initialNotes.length > 0 ? 'midi' : 'abc');
    const [abcInput, setAbcInput] = useState<string>("M:4/4\nL:1/4\nQ:120\nK:C\nc2 G c d e f g3 a b c'2");
    const [viewMode, setViewMode] = useState<'pairwise' | 'chain'>('chain'); 

    const [gradeFilter, setGradeFilter] = useState<Record<StrettoGrade, boolean>>({
        'STRONG': true,
        'VIABLE': true,
        'INVALID': false
    });

    const [savedSubjects, setSavedSubjects] = useState<SavedSubject[]>([]);
    const [saveName, setSaveName] = useState('');
    const [showLibrary, setShowLibrary] = useState(false);

    const [configIntervals, setConfigIntervals] = useState<number[]>([0, 12, -12, 7, -7, 5, -5, 24, -24]);
    const [includeExtensions, setIncludeExtensions] = useState(false);
    const [includeInversions, setIncludeInversions] = useState(false);
    const [searchRes, setSearchRes] = useState<SearchResolution>('full');
    const [selectedCandidate, setSelectedCandidate] = useState<StrettoCandidate | null>(null);
    const [checkedIds, setCheckedIds] = useState<Set<string>>(new Set());

    const [searchOptions, setSearchOptions] = useState<StrettoSearchOptions>({
        ensembleTotal: 4,
        targetChainLength: 8,
        subjectVoiceIndex: 2, 
        truncationMode: 'Max 1',
        truncationMusicalValue: '1/2',
        inversionMode: 'None',
        thirdSixthMode: 'None',
        pivotMidi: 65, 
        requireConsonantEnd: true,
        disallowComplexExceptions: false
    });
    const [chainResults, setChainResults] = useState<StrettoChainResult[]>([]);
    const [searchReport, setSearchReport] = useState<StrettoSearchReport | null>(null);
    const [isSearching, setIsSearching] = useState(false);
    const [selectedChain, setSelectedChain] = useState<StrettoChainResult | null>(null);

    const [isPlaying, setIsPlaying] = useState(false);

    useEffect(() => {
        const saved = localStorage.getItem('stretto_subject_library');
        if (saved) {
            try { setSavedSubjects(JSON.parse(saved)); } catch (e) { console.error(e); }
        }
    }, []);

    const handleSaveSubject = () => {
        if (!saveName.trim() || !abcInput.trim()) return;
        const newSubject: SavedSubject = { id: Date.now().toString(), name: saveName.trim(), data: abcInput };
        const updated = [...savedSubjects, newSubject];
        setSavedSubjects(updated);
        localStorage.setItem('stretto_subject_library', JSON.stringify(updated));
        setSaveName('');
    };

    const handleDeleteSubject = (id: string) => {
        const updated = savedSubjects.filter(s => s.id !== id);
        setSavedSubjects(updated);
        localStorage.setItem('stretto_subject_library', JSON.stringify(updated));
    };

    const handleLoadSubject = (data: string) => { setAbcInput(data); };

    const subjectNotes = useMemo(() => {
        if (mode === 'abc') return parseSimpleAbc(abcInput, ppq || 480);
        return initialNotes; 
    }, [mode, abcInput, initialNotes, ppq]);

    const { 
        isAssembling, assemblyStatus, assemblyResult, assemblyLog, 
        setAssemblyResult, runAssembly 
    } = useStrettoAssembly({ notes: subjectNotes, ppq: ppq || 480, ts });

    const pairwiseResults = useMemo(() => {
        if (subjectNotes.length === 0 || viewMode !== 'pairwise') return [];
        const candidates: StrettoCandidate[] = [];
        const validNotes = subjectNotes.filter(n => !!n);
        if (validNotes.length === 0) return [];

        const durationTicks = Math.max(...validNotes.map(n => n.ticks + n.durationTicks));
        const maxDelay = durationTicks * 0.75; 
        const currentPpq = ppq || 480;
        let stepTicks = currentPpq; 
        if (searchRes === 'half') stepTicks = currentPpq / 2;
        else if (searchRes === 'double') stepTicks = currentPpq * 2;

        let intervalsToCheck = [...configIntervals];
        if (includeExtensions) {
            const exts = [3, 4, 8, 9, -3, -4, -8, -9];
            exts.forEach(e => { if (!intervalsToCheck.includes(e)) intervalsToCheck.push(e); });
        }

        intervalsToCheck.forEach(interval => {
            for (let d = stepTicks; d <= maxDelay; d += stepTicks) {
                candidates.push(analyzeStrettoCandidate(validNotes, interval, Math.round(d), currentPpq, ts, false, 60));
                if (includeInversions) {
                    candidates.push(analyzeStrettoCandidate(validNotes, interval, Math.round(d), currentPpq, ts, true, 60));
                }
            }
        });
        return candidates;
    }, [subjectNotes, configIntervals, includeExtensions, includeInversions, ppq, ts, searchRes, viewMode]);

    const processedDiscoveryResults = useMemo(() => {
        return pairwiseResults.filter(r => gradeFilter[r.grade]);
    }, [pairwiseResults, gradeFilter]);

    const getSelectedCandidates = () => pairwiseResults.filter(r => checkedIds.has(r.id));

    const handleChainSearch = async () => {
        setIsSearching(true); setChainResults([]); setSearchReport(null); setSelectedChain(null);
        setTimeout(async () => {
            try {
                const report = await searchStrettoChains(subjectNotes.filter(n => !!n), { ...searchOptions, voiceNames }, ppq || 480);
                setChainResults(report.results); setSearchReport(report);
            } catch (e) { alert("Search failed."); } finally { setIsSearching(false); }
        }, 100);
    };

    const chainToCandidate = useMemo((): StrettoCandidate | null => {
        if (!selectedChain) return null;
        let allNotes: RawNote[] = [];
        const voices: RawNote[][] = [];
        const validSubjectNotes = subjectNotes.filter(n => !!n);
        const currentPpq = ppq || 480;
        if (validSubjectNotes.length === 0) return null;
        const sortedSubj = [...validSubjectNotes].sort((a,b)=>a.ticks-b.ticks);
        const startTick = sortedSubj[0].ticks;

        selectedChain.entries.forEach((entry) => {
            const entryStartTick = Math.round(entry.startBeat * currentPpq);
            const transformed = sortedSubj.map(n => {
                let pitch = n.midi;
                if (entry.type === 'I') {
                    // Anchor inversion entry pitch
                    const subjEntry = sortedSubj[0].midi;
                    const targetEntry = subjEntry + entry.transposition;
                    pitch = subjEntry + targetEntry - n.midi;
                } else {
                    pitch += entry.transposition;
                }
                return { ...n, ticks: (n.ticks - startTick) + entryStartTick, midi: pitch, name: getStrictPitchName(pitch), voiceIndex: entry.voiceIndex };
            });
            const entryEnd = entryStartTick + (entry.length * (currentPpq/4));
            const clipped = transformed.filter(n => n.ticks < entryEnd).map(n => ({ ...n, durationTicks: Math.min(n.durationTicks, entryEnd - n.ticks) }));
            voices.push(clipped); allNotes = [...allNotes, ...clipped];
        });

        let chainRegions: HarmonicRegion[] = [];
        for (let i = 0; i < voices.length - 1; i++) {
            const regions = generateHarmonicRegions(getVerticalIntervals(voices[i], voices[i+1]));
            chainRegions = [...chainRegions, ...regions];
        }

        return { id: selectedChain.id, intervalLabel: "Chain", intervalSemis: 0, delayBeats: 0, delayTicks: 0, grade: 'STRONG', errors: [], notes: allNotes, regions: chainRegions, dissonanceRatio: 0, endsOnDissonance: false };
    }, [selectedChain, subjectNotes, ppq, searchOptions.pivotMidi]);

    const handlePlay = (notes: RawNote[]) => {
        if (isPlaying) { stopPlayback(); setIsPlaying(false); return; }
        setIsPlaying(true);
        const currentPpq = ppq || 480;
        playSequence(notes.filter(n => !!n).map(n => ({ 
            midi: n.midi, 
            name: n.name, 
            time: n.ticks * (0.5 / currentPpq), 
            duration: n.durationTicks * (0.5 / currentPpq), 
            velocity: n.velocity 
        })), () => setIsPlaying(false));
    };

    const toggleCheck = (id: string) => {
        setCheckedIds(prev => {
            const next = new Set(prev);
            if (next.has(id)) next.delete(id); else next.add(id);
            const cand = pairwiseResults.find(r => r.id === id);
            if (cand) setSelectedCandidate(cand);
            return next;
        });
    };

    return (
        <div className="w-full bg-gray-dark p-6 rounded-2xl border border-gray-medium animate-slide-up pb-32 relative">
            <div className="flex justify-between items-center mb-6">
                <h2 className="text-2xl font-bold text-gray-light">Stretto Assembly Lab</h2>
                {isAssembling && (
                    <div className="flex items-center gap-2 bg-brand-primary/20 px-4 py-2 rounded-full border border-brand-primary/40 animate-pulse">
                        <Spinner className="w-4 h-4 text-brand-primary" />
