import { RawNote, StrettoChainResult, StrettoSearchOptions, StrettoChainOption, StrettoConstraintMode, ScoreLog, StrettoSearchReport } from '../../types';
import { SCORING, INTERVALS } from './strettoConstants';
import { analyzeStrettoHarmony } from './strettoHarmonyAnalysis';
import { getVoiceLabel } from './midiVoices';

// --- StrettoGrid: High-Performance Spatial Indexing ---
class StrettoGrid {
    private buffer: Int8Array;
    private width: number;
    private voices: number;

    constructor(voices: number, duration: number) {
        this.voices = voices;
        this.width = duration;
        this.buffer = new Int8Array(voices * duration).fill(-1);
    }

    write(voiceIndex: number, notes: InternalSubjectNote[], offset: number, transposition: number) {
        const rowOffset = voiceIndex * this.width;
        for (let i = 0; i < notes.length; i++) {
            const n = notes[i];
            const val = n.pitch + transposition;
            const start = rowOffset + offset + n.relTick16;
            for (let t = 0; t < n.dur16; t++) {
                if (start + t < this.buffer.length) {
                    this.buffer[start + t] = val;
                }
            }
        }
    }

    clear(voiceIndex: number, notes: InternalSubjectNote[], offset: number) {
        const rowOffset = voiceIndex * this.width;
        for (let i = 0; i < notes.length; i++) {
            const n = notes[i];
            const start = rowOffset + offset + n.relTick16;
            for (let t = 0; t < n.dur16; t++) {
                if (start + t < this.buffer.length) {
                    this.buffer[start + t] = -1;
                }
            }
        }
    }

    hasParallelErrors(voiceIndex: number, notes: InternalSubjectNote[], offset: number, transposition: number): boolean {
        const rowOffset = voiceIndex * this.width;

        for (let i = 0; i < notes.length; i++) {
            const n = notes[i];
            const t = offset + n.relTick16;

            if (t <= 0) continue; 
            if (t >= this.width) break;

            const p1Curr = n.pitch + transposition;

            const prevIdx = rowOffset + t - 1;
            const p1Prev = this.buffer[prevIdx];

            if (p1Prev === -1 || p1Prev === p1Curr) continue; 

            for (let v = 0; v < this.voices; v++) {
                if (v === voiceIndex) continue;

                const otherRow = v * this.width;
                const p2Curr = this.buffer[otherRow + t];
                const p2Prev = this.buffer[otherRow + t - 1];

                if (p2Curr === -1 || p2Prev === -1) continue; 
                if (p2Curr === p2Prev) continue; 

                const loCurr = Math.min(p1Curr, p2Curr);
                const hiCurr = Math.max(p1Curr, p2Curr);
                const sCurr = (hiCurr - loCurr) % 12;

                if (sCurr === 0 || sCurr === 7) {
                    const loPrev = Math.min(p1Prev, p2Prev);
                    const hiPrev = Math.max(p1Prev, p2Prev);
                    const sPrev = (hiPrev - loPrev) % 12;
                    if (sPrev === sCurr) return true; 
                }
            }
        }
        return false;
    }
}

// --- Helper Functions ---

function isDissonant(lo: number, hi: number, lowerIsBass: boolean): boolean {
    const s = (hi - lo) % 12;
    if (INTERVALS.DISSONANT_SIMPLE.has(s)) return true;
    if (s === 5 && lowerIsBass) return true; 
    return false;
}

function isParallelPerfect(lo: number, hi: number): boolean {
    const s = (hi - lo) % 12;
    return s === 0 || s === 7;
}

// Inversion Logic
const MAJOR_SCALE_STEPS = [0, 2, 4, 5, 7, 9, 11];

function invertPitch(pitch: number, pivot: number, useChromatic: boolean): number | null {
    if (useChromatic) {
        return pivot - (pitch - pivot);
    }

    // Diatonic Inversion (Major Scale Assumption)
    const diff = pitch - pivot;
    const octaves = Math.floor(diff / 12);
    const semitone = (diff % 12 + 12) % 12;

    // Find closest scale step
    let degree = -1;
    let minErr = 99;
    MAJOR_SCALE_STEPS.forEach((s, i) => {
        if (Math.abs(s - semitone) < minErr) { 
            minErr = Math.abs(s - semitone); 
            degree = i; 
        }
    });

    // Invert the degree index relative to 0 (root)
    // 0 -> 0, 1 -> -1, etc.
    const absDegree = (octaves * 7) + degree;
    const invAbsDegree = -absDegree;

    const invOctaves = Math.floor(invAbsDegree / 7);
    const invIndex = (invAbsDegree % 7 + 7) % 7;

    return pivot + (invOctaves * 12) + MAJOR_SCALE_STEPS[invIndex];
}

function getVoiceName(index: number, total: number, names?: Record<number, string>): string {
    if (names && names[index]) return names[index];
    return getVoiceLabel(index, total);
}

// --- Timeline & Validation ---

interface Timeline {
    [tick16: number]: { [voiceIdx: number]: { pitch: number, dur16: number } }; 
}

interface InternalSubjectNote {
    relTick16: number; 
    dur16: number;
    pitch: number;
}

function normalizeSubject(notes: RawNote[], ppq: number): InternalSubjectNote[] {
    const validNotes = notes.filter(n => !!n);
    const sorted = [...validNotes].sort((a,b) => a.ticks - b.ticks);
    if (sorted.length === 0) return [];
    const startTick = sorted[0].ticks;
    const ticksPer16 = ppq / 4;
    return sorted.map(n => ({
        relTick16: Math.round((n.ticks - startTick) / ticksPer16),
        dur16: Math.max(1, Math.round(n.durationTicks / ticksPer16)),
        pitch: n.midi
    }));
}

function getEffectiveSubjectLength16(notes: InternalSubjectNote[]): number {
    if (notes.length === 0) return 0;
    let maxEnd = 0;
    notes.forEach(n => {
        const end = n.relTick16 + n.dur16;
        if (end > maxEnd) maxEnd = end;
    });
    return maxEnd;
}

function getSubjectNotes(
    type: 'N' | 'I', 
    baseSubject: InternalSubjectNote[], 
    invertedSubject: InternalSubjectNote[], 
    length16: number
): InternalSubjectNote[] {
    const source = type === 'N' ? baseSubject : invertedSubject;
    return source.filter(n => n.relTick16 < length16).map(n => ({
        ...n,
        dur16: Math.min(n.dur16, length16 - n.relTick16)
    }));
}

function buildTimeline(
    specs: StrettoChainOption[], 
    baseSubject: InternalSubjectNote[], 
    invertedSubject: InternalSubjectNote[]
): Timeline {
    const tl: Timeline = {};
    specs.forEach((spec) => {
        const notes = getSubjectNotes(spec.type, baseSubject, invertedSubject, spec.length);
        const start16 = Math.round(spec.startBeat * 4);
        notes.forEach(n => {
            for (let t = 0; t < n.dur16; t++) {
                const absTick = start16 + n.relTick16 + t;
                if (!tl[absTick]) tl[absTick] = {};
                tl[absTick][spec.voiceIndex] = { 
                    pitch: n.pitch + spec.transposition,
                    dur16: n.dur16 
                };
            }
        });
    });
    return tl;
}

interface ValidationResult {
    isValid: boolean;
    errors: string[];
    warnings: string[];
    polyphonyIntegral: number;
    totalDuration: number;
    polyphonicDuration: number;
    bassDissDuration: number;
    upperDissDuration: number;
    harmonicReward: number;
    harmonicPenalty: number;
    detectedChords: string[];
}

function checkRulesAndStats(
    specs: StrettoChainOption[], 
    baseSubject: InternalSubjectNote[], 
    invertedSubject: InternalSubjectNote[],
    requireConsonantEnd: boolean,
    totalVoices: number,
    voiceNames?: Record<number, string>
): ValidationResult {

    const tl = buildTimeline(specs, baseSubject, invertedSubject);
    const ticks = Object.keys(tl).map(Number).sort((a,b) => a-b);
    const errors: string[] = [];
    const warnings: string[] = [];
    const usedVoices = new Set<number>();
    specs.forEach(s => usedVoices.add(s.voiceIndex));
    const voices = Array.from(usedVoices).sort((a,b) => a-b);

    let polyphonyIntegral = 0;
    let totalDuration = 0;
    let polyphonicDuration = 0;
    let bassDissDuration = 0;
    let upperDissDuration = 0;

    if (ticks.length > 0) {
        const minT = ticks[0];
        const maxT = ticks[ticks.length - 1];
        totalDuration = maxT - minT + 1;

        for (let t = minT; t <= maxT; t++) {
            const activeVoiceMap = tl[t];
            if (!activeVoiceMap) continue; 
            const activeCount = Object.keys(activeVoiceMap).length;
            if (activeCount > 0) polyphonyIntegral += (activeCount - SCORING.POLYPHONY_OFFSET);
            if (activeCount < 2) continue; 
            polyphonicDuration += 1;

            const pitches: number[] = [];
            const activeIndices = Object.keys(activeVoiceMap).map(Number);
            activeIndices.forEach(v => pitches.push(activeVoiceMap[v].pitch));
            pitches.sort((a,b) => a-b);
            const bassPitch = pitches[0];
            const bassVoiceIdx = parseInt(Object.keys(activeVoiceMap).find(k => activeVoiceMap[parseInt(k)].pitch === bassPitch) || "-1");

            for (let i = 0; i < activeIndices.length; i++) {
                for (let j = i + 1; j < activeIndices.length; j++) {
                    const vA = activeIndices[i];
                    const vB = activeIndices[j];
                    const p1 = activeVoiceMap[vA].pitch;
                    const p2 = activeVoiceMap[vB].pitch;
                    const lo = Math.min(p1, p2);
                    const hi = Math.max(p1, p2);
                    const isBassPair = (vA === bassVoiceIdx || vB === bassVoiceIdx);
                    if (isDissonant(lo, hi, isBassPair)) {
                        if (isBassPair) bassDissDuration += 1; 
                        else upperDissDuration += 1;
                    }
                }
            }
        }
    }

    const { reward, penalty, chords } = analyzeStrettoHarmony(tl, ticks);

    for (let i = 0; i < voices.length; i++) {
        for (let j = i + 1; j < voices.length; j++) {
            const vA = voices[i];
            const vB = voices[j];
            const sounding: { t: number, lo: number, hi: number, lowerIsBass: boolean, p1: number, p2: number }[] = [];

            ticks.forEach(t => {
                const v = tl[t];
                if (v[vA] !== undefined && v[vB] !== undefined) {
                    const minAll = Math.min(...Object.values(v).map(d => d.pitch));
                    const p1 = v[vA].pitch;
                    const p2 = v[vB].pitch;
                    const lo = Math.min(p1, p2);
                    const hi = Math.max(p1, p2);
                    sounding.push({ t, lo, hi, lowerIsBass: lo === minAll, p1, p2 });
                }
            });

            if (sounding.length < 2) continue;

            for (let k = 1; k < sounding.length; k++) {
                const prev = sounding[k-1];
                const curr = sounding[k];
                if (prev.p1 === curr.p1 && prev.p2 === curr.p2) continue;
                const p1Moved = prev.p1 !== curr.p1;
                const p2Moved = prev.p2 !== curr.p2;
                if (!p1Moved || !p2Moved) continue; 

                if (isParallelPerfect(curr.lo, curr.hi)) {
                    if (isParallelPerfect(prev.lo, prev.hi)) {
                        const int1 = (prev.hi - prev.lo) % 12;
                        const int2 = (curr.hi - curr.lo) % 12;
                        if (int1 === int2) {
                            errors.push(`Parallel ${int1 === 7 ? '5th' : '8ve'} (${getVoiceName(vA, totalVoices, voiceNames)}, ${getVoiceName(vB, totalVoices, voiceNames)})`);
                        }
                    }
                }
            }

            let k = 0;
            while (k < sounding.length) {
                const startEv = sounding[k];
                if (!isDissonant(startEv.lo, startEv.hi, startEv.lowerIsBass)) { k++; continue; }
                let segStart = k;
                while (k < sounding.length) {
                    const curr = sounding[k];
                    if (!isDissonant(curr.lo, curr.hi, curr.lowerIsBass)) break;
                    if ((curr.t - sounding[segStart].t + 1) >= 4) { 
                        const distinctPitches = new Set<string>();
                        for(let m = segStart; m <= k; m++) distinctPitches.add(`${sounding[m].p1}-${sounding[m].p2}`);
                        if (distinctPitches.size > 1) {
                            errors.push(`Unresolved Dissonance Run (${getVoiceName(vA, totalVoices, voiceNames)}, ${getVoiceName(vB, totalVoices, voiceNames)})`);
                            break; 
                        }
                    }
                    k++;
                }
            }
        }
    }

    if (requireConsonantEnd) {
        for (const spec of specs) {
            const start16 = Math.round(spec.startBeat * 4);
            const end16 = start16 + spec.length; 
            const checkTick = end16 - 1;
            const activeVoices = tl[checkTick];
            if (!activeVoices || Object.keys(activeVoices).length < 2) continue;

            const myData = activeVoices[spec.voiceIndex];
            if (!myData) continue;
            const myPitch = myData.pitch;
            const activePitches = Object.values(activeVoices).map(v => v.pitch);
            const bassPitch = Math.min(...activePitches);

            let hasConsonance = false;
            for (const otherVStr in activeVoices) {
                const otherV = parseInt(otherVStr);
                if (otherV === spec.voiceIndex) continue;
                const otherPitch = activeVoices[otherV].pitch;
                const interval = Math.abs(myPitch - otherPitch) % 12;
                if (INTERVALS.CONSONANT.has(interval)) { hasConsonance = true; break; }
                if (interval === 5) {
                    const pairLower = Math.min(myPitch, otherPitch);
                    if (pairLower > bassPitch) { hasConsonance = true; break; }
                }
            }
            if (!hasConsonance) errors.push(`Non-Consonant Ending (${getVoiceName(spec.voiceIndex, totalVoices, voiceNames)})`);
        }
    }

    return { 
        isValid: errors.length === 0, 
        errors, warnings, polyphonyIntegral, totalDuration, polyphonicDuration,
        bassDissDuration, upperDissDuration, harmonicReward: reward, harmonicPenalty: penalty,
        detectedChords: chords
    };
}

// --- Pre-Pass Discovery ---

interface EntryCandidate {
    transposition: number;
    delayBeats: number;
    type: 'N' | 'I';
    score: number;
}

function findValidPairwiseCandidates(
    baseSubject: InternalSubjectNote[], 
    invertedSubject: InternalSubjectNote[], 
    options: StrettoSearchOptions, 
    validTranspositions: number[],
    effectiveLen16: number,
    subjectDurationBeats: number
): EntryCandidate[] {
    const candidates: EntryCandidate[] = [];

    const voice0: StrettoChainOption = {
        startBeat: 0, transposition: 0, type: 'N', length: effectiveLen16, voiceIndex: 0
    };

    const delays: number[] = [];
    const maxDelay = Math.max(0.5, subjectDurationBeats * (2/3));
    for(let d = 0.5; d <= maxDelay; d += 0.5) delays.push(d);

    const types: {type: 'N'|'I', source: InternalSubjectNote[]}[] = [];
    types.push({ type: 'N', source: baseSubject });
    if (options.inversionMode !== 'None' && invertedSubject.length > 0) {
        types.push({ type: 'I', source: invertedSubject });
    }

    for (const d of delays) {
        for (const t of validTranspositions) {
            for (const typeObj of types) {
                if (options.disallowComplexExceptions && typeObj.type === 'I') {
                    const intervalClass = Math.abs(t % 12);
                    const isPerfect = [0, 5, 7].includes(intervalClass);
                    if (!isPerfect) continue; 
                }

                const voice1: StrettoChainOption = {
                    startBeat: d, transposition: t, type: typeObj.type,
                    length: effectiveLen16, voiceIndex: 1
                };

                const res = checkRulesAndStats([voice0, voice1], baseSubject, invertedSubject, options.requireConsonantEnd, options.ensembleTotal, options.voiceNames);
                if (res.isValid) {
                    let score = res.polyphonyIntegral;
                    if (res.bassDissDuration === 0) score += 50; 
                    candidates.push({
                        transposition: t, delayBeats: d, type: typeObj.type, score: score
                    });
                }
            }
        }
    }

    return candidates.sort((a,b) => {
        if (b.score !== a.score) return b.score - a.score;
        return Math.abs(a.transposition) - Math.abs(b.transposition);
    });
}

// --- Search Algorithm ---

export async function searchStrettoChains(
    rawSubject: RawNote[],
    options: StrettoSearchOptions,
    ppq: number
): Promise<StrettoSearchReport> {

    const START_TIME = Date.now();
    const TIME_LIMIT_MS = 30000; 
    const MAX_VISITED_NODES = 500000; 
    let nodesVisited = 0;
    let stopReason: 'Success' | 'Timeout' | 'NodeLimit' | 'Exhausted' = 'Exhausted';
    let maxDepthReached = 0;

    const baseSubject = normalizeSubject(rawSubject, ppq);
    if (baseSubject.length === 0) {
        return { results: [], stats: { nodesVisited: 0, timeMs: 0, stopReason: 'Exhausted', maxDepthReached: 0 } };
    }

    const effectiveLen16 = getEffectiveSubjectLength16(baseSubject);
    const subjectDurationBeats = effectiveLen16 / 4;

    const maxChainDuration16 = Math.ceil((options.targetChainLength * subjectDurationBeats * 4) * 2); 
    const grid = new StrettoGrid(options.ensembleTotal, maxChainDuration16);

    const invertedSubject: InternalSubjectNote[] = [];
    if (options.inversionMode !== 'None') {
        // Updated Inversion Calculation logic to respect Diatonic vs Chromatic setting
        const subjectStartMidi = baseSubject.length > 0 ? baseSubject[0].pitch : options.pivotMidi;

        // Logic: Calculate inverted shape first relative to pivot, then normalize to 0
        // The generator treats "transposition" as the offset from the base subject.
        // For Inversion: We calculate the inverted form starting at the SAME pitch as the subject (0 trans).

        const invertedRaw = baseSubject.map(n => {
            const inv = invertPitch(n.pitch, options.pivotMidi, options.useChromaticInversion);
            return { ...n, pitch: inv !== null ? inv : n.pitch };
        });

        // Re-align inverted shape to start at the subject's start pitch
        // If subject starts on C, inverted subject must assume it starts on C for 0 transposition.
        if (invertedRaw.length > 0) {
            const currentStart = invertedRaw[0].pitch;
            const diff = subjectStartMidi - currentStart;
            invertedRaw.forEach(n => n.pitch += diff);
        }

        invertedSubject.push(...invertedRaw);
    }

    const validResults: StrettoChainResult[] = [];
    const invalidResults: StrettoChainResult[] = [];
    const partialResults: StrettoChainResult[] = [];
    const MAX_VALID_RESULTS = 200; 
    const MAX_INVALID_BUFFER = 50; 
    const ensembleTotal = options.ensembleTotal;
    const targetChainLength = options.targetChainLength;

    const validTranspositions = Array.from(INTERVALS.TRAD_TRANSPOSITIONS);
    if (options.thirdSixthMode !== 'None') {
        INTERVALS.THIRD_SIXTH_TRANSPOSITIONS.forEach(t => {
            if (!validTranspositions.includes(t)) validTranspositions.push(t);
        });
    }

    const potentialCandidates = findValidPairwiseCandidates(baseSubject, invertedSubject, options, validTranspositions, effectiveLen16, subjectDurationBeats);

    const isBudgetAvailable = (mode: StrettoConstraintMode, currentUsage: number) => {
        if (mode === 'None') return false;
        if (mode === 'Max 1') return currentUsage < 1;
        return true; 
    };

    function processChain(chain: StrettoChainOption[], validation: ValidationResult, targetList: StrettoChainResult[]) {
        const log: ScoreLog = { base: 0, penalties: [], bonuses: [], total: 0 };
        let score = 0; 

        if (validation.totalDuration > 0) {
            const avgScore = validation.polyphonyIntegral / validation.totalDuration;
            const polyScore = SCORING.POLYPHONY_BASE_MULT * avgScore;
            score += polyScore;
            log.bonuses.push({ reason: `Polyphony Density`, points: Math.round(polyScore) });
        }

        if (validation.polyphonicDuration > 0) {
            const weightedDiss = (SCORING.DISS_WEIGHT_BASS * validation.bassDissDuration) + (SCORING.DISS_WEIGHT_UPPER * validation.upperDissDuration);
            const ratio = weightedDiss / validation.polyphonicDuration;

            if (ratio > SCORING.DISS_PENALTY_START) {
                const excess = ratio - SCORING.DISS_PENALTY_START;
                const penalty = excess * SCORING.DISS_PENALTY_SLOPE;
                score -= penalty;
                log.penalties.push({ reason: `Dissonance ${(ratio*100).toFixed(0)}%`, points: Math.round(penalty) });
            } else if (ratio >= SCORING.BUCKET_SWEET_MIN && ratio <= SCORING.BUCKET_SWEET_MAX) {
                score += SCORING.BUCKET_SWEET_SCORE;
                log.bonuses.push({ reason: `Rich Harmony (${(ratio*100).toFixed(0)}%)`, points: SCORING.BUCKET_SWEET_SCORE });
            }
        }

        if (validation.harmonicReward > 0) {
            score += validation.harmonicReward;
            log.bonuses.push({ reason: "Harmonic Quality", points: Math.round(validation.harmonicReward) });
        }
        if (validation.harmonicPenalty > 0) {
            score -= validation.harmonicPenalty;
            log.penalties.push({ reason: "NCT Clashing", points: Math.round(validation.harmonicPenalty) });
        }

        const distanceCounts: Record<string, number> = {};
        chain.forEach((e, i) => {
            if (i === 0) return;
            const prev = chain[i-1];
            const dist = e.startBeat - prev.startBeat;
            const distStr = dist.toFixed(2);
            distanceCounts[distStr] = (distanceCounts[distStr] || 0) + 1;

            const ratio = dist / subjectDurationBeats;
            if (ratio <= SCORING.COMPACT_HYPER_THRESH) {
                score += SCORING.COMPACT_HYPER_BONUS;
                log.bonuses.push({ reason: `Hyper-Stretto (V${i+1})`, points: SCORING.COMPACT_HYPER_BONUS });
            } else if (ratio <= SCORING.COMPACT_TIGHT_THRESH) {
                score += SCORING.COMPACT_TIGHT_BONUS;
                log.bonuses.push({ reason: `Tight Stretto (V${i+1})`, points: SCORING.COMPACT_TIGHT_BONUS });
            }

            const absInt = e.transposition;
            const absSemi = Math.abs(absInt % 12);
            if ([3,4,8,9].includes(absSemi)) {
                score += SCORING.IMPERFECT_CONS_BONUS;
                log.bonuses.push({ reason: `3rd/6th Entry`, points: SCORING.IMPERFECT_CONS_BONUS });
            }
        });

        const uniqueDistances = Object.keys(distanceCounts).length;
        if (uniqueDistances > 1) {
            const b = (uniqueDistances - 1) * SCORING.DIST_VARIETY_BONUS;
            score += b;
            log.bonuses.push({ reason: `Distance Variety`, points: b });
        }

        if (!validation.isValid) {
            const fatalPenalty = validation.errors.length * 1000;
            score -= fatalPenalty;
            log.penalties.push({ reason: `${validation.errors.length} Fatal Rules Broken`, points: fatalPenalty });
        }

        if (chain.length < targetChainLength) {
            const missing = targetChainLength - chain.length;
            score -= (missing * 50); 
        }

        log.total = Math.max(0, score);

        const resultObj: StrettoChainResult = {
            id: `chain-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
            entries: [...chain],
            warnings: [...validation.errors, ...validation.warnings],
            score: log.total,
            scoreLog: log,
            detectedChords: validation.detectedChords
        };

        targetList.push(resultObj);
        targetList.sort((a,b) => b.score - a.score);
        if (targetList.length > MAX_INVALID_BUFFER) {
            targetList.pop();
        }
    }

    async function solve(
        chain: StrettoChainOption[], 
        nInv: number, n3rd: number, nTrunc: number,
        voiceEndTimes16: number[] 
    ) {
        nodesVisited++;
        if (chain.length > maxDepthReached) maxDepthReached = chain.length;

        if (validResults.length >= MAX_VALID_RESULTS) {
            stopReason = 'Success';
            return;
        }
        if (Date.now() - START_TIME > TIME_LIMIT_MS) {
            stopReason = 'Timeout';
            if (chain.length >= 3) {
                 const validation = checkRulesAndStats(chain, baseSubject, invertedSubject, options.requireConsonantEnd, options.ensembleTotal, options.voiceNames);
                 processChain(chain, validation, partialResults);
            }
            return;
        }
        if (nodesVisited > MAX_VISITED_NODES) {
            stopReason = 'NodeLimit';
            if (chain.length >= 3) {
                 const validation = checkRulesAndStats(chain, baseSubject, invertedSubject, options.requireConsonantEnd, options.ensembleTotal, options.voiceNames);
                 processChain(chain, validation, partialResults);
            }
            return;
        }

        if (chain.length === targetChainLength) {
            const validation = checkRulesAndStats(chain, baseSubject, invertedSubject, options.requireConsonantEnd, options.ensembleTotal, options.voiceNames);
            if (validation.isValid) processChain(chain, validation, validResults);
            else processChain(chain, validation, invalidResults);
            return;
        }

        const lastEntry = chain[chain.length - 1];
        let extensionsFound = false;
        const lastTranspositions = new Map<number, number>();
        chain.forEach(entry => { lastTranspositions.set(entry.voiceIndex, entry.transposition); });
        const triedFunctions = new Set<string>();

        for (const cand of potentialCandidates) {
            if (stopReason !== 'Exhausted') break;

            const harmonicKey = `${cand.delayBeats.toFixed(2)}-${cand.type}-${(cand.transposition % 12 + 12) % 12}`;
            const newStart = lastEntry.startBeat + cand.delayBeats;

            if (chain.length >= 2) {
                const prevDist = lastEntry.startBeat - chain[chain.length - 2].startBeat;
                const newDist = cand.delayBeats;
                let isUnique = true;
                for (let k = 1; k < chain.length; k++) {
                    const existingDist = chain[k].startBeat - chain[k-1].startBeat;
                    if (Math.abs(existingDist - newDist) < 0.01) { isUnique = false; break; }
                }
                if (!isUnique) continue;
                if (newDist > prevDist + 1.0 + 0.01) continue;
                if (chain.length >= 3) {
                    const prevPrevDist = chain[chain.length - 2].startBeat - chain[chain.length - 3].startBeat;
                    if (prevDist > prevPrevDist + 0.01) {
                        if (newDist > prevPrevDist - 1.0 + 0.01) continue;
                    }
                }
            }

            const entryIndex = chain.length + 1;
            const constraintThreshold = Math.floor(targetChainLength / 2) + 1;
            const maxDelayEarly = subjectDurationBeats * (2/3);
            const maxDelayLate = subjectDurationBeats * 0.5;
            const limit = entryIndex >= constraintThreshold ? maxDelayLate : maxDelayEarly;

            if (cand.delayBeats > limit) continue;

            const absTrans = cand.transposition; 
            if (absTrans === lastEntry.transposition) continue;

            const start16 = Math.round(newStart * 4);
            let assignedVoice = -1;

            for (let v = 0; v < ensembleTotal; v++) {
                const lastEnd16 = voiceEndTimes16[v];
                const allowedStart16 = Math.max(0, lastEnd16 - 4); 
                if (start16 < allowedStart16) continue; 
                if (lastTranspositions.has(v - 1)) {
                    const tAbove = lastTranspositions.get(v - 1)!;
                    if (absTrans > tAbove) continue;
                }
                if (lastTranspositions.has(v + 1)) {
                    const tBelow = lastTranspositions.get(v + 1)!;
                    if (absTrans < tBelow) continue;
                }
                assignedVoice = v;
                break; 
            }

            if (assignedVoice === -1) continue; 

            const isOuterVoice = (assignedVoice === 0 || assignedVoice === ensembleTotal - 1);
            if (isOuterVoice && triedFunctions.has(harmonicKey)) continue;

            const lengthsToTry: { len: number, isTrunc: boolean }[] = [];
            lengthsToTry.push({ len: effectiveLen16, isTrunc: false });

            const targetTrunc16 = Math.round(options.truncationTargetBeats * 4);
            if (options.truncationMode !== 'None' && targetTrunc16 < effectiveLen16 && targetTrunc16 > 0) {
                 if (isBudgetAvailable(options.truncationMode, nTrunc)) {
                     const absSemi = Math.abs(cand.transposition % 12);
                     const is3rd = [3,4,8,9].includes(absSemi);
                     const isInv = cand.type === 'I';
                     let allowed = true;
                     if (options.disallowComplexExceptions) { if (is3rd || isInv) allowed = false; }
                     if (allowed) lengthsToTry.push({ len: targetTrunc16, isTrunc: true });
                 }
            }

            const absSemi = Math.abs(absTrans % 12);
            const is3rd = [3,4,8,9].includes(absSemi);
            if (is3rd) { if (!isBudgetAvailable(options.thirdSixthMode, n3rd)) continue; }

            const costInv = cand.type === 'I' ? 1 : 0;
            if (costInv > 0 && !isBudgetAvailable(options.inversionMode, nInv)) continue;

            const sourceNotes = cand.type === 'N' ? baseSubject : invertedSubject;
            let successForCandidate = false;

            for (const lengthObj of lengthsToTry) {
                if (validResults.length >= MAX_VALID_RESULTS) return;
                const truncatedNotes = sourceNotes.filter(n => n.relTick16 < lengthObj.len).map(n => ({
                    ...n,
                    dur16: Math.min(n.dur16, lengthObj.len - n.relTick16)
                }));

                grid.write(assignedVoice, truncatedNotes, start16, absTrans);
                const hasParallel = grid.hasParallelErrors(assignedVoice, truncatedNotes, start16, absTrans);

                if (hasParallel) {
                    grid.clear(assignedVoice, truncatedNotes, start16);
                    continue; 
                }

                successForCandidate = true;
                const newEntry: StrettoChainOption = {
                    startBeat: newStart, transposition: absTrans, type: cand.type,
                    length: lengthObj.len, voiceIndex: assignedVoice
                };

                const testChain = [...chain, newEntry];
                const newVoiceState = [...voiceEndTimes16];
                const entryEnd16 = start16 + lengthObj.len;
                newVoiceState[assignedVoice] = Math.max(newVoiceState[assignedVoice], entryEnd16);

                extensionsFound = true;

                await solve(testChain, nInv + costInv, n3rd + (is3rd?1:0), nTrunc + (lengthObj.isTrunc?1:0), newVoiceState);
                grid.clear(assignedVoice, truncatedNotes, start16);
            }

            if (successForCandidate && isOuterVoice) triedFunctions.add(harmonicKey);
        }

        if (!extensionsFound && chain.length >= 3) {
             const validation = checkRulesAndStats(chain, baseSubject, invertedSubject, options.requireConsonantEnd, options.ensembleTotal, options.voiceNames);
             processChain(chain, validation, partialResults);
        }
    }

    const initialVoiceState = new Array(ensembleTotal).fill(0);
    initialVoiceState[options.subjectVoiceIndex] = effectiveLen16;
    grid.write(options.subjectVoiceIndex, baseSubject, 0, 0);

    await solve([{
        startBeat: 0, transposition: 0, type: 'N',
        length: effectiveLen16, voiceIndex: options.subjectVoiceIndex
    }], 0, 0, 0, initialVoiceState);

    let rawResults = validResults;
    if (rawResults.length === 0) rawResults = partialResults;
    if (rawResults.length === 0) rawResults = invalidResults;

    const uniqueChains = new Map<string, StrettoChainResult>();
    rawResults.forEach(res => {
        const signature = res.entries.map(e => {
            const pc = (e.transposition % 12 + 12) % 12;
            const dist = e.startBeat.toFixed(2);
            return `${pc}@${dist}`;
        }).join('|');
        if (!uniqueChains.has(signature)) uniqueChains.set(signature, res);
        else {
            const existing = uniqueChains.get(signature)!;
            if (res.score > existing.score) uniqueChains.set(signature, res);
        }
    });

    let resultsToReturn = Array.from(uniqueChains.values());
    const groups = new Map<string, StrettoChainResult[]>();
    const sortStrategy = (a: StrettoChainResult, b: StrettoChainResult) => {
        if (a.entries.length !== b.entries.length) return b.entries.length - a.entries.length;
        return b.score - a.score;
    };

    resultsToReturn.forEach(res => {
        const rhythmKey = res.entries.map(e => e.startBeat.toFixed(2)).join('|');
        if (!groups.has(rhythmKey)) groups.set(rhythmKey, []);
        groups.get(rhythmKey)!.push(res);
    });

    const finalResults: StrettoChainResult[] = [];
    groups.forEach((group) => {
        group.sort(sortStrategy);
        const leader = group[0];
        if (group.length > 1) leader.variations = group.slice(1);
        finalResults.push(leader);
    });

    return {
        results: finalResults.sort(sortStrategy).slice(0, 50),
        stats: {
            nodesVisited, timeMs: Date.now() - START_TIME,
            stopReason: validResults.length > 0 ? 'Success' : stopReason, maxDepthReached
        }
    };
}

import React from 'react';
import { StrettoSearchOptions, StrettoChainResult, StrettoCandidate, RawNote, StrettoSearchReport } from '../../types';
import StrettoSearchPanel from './StrettoSearchPanel';
import StrettoResultsList from './StrettoResultsList';
import StrettoInspector from './StrettoInspector';
import { DownloadIcon } from '../Icons';

interface StrettoChainViewProps {
    searchOptions: StrettoSearchOptions;
    setSearchOptions: (opt: StrettoSearchOptions) => void;
    onSearch: () => void;
    isSearching: boolean;
    chainResults: StrettoChainResult[];
    selectedChain: StrettoChainResult | null;
    setSelectedChain: (res: StrettoChainResult | null) => void;
    voiceNames?: Record<number, string>;
    setVoiceNames?: (names: Record<number, string>) => void;

    // Inspector Props
    chainToCandidate: StrettoCandidate | null;
    ppq: number;
    ts: { num: number, den: number };
    isPlaying: boolean;
    onPlay: (notes: RawNote[]) => void;
    onDownloadChain: () => void;
    searchReport?: StrettoSearchReport | null;

    // Master Transposition
    masterTransposition: number;
    setMasterTransposition: (val: number) => void;
}

export default function StrettoChainView({
    searchOptions, setSearchOptions, onSearch, isSearching,
    chainResults, selectedChain, setSelectedChain, voiceNames, setVoiceNames,
    chainToCandidate, ppq, ts, isPlaying, onPlay, onDownloadChain,
    searchReport, masterTransposition, setMasterTransposition
}: StrettoChainViewProps) {
    return (
        <>
            <StrettoSearchPanel 
                options={searchOptions} 
                setOptions={setSearchOptions}
                onSearch={onSearch}
                isSearching={isSearching}
                voiceNames={voiceNames}
                setVoiceNames={setVoiceNames}
            />

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8">
                <div className="lg:col-span-1 bg-gray-900 border border-gray-700 rounded shadow-inner">
                    <div className="p-3 border-b border-gray-700 bg-gray-800 flex justify-between items-center">
                        <h3 className="text-xs font-bold text-gray-400">FOUND CHAINS ({chainResults.length})</h3>
                        {searchReport && (
                            <div className="text-[9px] text-gray-500 text-right">
                                {searchReport.stats.nodesVisited.toLocaleString()} nodes in {searchReport.stats.timeMs}ms
                            </div>
                        )}
                    </div>
                    {searchReport && searchReport.stats.stopReason !== 'Success' && (
                        <div className="bg-yellow-900/30 border-b border-yellow-800 p-2 text-[10px] text-yellow-300">
                            <strong>Search {searchReport.stats.stopReason}:</strong> No valid chains of length {searchOptions.targetChainLength} found.
                            Showing partial chains (Max Depth: {searchReport.stats.maxDepthReached}).
                        </div>
                    )}
                    <StrettoResultsList 
                        results={chainResults}
                        selectedId={selectedChain?.id || null}
                        onSelect={setSelectedChain}
                        voiceNames={voiceNames}
                    />
                </div>
                <div className="lg:col-span-2">
                    <StrettoInspector 
                        candidate={chainToCandidate}
                        ppq={ppq}
                        ts={ts}
                        isPlaying={isPlaying}
                        onPlay={onPlay}
                        assemblyResult={""}
                        assemblyLog={[]}
                        onClearAssembly={() => {}}
                        onDownloadChain={onDownloadChain}
                    />

                    <div className="mt-4 flex flex-col md:flex-row justify-between items-center gap-4 bg-gray-800 p-3 rounded border border-gray-700">
                        <div className="flex items-center gap-4">
                            <span className="text-xs font-bold text-gray-400 uppercase">Master Transpose:</span>
                            <div className="flex items-center gap-2">
                                <button 
                                    onClick={() => setMasterTransposition(Math.max(-24, masterTransposition - 1))}
                                    className="bg-gray-700 hover:bg-gray-600 text-white w-6 h-6 rounded flex items-center justify-center font-bold text-sm"
                                >-</button>
                                <span className={`text-sm font-mono w-12 text-center ${masterTransposition !== 0 ? 'text-brand-primary font-bold' : 'text-gray-300'}`}>
                                    {masterTransposition > 0 ? '+' : ''}{masterTransposition}
                                </span>
                                <button 
                                    onClick={() => setMasterTransposition(Math.min(24, masterTransposition + 1))}
                                    className="bg-gray-700 hover:bg-gray-600 text-white w-6 h-6 rounded flex items-center justify-center font-bold text-sm"
                                >+</button>
                            </div>
                            <span className="text-[10px] text-gray-500 hidden sm:inline">Shift entire chain before export.</span>
                        </div>

                        {chainToCandidate && (
                            <button 
                                onClick={onDownloadChain}
                                className="flex items-center gap-2 px-4 py-2 bg-brand-primary text-white font-bold rounded shadow-lg hover:bg-brand-secondary transition-colors"
                            >
                                <DownloadIcon className="w-4 h-4" /> Download Chain MIDI
                            </button>
                        )}
                    </div>
                </div>
            </div>
        </>
    );
}

import { RawNote, StrettoCandidate, StrettoError, StrettoGrade, HarmonicRegion } from '../../types';
import { getFormattedTime } from './midiHarmony';
import { getStrictPitchName, getIntervalLabel } from './midiSpelling';

const DISSONANT_INTERVALS = [1, 2, 6, 10, 11]; // m2, M2, TT, m7, M7
const PERFECT_CONSONANCES = [0, 7]; // P1, P5

export interface VoiceEvent {
    tick: number;
    endTick: number; 
    pitch1: number;
    pitch2: number;
    hasAttack1: boolean;
    hasAttack2: boolean;
}

const MAJOR_SCALE_STEPS = [0, 2, 4, 5, 7, 9, 11];

function invertPitch(pitch: number, pivot: number, useChromatic: boolean): number {
    if (useChromatic) {
        return pivot - (pitch - pivot);
    }

    // Diatonic Inversion (Major Scale Assumption)
    const diff = pitch - pivot;
    const octaves = Math.floor(diff / 12);
    const semitone = (diff % 12 + 12) % 12;

    // Find closest scale step
    let degree = -1;
    let minErr = 99;
    MAJOR_SCALE_STEPS.forEach((s, i) => {
        if (Math.abs(s - semitone) < minErr) { 
            minErr = Math.abs(s - semitone); 
            degree = i; 
        }
    });

    // Invert the degree index relative to 0 (root)
    const absDegree = (octaves * 7) + degree;
    const invAbsDegree = -absDegree;

    const invOctaves = Math.floor(invAbsDegree / 7);
    const invIndex = (invAbsDegree % 7 + 7) % 7;

    return pivot + (invOctaves * 12) + MAJOR_SCALE_STEPS[invIndex];
}

export function getVerticalIntervals(subject: RawNote[], answer: RawNote[]): VoiceEvent[] {
    const timePoints = new Set<number>();
    [...subject, ...answer].forEach(n => {
        if (!n) return;
        timePoints.add(n.ticks);
        timePoints.add(n.ticks + n.durationTicks);
    });

    const sortedPoints = Array.from(timePoints).sort((a,b) => a-b);
    const events: VoiceEvent[] = [];
    const endOfMusic = Math.max(0, ...[...subject, ...answer].map(n => n ? n.ticks + n.durationTicks : 0));

    for (let i = 0; i < sortedPoints.length - 1; i++) {
        const t = sortedPoints[i];
        if (t >= endOfMusic) break;

        const checkTime = t; 
        const n1 = subject.find(n => n && n.ticks <= checkTime && (n.ticks + n.durationTicks) > checkTime);
        const n2 = answer.find(n => n && n.ticks <= checkTime && (n.ticks + n.durationTicks) > checkTime);

        if (n1 && n2) {
            events.push({
                tick: t,
                endTick: sortedPoints[i+1],
                pitch1: n1.midi,
                pitch2: n2.midi,
                hasAttack1: n1.ticks === t,
                hasAttack2: n2.ticks === t
            });
        }
    }
    return events;
}

function isStrongBeat(tick: number, ppq: number, tsNum: number, tsDenom: number): boolean {
    const ticksPerMeasure = ppq * tsNum * (4 / tsDenom);
    const pos = tick % ticksPerMeasure;
    if (pos === 0) return true; 
    if (tsNum === 4 && tsDenom === 4 && pos === (ticksPerMeasure / 2)) return true;
    return false; 
}

export function generateHarmonicRegions(events: VoiceEvent[]): HarmonicRegion[] {
    const regions: HarmonicRegion[] = [];
    let previousState: 'consonance' | 'dissonance' = 'consonance';
    let prevP1: number | null = null;
    let prevP2: number | null = null;

    for (let i = 0; i < events.length; i++) {
        const ev = events[i];
        const duration = ev.endTick - ev.tick;
        if (duration <= 0) continue;

        const p1 = ev.pitch1;
        const p2 = ev.pitch2;
        const interval = Math.abs(p1 - p2);
        const intervalClass = interval % 12;
        const isBass1 = p1 < p2;
        const upperPitch = isBass1 ? p2 : p1;
        const prevUpperPitch = isBass1 ? (prevP2) : (prevP1);

        const isP4 = intervalClass === 5; 
        const isDiss = DISSONANT_INTERVALS.includes(intervalClass) || isP4;
        let regionType: HarmonicRegion['type'];

        if (isDiss) {
            regionType = (previousState === 'consonance') ? 'dissonance_1' : 'dissonance_consecutive';
            previousState = 'dissonance';
        } else {
            regionType = (PERFECT_CONSONANCES.includes(intervalClass)) ? 'perfect_consonance' : 'imperfect_consonance';
            previousState = 'consonance';
        }

        let errorType: HarmonicRegion['errorType'] = null;
        if (prevP1 !== null && prevP2 !== null) {
            const p1Moved = prevP1 !== p1;
            const p2Moved = prevP2 !== p2;
            if (p1Moved && p2Moved) {
                const isParallelMotion = (p1 - prevP1) * (p2 - prevP2) > 0;
                const isPerfect = intervalClass === 0 || intervalClass === 7;
                if (isPerfect && isParallelMotion) {
                    const prevInterval = Math.abs(prevP1 - prevP2);
                    if (prevInterval % 12 === intervalClass) errorType = 'parallel';
                }
                if (!errorType && isPerfect && isParallelMotion && prevUpperPitch !== null) {
                    if (Math.abs(upperPitch - prevUpperPitch) > 2) errorType = 'direct';
                }
            }
        }

        regions.push({
            startTick: ev.tick,
            endTick: ev.endTick, 
            type: regionType,
            errorType: errorType,
            intervalLabel: getIntervalLabel(interval),
            description: `${getIntervalLabel(interval)}: ${getStrictPitchName(p1)}, ${getStrictPitchName(p2)}`
        });
        prevP1 = p1; prevP2 = p2;
    }
    return regions;
}

export function analyzeStrettoCandidate(
    subject: RawNote[], 
    intervalSemis: number, 
    delayTicks: number, 
    ppq: number,
    ts: { num: number, den: number },
    isInverted: boolean = false,
    pivotMidi: number = 60,
    useChromaticInversion: boolean = false
): StrettoCandidate {

    if (subject.length === 0) {
        return {
            id: `empty`, intervalSemis, intervalLabel: 'N/A', delayBeats: 0, delayTicks,
            grade: 'INVALID', errors: [], notes: [], dissonanceRatio: 0, endsOnDissonance: true
        };
    }

    const subjectEntryPitch = subject[0].midi;

    const answer: RawNote[] = subject.map(n => {
        if (!n) return null as any;
        let newMidi: number;

        if (isInverted) {
            // 1. Calculate the raw inverted shape around the pivot
            const rawInverted = invertPitch(n.midi, pivotMidi, useChromaticInversion);

            // 2. Calculate where the "Subject Start Note" maps to in this raw inversion
            const invertedStart = invertPitch(subjectEntryPitch, pivotMidi, useChromaticInversion);

            // 3. Determine the target start pitch for the Answer
            // Usually Subject Start + Interval
            const targetStart = subjectEntryPitch + intervalSemis;

            // 4. Calculate shift needed to move the inverted shape to the target start
            const shift = targetStart - invertedStart;

            newMidi = rawInverted + shift;
        } else {
            newMidi = n.midi + intervalSemis;
        }

        return {
            ...n,
            ticks: n.ticks + delayTicks,
            midi: newMidi,
            name: getStrictPitchName(newMidi),
            voiceIndex: 1
        };
    }).filter(n => !!n);

    const startOverlap = delayTicks; 
    const subjectEnd = Math.max(0, ...subject.map(n => n ? n.ticks + n.durationTicks : 0));

    if (startOverlap >= subjectEnd) {
        return {
            id: `invalid_gap`,
            intervalSemis, intervalLabel: 'N/A', delayBeats: 0, delayTicks,
            grade: 'INVALID', errors: [], notes: [], dissonanceRatio: 0, endsOnDissonance: true
        };
    }

    const events = getVerticalIntervals(subject, answer).filter(e => e.tick >= startOverlap);
    const harmonicRegions = generateHarmonicRegions(events);

    let totalOverlapTicks = 0;
    let dissonantTicks = 0;
    let endsOnDissonance = false;

    harmonicRegions.forEach((r, idx) => {
        const dur = r.endTick - r.startTick;
        totalOverlapTicks += dur;
        if (r.type === 'dissonance_1' || r.type === 'dissonance_consecutive') {
            dissonantTicks += dur;
            if (idx === harmonicRegions.length - 1) endsOnDissonance = true;
        }
    });

    const dissonanceRatio = totalOverlapTicks > 0 ? (dissonantTicks / totalOverlapTicks) : 0;
    const errors: StrettoError[] = [];

    harmonicRegions.forEach(r => {
        const timeStr = getFormattedTime(r.startTick, ppq, ts.num, ts.den);
        const onStrong = isStrongBeat(r.startTick, ppq, ts.num, ts.den);
        if (r.errorType === 'parallel') {
            errors.push({
                tick: r.startTick, timeFormatted: timeStr,
                type: r.intervalLabel.includes('P5') ? 'Parallel 5th' : 'Parallel 8ve',
                details: `Parallel motion into ${r.intervalLabel}`,
                severity: onStrong ? 'fatal' : 'warning'
            });
        }
        if (r.errorType === 'direct') {
             errors.push({
                tick: r.startTick, timeFormatted: timeStr,
                type: r.intervalLabel.includes('P5') ? 'Direct 5th' : 'Direct 8ve',
                details: `Direct motion into ${r.intervalLabel} (Upper leap)`,
                severity: 'warning'
            });
        }
        if (r.type === 'dissonance_consecutive' && onStrong) {
             const isP4Run = r.intervalLabel.includes('P4');
             errors.push({
                 tick: r.startTick, timeFormatted: timeStr,
                 type: 'Consecutive Dissonance',
                 details: 'Consecutive dissonance',
                 severity: isP4Run ? 'warning' : 'fatal'
             });
        }
    });

    let grade: StrettoGrade = 'STRONG';
    if (errors.some(e => e.severity === 'fatal')) grade = 'INVALID';
    else if (errors.length > 0) grade = 'VIABLE';

    let intLabel = getIntervalLabel(intervalSemis);
    if (intervalSemis < 0 && !intLabel.startsWith('-')) intLabel = '-' + intLabel;
    else if (intervalSemis > 0 && !intLabel.startsWith('+')) intLabel = '+' + intLabel;
    if (isInverted) intLabel += " (Inv)";

    const delayBeats = delayTicks / (ppq * (4 / ts.den));

    return {
        id: `${intLabel}@${delayBeats.toFixed(1)}${isInverted?'i':''}`,
        intervalSemis,
        intervalLabel: intLabel,
        delayBeats: parseFloat(delayBeats.toFixed(2)),
        delayTicks,
        grade,
        errors,
        notes: [...subject, ...answer],
        regions: harmonicRegions,
        dissonanceRatio,
        endsOnDissonance
    };
}

import React, { useMemo } from 'react';
import { StrettoSearchOptions, StrettoConstraintMode, RawNote } from '../../types';
import { getStrictPitchName } from '../services/midiSpelling';
import { getVoiceLabel } from '../services/midiVoices';

interface StrettoSearchPanelProps {
    options: StrettoSearchOptions;
    setOptions: (opt: StrettoSearchOptions) => void;
    onSearch: () => void;
    isSearching: boolean;
    voiceNames?: Record<number, string>;
    setVoiceNames?: (names: Record<number, string>) => void;
    subjectNotes: RawNote[];
    ppq: number;
}

export default function StrettoSearchPanel({ 
    options, setOptions, onSearch, isSearching, 
    voiceNames, setVoiceNames, subjectNotes, ppq 
}: StrettoSearchPanelProps) {

    const handleChange = (field: keyof StrettoSearchOptions, val: any) => {
        setOptions({ ...options, [field]: val });
    };

    const handleVoiceNameChange = (idx: number, name: string) => {
        if (setVoiceNames && voiceNames) {
            setVoiceNames({ ...voiceNames, [idx]: name });
        }
    };

    const renderConstraintSelector = (label: string, field: keyof StrettoSearchOptions, value: StrettoConstraintMode) => (
        <div className="bg-gray-900 p-2 rounded border border-gray-700">
            <label className="block text-[10px] font-bold text-gray-400 mb-2 uppercase">{label}</label>
            <div className="flex gap-1">
                {['None', 'Max 1', 'Unlimited'].map((mode) => (
                    <button
                        key={mode}
                        onClick={() => handleChange(field, mode as StrettoConstraintMode)}
                        className={`flex-1 py-1 text-[10px] rounded border transition-colors ${value === mode ? 'bg-brand-primary text-white border-brand-primary' : 'bg-gray-800 text-gray-500 border-gray-600 hover:border-gray-500'}`}
                    >
                        {mode}
                    </button>
                ))}
            </div>
        </div>
    );

    const availableAbove = options.subjectVoiceIndex; 
    const availableBelow = (options.ensembleTotal - 1) - options.subjectVoiceIndex;

    // Truncation Visualization Logic
    const truncationVisual = useMemo(() => {
        if (subjectNotes.length === 0) return null;

        const sorted = [...subjectNotes].sort((a,b) => a.ticks - b.ticks);
        const startTick = sorted[0].ticks;
        const totalDuration = Math.max(...sorted.map(n => n.ticks + n.durationTicks)) - startTick;

        const targetTicks = Math.round(options.truncationTargetBeats * ppq);
        const minMidi = Math.min(...sorted.map(n => n.midi));
        const maxMidi = Math.max(...sorted.map(n => n.midi));
        const range = maxMidi - minMidi + 12; // Buffer

        return (
            <div className="w-full h-16 bg-gray-900 border border-gray-700 rounded mt-2 relative overflow-hidden select-none">
                <svg className="w-full h-full" preserveAspectRatio="none" viewBox={`0 0 ${totalDuration} ${range}`}>
                    {/* Background Grid (Beats) */}
                    {Array.from({ length: Math.ceil(totalDuration / ppq) }).map((_, i) => (
                        <line 
                            key={i} 
                            x1={i * ppq} y1={0} 
                            x2={i * ppq} y2={range} 
                            stroke="#333" 
                            strokeWidth={i % 4 === 0 ? 2 : 1}
                            vectorEffect="non-scaling-stroke" 
                        />
                    ))}

                    {/* Notes */}
                    {sorted.map((n, i) => {
                        const relStart = n.ticks - startTick;
                        const relEnd = relStart + n.durationTicks;

                        // Check if note is cut
                        let isKept = true;
                        let opacity = 1.0;
                        let fill = "#14b8a6"; // brand-primary

                        if (relStart >= targetTicks) {
                            isKept = false;
                            opacity = 0.3;
                            fill = "#4b5563"; // gray-600
                        } else if (relEnd > targetTicks) {
                            // Split note visualization?
                            fill = "#f59e0b"; // amber for clipped
                        }

                        // Invert Y for SVG
                        const y = range - (n.midi - minMidi) - 6;

                        return (
                            <rect 
                                key={i}
                                x={relStart}
                                y={y}
                                width={n.durationTicks}
                                height={4} // Note height
                                fill={fill}
                                opacity={opacity}
                                rx={2}
                            />
                        );
                    })}

                    {/* Cut Line */}
                    <line 
                        x1={targetTicks} y1={0} 
                        x2={targetTicks} y2={range} 
                        stroke="#ef4444" 
                        strokeWidth={2} 
                        strokeDasharray="4,4"
                        vectorEffect="non-scaling-stroke"
                    />
                </svg>
                <div className="absolute top-1 right-1 text-[9px] bg-black/50 px-1 rounded text-gray-400">
                    {options.truncationTargetBeats} Beats / {(totalDuration/ppq).toFixed(1)} Total
                </div>
            </div>
        );
    }, [subjectNotes, options.truncationTargetBeats, ppq]);

    return (
        <div className="bg-gray-800 border border-gray-700 rounded p-4 mb-6 shadow-sm">
            <div className="flex justify-between items-center mb-4 border-b border-gray-700 pb-2">
                <h3 className="text-sm font-bold text-gray-300 uppercase tracking-wider">Algorithmic Chain Finder</h3>
                {isSearching && <span className="text-xs text-brand-primary animate-pulse">Searching...</span>}
            </div>

            {/* Ensemble & Voice Naming Configuration */}
            <div className="mb-6 bg-black/20 p-4 rounded border border-gray-700">
                <h4 className="text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-4">Voice Configuration (SATB)</h4>
                <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                    {Array.from({ length: options.ensembleTotal }).map((_, idx) => {
                        const defaultLabel = getVoiceLabel(idx, options.ensembleTotal);
                        return (
                            <div key={idx} className="flex flex-col gap-1">
                                <label className="text-[9px] text-gray-400 font-bold uppercase">
                                    Voice {idx + 1} {idx === options.subjectVoiceIndex ? "(Subject)" : ""}
                                </label>
                                <input 
                                    type="text"
                                    placeholder={defaultLabel}
                                    value={voiceNames?.[idx] || ''}
                                    onChange={(e) => handleVoiceNameChange(idx, e.target.value)}
                                    className="bg-gray-900 border border-gray-600 rounded px-2 py-1 text-xs text-white focus:border-brand-primary outline-none"
                                />
                            </div>
                        );
                    })}
                </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-12 gap-4 mb-4">

                {/* 1. Ensemble Configuration (Col 3) */}
                <div className="lg:col-span-3 bg-gray-900 p-2 rounded border border-gray-700 flex flex-col gap-2">
                    <label className="block text-[10px] font-bold text-gray-400 uppercase">Search Setup</label>

                    <div className="flex gap-2">
                        <div className="flex-1">
                            <label className="block text-[9px] text-gray-500 mb-1">Total Voices</label>
                            <select 
                                value={options.ensembleTotal}
                                onChange={(e) => {
                                    const total = parseInt(e.target.value);
                                    const newSubj = Math.min(options.subjectVoiceIndex, total - 1);
                                    setOptions({ ...options, ensembleTotal: total, subjectVoiceIndex: newSubj });
                                }}
                                className="w-full bg-gray-800 border border-gray-600 rounded text-xs text-white px-1 py-1"
                            >
                                {Array.from({length: 7}, (_, i) => i + 2).map(num => (
                                    <option key={num} value={num}>{num} Voices</option>
                                ))}
                            </select>
                        </div>
                        <div className="flex-1">
                            <label className="block text-[9px] text-gray-500 mb-1">Subject Voice</label>
                            <select 
                                value={options.subjectVoiceIndex}
                                onChange={(e) => handleChange('subjectVoiceIndex', parseInt(e.target.value))}
                                className="w-full bg-gray-800 border border-gray-600 rounded text-xs text-white px-1 py-1"
                            >
                                {Array.from({length: options.ensembleTotal}, (_, i) => i).map(idx => {
                                    const label = voiceNames?.[idx] || getVoiceLabel(idx, options.ensembleTotal);
                                    return <option key={idx} value={idx}>{label}</option>;
                                })}
                            </select>
                        </div>
                    </div>

                    <div className="flex-1 mt-1">
                        <label className="block text-[9px] text-gray-500 mb-1">Chain Length (Entries)</label>
                        <select 
                            value={options.targetChainLength}
                            onChange={(e) => handleChange('targetChainLength', parseInt(e.target.value))}
                            className="w-full bg-gray-800 border border-brand-primary/50 rounded text-xs text-white px-1 py-1"
                        >
                            {Array.from({length: 12}, (_, i) => i + 2).map(num => (
                                <option key={num} value={num}>{num} Entries</option>
                            ))}
                        </select>
                    </div>

                    <div className="text-[10px] text-gray-400 flex justify-between bg-black/20 p-1 rounded mt-1">
                        <span>↑ {availableAbove} Above</span>
                        <span className="font-bold text-brand-primary">S</span>
                        <span>↓ {availableBelow} Below</span>
                    </div>
                </div>

                {/* 2. Truncation (Col 4) */}
                <div className="lg:col-span-4 flex flex-col gap-2">
                    {renderConstraintSelector("Truncated Entries", "truncationMode", options.truncationMode)}
                    <div className={`flex flex-col gap-2 px-1 transition-opacity ${options.truncationMode === 'None' ? 'opacity-30 pointer-events-none' : ''}`}>
                        <div className="flex items-center gap-2">
                            <label className="text-[9px] text-gray-500 block">Cut Length (Beats)</label>
                            <input 
                                type="number" 
                                min="0.5" step="0.5"
                                value={options.truncationTargetBeats}
                                onChange={(e) => handleChange('truncationTargetBeats', parseFloat(e.target.value))}
                                className="w-16 bg-gray-900 border border-gray-600 text-xs rounded px-1 py-1 text-white text-center"
                            />
                        </div>
                        {truncationVisual}
                    </div>
                </div>

                {/* 3. Inversion (Col 2) */}
                <div className="lg:col-span-2 flex flex-col gap-2">
                    {renderConstraintSelector("Inverted Entries", "inversionMode", options.inversionMode)}
                    <div className={`flex flex-col gap-1 px-1 transition-opacity ${options.inversionMode === 'None' ? 'opacity-30 pointer-events-none' : ''}`}>
                        <div className="flex items-center gap-2">
                            <span className="text-[10px] text-gray-500 whitespace-nowrap">Pivot:</span>
                            <select 
                                value={options.pivotMidi}
                                onChange={(e) => handleChange('pivotMidi', parseInt(e.target.value))}
                                className="bg-gray-900 border border-gray-600 text-[10px] rounded px-1 py-0.5 text-gray-300 flex-grow"
                            >
                                {Array.from({length: 12}).map((_, i) => {
                                    const midi = 60 + i; 
                                    return <option key={midi} value={midi}>{getStrictPitchName(midi)}</option>
                                })}
                            </select>
                        </div>
                        <label className="flex items-center cursor-pointer mt-1">
                            <input 
                                type="checkbox" 
                                checked={options.useChromaticInversion} 
                                onChange={(e) => handleChange('useChromaticInversion', e.target.checked)} 
                                className="h-3 w-3 rounded bg-gray-900 border-gray-600 text-brand-primary focus:ring-0"
                            />
                            <span className="ml-2 text-[9px] font-bold text-gray-400">Chromatic (Pure)</span>
                        </label>
                    </div>
                </div>

                {/* 4. Intervals (Col 3) */}
                <div className="lg:col-span-3 bg-gray-900 p-2 rounded border border-gray-700 flex flex-col gap-2">
                    {renderConstraintSelector("Intervals (from Prev)", "thirdSixthMode", options.thirdSixthMode)}

                    <div className="flex flex-col gap-2 mt-1">
                        <label className="flex items-center cursor-pointer">
                            <input 
                                type="checkbox" 
                                checked={options.requireConsonantEnd} 
                                onChange={(e) => handleChange('requireConsonantEnd', e.target.checked)} 
                                className="h-3 w-3 rounded bg-gray-900 border-gray-600 text-brand-primary focus:ring-0"
                            />
                            <span className="ml-2 text-[10px] font-bold text-gray-300">Require Consonant End</span>
                        </label>

                        <label className="flex items-center cursor-pointer">
                            <input 
                                type="checkbox" 
                                checked={options.disallowComplexExceptions} 
                                onChange={(e) => handleChange('disallowComplexExceptions', e.target.checked)} 
                                className="h-3 w-3 rounded bg-gray-900 border-gray-600 text-brand-primary focus:ring-0"
                            />
                            <span className="ml-2 text-[10px] font-bold text-gray-300" title="Prevents combining Inversion/Truncation with 3rd/6th intervals">Disallow Complex Exceptions</span>
                        </label>
                    </div>
                </div>
            </div>

            <button 
                onClick={onSearch}
                disabled={isSearching}
                className="w-full py-2 bg-brand-primary hover:bg-brand-secondary text-white font-bold rounded shadow-lg transition-all disabled:opacity-50 disabled:cursor-not-allowed text-sm uppercase tracking-wide"
            >
                {isSearching ? 'Processing Combinations...' : 'Run Search Algorithm'}
            </button>
        </div>
    );
}

import React, { useState, useMemo, useEffect } from 'react';
import { RawNote, StrettoCandidate, StrettoSearchOptions, StrettoChainResult, HarmonicRegion, StrettoSearchReport, StrettoGrade } from '../types';
import { parseSimpleAbc } from './services/abcBridge';
import { analyzeStrettoCandidate, getVerticalIntervals, generateHarmonicRegions } from './services/strettoCore';
import { searchStrettoChains } from './services/strettoGenerator'; 
import { getStrictPitchName } from './services/midiSpelling';
import { downloadStrettoCandidate, downloadStrettoSelection } from './services/strettoExport';
import { Spinner, DocumentTextIcon } from './Icons';
import { playSequence, stopPlayback } from './midiPlaybackService';
import { useStrettoAssembly } from '../hooks/useStrettoAssembly';
import { predictKey } from './services/analysis/keyPrediction'; // Robust key finding

import StrettoConfig, { SearchResolution } from './stretto/StrettoConfig';
import StrettoList from './stretto/StrettoList';
import StrettoInspector from './stretto/StrettoInspector';
import StrettoFooter from './stretto/StrettoFooter';
import StrettoChainView from './stretto/StrettoChainView'; 

interface StrettoViewProps {
    notes: RawNote[]; 
    ppq: number;
    ts: { num: number, den: number };
    voiceNames?: Record<number, string>;
    setVoiceNames?: (names: Record<number, string>) => void;
}

interface SavedSubject {
    id: string;
    name: string;
    data: string;
}

export default function StrettoView({ notes: initialNotes, ppq, ts, voiceNames, setVoiceNames }: StrettoViewProps) {
    const [mode, setMode] = useState<'midi' | 'abc'>(initialNotes.length > 0 ? 'midi' : 'abc');
    const [abcInput, setAbcInput] = useState<string>("M:4/4\nL:1/4\nQ:120\nK:C\nc2 G c d e f g3 a b c'2");
    const [viewMode, setViewMode] = useState<'pairwise' | 'chain'>('chain'); 

    const [gradeFilter, setGradeFilter] = useState<Record<StrettoGrade, boolean>>({
        'STRONG': true,
        'VIABLE': true,
        'INVALID': false
    });

    const [savedSubjects, setSavedSubjects] = useState<SavedSubject[]>([]);
    const [saveName, setSaveName] = useState('');
    const [showLibrary, setShowLibrary] = useState(false);

    const [configIntervals, setConfigIntervals] = useState<number[]>([0, 12, -12, 7, -7, 5, -5, 24, -24]);
    const [includeExtensions, setIncludeExtensions] = useState(false);
    const [includeInversions, setIncludeInversions] = useState(false);
    const [searchRes, setSearchRes] = useState<SearchResolution>('full');
    const [selectedCandidate, setSelectedCandidate] = useState<StrettoCandidate | null>(null);
    const [checkedIds, setCheckedIds] = useState<Set<string>>(new Set());

    // Master Transposition State (Post-processing)
    const [masterTransposition, setMasterTransposition] = useState<number>(0);

    const [searchOptions, setSearchOptions] = useState<StrettoSearchOptions>({
        ensembleTotal: 4,
        targetChainLength: 8,
        subjectVoiceIndex: 2, 
        truncationMode: 'None', 
        truncationTargetBeats: 4,
        inversionMode: 'Max 1', 
        useChromaticInversion: false, 
        thirdSixthMode: 'Max 1', 
        pivotMidi: 60, // Placeholder, updated in effect
        requireConsonantEnd: true,
        disallowComplexExceptions: false
    });

    const [chainResults, setChainResults] = useState<StrettoChainResult[]>([]);
    const [searchReport, setSearchReport] = useState<StrettoSearchReport | null>(null);
    const [isSearching, setIsSearching] = useState(false);
    const [selectedChain, setSelectedChain] = useState<StrettoChainResult | null>(null);

    const [isPlaying, setIsPlaying] = useState(false);

    useEffect(() => {
        const saved = localStorage.getItem('stretto_subject_library');
        if (saved) {
            try { setSavedSubjects(JSON.parse(saved)); } catch (e) { console.error(e); }
        }
    }, []);

    const subjectNotes = useMemo(() => {
        if (mode === 'abc') return parseSimpleAbc(abcInput, ppq || 480);
        return initialNotes; 
    }, [mode, abcInput, initialNotes, ppq]);

    // Intelligent Pivot Initialization using Key Prediction
    useEffect(() => {
        if (subjectNotes && subjectNotes.length > 0) {
            // 1. Generate Histogram
            const histogram: Record<number, number> = {};
            for (let i = 0; i < 12; i++) histogram[i] = 0;
            subjectNotes.forEach(n => histogram[n.midi % 12]++);

            // 2. Predict Key to find the Tonic Pitch Class
            const predictions = predictKey(histogram, subjectNotes.length);
            const predictedRoot = predictions.length > 0 ? predictions[0].winner.root : subjectNotes[0].midi % 12;

            // 3. Find the best octave for the pivot
            // We want the tonic instance that sits comfortably within the subject's range
            // or closest to the starting note to preserve register intent.
            const startMidi = subjectNotes[0].midi;

            // Find instances of the Root Pitch Class near the start note
            // Candidates: Root in same octave, octave below, octave above
            const candidates = [
                predictedRoot + (Math.floor(startMidi / 12) - 1) * 12,
                predictedRoot + (Math.floor(startMidi / 12)) * 12,
                predictedRoot + (Math.floor(startMidi / 12) + 1) * 12,
            ];

            // Choose the one closest to the start note
            let closest = candidates[0];
            let minDiff = Math.abs(candidates[0] - startMidi);

            for (let i=1; i<candidates.length; i++) {
                const diff = Math.abs(candidates[i] - startMidi);
                if (diff < minDiff) {
                    minDiff = diff;
                    closest = candidates[i];
                }
            }

            // Ensure valid MIDI range
            const validPivot = Math.max(0, Math.min(127, closest));

            setSearchOptions(prev => ({ ...prev, pivotMidi: validPivot }));
        }
    }, [subjectNotes]);

    const handleSaveSubject = () => {
        if (!saveName.trim() || !abcInput.trim()) return;
        const newSubject: SavedSubject = { id: Date.now().toString(), name: saveName.trim(), data: abcInput };
        const updated = [...savedSubjects, newSubject];
        setSavedSubjects(updated);
        localStorage.setItem('stretto_subject_library', JSON.stringify(updated));
        setSaveName('');
    };

    const handleDeleteSubject = (id: string) => {
        const updated = savedSubjects.filter(s => s.id !== id);
        setSavedSubjects(updated);
        localStorage.setItem('stretto_subject_library', JSON.stringify(updated));
    };

    const handleLoadSubject = (data: string) => { setAbcInput(data); };

    const { 
        isAssembling, assemblyStatus, assemblyResult, assemblyLog, 
        setAssemblyResult, runAssembly 
    } = useStrettoAssembly({ notes: subjectNotes, ppq: ppq || 480, ts });

    const pairwiseResults = useMemo(() => {
        if (subjectNotes.length === 0 || viewMode !== 'pairwise') return [];
        const candidates: StrettoCandidate[] = [];
        const validNotes = subjectNotes.filter(n => !!n);
        if (validNotes.length === 0) return [];

        const durationTicks = Math.max(...validNotes.map(n => n.ticks + n.durationTicks));
        const maxDelay = durationTicks * (2/3); 
        const currentPpq = ppq || 480;
        let stepTicks = currentPpq; 
        if (searchRes === 'half') stepTicks = currentPpq / 2;
        else if (searchRes === 'double') stepTicks = currentPpq * 2;

        let intervalsToCheck = [...configIntervals];
        if (includeExtensions) {
            const exts = [3, 4, 8, 9, -3, -4, -8, -9];
            exts.forEach(e => { if (!intervalsToCheck.includes(e)) intervalsToCheck.push(e); });
        }

        intervalsToCheck.forEach(interval => {
            for (let d = stepTicks; d <= maxDelay; d += stepTicks) {
                candidates.push(analyzeStrettoCandidate(validNotes, interval, Math.round(d), currentPpq, ts, false, searchOptions.pivotMidi, searchOptions.useChromaticInversion));
                if (includeInversions) {
                    candidates.push(analyzeStrettoCandidate(validNotes, interval, Math.round(d), currentPpq, ts, true, searchOptions.pivotMidi, searchOptions.useChromaticInversion));
                }
            }
        });
        return candidates;
    }, [subjectNotes, configIntervals, includeExtensions, includeInversions, ppq, ts, searchRes, viewMode, searchOptions.pivotMidi, searchOptions.useChromaticInversion]);

    const processedDiscoveryResults = useMemo(() => {
        return pairwiseResults.filter(r => gradeFilter[r.grade]);
    }, [pairwiseResults, gradeFilter]);

    const getSelectedCandidates = () => pairwiseResults.filter(r => checkedIds.has(r.id));

    const handleChainSearch = async () => {
        setIsSearching(true); setChainResults([]); setSearchReport(null); setSelectedChain(null);
        setTimeout(async () => {
            try {
                const report = await searchStrettoChains(subjectNotes.filter(n => !!n), { ...searchOptions, voiceNames }, ppq || 480);
                setChainResults(report.results); setSearchReport(report);
            } catch (e) { alert("Search failed."); } finally { setIsSearching(false); }
        }, 100);
    };

    const chainToCandidate = useMemo((): StrettoCandidate | null => {
        if (!selectedChain) return null;
        let allNotes: RawNote[] = [];
        const voices: RawNote[][] = [];
        const validSubjectNotes = subjectNotes.filter(n => !!n);
        const currentPpq = ppq || 480;
        if (validSubjectNotes.length === 0) return null;
        const sortedSubj = [...validSubjectNotes].sort((a,b)=>a.ticks-b.ticks);
        const startTick = sortedSubj[0].ticks;

        // Helper to determine diatonic inversion based on MAJOR Scale assumption (per user req)
        const SCALE_STEPS = [0, 2, 4, 5, 7, 9, 11];
        const invertPitchDiatonic = (pitch: number, pivot: number) => {
            const diff = pitch - pivot;
            const oct = Math.floor(diff / 12);
            const semi = (diff % 12 + 12) % 12;
            let degree = -1;
            let minErr = 99;
            SCALE_STEPS.forEach((s, i) => {
                if (Math.abs(s - semi) < minErr) { minErr = Math.abs(s - semi); degree = i; }
            });
            const absDegree = (oct * 7) + degree;
            const invAbsDegree = -absDegree;
            const invOct = Math.floor(invAbsDegree / 7);
            const invIndex = (invAbsDegree % 7 + 7) % 7;
            return pivot + (invOct * 12) + SCALE_STEPS[invIndex];
        };

        const invertPitchChromatic = (pitch: number, pivot: number) => {
            return pivot - (pitch - pivot);
        }

        selectedChain.entries.forEach((entry) => {
            const entryStartTick = Math.round(entry.startBeat * currentPpq);
            const transformed = sortedSubj.map(n => {
                let pitch = n.midi;

                if (entry.type === 'I') {
                    // Logic: Invert first, then transpose to entry point
                    const rawInverted = searchOptions.useChromaticInversion 
                        ? invertPitchChromatic(n.midi, searchOptions.pivotMidi)
                        : invertPitchDiatonic(n.midi, searchOptions.pivotMidi);

                    const subjectFirst = sortedSubj[0].midi;
                    const invertedFirst = searchOptions.useChromaticInversion 
                        ? invertPitchChromatic(subjectFirst, searchOptions.pivotMidi)
                        : invertPitchDiatonic(subjectFirst, searchOptions.pivotMidi);

                    const targetStart = subjectFirst + entry.transposition;
                    const shift = targetStart - invertedFirst;

                    pitch = rawInverted + shift;

                } else {
                    pitch += entry.transposition;
                }

                // APPLY MASTER TRANSPOSITION
                pitch += masterTransposition;

                return { ...n, ticks: (n.ticks - startTick) + entryStartTick, midi: pitch, name: getStrictPitchName(pitch), voiceIndex: entry.voiceIndex };
            });
            const entryEnd = entryStartTick + (entry.length * (currentPpq/4));
            const clipped = transformed.filter(n => n.ticks < entryEnd).map(n => ({ ...n, durationTicks: Math.min(n.durationTicks, entryEnd - n.ticks) }));
            voices.push(clipped); allNotes = [...allNotes, ...clipped];
        });

        let chainRegions: HarmonicRegion[] = [];
        for (let i = 0; i < voices.length - 1; i++) {
            const regions = generateHarmonicRegions(getVerticalIntervals(voices[i], voices[i+1]));
            chainRegions = [...chainRegions, ...regions];
        }

        return { id: selectedChain.id, intervalLabel: "Chain", intervalSemis: 0, delayBeats: 0, delayTicks: 0, grade: 'STRONG', errors: [], notes: allNotes, regions: chainRegions, dissonanceRatio: 0, endsOnDissonance: false };
    }, [selectedChain, subjectNotes, ppq, searchOptions.pivotMidi, searchOptions.useChromaticInversion, masterTransposition]);

    const handlePlay = (notes: RawNote[]) => {
        if (isPlaying) { stopPlayback(); setIsPlaying(false); return; }
        setIsPlaying(true);
        const currentPpq = ppq || 480;
        playSequence(notes.filter(n => !!n).map(n => ({ 
            midi: n.midi, 
            name: n.name, 
            time: n.ticks * (0.5 / currentPpq), 
            duration: n.durationTicks * (0.5 / currentPpq), 
            velocity: n.velocity 
        })), () => setIsPlaying(false));
    };

    const toggleCheck = (id: string) => {
        setCheckedIds(prev => {
            const next = new Set(prev);
            if (next.has(id)) next.delete(id); else next.add(id);
            const cand = pairwiseResults.find(r => r.id === id);
            if (cand) setSelectedCandidate(cand);
            return next;
        });
    };

    return (
        <div className="w-full bg-gray-dark p-6 rounded-2xl border border-gray-medium animate-slide-up pb-32 relative">
            <div className="flex justify-between items-center mb-6">
                <h2 className="text-2xl font-bold text-gray-light">Stretto Assembly Lab</h2>
                {isAssembling && (
                    <div className="flex items-center gap-2 bg-brand-primary/20 px-4 py-2 rounded-full border border-brand-primary/40 animate-pulse">
                        <Spinner className="w-4 h-4 text-brand-primary" />
                        <span className="text-xs font-bold text-brand-primary">{assemblyStatus}</span>
                    </div>
                )}
            </div>

            <div className="flex flex-col md:flex-row gap-4 mb-6 p-4 bg-gray-800 rounded-lg border border-gray-700 justify-between">
                <div className="flex gap-2 items-center">
                    <span className="text-xs font-bold text-gray-500 mr-2">INPUT:</span>
                    <button onClick={() => setMode('midi')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${mode === 'midi' ? 'bg-brand-primary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Selected MIDI</button>
                    <button onClick={() => setMode('abc')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${mode === 'abc' ? 'bg-brand-primary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>ABC Notation</button>
                </div>
                <div className="flex gap-2 items-center border-l border-gray-600 pl-4">
                    <span className="text-xs font-bold text-gray-500 mr-2">MODE:</span>
                    <button onClick={() => setViewMode('pairwise')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${viewMode === 'pairwise' ? 'bg-brand-secondary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Pairwise Discovery</button>
                    <button onClick={() => setViewMode('chain')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${viewMode === 'chain' ? 'bg-brand-secondary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Algorithmic Chain</button>
                </div>
            </div>

            {mode === 'abc' && (
                <div className="mb-6 space-y-4">
                    <div className="flex justify-between items-center">
                        <label className="block text-sm text-gray-400 font-bold uppercase tracking-wider">Subject ABC</label>
                        <button onClick={() => setShowLibrary(!showLibrary)} className="text-xs bg-gray-800 hover:bg-gray-700 text-brand-primary border border-brand-primary/30 px-3 py-1 rounded flex items-center gap-2 transition-colors">
                            <DocumentTextIcon className="w-3 h-3" /> {showLibrary ? "Hide Library" : "Subject Library"}
                        </button>
                    </div>
                    {showLibrary && (
                        <div className="bg-gray-800 p-4 rounded-lg border border-gray-700 animate-fade-in">
                            <div className="flex gap-2 mb-4 border-b border-gray-700 pb-4">
                                <input type="text" placeholder="Subject Name..." value={saveName} onChange={(e) => setSaveName(e.target.value)} className="flex-grow bg-gray-900 border border-gray-600 rounded px-3 py-1 text-sm text-white outline-none" />
                                <button onClick={handleSaveSubject} disabled={!saveName.trim()} className="bg-brand-primary hover:bg-brand-secondary text-white px-4 py-1 rounded text-sm font-bold transition-colors disabled:bg-gray-600">Save</button>
                            </div>
                            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-2 max-h-48 overflow-y-auto">
                                {savedSubjects.length > 0 ? savedSubjects.map(s => (
                                    <div key={s.id} className="flex justify-between items-center bg-gray-900 p-2 rounded border border-gray-700 group">
                                        <span className="text-sm font-bold text-gray-300 truncate mr-2">{s.name}</span>
                                        <div className="flex gap-1 opacity-50 group-hover:opacity-100">
                                            <button onClick={() => handleLoadSubject(s.data)} className="text-[10px] bg-brand-secondary/50 px-2 py-0.5 rounded">Load</button>
                                            <button onClick={() => handleDeleteSubject(s.id)} className="text-[10px] bg-red-900/50 px-2 py-0.5 rounded">×</button>
                                        </div>
                                    </div>
                                )) : <p className="text-xs text-gray-500 col-span-full text-center py-2">Library empty.</p>}
                            </div>
                        </div>
                    )}
                    <textarea value={abcInput} onChange={e => setAbcInput(e.target.value)} className="w-full bg-gray-900 border border-gray-700 rounded p-3 text-white font-mono h-24 outline-none focus:border-brand-primary" />
                </div>
            )}

            {viewMode === 'pairwise' ? (
                <>
                    <StrettoConfig 
                        selectedIntervals={configIntervals} 
                        setSelectedIntervals={setConfigIntervals} 
                        searchRes={searchRes} 
                        setSearchRes={setSearchRes} 
                        includeInversions={includeInversions} 
                        setIncludeInversions={setIncludeInversions} 
                        includeExtensions={includeExtensions} 
                        setIncludeExtensions={setIncludeExtensions} 
                        pivotMidi={searchOptions.pivotMidi}
                        setPivotMidi={(val) => setSearchOptions({...searchOptions, pivotMidi: val})}
                    />

                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
                        <StrettoList 
                            candidates={pairwiseResults} 
                            processedResults={processedDiscoveryResults}
                            gradeFilter={gradeFilter}
                            setGradeFilter={setGradeFilter}
                            selectedId={selectedCandidate?.id || null} 
                            onSelect={setSelectedCandidate} 
                            checkedIds={checkedIds} 
                            onToggleCheck={toggleCheck} 
                        />
                        <StrettoInspector candidate={selectedCandidate} ppq={ppq || 480} ts={ts} isPlaying={isPlaying} onPlay={handlePlay} assemblyResult={assemblyResult} assemblyLog={assemblyLog} onClearAssembly={() => setAssemblyResult('')} onDownloadChain={() => selectedCandidate && downloadStrettoCandidate(selectedCandidate, ppq || 480, voiceNames)} />
                    </div>
                    <StrettoFooter selectedCandidates={getSelectedCandidates()} onDownloadMidi={() => downloadStrettoSelection(getSelectedCandidates(), ppq || 480, voiceNames)} onAssemble={() => runAssembly(checkedIds.size > 0 ? getSelectedCandidates() : (selectedCandidate ? [selectedCandidate] : []), abcInput)} isAssembling={isAssembling} onRemoveCandidate={toggleCheck} />
                </>
            ) : (
                <StrettoChainView 
                    searchOptions={searchOptions} 
                    setSearchOptions={setSearchOptions} 
                    onSearch={handleChainSearch} 
                    isSearching={isSearching} 
                    chainResults={chainResults} 
                    selectedChain={selectedChain} 
                    setSelectedChain={setSelectedChain} 
                    voiceNames={voiceNames} 
                    setVoiceNames={setVoiceNames} 
                    chainToCandidate={chainToCandidate} 
                    ppq={ppq || 480} 
                    ts={ts} 
                    isPlaying={isPlaying} 
                    onPlay={handlePlay} 
                    onDownloadChain={() => chainToCandidate && downloadStrettoCandidate(chainToCandidate, ppq || 480, voiceNames)} 
                    searchReport={searchReport}
                    masterTransposition={masterTransposition}
                    setMasterTransposition={setMasterTransposition}
                    subjectNotes={subjectNotes} // PASSED DOWN FOR VISUALIZATION
                />
            )}
        </div>
    );
}

import React from 'react';
import { StrettoSearchOptions, StrettoChainResult, StrettoCandidate, RawNote, StrettoSearchReport } from '../../types';
import StrettoSearchPanel from './StrettoSearchPanel';
import StrettoResultsList from './StrettoResultsList';
import StrettoInspector from './StrettoInspector';
import { DownloadIcon } from '../Icons';

interface StrettoChainViewProps {
    searchOptions: StrettoSearchOptions;
    setSearchOptions: (opt: StrettoSearchOptions) => void;
    onSearch: () => void;
    isSearching: boolean;
    chainResults: StrettoChainResult[];
    selectedChain: StrettoChainResult | null;
    setSelectedChain: (res: StrettoChainResult | null) => void;
    voiceNames?: Record<number, string>;
    setVoiceNames?: (names: Record<number, string>) => void;

    // Inspector Props
    chainToCandidate: StrettoCandidate | null;
    ppq: number;
    ts: { num: number, den: number };
    isPlaying: boolean;
    onPlay: (notes: RawNote[]) => void;
    onDownloadChain: () => void;
    searchReport?: StrettoSearchReport | null;

    // Master Transposition
    masterTransposition: number;
    setMasterTransposition: (val: number) => void;
    subjectNotes: RawNote[]; // New prop
}

export default function StrettoChainView({
    searchOptions, setSearchOptions, onSearch, isSearching,
    chainResults, selectedChain, setSelectedChain, voiceNames, setVoiceNames,
    chainToCandidate, ppq, ts, isPlaying, onPlay, onDownloadChain,
    searchReport, masterTransposition, setMasterTransposition,
    subjectNotes
}: StrettoChainViewProps) {
    return (
        <>
            <StrettoSearchPanel 
                options={searchOptions} 
                setOptions={setSearchOptions}
                onSearch={onSearch}
                isSearching={isSearching}
                voiceNames={voiceNames}
                setVoiceNames={setVoiceNames}
                subjectNotes={subjectNotes}
                ppq={ppq}
            />

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8">
                <div className="lg:col-span-1 bg-gray-900 border border-gray-700 rounded shadow-inner">
                    <div className="p-3 border-b border-gray-700 bg-gray-800 flex justify-between items-center">
                        <h3 className="text-xs font-bold text-gray-400">FOUND CHAINS ({chainResults.length})</h3>
                        {searchReport && (
                            <div className="text-[9px] text-gray-500 text-right">
                                {searchReport.stats.nodesVisited.toLocaleString()} nodes in {searchReport.stats.timeMs}ms
                            </div>
                        )}
                    </div>
                    {searchReport && searchReport.stats.stopReason !== 'Success' && (
                        <div className="bg-yellow-900/30 border-b border-yellow-800 p-2 text-[10px] text-yellow-300">
                            <strong>Search {searchReport.stats.stopReason}:</strong> No valid chains of length {searchOptions.targetChainLength} found.
                            Showing partial chains (Max Depth: {searchReport.stats.maxDepthReached}).
                        </div>
                    )}
                    <StrettoResultsList 
                        results={chainResults}
                        selectedId={selectedChain?.id || null}
                        onSelect={setSelectedChain}
                        voiceNames={voiceNames}
                    />
                </div>
                <div className="lg:col-span-2">
                    <StrettoInspector 
                        candidate={chainToCandidate}
                        ppq={ppq}
                        ts={ts}
                        isPlaying={isPlaying}
                        onPlay={onPlay}
                        assemblyResult={""}
                        assemblyLog={[]}
                        onClearAssembly={() => {}}
                        onDownloadChain={onDownloadChain}
                    />

                    <div className="mt-4 flex flex-col md:flex-row justify-between items-center gap-4 bg-gray-800 p-3 rounded border border-gray-700">
                        <div className="flex items-center gap-4">
                            <span className="text-xs font-bold text-gray-400 uppercase">Master Transpose:</span>
                            <div className="flex items-center gap-2">
                                <button 
                                    onClick={() => setMasterTransposition(Math.max(-24, masterTransposition - 1))}
                                    className="bg-gray-700 hover:bg-gray-600 text-white w-6 h-6 rounded flex items-center justify-center font-bold text-sm"
                                >-</button>
                                <span className={`text-sm font-mono w-12 text-center ${masterTransposition !== 0 ? 'text-brand-primary font-bold' : 'text-gray-300'}`}>
                                    {masterTransposition > 0 ? '+' : ''}{masterTransposition}
                                </span>
                                <button 
                                    onClick={() => setMasterTransposition(Math.min(24, masterTransposition + 1))}
                                    className="bg-gray-700 hover:bg-gray-600 text-white w-6 h-6 rounded flex items-center justify-center font-bold text-sm"
                                >+</button>
                            </div>
                            <span className="text-[10px] text-gray-500 hidden sm:inline">Shift entire chain before export.</span>
                        </div>

                        {chainToCandidate && (
                            <button 
                                onClick={onDownloadChain}
                                className="flex items-center gap-2 px-4 py-2 bg-brand-primary text-white font-bold rounded shadow-lg hover:bg-brand-secondary transition-colors"
                            >
                                <DownloadIcon className="w-4 h-4" /> Download Chain MIDI
                            </button>
                        )}
                    </div>
                </div>
            </div>
        </>
    );
}

