import React, { useRef, useEffect, useState } from 'react';
import { PianoRollTrackData, HarmonicRegion } from '../types';
import { getVoiceLabel } from './services/midiVoices';

interface PianoRollProps {
  trackData: PianoRollTrackData;
  onRegionClick?: (region: HarmonicRegion) => void;
}

const NOTE_HEIGHT = 14;
const MIN_MIDI = 21; 
const MAX_MIDI = 108; 
const NUM_NOTES = MAX_MIDI - MIN_MIDI + 1;
const KEY_WIDTH = 60;
const RULER_HEIGHT = 32;

const VOICE_COLORS = [
    '#3b82f6', // Blue
    '#ef4444', // Red
    '#10b981', // Green
    '#f59e0b', // Amber
    '#8b5cf6', // Violet
    '#ec4899', // Pink
    '#6366f1', // Indigo
    '#14b8a6', // Teal
];

const isBlackKey = (midi: number) => {
  const note = midi % 12;
  return note === 1 || note === 3 || note === 6 || note === 8 || note === 10;
};

const getRegionColor = (type: HarmonicRegion['type']): string => {
    switch (type) {
        case 'perfect_consonance': return '#2dd4bf'; // Turquoise (Teal-400)
        case 'imperfect_consonance': return '#2dd4bf'; // Keep consonant distinct from dissonance
        case 'dissonance_1': return '#a855f7'; // Purple (Purple-500)
        case 'dissonance_consecutive': return '#ef4444'; // Red (Red-500)
        default: return 'transparent';
    }
};

const PianoRoll: React.FC<PianoRollProps> = ({ trackData, onRegionClick }) => {
  const { notes, ppq, timeSignature, harmonicRegions } = trackData;
  const gridContainerRef = useRef<HTMLDivElement>(null);
  const keysContainerRef = useRef<HTMLDivElement>(null);
  const rulerContainerRef = useRef<HTMLDivElement>(null);

  const [zoom, setZoom] = useState(1.0);
  const [hoveredRegion, setHoveredRegion] = useState<HarmonicRegion | null>(null);

  const maxVoiceIdx = notes.reduce((max, n) => Math.max(max, n.voiceIndex ?? -1), -1);
  const [showVoices, setShowVoices] = useState(maxVoiceIdx > 0);
  const totalVoices = maxVoiceIdx + 1;

  useEffect(() => {
    if (gridContainerRef.current && notes.length > 0) {
      const sumMidi = notes.reduce((sum, n) => sum + n.midi, 0);
      const avgMidi = sumMidi / notes.length;
      const targetMidi = Math.min(Math.max(avgMidi, MIN_MIDI), MAX_MIDI);
      const y = (MAX_MIDI - targetMidi) * NOTE_HEIGHT;
      const containerHeight = gridContainerRef.current.clientHeight;
      gridContainerRef.current.scrollTop = y - containerHeight / 2;
    }
  }, [notes]); 

  const handleGridScroll = () => {
    if (gridContainerRef.current) {
        if (keysContainerRef.current) keysContainerRef.current.scrollTop = gridContainerRef.current.scrollTop;
        if (rulerContainerRef.current) rulerContainerRef.current.scrollLeft = gridContainerRef.current.scrollLeft;
    }
  };

  const totalTicks = Math.max(...notes.map(n => n.ticks + n.durationTicks), ppq * 4 * timeSignature.numerator);
  const ticksPerMeasure = ppq * timeSignature.numerator * (4 / timeSignature.denominator);
  const totalMeasures = Math.ceil(totalTicks / ticksPerMeasure) + 1; 

  const BASE_TICK_WIDTH = 0.15; 
  const TICK_WIDTH = BASE_TICK_WIDTH * zoom;
  const SVG_WIDTH = Math.max(totalTicks * TICK_WIDTH + 100, 100); 
  const SVG_HEIGHT = NUM_NOTES * NOTE_HEIGHT;

  const tickToX = (tick: number) => tick * TICK_WIDTH;
  const midiToY = (midi: number) => (MAX_MIDI - midi) * NOTE_HEIGHT;

  const handleZoomIn = () => setZoom(prev => Math.min(prev * 1.25, 4));
  const handleZoomOut = () => setZoom(prev => Math.max(prev * 0.8, 0.1));

  const patternId = `beatPattern-${zoom}`;
  const parallelPatternId = `parallelPattern`;

  if (!notes || notes.length === 0) {
    return <div className="flex items-center justify-center h-full text-gray-400">No notes to display.</div>;
  }

  return (
    <div className="flex flex-col h-full bg-gray-900 border border-gray-700 rounded-lg overflow-hidden select-none relative">

       {/* Harmonic Inspector Overlay */}
       {hoveredRegion && (
           <div className="absolute top-10 left-1/2 transform -translate-x-1/2 z-50 bg-black/80 backdrop-blur-md border border-brand-primary rounded-lg p-2 shadow-xl animate-fade-in pointer-events-none">
               <div className="text-center">
                   <span className="text-brand-primary font-bold text-sm block">{hoveredRegion.intervalLabel}</span>
                   {hoveredRegion.description && <span className="text-gray-300 text-xs block">{hoveredRegion.description}</span>}
                   {hoveredRegion.errorType && <span className="text-red-400 text-[10px] font-bold uppercase tracking-wider block mt-1">{hoveredRegion.errorType} Motion</span>}
                   <span className="text-[9px] text-gray-500 mt-1 block">Click to audition</span>
               </div>
           </div>
       )}

       <div className="flex items-center justify-between px-3 py-1 bg-gray-800 border-b border-gray-700 z-20">
            <div className="flex items-center gap-6">
                <div className="flex items-center gap-3">
                    <span className="text-xs text-gray-400 uppercase font-bold tracking-wider">Zoom</span>
                    <div className="flex items-center bg-gray-700 rounded-md overflow-hidden">
                        <button onClick={handleZoomOut} className="p-1 px-2 text-gray-300 hover:text-white hover:bg-gray-600 transition-colors">
                            <svg className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20 12H4" /></svg>
                        </button>
                        <span className="text-[10px] text-gray-300 w-10 text-center border-l border-r border-gray-600 px-1">{Math.round(zoom * 100)}%</span>
                        <button onClick={handleZoomIn} className="p-1 px-2 text-gray-300 hover:text-white hover:bg-gray-600 transition-colors">
                            <svg className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg>
                        </button>
                    </div>
                </div>

                <label className="flex items-center cursor-pointer gap-2">
                    <div className="relative">
                        <input type="checkbox" className="sr-only" checked={showVoices} onChange={(e) => setShowVoices(e.target.checked)} />
                        <div className={`block w-7 h-3.5 rounded-full transition-colors ${showVoices ? 'bg-brand-primary' : 'bg-gray-600'}`}></div>
                        <div className={`absolute left-0.5 top-0.5 bg-white w-2.5 h-2.5 rounded-full transition-transform ${showVoices ? 'transform translate-x-3.5' : ''}`}></div>
                    </div>
                    <span className="text-[10px] text-gray-400 uppercase font-bold tracking-wider">Show Voices</span>
                </label>
            </div>
            <div className="text-[10px] text-gray-500 font-mono">
                {timeSignature.numerator}/{timeSignature.denominator} • {ppq} PPQ
            </div>
       </div>

       <div className="flex flex-shrink-0 h-[32px] bg-gray-800 border-b border-gray-700 z-10">
          <div className="w-[60px] flex-shrink-0 border-r border-gray-700 bg-gray-800 flex items-center justify-center">
            <span className="text-[10px] text-gray-500 font-mono">Key</span>
          </div>
          <div ref={rulerContainerRef} className="flex-grow overflow-hidden relative bg-gray-800">
             <svg width={SVG_WIDTH} height={RULER_HEIGHT}>
                {Array.from({ length: totalMeasures }).map((_, i) => {
                    const x = tickToX(i * ticksPerMeasure);
                    return (
                        <g key={i} transform={`translate(${x}, 0)`}>
                            <line x1={0} y1={15} x2={0} y2={32} stroke="#4b5563" strokeWidth={1} />
                            <text x={4} y={24} fill="#6b7280" fontSize="10" fontFamily="monospace" fontWeight="bold">{i + 1}</text>
                        </g>
                    );
                })}
             </svg>
          </div>
       </div>

       <div className="flex flex-grow overflow-hidden relative">
          <div ref={keysContainerRef} className="w-[60px] flex-shrink-0 overflow-hidden border-r border-gray-700 bg-gray-800">
            <svg width={KEY_WIDTH} height={SVG_HEIGHT}>
                {Array.from({ length: NUM_NOTES }, (_, i) => {
                    const midi = MAX_MIDI - i;
                    const y = i * NOTE_HEIGHT;
                    const black = isBlackKey(midi);
                    const isC = midi % 12 === 0;
                    return (
                        <g key={midi}>
                           <rect x={0} y={y} width={KEY_WIDTH} height={NOTE_HEIGHT} fill={black ? '#111827' : '#f9fafb'} stroke="#1f2937" strokeWidth={0.5} />
                            {(isC || midi % 12 === 5) && (
                                <text x={KEY_WIDTH - 4} y={y + NOTE_HEIGHT - 3} textAnchor="end" fontSize="9" fill={black ? '#4b5563' : '#9ca3af'} fontWeight={isC ? "bold" : "normal"}>{isC ? `C${Math.floor(midi/12)-1}` : 'F'}</text>
                            )}
                        </g>
                    )
                })}
            </svg>
          </div>

          <div ref={gridContainerRef} onScroll={handleGridScroll} className="flex-grow overflow-auto bg-gray-900 relative cursor-default">
            <svg width={SVG_WIDTH} height={SVG_HEIGHT}>
                <defs>
                    <pattern id={patternId} x="0" y="0" width={tickToX(ppq)} height={SVG_HEIGHT} patternUnits="userSpaceOnUse">
                         <line x1={tickToX(ppq)} y1={0} x2={tickToX(ppq)} y2={SVG_HEIGHT} stroke="#1f2937" strokeWidth={0.5} strokeDasharray="2,2" />
                    </pattern>
                    <pattern id={parallelPatternId} width="4" height="4" patternUnits="userSpaceOnUse" patternTransform="rotate(45)">
                        <line stroke="#ffffff" strokeWidth="1" x1="0" y1="0" x2="0" y2="4" opacity="0.3" />
                    </pattern>
                </defs>

                {/* Background Grid */}
                {Array.from({ length: NUM_NOTES }, (_, i) => {
                     const midi = MAX_MIDI - i;
                     const y = i * NOTE_HEIGHT;
                     const black = isBlackKey(midi);
                     return <rect key={`bg-${midi}`} x={0} y={y} width={SVG_WIDTH} height={NOTE_HEIGHT} fill={black ? '#111827' : '#1f2937'} fillOpacity={black ? 1 : 0.2} />;
                })}
                {Array.from({ length: NUM_NOTES }, (_, i) => {
                    const midi = MAX_MIDI - i;
                    if (midi % 12 === 0 && midi !== MAX_MIDI) return <line key={`oct-${midi}`} x1={0} y1={i * NOTE_HEIGHT} x2={SVG_WIDTH} y2={i * NOTE_HEIGHT} stroke="#374151" strokeWidth={0.5} />;
                    return null;
                })}
                <rect x="0" y="0" width={SVG_WIDTH} height={SVG_HEIGHT} fill={`url(#${patternId})`} />

                {/* Harmonic Regions Shading (Clickable) */}
                {harmonicRegions && harmonicRegions.map((region, i) => {
                    const x = tickToX(region.startTick);
                    const width = tickToX(region.endTick - region.startTick);
                    const color = getRegionColor(region.type);
                    const isHovered = hoveredRegion === region;

                    return (
                        <g 
                            key={`region-${i}`} 
                            onMouseEnter={() => setHoveredRegion(region)} 
                            onMouseLeave={() => setHoveredRegion(null)}
                            onClick={(e) => {
                                e.stopPropagation();
                                if(onRegionClick) onRegionClick(region);
                            }}
                            className="cursor-pointer transition-opacity"
                            style={{ opacity: isHovered ? 1 : 0.7 }}
                        >
                            {/* Color Block */}
                            <rect 
                                x={x} 
                                y={0} 
                                width={Math.max(width, 1)} 
                                height={SVG_HEIGHT} 
                                fill={color} 
                                fillOpacity={isHovered ? 0.4 : 0.25} 
                                stroke={isHovered ? color : 'none'}
                                strokeWidth={isHovered ? 1 : 0}
                            />
                            {/* Error Overlays */}
                            {region.errorType === 'parallel' && (
                                <rect x={x} y={0} width={Math.max(width, 1)} height={SVG_HEIGHT} fill={`url(#${parallelPatternId})`} fillOpacity={0.5} stroke="red" strokeWidth={1} strokeOpacity={0.5} />
                            )}
                            {region.errorType === 'direct' && (
                                <rect x={x} y={0} width={Math.max(width, 1)} height={SVG_HEIGHT} fill="none" stroke="orange" strokeWidth={2} strokeDasharray="4,2" />
                            )}
                            {/* Interval Label at top */}
                            <text x={x + 2} y={12} fill="rgba(255,255,255,0.7)" fontSize="9" fontFamily="monospace" fontWeight={isHovered ? 'bold' : 'normal'}>
                                {region.intervalLabel}
                            </text>
                        </g>
                    );
                })}

                {/* Measure Lines */}
                {Array.from({ length: totalMeasures }).map((_, i) => (
                     <line key={`meas-${i}`} x1={tickToX(i * ticksPerMeasure)} y1={0} x2={tickToX(i * ticksPerMeasure)} y2={SVG_HEIGHT} stroke="#4b5563" strokeWidth={0.5} />
                ))}

                {/* Notes */}
                {notes.map((note, idx) => {
                    let noteColor = '#14b8a6';
                    let strokeColor = '#0f766e';
                    let opacity = 1;
                    if (note.isOrnament) { opacity = 0.5; strokeColor = 'rgba(255,255,255,0.2)'; }
                    if (showVoices && note.voiceIndex !== undefined) {
                        noteColor = VOICE_COLORS[note.voiceIndex % VOICE_COLORS.length];
                        strokeColor = 'rgba(0,0,0,0.2)';
                    }
                    const voiceName = note.voiceIndex !== undefined ? getVoiceLabel(note.voiceIndex, totalVoices) : 'N/A';
                    return (
                        <rect 
                            key={idx}
                            x={tickToX(note.ticks)}
                            y={midiToY(note.midi) + 1}
                            width={Math.max(tickToX(note.durationTicks), 2)}
                            height={NOTE_HEIGHT - 2}
                            fill={noteColor}
                            fillOpacity={opacity}
                            rx={1}
                            stroke={strokeColor}
                            strokeWidth={0.5}
                            className="pointer-events-none" // Notes aren't clicked, regions are
                        >
                            <title>{`${note.name} | ${voiceName}`}</title>
                        </rect>
                    );
                })}
            </svg>
          </div>
       </div>
    </div>
  );
};

export default PianoRoll;

import React, { useMemo } from 'react';
import { StrettoCandidate, PianoRollTrackData, HarmonicRegion, RawNote } from '../../types';
import { PlayIcon, StopIcon, DocumentTextIcon, DownloadIcon } from '../Icons';
import PianoRoll from '../PianoRoll';
import { playSpecificNotes } from '../midiPlaybackService';
import { getIntervalLabel } from '../services/midiSpelling';

interface StrettoInspectorProps {
    candidate: StrettoCandidate | null;
    ppq: number;
    ts: { num: number, den: number };
    isPlaying: boolean;
    onPlay: (notes: RawNote[]) => void;
    assemblyResult: string;
    assemblyLog: string[];
    onClearAssembly: () => void;
    onDownloadChain: () => void;
}

export default function StrettoInspector({ 
    candidate, ppq, ts, isPlaying, onPlay, 
    assemblyResult, assemblyLog, onClearAssembly, onDownloadChain 
}: StrettoInspectorProps) {

    const pianoRollData: PianoRollTrackData | null = useMemo(() => {
        if (!candidate) return null;
        return {
            name: `Stretto ${candidate.intervalLabel}`,
            ppq,
            timeSignature: { numerator: ts.num, denominator: ts.den },
            notes: candidate.notes.map(n => ({
                midi: n.midi,
                ticks: n.ticks,
                durationTicks: n.durationTicks,
                velocity: n.velocity,
                name: n.name,
                voiceIndex: n.voiceIndex ?? 0, 
                isOrnament: false
            })),
            harmonicRegions: candidate.regions 
        };
    }, [candidate, ppq, ts]);

    const intervalStats = useMemo(() => {
        if (!candidate) return { spectrum: [], total: 0 };
        const counts: Record<string, number> = {};
        const categories: Record<string, 'perf' | 'imp' | 'diss'> = {};
        let total = 0;

        // Sampling Resolution: 16th notes
        const step = ppq / 4;
        const maxTick = Math.max(...candidate.notes.map(n => n.ticks + n.durationTicks));

        for(let t = 0; t < maxTick; t += step) {
            const active = candidate.notes.filter(n => n.ticks <= t && (n.ticks + n.durationTicks) > t);
            if (active.length < 2) continue;

            const midis = active.map(n => n.midi).sort((a,b) => a-b);
            const sliceIntervals = new Set<string>();

            for(let i=0; i<midis.length; i++) {
                for(let j=i+1; j<midis.length; j++) {
                    const diff = Math.abs(midis[j] - midis[i]) % 12;
                    let label = getIntervalLabel(diff);
                    if (label.startsWith('P8')) label = 'P8';
                    if (label.startsWith('P1')) label = 'P1';

                    sliceIntervals.add(label);

                    if ([0, 7].includes(diff)) categories[label] = 'perf';
                    else if ([3, 4, 8, 9].includes(diff)) categories[label] = 'imp';
                    else categories[label] = 'diss';
                }
            }

            sliceIntervals.forEach(l => {
                counts[l] = (counts[l] || 0) + 1;
                total++;
            });
        }

        // Group for spectrum
        const spectrum = Object.entries(counts)
            .map(([label, count]) => ({ label, count, pct: (count/total)*100, cat: categories[label] }))
            .sort((a,b) => {
                // Sort order: Perfect -> Imperfect -> Dissonant
                const score = (c: string) => c === 'perf' ? 3 : c === 'imp' ? 2 : 1;
                if (score(a.cat) !== score(b.cat)) return score(b.cat) - score(a.cat);
                return b.count - a.count;
            });

        return { spectrum, total };
    }, [candidate, ppq]);

    const handleRegionClick = (region: HarmonicRegion) => {
        if (!candidate) return;
        const activeNotes = candidate.notes.filter(n => 
            n.ticks < region.endTick && (n.ticks + n.durationTicks) > region.startTick
        );
        if (activeNotes.length > 0) {
            const notesToPlay = activeNotes.map(n => ({
                midi: n.midi, 
                duration: n.durationTicks * (0.5 / ppq), 
                velocity: n.velocity
            }));
            playSpecificNotes(notesToPlay);
        }
    };

    const handleExportAnalysis = () => {
        if (!candidate) return;
        let text = `STRETTO ANALYSIS REPORT\nCandidate ID: ${candidate.id}\nInterval: ${candidate.intervalLabel}\nDelay: ${candidate.delayBeats} Beats\n`;
        text += `\nMETRICS\n`;
        text += `Dissonant Time: ${Math.round(candidate.dissonanceRatio * 100)}%\n`;
        text += `Pair Intensity: ${candidate.pairDissonanceScore.toFixed(1)}\n`;
        text += `Grade: ${candidate.grade}\n`;
        text += `Errors: ${candidate.errors.length}\n`;

        text += `\nHARMONIC SPECTRUM\n`;
        intervalStats.spectrum.forEach(s => {
            text += `${s.label.padEnd(6)}: ${Math.round(s.pct)}% (${s.cat})\n`;
        });

        if (candidate.detectedChords && candidate.detectedChords.length > 0) {
            text += `\nDETECTED CHORDS\n${candidate.detectedChords.join(', ')}\n`;
        }

        const blob = new Blob([text], { type: 'text/plain' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `Analysis_${candidate.id}.txt`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
    };

    const getColor = (cat: string) => {
        if (cat === 'perf') return 'bg-blue-500';
        if (cat === 'imp') return 'bg-green-500';
        return 'bg-red-500';
    };

    return (
        <div className="bg-gray-800 border border-gray-700 rounded p-4 flex flex-col h-[600px] shadow-lg relative overflow-hidden">
            {/* Gemini Assembly Overlay */}
            {assemblyResult && (
                <div className="absolute inset-0 bg-gray-800 z-30 p-4 flex flex-col animate-fade-in">
                    <div className="flex justify-between items-center mb-4 border-b border-gray-700 pb-2">
                        <h3 className="font-bold text-brand-primary">Gemini Stretto Chain</h3>
                        <button onClick={onClearAssembly} className="text-gray-500 hover:text-white">✕ Close</button>
                    </div>
                    <div className="flex-grow flex flex-col gap-4 overflow-hidden">
                        <div className="flex-1 bg-black rounded p-3 font-mono text-xs text-gray-300 overflow-auto border border-gray-700 whitespace-pre-wrap">
                            {assemblyResult}
                        </div>
                        <div className="grid grid-cols-2 gap-2">
                            <button onClick={onDownloadChain} className="w-full py-2 bg-brand-secondary text-white font-bold rounded flex items-center justify-center gap-2 hover:bg-brand-primary transition-colors">
                                <DownloadIcon className="w-4 h-4"/> Download Chain MIDI
                            </button>
                            <button onClick={() => { navigator.clipboard.writeText(assemblyResult); alert("ABC Chain copied to clipboard!"); }} className="w-full py-2 bg-gray-700 text-white font-bold rounded hover:bg-gray-600 transition-colors">
                                Copy ABC Text
                            </button>
                        </div>
                        <div className="h-24 bg-gray-900 rounded p-2 border border-gray-700 overflow-auto text-[10px]">
                            <h4 className="font-bold text-gray-500 uppercase mb-1">Verification History</h4>
                            {assemblyLog.map((log, i) => (
                                <div key={i} className="border-l border-gray-700 pl-2 mb-1 text-gray-400">{log}</div>
                            ))}
                        </div>
                    </div>
                </div>
            )}

            {candidate && pianoRollData ? (
                <>
                    <div className="flex justify-between items-start mb-4">
                        <div>
                            <h3 className="text-xl font-bold text-white">
                                Stretto: {candidate.intervalLabel} @ {candidate.delayBeats}B
                            </h3>
                            <div className="flex items-center gap-4 mt-1">
                                <div className="flex items-center gap-1 text-[10px] bg-black/30 px-2 py-1 rounded">
                                    <span className="text-gray-400">Time Diss:</span>
                                    <span className={`${candidate.dissonanceRatio > 0.4 ? 'text-red-400' : 'text-green-400'} font-bold`}>
                                        {Math.round(candidate.dissonanceRatio * 100)}%
                                    </span>
                                </div>
                                <div className="flex items-center gap-1 text-[10px] bg-black/30 px-2 py-1 rounded">
                                    <span className="text-gray-400">Pair Intensity:</span>
                                    <span className="text-gray-200 font-bold">{candidate.pairDissonanceScore.toFixed(1)}</span>
                                </div>
                                <span className={`text-xs font-bold ${candidate.grade === 'STRONG' ? 'text-green-400' : candidate.grade === 'VIABLE' ? 'text-yellow-400' : 'text-red-400'}`}>
                                    {candidate.grade}
                                </span>
                            </div>
                        </div>
                        <div className="flex gap-2">
                            <button onClick={handleExportAnalysis} className="p-2 bg-gray-700 rounded-full hover:bg-gray-600 transition-colors text-white" title="Export Analysis Report">
                                <DocumentTextIcon className="w-5 h-5"/>
                            </button>
                            <button onClick={() => onPlay(candidate.notes)} className="bg-brand-primary p-2 rounded-full hover:bg-brand-secondary transition-transform active:scale-95 shadow-md">
                                {isPlaying ? <StopIcon className="w-5 h-5 text-white"/> : <PlayIcon className="w-5 h-5 text-white"/>}
                            </button>
                        </div>
                    </div>

                    <div className="h-80 flex-grow bg-gray-900 rounded border border-gray-700 mb-2 overflow-hidden shadow-inner relative">
                        <PianoRoll trackData={pianoRollData} onRegionClick={handleRegionClick} />
                        <div className="absolute top-2 right-2 flex flex-col gap-1 text-[9px] bg-black/70 p-1.5 rounded backdrop-blur-sm pointer-events-none z-10">
                            <span className="text-purple-400 font-bold">■ Dissonance</span>
                            <span className="text-red-500 font-bold">■ Consecutive Diss</span>
                            <span className="text-teal-400 font-bold">■ Consonance</span>
                        </div>
                    </div>

                    {/* Harmonic Spectrum Bar */}
                    <div className="h-24 bg-gray-900/50 rounded p-2 border border-gray-700 flex flex-col">
                        <div className="flex justify-between items-center mb-1">
                            <h4 className="text-[9px] font-bold text-gray-500 uppercase">Harmonic Spectrum</h4>
                            <div className="flex gap-2 text-[8px] text-gray-400">
                                <span className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-blue-500"></div> Perfect</span>
                                <span className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-green-500"></div> Imperfect</span>
                                <span className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-red-500"></div> Dissonant</span>
                            </div>
                        </div>

                        {/* Stacked Bar Visual */}
                        <div className="w-full h-4 rounded-full overflow-hidden flex mb-2 bg-gray-800">
                            {intervalStats.spectrum.map((s, i) => (
                                <div 
                                    key={i} 
                                    className={`${getColor(s.cat)} h-full hover:opacity-80 transition-opacity`} 
                                    style={{ width: `${s.pct}%` }} 
                                    title={`${s.label}: ${Math.round(s.pct)}%`}
                                ></div>
                            ))}
                        </div>

                        {/* Top Intervals Legend */}
                        <div className="flex gap-2 overflow-x-auto pb-1">
                            {intervalStats.spectrum.slice(0, 6).map((item, i) => (
                                <div key={i} className="flex flex-col items-center bg-black/20 px-2 py-1 rounded min-w-[30px]">
                                    <span className={`text-[10px] font-bold ${item.cat === 'diss' ? 'text-red-400' : 'text-gray-300'}`}>{item.label}</span>
                                    <span className="text-[9px] text-gray-500">{Math.round(item.pct)}%</span>
                                </div>
                            ))}
                        </div>
                    </div>
                </>
            ) : (
                <div className="flex flex-col items-center justify-center h-full text-gray-500">
                    <span className="text-4xl mb-4 opacity-50">🎹</span>
                    <p className="font-bold text-gray-400">Select a candidate to visualize.</p>
                </div>
            )}
        </div>
    );
}

import React, { useState, useMemo } from 'react';
import { StrettoCandidate, StrettoGrade } from '../../types';
import { getStrictPitchName } from '../services/midiSpelling';
import { DocumentTextIcon } from '../Icons';

interface StrettoListProps {
    candidates: StrettoCandidate[];
    processedResults: StrettoCandidate[]; 
    gradeFilter: Record<StrettoGrade, boolean>;
    setGradeFilter: (val: Record<StrettoGrade, boolean>) => void;
    selectedId: string | null;
    onSelect: (candidate: StrettoCandidate) => void;
    checkedIds: Set<string>;
    onToggleCheck: (id: string) => void;
}

type SortKey = 'grade' | 'delay' | 'interval' | 'dissonance' | 'intensity' | 'entry' | 'errors';

export default function StrettoList({ 
    candidates, processedResults, gradeFilter, setGradeFilter, 
    selectedId, onSelect, checkedIds, onToggleCheck 
}: StrettoListProps) {
    const [sortKey, setSortKey] = useState<SortKey>('grade');
    const [sortDir, setSortDir] = useState<'asc' | 'desc'>('desc');

    // Multi-select Filters
    const [selectedPitches, setSelectedPitches] = useState<Set<string>>(new Set());
    const [selectedIntervals, setSelectedIntervals] = useState<Set<string>>(new Set());
    const [selectedDelays, setSelectedDelays] = useState<Set<string>>(new Set());

    // Logic Filters
    const [maxDissonance, setMaxDissonance] = useState<number>(100);
    const [onlyResolved, setOnlyResolved] = useState<boolean>(false);

    // Extract unique values for filter toggles
    const { availablePitches, availableIntervals, availableDelays } = useMemo(() => {
        const pitches = new Set<string>();
        const intervals = new Set<string>();
        const delays = new Set<string>();

        candidates.forEach(c => {
            delays.add(c.delayBeats.toString());
            intervals.add(c.intervalLabel);
            const firstAnswerNote = c.notes.find(n => n.voiceIndex === 1);
            if (firstAnswerNote) {
                pitches.add(getStrictPitchName(firstAnswerNote.midi).replace(/\d/g, ''));
            }
        });

        return {
            availablePitches: Array.from(pitches).sort(),
            availableIntervals: Array.from(intervals).sort((a,b) => a.localeCompare(b, undefined, {numeric: true})),
            availableDelays: Array.from(delays).sort((a,b) => parseFloat(a) - parseFloat(b))
        };
    }, [candidates]);

    // Combined Advanced Filtering
    const finalFilteredResults = useMemo(() => {
        return processedResults.filter(r => {
            if (!gradeFilter[r.grade]) return false;

            if (selectedPitches.size > 0) {
                const firstAnswerNote = r.notes.find(n => n.voiceIndex === 1);
                if (!firstAnswerNote) return false;
                const pName = getStrictPitchName(firstAnswerNote.midi).replace(/\d/g, '');
                if (!selectedPitches.has(pName)) return false;
            }

            if (selectedIntervals.size > 0 && !selectedIntervals.has(r.intervalLabel)) return false;

            if (selectedDelays.size > 0 && !selectedDelays.has(r.delayBeats.toString())) return false;

            if (Math.round(r.dissonanceRatio * 100) > maxDissonance) return false;

            if (onlyResolved && r.endsOnDissonance) return false;

            return true;
        });
    }, [processedResults, gradeFilter, selectedPitches, selectedIntervals, selectedDelays, maxDissonance, onlyResolved]);

    // Sorting Logic
    const sortedResults = useMemo(() => {
        const res = [...finalFilteredResults];
        res.sort((a, b) => {
            let diff = 0;
            const firstA = a.notes.find(n => n.voiceIndex === 1);
            const firstB = b.notes.find(n => n.voiceIndex === 1);

            switch (sortKey) {
                case 'grade':
                    const score = { 'STRONG': 3, 'VIABLE': 2, 'INVALID': 1 };
                    diff = score[a.grade] - score[b.grade];
                    break;
                case 'delay':
                    diff = a.delayTicks - b.delayTicks;
                    break;
                case 'interval':
                    diff = Math.abs(a.intervalSemis) - Math.abs(b.intervalSemis);
                    break;
                case 'dissonance':
                    diff = a.dissonanceRatio - b.dissonanceRatio;
                    break;
                case 'intensity':
                    diff = a.pairDissonanceScore - b.pairDissonanceScore;
                    break;
                case 'entry':
                    diff = (firstA?.midi || 0) - (firstB?.midi || 0);
                    break;
                case 'errors':
                    diff = a.errors.length - b.errors.length;
                    break;
            }
            return sortDir === 'asc' ? diff : -diff;
        });
        return res;
    }, [finalFilteredResults, sortKey, sortDir]);

    const handleSort = (key: SortKey) => {
        if (sortKey === key) setSortDir(prev => prev === 'asc' ? 'desc' : 'asc');
        else { setSortKey(key); setSortDir(key === 'grade' || key === 'dissonance' || key === 'intensity' ? 'desc' : 'asc'); }
    };

    const handleExport = () => {
        if (sortedResults.length === 0) return;

        let md = `| Interval | Delay | Entry | Diss Time | Intensity | Errors |\n`;
        md += `| :--- | :--- | :--- | :--- | :--- | :--- |\n`;

        sortedResults.forEach(r => {
            const firstAnswerNote = r.notes.find(n => n.voiceIndex === 1);
            const entryNote = firstAnswerNote ? getStrictPitchName(firstAnswerNote.midi) : '?';
            const diss = `${Math.round(r.dissonanceRatio * 100)}%`;
            const intent = r.pairDissonanceScore.toFixed(1);
            const errs = r.errors.length > 0 ? r.errors.map(e => e.type).join(', ') : '-';

            md += `| ${r.intervalLabel} | ${r.delayBeats}B | ${entryNote} | ${diss} | ${intent} | ${errs} |\n`;
        });

        const blob = new Blob([md], { type: 'text/markdown' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `Stretto_Lab_Export_${Date.now()}.md`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
    };

    const toggleFilterSet = (set: Set<string>, val: string) => {
        const next = new Set(set);
        if (next.has(val)) next.delete(val);
        else next.add(val);
        return next;
    };

    const renderToggleGroup = (label: string, items: string[], current: Set<string>, update: (s: Set<string>) => void) => (
        <div className="flex flex-col gap-1">
            <div className="flex justify-between items-center">
                <label className="text-[9px] font-bold text-gray-500 uppercase tracking-widest">{label}</label>
                <button onClick={() => update(new Set())} className="text-[8px] text-brand-primary hover:underline">{current.size === 0 ? 'All' : 'Clear'}</button>
            </div>
            <div className="flex flex-wrap gap-1 max-h-12 overflow-y-auto bg-black/20 p-1 rounded border border-gray-700 shadow-inner">
                {items.map(item => (
                    <button
                        key={item}
                        onClick={() => update(toggleFilterSet(current, item))}
                        className={`px-1.5 py-0.5 text-[9px] font-bold rounded transition-all border ${current.has(item) ? 'bg-brand-primary border-brand-primary text-white shadow-sm' : 'bg-gray-800 border-gray-600 text-gray-500 hover:border-gray-400'}`}
                    >
                        {item}
                    </button>
                ))}
            </div>
        </div>
    );

    return (
        <div className="bg-gray-900 border border-gray-700 rounded h-[600px] flex flex-col shadow-inner relative">
            <div className="p-3 border-b border-gray-700 bg-gray-800 flex flex-col gap-4">
                <div className="flex justify-between items-center -mb-2">
                    <h3 className="text-[10px] font-bold text-brand-primary uppercase tracking-tighter">Power Filter</h3>
                    <button 
                        onClick={handleExport}
                        className="flex items-center gap-1.5 px-2 py-1 bg-gray-700 hover:bg-gray-600 text-[9px] text-gray-300 rounded border border-gray-600 transition-colors"
                    >
                        <DocumentTextIcon className="w-3.5 h-3.5" /> Export Grid
                    </button>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
                    {renderToggleGroup("Intervals", availableIntervals, selectedIntervals, setSelectedIntervals)}
                    {renderToggleGroup("Delays", availableDelays, selectedDelays, setSelectedDelays)}
                    {renderToggleGroup("Entry Pitches", availablePitches, selectedPitches, setSelectedPitches)}
                </div>

                <div className="grid grid-cols-1 md:grid-cols-3 gap-4 border-t border-gray-700 pt-3">
                    <div className="flex flex-col gap-1">
                        <label className="text-[9px] font-bold text-gray-500 uppercase tracking-widest">Verdict</label>
                        <div className="flex gap-1">
                            {(['STRONG', 'VIABLE', 'INVALID'] as StrettoGrade[]).map(g => (
                                <button 
                                    key={g}
                                    onClick={() => setGradeFilter({ ...gradeFilter, [g]: !gradeFilter[g] })} 
                                    className={`flex-1 py-1 text-[9px] rounded font-bold border transition-all ${gradeFilter[g] ? 'bg-brand-primary/20 border-brand-primary text-brand-primary' : 'bg-gray-900 border-gray-700 text-gray-600'}`}
                                >
                                    {g.charAt(0)}
                                </button>
                            ))}
                        </div>
                    </div>

                    <div className="flex flex-col gap-1">
                        <div className="flex justify-between">
                            <label className="text-[9px] font-bold text-gray-500 uppercase tracking-widest">Max Dissonance</label>
                            <span className="text-[9px] font-mono text-brand-primary font-bold">{maxDissonance}%</span>
                        </div>
                        <input 
                            type="range" min="0" max="100" step="1" 
                            value={maxDissonance} 
                            onChange={(e) => setMaxDissonance(parseInt(e.target.value))}
                            className="w-full h-1 bg-gray-700 rounded-lg appearance-none cursor-pointer accent-brand-primary"
                        />
                    </div>

                    <div className="flex flex-col justify-end">
                        <label className={`flex items-center gap-2 p-2 bg-gray-900/50 rounded border cursor-pointer transition-all ${onlyResolved ? 'border-green-500/50 bg-green-900/10' : 'border-gray-700'}`}>
                            <input 
                                type="checkbox" 
                                checked={onlyResolved} 
                                onChange={(e) => setOnlyResolved(e.target.checked)}
                                className="w-3 h-3 rounded bg-gray-800 border-gray-600 text-brand-primary"
                            />
                            <span className={`text-[10px] font-bold uppercase tracking-tight ${onlyResolved ? 'text-green-400' : 'text-gray-500'}`}>Resolved End Only</span>
                        </label>
                    </div>
                </div>
            </div>

            <div className="overflow-y-auto flex-grow p-1">
                <div className="sticky top-0 bg-gray-900 z-10 grid grid-cols-12 gap-1 px-2 py-2 text-[9px] font-bold text-gray-500 uppercase border-b border-gray-800">
                    <div className="col-span-1"></div>
                    <button onClick={() => handleSort('interval')} className={`col-span-2 text-left hover:text-white transition-colors ${sortKey === 'interval' ? 'text-brand-primary' : ''}`}>
                        Int {sortKey === 'interval' && (sortDir === 'asc' ? '↑' : '↓')}
                    </button>
                    <button onClick={() => handleSort('delay')} className={`col-span-1 text-left hover:text-white transition-colors ${sortKey === 'delay' ? 'text-brand-primary' : ''}`}>
                        Del {sortKey === 'delay' && (sortDir === 'asc' ? '↑' : '↓')}
                    </button>
                    <button onClick={() => handleSort('entry')} className={`col-span-2 text-left hover:text-white transition-colors ${sortKey === 'entry' ? 'text-brand-primary' : ''}`}>
                        Entry {sortKey === 'entry' && (sortDir === 'asc' ? '↑' : '↓')}
                    </button>
                    <button onClick={() => handleSort('dissonance')} className={`col-span-2 text-left hover:text-white transition-colors ${sortKey === 'dissonance' ? 'text-brand-primary' : ''}`}>
                        Time% {sortKey === 'dissonance' && (sortDir === 'asc' ? '↑' : '↓')}
                    </button>
                    <button onClick={() => handleSort('intensity')} className={`col-span-2 text-left hover:text-white transition-colors ${sortKey === 'intensity' ? 'text-brand-primary' : ''}`}>
                        Intens {sortKey === 'intensity' && (sortDir === 'asc' ? '↑' : '↓')}
                    </button>
                    <button onClick={() => handleSort('errors')} className={`col-span-2 text-right hover:text-white transition-colors ${sortKey === 'errors' ? 'text-brand-primary' : ''}`}>
                        Err {sortKey === 'errors' && (sortDir === 'asc' ? '↑' : '↓')}
                    </button>
                </div>

                {sortedResults.length === 0 ? (
                    <div className="py-20 text-center text-gray-600 text-sm italic">No matching strettos. Try widening filters.</div>
                ) : (
                    sortedResults.map((r) => {
                        const firstAnswerNote = r.notes.find(n => n.voiceIndex === 1);
                        const entryNote = firstAnswerNote ? getStrictPitchName(firstAnswerNote.midi) : '?';
                        return (
                            <div 
                                key={r.id} 
                                onClick={() => onSelect(r)} 
                                className={`grid grid-cols-12 gap-1 p-2 rounded cursor-pointer border-b border-gray-800 items-center transition-all ${selectedId === r.id ? 'bg-gray-800 ring-1 ring-brand-primary/50' : 'hover:bg-gray-800/50'}`}
                            >
                                <div className="col-span-1 flex justify-center" onClick={(e) => e.stopPropagation()}>
                                    <input 
                                        type="checkbox" 
                                        checked={checkedIds.has(r.id)} 
                                        onChange={() => onToggleCheck(r.id)} 
                                        className="rounded bg-gray-700 border-gray-600 text-brand-primary w-3 h-3" 
                                    />
                                </div>
                                <span className={`col-span-2 font-bold text-[10px] truncate ${r.intervalLabel.includes('Inv') ? 'text-blue-400' : 'text-brand-primary'}`}>
                                    {r.intervalLabel}
                                </span>
                                <span className="col-span-1 text-gray-300 text-[10px]">{r.delayBeats}B</span>
                                <span className="col-span-2 text-gray-500 text-[10px] font-mono">{entryNote}</span>
                                <span className={`col-span-2 text-[10px] font-mono font-bold ${r.dissonanceRatio > 0.4 ? 'text-red-400' : r.dissonanceRatio > 0.2 ? 'text-yellow-400' : 'text-green-400'}`}>
                                    {Math.round(r.dissonanceRatio * 100)}%
                                </span>
                                <span className="col-span-2 text-[10px] text-gray-400 font-mono">
                                    {r.pairDissonanceScore.toFixed(1)}
                                </span>
                                <span className="col-span-2 text-[9px] text-gray-500 text-right">
                                    {r.errors.length > 0 ? (
                                        <span className="bg-red-900/30 text-red-400 px-1 rounded border border-red-900/50">{r.errors.length}</span>
                                    ) : '-'}
                                </span>
                            </div>
                        );
                    })
                )}
            </div>

            <div className="p-2 border-t border-gray-800 bg-gray-800/50 flex justify-between items-center px-4">
                <div className="flex items-center gap-3">
                    <span className="text-[10px] text-gray-500 italic">{sortedResults.length} Visible</span>
                    <span className="text-[10px] text-gray-700">|</span>
                    <span className="text-[10px] text-gray-500">{checkedIds.size} Selected</span>
                </div>
                <button 
                    onClick={() => { 
                        setSelectedIntervals(new Set()); 
                        setSelectedDelays(new Set()); 
                        setSelectedPitches(new Set()); 
                        setMaxDissonance(100); 
                        setOnlyResolved(false);
                        setGradeFilter({STRONG: true, VIABLE: true, INVALID: true}) 
                    }}
                    className="text-[9px] text-brand-primary hover:text-white uppercase font-bold tracking-wider"
                >
                    Reset Power Filter
                </button>
            </div>
        </div>
    );
}

import React from 'react';
import { StrettoSearchOptions, StrettoChainResult, StrettoCandidate, RawNote, StrettoSearchReport, HarmonicRegion } from '../../types';
import StrettoSearchPanel from './StrettoSearchPanel';
import StrettoResultsList from './StrettoResultsList';
import StrettoInspector from './StrettoInspector';
import { DownloadIcon } from '../Icons';
import { generatePolyphonicHarmonicRegions } from '../services/strettoCore'; // NEW IMPORT
import { getStrictPitchName } from '../services/midiSpelling';

interface StrettoChainViewProps {
    searchOptions: StrettoSearchOptions;
    setSearchOptions: (opt: StrettoSearchOptions) => void;
    onSearch: () => void;
    isSearching: boolean;
    chainResults: StrettoChainResult[];
    selectedChain: StrettoChainResult | null;
    setSelectedChain: (res: StrettoChainResult | null) => void;
    voiceNames?: Record<number, string>;
    setVoiceNames?: (names: Record<number, string>) => void;

    // Inspector Props
    chainToCandidate: StrettoCandidate | null; // Note: We actually override this logic locally to ensure polyphony
    ppq: number;
    ts: { num: number, den: number };
    isPlaying: boolean;
    onPlay: (notes: RawNote[]) => void;
    onDownloadChain: () => void;
    searchReport?: StrettoSearchReport | null;

    // Master Transposition
    masterTransposition: number;
    setMasterTransposition: (val: number) => void;
    subjectNotes: RawNote[]; // New prop
}

export default function StrettoChainView({
    searchOptions, setSearchOptions, onSearch, isSearching,
    chainResults, selectedChain, setSelectedChain, voiceNames, setVoiceNames,
    chainToCandidate: _unusedLegacyProp, // We recreate it here to ensure correct polyphonic region generation
    ppq, ts, isPlaying, onPlay, onDownloadChain,
    searchReport, masterTransposition, setMasterTransposition,
    subjectNotes
}: StrettoChainViewProps) {

    // Re-implement candidate generation here to use the new Polyphonic Region Logic
    // instead of relying on the parent's potentially outdated logic
    const chainCandidate = React.useMemo((): StrettoCandidate | null => {
        if (!selectedChain) return null;
        let allNotes: RawNote[] = [];
        const validSubjectNotes = subjectNotes.filter(n => !!n);
        const currentPpq = ppq || 480;
        if (validSubjectNotes.length === 0) return null;
        const sortedSubj = [...validSubjectNotes].sort((a,b)=>a.ticks-b.ticks);
        const startTick = sortedSubj[0].ticks;

        const SCALE_STEPS = [0, 2, 4, 5, 7, 9, 11];
        const invertPitchDiatonic = (pitch: number, pivot: number) => {
            const diff = pitch - pivot;
            const oct = Math.floor(diff / 12);
            const semi = (diff % 12 + 12) % 12;
            let degree = -1;
            let minErr = 99;
            SCALE_STEPS.forEach((s, i) => {
                if (Math.abs(s - semi) < minErr) { minErr = Math.abs(s - semi); degree = i; }
            });
            const absDegree = (oct * 7) + degree;
            const invAbsDegree = -absDegree;
            const invOct = Math.floor(invAbsDegree / 7);
            const invIndex = (invAbsDegree % 7 + 7) % 7;
            return pivot + (invOct * 12) + SCALE_STEPS[invIndex];
        };

        const invertPitchChromatic = (pitch: number, pivot: number) => {
            return pivot - (pitch - pivot);
        }

        selectedChain.entries.forEach((entry) => {
            const entryStartTick = Math.round(entry.startBeat * currentPpq);
            const transformed = sortedSubj.map(n => {
                let pitch = n.midi;

                if (entry.type === 'I') {
                    const rawInverted = searchOptions.useChromaticInversion 
                        ? invertPitchChromatic(n.midi, searchOptions.pivotMidi)
                        : invertPitchDiatonic(n.midi, searchOptions.pivotMidi);

                    const subjectFirst = sortedSubj[0].midi;
                    const invertedFirst = searchOptions.useChromaticInversion 
                        ? invertPitchChromatic(subjectFirst, searchOptions.pivotMidi)
                        : invertPitchDiatonic(subjectFirst, searchOptions.pivotMidi);

                    const targetStart = subjectFirst + entry.transposition;
                    const shift = targetStart - invertedFirst;
                    pitch = rawInverted + shift;
                } else {
                    pitch += entry.transposition;
                }

                pitch += masterTransposition;

                return { ...n, ticks: (n.ticks - startTick) + entryStartTick, midi: pitch, name: getStrictPitchName(pitch), voiceIndex: entry.voiceIndex };
            });
            const entryEnd = entryStartTick + (entry.length * (currentPpq/4));
            const clipped = transformed.filter(n => n.ticks < entryEnd).map(n => ({ ...n, durationTicks: Math.min(n.durationTicks, entryEnd - n.ticks) }));
            allNotes = [...allNotes, ...clipped];
        });

        // Use new Polyphonic logic for the Chain
        const harmonicRegions = generatePolyphonicHarmonicRegions(allNotes);

        return { 
            id: selectedChain.id, 
            intervalLabel: "Chain", 
            intervalSemis: 0, 
            delayBeats: 0, 
            delayTicks: 0, 
            grade: 'STRONG', 
            errors: [], 
            notes: allNotes, 
            regions: harmonicRegions, 
            dissonanceRatio: selectedChain.dissonanceRatio || 0,
            pairDissonanceScore: 0, // Not calculated for chain summary currently, visual only
            endsOnDissonance: false,
            detectedChords: selectedChain.detectedChords
        };
    }, [selectedChain, subjectNotes, ppq, searchOptions.pivotMidi, searchOptions.useChromaticInversion, masterTransposition]);

    return (
        <>
            <StrettoSearchPanel 
                options={searchOptions} 
                setOptions={setSearchOptions}
                onSearch={onSearch}
                isSearching={isSearching}
                voiceNames={voiceNames}
                setVoiceNames={setVoiceNames}
                subjectNotes={subjectNotes}
                ppq={ppq}
            />

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8">
                <div className="lg:col-span-1 bg-gray-900 border border-gray-700 rounded shadow-inner">
                    <div className="p-3 border-b border-gray-700 bg-gray-800 flex justify-between items-center">
                        <h3 className="text-xs font-bold text-gray-400">FOUND CHAINS ({chainResults.length})</h3>
                        {searchReport && (
                            <div className="text-[9px] text-gray-500 text-right">
                                {searchReport.stats.nodesVisited.toLocaleString()} nodes in {searchReport.stats.timeMs}ms
                            </div>
                        )}
                    </div>
                    {searchReport && searchReport.stats.stopReason !== 'Success' && (
                        <div className="bg-yellow-900/30 border-b border-yellow-800 p-2 text-[10px] text-yellow-300">
                            <strong>Search {searchReport.stats.stopReason}:</strong> No valid chains of length {searchOptions.targetChainLength} found.
                            Showing partial chains (Max Depth: {searchReport.stats.maxDepthReached}).
                        </div>
                    )}
                    <StrettoResultsList 
                        results={chainResults}
                        selectedId={selectedChain?.id || null}
                        onSelect={setSelectedChain}
                        voiceNames={voiceNames}
                    />
                </div>
                <div className="lg:col-span-2">
                    <StrettoInspector 
                        candidate={chainCandidate}
                        ppq={ppq}
                        ts={ts}
                        isPlaying={isPlaying}
                        onPlay={onPlay}
                        assemblyResult={""}
                        assemblyLog={[]}
                        onClearAssembly={() => {}}
                        onDownloadChain={onDownloadChain}
                    />

                    <div className="mt-4 flex flex-col md:flex-row justify-between items-center gap-4 bg-gray-800 p-3 rounded border border-gray-700">
                        <div className="flex items-center gap-4">
                            <span className="text-xs font-bold text-gray-400 uppercase">Master Transpose:</span>
                            <div className="flex items-center gap-2">
                                <button 
                                    onClick={() => setMasterTransposition(Math.max(-24, masterTransposition - 1))}
                                    className="bg-gray-700 hover:bg-gray-600 text-white w-6 h-6 rounded flex items-center justify-center font-bold text-sm"
                                >-</button>
                                <span className={`text-sm font-mono w-12 text-center ${masterTransposition !== 0 ? 'text-brand-primary font-bold' : 'text-gray-300'}`}>
                                    {masterTransposition > 0 ? '+' : ''}{masterTransposition}
                                </span>
                                <button 
                                    onClick={() => setMasterTransposition(Math.min(24, masterTransposition + 1))}
                                    className="bg-gray-700 hover:bg-gray-600 text-white w-6 h-6 rounded flex items-center justify-center font-bold text-sm"
                                >+</button>
                            </div>
                            <span className="text-[10px] text-gray-500 hidden sm:inline">Shift entire chain before export.</span>
                        </div>

                        {chainCandidate && (
                            <button 
                                onClick={onDownloadChain}
                                className="flex items-center gap-2 px-4 py-2 bg-brand-primary text-white font-bold rounded shadow-lg hover:bg-brand-secondary transition-colors"
                            >
                                <DownloadIcon className="w-4 h-4" /> Download Chain MIDI
                            </button>
                        )}
                    </div>
                </div>
            </div>
        </>
    );
}

export interface TrackInfo {
  id: number;
  name: string;
  instrument: {
    name: string;
    number: number;
    family: string;
  };
  noteCount: number;
  ornamentCount?: number;
}

export enum AppState {
  IDLE = 'IDLE',
  LOADING = 'LOADING',
  LOADED = 'LOADED',
  ERROR = 'ERROR',
  GENERATING = 'GENERATING', 
  SUCCESS = 'SUCCESS',
}

export type MidiEventType = 'pitchBend' | 'controlChange' | 'programChange';

export interface MidiEventCounts {
  pitchBend: number;
  controlChange: number;
  programChange: number;
}

export type TempoChangeMode = 'speed' | 'time';

export type InversionMode = 'off' | 'global' | '1beat' | '2beats' | 'measure' | '2measures' | '4measures' | '8measures';

export type OutputStrategy = 'combine' | 'separate_tracks' | 'separate_voices';

export type VoiceAssignmentMode = 'auto' | 'manual'; 

export type RhythmFamily = 'Simple' | 'Triple' | 'Quintuplet';

export type HarmonicAnalysisMode = 'attack' | 'sustain' | 'hybrid' | 'arpeggio_window' | 'hia_v2';

export type PitchAnalysisMode = 'modal' | 'frequency';

export type HybridVoiceRole = 'sustain' | 'attack' | 'arpeggio' | 'ignore';

export type ArpeggioStrategy = 'note_based' | 'time_based';

export interface RhythmRule {
    enabled: boolean;
    family: RhythmFamily;
    minNoteValue: string; 
}

export interface AnalysisSection {
    id: string;
    name: string;
    startMeasure: number;
    endMeasure: number;
    harmonyMode: HarmonicAnalysisMode;
    pitchStatsMode: PitchAnalysisMode;

    // Granular Harmony Settings
    chordTolerance: string; 
    chordMinDuration: string; 
    arpeggioWindowVal: string; // Replaces bucketSizeBeats
    ignorePassingMotion: boolean; 

    // Hybrid Specifics
    hybridConfig: {
        voiceRoles: Record<number, HybridVoiceRole>;
        arpStrategy: ArpeggioStrategy;
        arpHistoryCount: number; 
        arpHistoryTime: string; 
    };

    // Reporting
    debugLogging?: boolean;
}

export interface ModalConversionOptions {
    enabled: boolean;
    root: number; 
    modeName: string; 
    mappings: Record<number, number>; 
}

export interface ConversionOptions {
    tempo: number;
    timeSignature: {
        numerator: number;
        denominator: number;
    };
    tempoChangeMode: TempoChangeMode;
    originalTempo: number;
    transposition: number;
    noteTimeScale: number;
    inversionMode: InversionMode;

    // Shadow Grid Options
    primaryRhythm: RhythmRule;
    secondaryRhythm: RhythmRule;

    quantizationValue: string; 

    quantizeDurationMin: string; 
    shiftToMeasure: boolean;
    detectOrnaments: boolean; 
    modalConversion: ModalConversionOptions;
    removeShortNotesThreshold: number; 
    pruneOverlaps: boolean; 
    pruneThresholdIndex: number;
    // Voice Separation Logic
    voiceSeparationOverlapTolerance: number; 
    voiceSeparationPitchBias: number; 
    voiceSeparationMaxVoices: number; 
    voiceSeparationDisableChords: boolean; 
    voiceAssignmentMode: VoiceAssignmentMode; 

    // Export Options
    outputStrategy: OutputStrategy;

    // Global Voice Naming
    voiceNames: Record<number, string>;

    // Analysis Options
    sections: AnalysisSection[];
}

export interface HarmonicRegion {
    startTick: number;
    endTick: number;
    type: 'perfect_consonance' | 'imperfect_consonance' | 'dissonance_1' | 'dissonance_consecutive';
    errorType?: 'parallel' | 'direct' | null;
    intervalLabel: string;
    description?: string;
}

export interface PianoRollTrackData {
    notes: {
        midi: number;
        ticks: number;
        durationTicks: number;
        velocity: number;
        name: string;
        voiceIndex?: number;
        isOrnament?: boolean;
    }[]; 
    name: string;
    ppq: number;
    timeSignature: {
        numerator: number;
        denominator: number;
    };
    harmonicRegions?: HarmonicRegion[];
}

export interface NoteValueStat {
    name: string;
    count: number;
    percentage: number;
    standardMultiplier: number; 
}

export interface ChordMatch {
