    root: string;
    quality: string;
    bass?: string;
    inversion?: string;
    score: number;
    missingNotes: string[];
}

export interface ChordEvent {
    timestamp: number; 
    measure: number;   
    formattedTime: string; 
    name: string;      
    root: string;
    quality: string;
    bass?: string;     
    inversion?: string; 
    ticks: number;     
    constituentNotes: string[]; 
    missingNotes: string[]; 
    alternatives: ChordMatch[];
