const MAJOR_SCALE_STEPS = [0, 2, 4, 5, 7, 9, 11];

function invertPitch(pitch: number, pivot: number, useChromatic: boolean): number {
    if (useChromatic) {
        return pivot - (pitch - pivot);
    }

    // Diatonic Inversion (Major Scale Assumption)
    const diff = pitch - pivot;
    const octaves = Math.floor(diff / 12);
    const semitone = (diff % 12 + 12) % 12;

    // Find closest scale step
    let degree = -1;
    let minErr = 99;
    MAJOR_SCALE_STEPS.forEach((s, i) => {
        if (Math.abs(s - semitone) < minErr) { 
            minErr = Math.abs(s - semitone); 
            degree = i; 
        }
    });

    // Invert the degree index relative to 0 (root)
    const absDegree = (octaves * 7) + degree;
    const invAbsDegree = -absDegree;

    const invOctaves = Math.floor(invAbsDegree / 7);
    const invIndex = (invAbsDegree % 7 + 7) % 7;

    return pivot + (invOctaves * 12) + MAJOR_SCALE_STEPS[invIndex];
}

// Determines if any dissonance exists in a set of pitches
function analyzeVerticalSlice(pitches: number[]): { isDissonant: boolean; label: string } {
    if (pitches.length < 2) return { isDissonant: false, label: '' };

    const sorted = [...pitches].sort((a,b) => a-b);
    const bass = sorted[0];

    for (let i = 0; i < sorted.length; i++) {
        for (let j = i + 1; j < sorted.length; j++) {
            const p1 = sorted[i];
            const p2 = sorted[j];
            const interval = Math.abs(p1 - p2);
            const ic = interval % 12;

            const isBassPair = (p1 === bass || p2 === bass);
            let isDiss = DISSONANT_INTERVALS.includes(ic);
            if (ic === 5 && isBassPair) isDiss = true; // P4 against bass

            if (isDiss) {
                // Prioritize displaying the "crunchiest" interval
                return { isDissonant: true, label: getIntervalLabel(interval) };
            }
        }
    }

    // If no dissonance, return first interval label or generic
    const firstInt = Math.abs(sorted[1] - sorted[0]);
    return { isDissonant: false, label: getIntervalLabel(firstInt) };
}

// Helper to identify chord and return quality + NCT count
// Prioritizes shapes where the chord root matches the actual bass note (to prefer C6 over Am7/C if bass is C)
function identifyChordWithNCT(pitches: number[]): { name: string, quality: string, nct: number } | null {
    if (pitches.length < 2) return null;
    const uniquePCs = Array.from(new Set(pitches.map(p => p % 12)));

    const sorted = [...pitches].sort((a,b) => a-b);
    const bassPC = sorted[0] % 12;

    let bestMatch = null;
    let bestScore = -Infinity;

    for (const root of uniquePCs) {
        const intervals = uniquePCs.map(pc => (pc - root + 12) % 12);
        for (const shape of CHORD_SHAPES) {
            const matchedIntervals = intervals.filter(i => shape.intervals.includes(i));
            const nctCount = intervals.length - matchedIntervals.length;

            // Basic heuristic: Must match at least 2 notes of the shape
            if (matchedIntervals.length < 2) continue;

            let score = (matchedIntervals.length * 10) - (nctCount * 10);

            // Prefer if Root is in Bass (handles 6th vs 7th ambiguity)
            if (root === bassPC) score += 5;

            if (score > bestScore) {
                bestScore = score;
                bestMatch = { name: shape.name, quality: shape.name, nct: nctCount };
            }
        }
    }
    return bestMatch;
}

export function generatePolyphonicHarmonicRegions(notes: RawNote[]): HarmonicRegion[] {
    if (notes.length === 0) return [];

    // 1. Collect all time boundaries
    const timePoints = new Set<number>();
    notes.forEach(n => {
        timePoints.add(n.ticks);
        timePoints.add(n.ticks + n.durationTicks);
    });
    const sortedPoints = Array.from(timePoints).sort((a,b) => a-b);

    const regions: HarmonicRegion[] = [];
    let consecutiveDissonanceCount = 0;

    for (let i = 0; i < sortedPoints.length - 1; i++) {
        const start = sortedPoints[i];
        const end = sortedPoints[i+1];
        const mid = start + (end - start) / 2; // Sample middle to avoid boundary edge cases

        // Active notes in this slice
        const active = notes.filter(n => n.ticks <= mid && (n.ticks + n.durationTicks) > mid);
        if (active.length < 2) {
            consecutiveDissonanceCount = 0; // Reset on rest/monophony
            continue;
        }

        const pitches = active.map(n => n.midi);
        const chordMatch = identifyChordWithNCT(pitches);
        const { isDissonant, label } = analyzeVerticalSlice(pitches);

        let type: HarmonicRegion['type'] = 'consonant_stable';
        let desc = "";

        if (chordMatch) {
            const { quality, nct } = chordMatch;
            const isConsonantChord = CONSONANT_QUALITIES.has(quality);

            // Case 5: 2+ NCTs -> Red
            if (nct >= 2) {
                type = 'dissonant_severe';
                desc = `${quality} + ${nct} NCTs`;
                consecutiveDissonanceCount++; // Counts as complex dissonance
            } 
            // 1 NCT cases
            else if (nct === 1) {
                if (isConsonantChord) {
                    // Case 3 (part a): Consonant Chord + 1 NCT -> Amber
                    type = 'dissonant_secondary'; 
                    desc = `${quality} + 1 NCT`;
                } else {
                    // Case 4 (part a): Dissonant Chord + 1 NCT -> Orange
                    type = 'dissonant_tertiary'; 
                    desc = `${quality} (Diss) + 1 NCT`;
                }
                consecutiveDissonanceCount++;
            }
            // Clean Chords (0 NCT)
            else {
                if (isConsonantChord) {
                    // Case 1: Consonant Chord -> Green
                    type = 'consonant_stable'; 
                    desc = quality;
                    consecutiveDissonanceCount = 0; // Reset
                } else {
                    // Case 2 (part a): Dissonant Chord -> Purple
                    type = 'dissonant_primary'; 
                    desc = quality;
                    consecutiveDissonanceCount++;
                }
            }
        } else {
            // No Chord Detected (usually 2 notes or chaotic) -> Interval Logic
            if (isDissonant) {
                consecutiveDissonanceCount++;
                if (consecutiveDissonanceCount === 1) {
                    // Case 2 (part b): First Diss Interval -> Purple
                    type = 'dissonant_primary'; 
                } else if (consecutiveDissonanceCount === 2) {
                    // Case 3 (part b): Second Diss Interval -> Amber
                    type = 'dissonant_secondary'; 
                } else {
                    // Case 4 (part b): 3rd+ Diss Interval -> Orange
                    type = 'dissonant_tertiary'; 
                }
                desc = `Interval: ${label}`;
            } else {
                // Case 1 (part b): Consonant Interval -> Green
                type = 'consonant_stable'; 
                desc = `Interval: ${label}`;
                consecutiveDissonanceCount = 0; // Reset
            }
        }

        regions.push({
            startTick: start,
            endTick: end,
            type: type,
            intervalLabel: label,
            description: desc
        });
    }

    return regions;
}

function isStrongBeat(tick: number, ppq: number, tsNum: number, tsDenom: number): boolean {
    const ticksPerMeasure = ppq * tsNum * (4 / tsDenom);
    const pos = tick % ticksPerMeasure;
    if (pos === 0) return true; 
    if (tsNum === 4 && tsDenom === 4 && pos === (ticksPerMeasure / 2)) return true;
    return false; 
}

export function analyzeStrettoCandidate(
    subject: RawNote[], 
    intervalSemis: number, 
    delayTicks: number, 
    ppq: number,
    ts: { num: number, den: number },
    isInverted: boolean = false,
    pivotMidi: number = 60,
    useChromaticInversion: boolean = false
): StrettoCandidate {

    if (subject.length === 0) {
        return {
            id: `empty`, intervalSemis, intervalLabel: 'N/A', delayBeats: 0, delayTicks,
            grade: 'INVALID', errors: [], notes: [], dissonanceRatio: 0, pairDissonanceScore: 0, endsOnDissonance: true
        };
    }

    const subjectEntryPitch = subject[0].midi;

    const answer: RawNote[] = subject.map(n => {
        if (!n) return null as any;
        let newMidi: number;

        if (isInverted) {
            const rawInverted = invertPitch(n.midi, pivotMidi, useChromaticInversion);
            const invertedStart = invertPitch(subjectEntryPitch, pivotMidi, useChromaticInversion);
            const targetStart = subjectEntryPitch + intervalSemis;
            const shift = targetStart - invertedStart;
            newMidi = rawInverted + shift;
        } else {
            newMidi = n.midi + intervalSemis;
        }

        return {
            ...n,
            ticks: n.ticks + delayTicks,
            midi: newMidi,
            name: getStrictPitchName(newMidi),
            voiceIndex: 1
        };
    }).filter(n => !!n);

    const allNotes = [...subject, ...answer];

    // Generate Regions using Polyphonic Logic
    const harmonicRegions = generatePolyphonicHarmonicRegions(allNotes);

    // Calculate Metrics
    let totalOverlapTicks = 0;
    let dissonantTicks = 0;
    let endsOnDissonance = false;

    // 1. Time-Based Dissonance Ratio
    harmonicRegions.forEach((r, idx) => {
        const dur = r.endTick - r.startTick;
        totalOverlapTicks += dur;
        if (r.type !== 'consonant_stable') {
            dissonantTicks += dur;
            if (idx === harmonicRegions.length - 1) endsOnDissonance = true;
        }
    });

    const dissonanceRatio = totalOverlapTicks > 0 ? (dissonantTicks / totalOverlapTicks) : 0;

    // 2. Pair-Wise Intensity Score (Old Metric requested back)
    // We need to check exact pairs for this
    let pairDissonanceScore = 0;
    // Iterate through regions again (they represent time slices)
    harmonicRegions.forEach(r => {
        const mid = r.startTick + (r.endTick - r.startTick)/2;
        const active = allNotes.filter(n => n.ticks <= mid && (n.ticks + n.durationTicks) > mid);
        if (active.length < 2) return;

        const sorted = active.map(n => n.midi).sort((a,b) => a-b);
        const bass = sorted[0];
        let pairDissCount = 0;

        for(let i=0; i<sorted.length; i++) {
            for(let j=i+1; j<sorted.length; j++) {
                const interval = Math.abs(sorted[i] - sorted[j]);
                const ic = interval % 12;
                const isBassPair = (sorted[i] === bass || sorted[j] === bass);
                let isDiss = DISSONANT_INTERVALS.includes(ic);
                if (ic === 5 && isBassPair) isDiss = true;

                if (isDiss) pairDissCount++;
            }
        }

        // Weight by duration of the slice
        // Normalize: (Duration in Beats) * (Count of Dissonant Pairs)
        const durBeats = (r.endTick - r.startTick) / ppq;
        pairDissonanceScore += (durBeats * pairDissCount);
    });


    // Error Check (Parallel 5ths/8ves) - Still Pairwise
    const errors: StrettoError[] = [];

    // Quick Pairwise Check for Parallels

    let prevP1: number | null = null;
    let prevP2: number | null = null;

    // We need events for P1/P2 transitions.
    const timePoints = new Set<number>();
    allNotes.forEach(n => { timePoints.add(n.ticks); timePoints.add(n.ticks+n.durationTicks); });
    const tPoints = Array.from(timePoints).sort((a,b)=>a-b);

    for(let i=0; i<tPoints.length-1; i++) {
        const t = tPoints[i];
        const n1 = subject.find(n => n.ticks <= t && (n.ticks+n.durationTicks) > t);
        const n2 = answer.find(n => n.ticks <= t && (n.ticks+n.durationTicks) > t);

        if (n1 && n2) {
            const p1 = n1.midi;
            const p2 = n2.midi;

            if (prevP1 !== null && prevP2 !== null) {
                if (prevP1 !== p1 && prevP2 !== p2) { // Both moved
                    const int1 = Math.abs(prevP1 - prevP2) % 12;
                    const int2 = Math.abs(p1 - p2) % 12;
                    const isPerfect = int2 === 0 || int2 === 7;
                    if (isPerfect && int1 === int2) {
                        const timeStr = getFormattedTime(t, ppq, ts.num, ts.den);
                        const isStrong = isStrongBeat(t, ppq, ts.num, ts.den);
                        errors.push({
                            tick: t, timeFormatted: timeStr,
                            type: int2 === 7 ? 'Parallel 5th' : 'Parallel 8ve',
                            details: 'Parallel Perfect Interval',
                            severity: isStrong ? 'fatal' : 'warning'
                        });
                    }
                }
            }
            prevP1 = p1; prevP2 = p2;
        } else {
            prevP1 = null; prevP2 = null;
        }
    }

    let grade: StrettoGrade = 'STRONG';
    if (errors.some(e => e.severity === 'fatal')) grade = 'INVALID';
    else if (errors.length > 0) grade = 'VIABLE';

    let intLabel = getIntervalLabel(intervalSemis);
    if (intervalSemis < 0 && !intLabel.startsWith('-')) intLabel = '-' + intLabel;
    else if (intervalSemis > 0 && !intLabel.startsWith('+')) intLabel = '+' + intLabel;
    if (isInverted) intLabel += " (Inv)";

    const delayBeats = delayTicks / (ppq * (4 / ts.den));

    return {
        id: `${intLabel}@${delayBeats.toFixed(1)}${isInverted?'i':''}`,
        intervalSemis,
        intervalLabel: intLabel,
        delayBeats: parseFloat(delayBeats.toFixed(2)),
        delayTicks,
        grade,
        errors,
        notes: allNotes,
        regions: harmonicRegions,
        dissonanceRatio,
        pairDissonanceScore: parseFloat(pairDissonanceScore.toFixed(1)),
        endsOnDissonance
    };
}

import React, { useRef, useEffect, useState } from 'react';
import { PianoRollTrackData, HarmonicRegion } from '../types';
import { getVoiceLabel } from './services/midiVoices';

interface PianoRollProps {
  trackData: PianoRollTrackData;
  onRegionClick?: (region: HarmonicRegion) => void;
}

const NOTE_HEIGHT = 14;
const MIN_MIDI = 21; 
const MAX_MIDI = 108; 
const NUM_NOTES = MAX_MIDI - MIN_MIDI + 1;
const KEY_WIDTH = 60;
const RULER_HEIGHT = 32;

const VOICE_COLORS = [
    '#3b82f6', // Blue
    '#ef4444', // Red
    '#10b981', // Green
    '#f59e0b', // Amber
    '#8b5cf6', // Violet
    '#ec4899', // Pink
    '#6366f1', // Indigo
    '#14b8a6', // Teal
];

const isBlackKey = (midi: number) => {
  const note = midi % 12;
  return note === 1 || note === 3 || note === 6 || note === 8 || note === 10;
};

const getRegionColor = (type: HarmonicRegion['type']): string => {
    switch (type) {
        case 'consonant_stable': return '#10b981'; // Green (Emerald-500)
        case 'dissonant_primary': return '#a855f7'; // Purple (Purple-500)
        case 'dissonant_secondary': return '#f59e0b'; // Amber (Amber-500)
        case 'dissonant_tertiary': return '#ea580c'; // Orange (Orange-600)
        case 'dissonant_severe': return '#ef4444'; // Red (Red-500)
        default: return 'transparent';
    }
};

const PianoRoll: React.FC<PianoRollProps> = ({ trackData, onRegionClick }) => {
  const { notes, ppq, timeSignature, harmonicRegions } = trackData;
  const gridContainerRef = useRef<HTMLDivElement>(null);
  const keysContainerRef = useRef<HTMLDivElement>(null);
  const rulerContainerRef = useRef<HTMLDivElement>(null);

  const [zoom, setZoom] = useState(1.0);
  const [hoveredRegion, setHoveredRegion] = useState<HarmonicRegion | null>(null);

  const maxVoiceIdx = notes.reduce((max, n) => Math.max(max, n.voiceIndex ?? -1), -1);
  const [showVoices, setShowVoices] = useState(maxVoiceIdx > 0);
  const totalVoices = maxVoiceIdx + 1;

  useEffect(() => {
    if (gridContainerRef.current && notes.length > 0) {
      const sumMidi = notes.reduce((sum, n) => sum + n.midi, 0);
      const avgMidi = sumMidi / notes.length;
      const targetMidi = Math.min(Math.max(avgMidi, MIN_MIDI), MAX_MIDI);
      const y = (MAX_MIDI - targetMidi) * NOTE_HEIGHT;
      const containerHeight = gridContainerRef.current.clientHeight;
      gridContainerRef.current.scrollTop = y - containerHeight / 2;
    }
  }, [notes]); 

  const handleGridScroll = () => {
    if (gridContainerRef.current) {
        if (keysContainerRef.current) keysContainerRef.current.scrollTop = gridContainerRef.current.scrollTop;
        if (rulerContainerRef.current) rulerContainerRef.current.scrollLeft = gridContainerRef.current.scrollLeft;
    }
  };

  const totalTicks = Math.max(...notes.map(n => n.ticks + n.durationTicks), ppq * 4 * timeSignature.numerator);
  const ticksPerMeasure = ppq * timeSignature.numerator * (4 / timeSignature.denominator);
  const totalMeasures = Math.ceil(totalTicks / ticksPerMeasure) + 1; 

  const BASE_TICK_WIDTH = 0.15; 
  const TICK_WIDTH = BASE_TICK_WIDTH * zoom;
  const SVG_WIDTH = Math.max(totalTicks * TICK_WIDTH + 100, 100); 
  const SVG_HEIGHT = NUM_NOTES * NOTE_HEIGHT;

  const tickToX = (tick: number) => tick * TICK_WIDTH;
  const midiToY = (midi: number) => (MAX_MIDI - midi) * NOTE_HEIGHT;

  const handleZoomIn = () => setZoom(prev => Math.min(prev * 1.25, 4));
  const handleZoomOut = () => setZoom(prev => Math.max(prev * 0.8, 0.1));

  const patternId = `beatPattern-${zoom}`;
  const parallelPatternId = `parallelPattern`;

  if (!notes || notes.length === 0) {
    return <div className="flex items-center justify-center h-full text-gray-400">No notes to display.</div>;
  }

  return (
    <div className="flex flex-col h-full bg-gray-900 border border-gray-700 rounded-lg overflow-hidden select-none relative">

       {/* Harmonic Inspector Overlay */}
       {hoveredRegion && (
           <div className="absolute top-10 left-1/2 transform -translate-x-1/2 z-50 bg-black/80 backdrop-blur-md border border-brand-primary rounded-lg p-2 shadow-xl animate-fade-in pointer-events-none">
               <div className="text-center">
                   <span className="text-brand-primary font-bold text-sm block">{hoveredRegion.intervalLabel}</span>
                   {hoveredRegion.description && <span className="text-gray-300 text-xs block">{hoveredRegion.description}</span>}
                   {hoveredRegion.errorType && <span className="text-red-400 text-[10px] font-bold uppercase tracking-wider block mt-1">{hoveredRegion.errorType} Motion</span>}
                   <span className="text-[9px] text-gray-500 mt-1 block">Click to audition</span>
               </div>
           </div>
       )}

       <div className="flex items-center justify-between px-3 py-1 bg-gray-800 border-b border-gray-700 z-20">
            <div className="flex items-center gap-6">
                <div className="flex items-center gap-3">
                    <span className="text-xs text-gray-400 uppercase font-bold tracking-wider">Zoom</span>
                    <div className="flex items-center bg-gray-700 rounded-md overflow-hidden">
                        <button onClick={handleZoomOut} className="p-1 px-2 text-gray-300 hover:text-white hover:bg-gray-600 transition-colors">
                            <svg className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20 12H4" /></svg>
                        </button>
                        <span className="text-[10px] text-gray-300 w-10 text-center border-l border-r border-gray-600 px-1">{Math.round(zoom * 100)}%</span>
                        <button onClick={handleZoomIn} className="p-1 px-2 text-gray-300 hover:text-white hover:bg-gray-600 transition-colors">
                            <svg className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" /></svg>
                        </button>
                    </div>
                </div>

                <label className="flex items-center cursor-pointer gap-2">
                    <div className="relative">
                        <input type="checkbox" className="sr-only" checked={showVoices} onChange={(e) => setShowVoices(e.target.checked)} />
                        <div className={`block w-7 h-3.5 rounded-full transition-colors ${showVoices ? 'bg-brand-primary' : 'bg-gray-600'}`}></div>
                        <div className={`absolute left-0.5 top-0.5 bg-white w-2.5 h-2.5 rounded-full transition-transform ${showVoices ? 'transform translate-x-3.5' : ''}`}></div>
                    </div>
                    <span className="text-[10px] text-gray-400 uppercase font-bold tracking-wider">Show Voices</span>
                </label>
            </div>
            <div className="text-[10px] text-gray-500 font-mono">
                {timeSignature.numerator}/{timeSignature.denominator} • {ppq} PPQ
            </div>
       </div>

       <div className="flex flex-shrink-0 h-[32px] bg-gray-800 border-b border-gray-700 z-10">
          <div className="w-[60px] flex-shrink-0 border-r border-gray-700 bg-gray-800 flex items-center justify-center">
            <span className="text-[10px] text-gray-500 font-mono">Key</span>
          </div>
          <div ref={rulerContainerRef} className="flex-grow overflow-hidden relative bg-gray-800">
             <svg width={SVG_WIDTH} height={RULER_HEIGHT}>
                {Array.from({ length: totalMeasures }).map((_, i) => {
                    const x = tickToX(i * ticksPerMeasure);
                    return (
                        <g key={i} transform={`translate(${x}, 0)`}>
                            <line x1={0} y1={15} x2={0} y2={32} stroke="#4b5563" strokeWidth={1} />
                            <text x={4} y={24} fill="#6b7280" fontSize="10" fontFamily="monospace" fontWeight="bold">{i + 1}</text>
                        </g>
                    );
                })}
             </svg>
          </div>
       </div>

       <div className="flex flex-grow overflow-hidden relative">
          <div ref={keysContainerRef} className="w-[60px] flex-shrink-0 overflow-hidden border-r border-gray-700 bg-gray-800">
            <svg width={KEY_WIDTH} height={SVG_HEIGHT}>
                {Array.from({ length: NUM_NOTES }, (_, i) => {
                    const midi = MAX_MIDI - i;
                    const y = i * NOTE_HEIGHT;
                    const black = isBlackKey(midi);
                    const isC = midi % 12 === 0;
                    return (
                        <g key={midi}>
                           <rect x={0} y={y} width={KEY_WIDTH} height={NOTE_HEIGHT} fill={black ? '#111827' : '#f9fafb'} stroke="#1f2937" strokeWidth={0.5} />
                            {(isC || midi % 12 === 5) && (
                                <text x={KEY_WIDTH - 4} y={y + NOTE_HEIGHT - 3} textAnchor="end" fontSize="9" fill={black ? '#4b5563' : '#9ca3af'} fontWeight={isC ? "bold" : "normal"}>{isC ? `C${Math.floor(midi/12)-1}` : 'F'}</text>
                            )}
                        </g>
                    )
                })}
            </svg>
          </div>

          <div ref={gridContainerRef} onScroll={handleGridScroll} className="flex-grow overflow-auto bg-gray-900 relative cursor-default">
            <svg width={SVG_WIDTH} height={SVG_HEIGHT}>
                <defs>
                    <pattern id={patternId} x="0" y="0" width={tickToX(ppq)} height={SVG_HEIGHT} patternUnits="userSpaceOnUse">
                         <line x1={tickToX(ppq)} y1={0} x2={tickToX(ppq)} y2={SVG_HEIGHT} stroke="#1f2937" strokeWidth={0.5} strokeDasharray="2,2" />
                    </pattern>
                    <pattern id={parallelPatternId} width="4" height="4" patternUnits="userSpaceOnUse" patternTransform="rotate(45)">
                        <line stroke="#ffffff" strokeWidth="1" x1="0" y1="0" x2="0" y2="4" opacity="0.3" />
                    </pattern>
                </defs>

                {/* Background Grid */}
                {Array.from({ length: NUM_NOTES }, (_, i) => {
                     const midi = MAX_MIDI - i;
                     const y = i * NOTE_HEIGHT;
                     const black = isBlackKey(midi);
                     return <rect key={`bg-${midi}`} x={0} y={y} width={SVG_WIDTH} height={NOTE_HEIGHT} fill={black ? '#111827' : '#1f2937'} fillOpacity={black ? 1 : 0.2} />;
                })}
                {Array.from({ length: NUM_NOTES }, (_, i) => {
                    const midi = MAX_MIDI - i;
                    if (midi % 12 === 0 && midi !== MAX_MIDI) return <line key={`oct-${midi}`} x1={0} y1={i * NOTE_HEIGHT} x2={SVG_WIDTH} y2={i * NOTE_HEIGHT} stroke="#374151" strokeWidth={0.5} />;
                    return null;
                })}
                <rect x="0" y="0" width={SVG_WIDTH} height={SVG_HEIGHT} fill={`url(#${patternId})`} />

                {/* Harmonic Regions Shading (Clickable) */}
                {harmonicRegions && harmonicRegions.map((region, i) => {
                    const x = tickToX(region.startTick);
                    const width = tickToX(region.endTick - region.startTick);
                    const color = getRegionColor(region.type);
                    const isHovered = hoveredRegion === region;

                    return (
                        <g 
                            key={`region-${i}`} 
                            onMouseEnter={() => setHoveredRegion(region)} 
                            onMouseLeave={() => setHoveredRegion(null)}
                            onClick={(e) => {
                                e.stopPropagation();
                                if(onRegionClick) onRegionClick(region);
                            }}
                            className="cursor-pointer transition-opacity"
                            style={{ opacity: isHovered ? 1 : 0.7 }}
                        >
                            {/* Color Block */}
                            <rect 
                                x={x} 
                                y={0} 
                                width={Math.max(width, 1)} 
                                height={SVG_HEIGHT} 
                                fill={color} 
                                fillOpacity={isHovered ? 0.4 : 0.25} 
                                stroke={isHovered ? color : 'none'}
                                strokeWidth={isHovered ? 1 : 0}
                            />
                            {/* Error Overlays */}
                            {region.errorType === 'parallel' && (
                                <rect x={x} y={0} width={Math.max(width, 1)} height={SVG_HEIGHT} fill={`url(#${parallelPatternId})`} fillOpacity={0.5} stroke="red" strokeWidth={1} strokeOpacity={0.5} />
                            )}
                            {region.errorType === 'direct' && (
                                <rect x={x} y={0} width={Math.max(width, 1)} height={SVG_HEIGHT} fill="none" stroke="orange" strokeWidth={2} strokeDasharray="4,2" />
                            )}
                            {/* Interval Label at top */}
                            <text x={x + 2} y={12} fill="rgba(255,255,255,0.7)" fontSize="9" fontFamily="monospace" fontWeight={isHovered ? 'bold' : 'normal'}>
                                {region.intervalLabel}
                            </text>
                        </g>
                    );
                })}

                {/* Measure Lines */}
                {Array.from({ length: totalMeasures }).map((_, i) => (
                     <line key={`meas-${i}`} x1={tickToX(i * ticksPerMeasure)} y1={0} x2={tickToX(i * ticksPerMeasure)} y2={SVG_HEIGHT} stroke="#4b5563" strokeWidth={0.5} />
                ))}

                {/* Notes */}
                {notes.map((note, idx) => {
                    let noteColor = '#14b8a6';
                    let strokeColor = '#0f766e';
                    let opacity = 1;
                    if (note.isOrnament) { opacity = 0.5; strokeColor = 'rgba(255,255,255,0.2)'; }
                    if (showVoices && note.voiceIndex !== undefined) {
                        noteColor = VOICE_COLORS[note.voiceIndex % VOICE_COLORS.length];
                        strokeColor = 'rgba(0,0,0,0.2)';
                    }
                    const voiceName = note.voiceIndex !== undefined ? getVoiceLabel(note.voiceIndex, totalVoices) : 'N/A';
                    return (
                        <rect 
                            key={idx}
                            x={tickToX(note.ticks)}
                            y={midiToY(note.midi) + 1}
                            width={Math.max(tickToX(note.durationTicks), 2)}
                            height={NOTE_HEIGHT - 2}
                            fill={noteColor}
                            fillOpacity={opacity}
                            rx={1}
                            stroke={strokeColor}
                            strokeWidth={0.5}
                            className="pointer-events-none" // Notes aren't clicked, regions are
                        >
                            <title>{`${note.name} | ${voiceName}`}</title>
                        </rect>
                    );
                })}
            </svg>
          </div>
       </div>
    </div>
  );
};

export default PianoRoll;

export interface TrackInfo {
  id: number;
  name: string;
  instrument: {
    name: string;
    number: number;
    family: string;
  };
  noteCount: number;
  ornamentCount?: number;
}

export enum AppState {
  IDLE = 'IDLE',
  LOADING = 'LOADING',
  LOADED = 'LOADED',
  ERROR = 'ERROR',
  GENERATING = 'GENERATING', 
  SUCCESS = 'SUCCESS',
}

export type MidiEventType = 'pitchBend' | 'controlChange' | 'programChange';

export interface MidiEventCounts {
  pitchBend: number;
  controlChange: number;
  programChange: number;
}

export type TempoChangeMode = 'speed' | 'time';

export type InversionMode = 'off' | 'global' | '1beat' | '2beats' | 'measure' | '2measures' | '4measures' | '8measures';

export type OutputStrategy = 'combine' | 'separate_tracks' | 'separate_voices';

export type VoiceAssignmentMode = 'auto' | 'manual'; 

export type RhythmFamily = 'Simple' | 'Triple' | 'Quintuplet';

export type HarmonicAnalysisMode = 'attack' | 'sustain' | 'hybrid' | 'arpeggio_window' | 'hia_v2';

export type PitchAnalysisMode = 'modal' | 'frequency';

export type HybridVoiceRole = 'sustain' | 'attack' | 'arpeggio' | 'ignore';

export type ArpeggioStrategy = 'note_based' | 'time_based';

export interface RhythmRule {
    enabled: boolean;
    family: RhythmFamily;
    minNoteValue: string; 
}

export interface AnalysisSection {
    id: string;
    name: string;
    startMeasure: number;
    endMeasure: number;
    harmonyMode: HarmonicAnalysisMode;
    pitchStatsMode: PitchAnalysisMode;

    // Granular Harmony Settings
    chordTolerance: string; 
    chordMinDuration: string; 
    arpeggioWindowVal: string; // Replaces bucketSizeBeats
    ignorePassingMotion: boolean; 

    // Hybrid Specifics
    hybridConfig: {
        voiceRoles: Record<number, HybridVoiceRole>;
        arpStrategy: ArpeggioStrategy;
        arpHistoryCount: number; 
        arpHistoryTime: string; 
    };

    // Reporting
    debugLogging?: boolean;
}

export interface ModalConversionOptions {
    enabled: boolean;
    root: number; 
    modeName: string; 
    mappings: Record<number, number>; 
}

export interface ConversionOptions {
    tempo: number;
    timeSignature: {
        numerator: number;
        denominator: number;
    };
    tempoChangeMode: TempoChangeMode;
    originalTempo: number;
    transposition: number;
    noteTimeScale: number;
    inversionMode: InversionMode;

    // Shadow Grid Options
    primaryRhythm: RhythmRule;
    secondaryRhythm: RhythmRule;

    quantizationValue: string; 

    quantizeDurationMin: string; 
    shiftToMeasure: boolean;
    detectOrnaments: boolean; 
    modalConversion: ModalConversionOptions;
    removeShortNotesThreshold: number; 
    pruneOverlaps: boolean; 
    pruneThresholdIndex: number;
    // Voice Separation Logic
    voiceSeparationOverlapTolerance: number; 
