const MAJOR_SCALE_STEPS = [0, 2, 4, 5, 7, 9, 11];

function invertPitch(pitch: number, pivot: number, useChromatic: boolean): number {
    if (useChromatic) {
        return pivot - (pitch - pivot);
    }

    // Diatonic Inversion (Major Scale Assumption)
    const diff = pitch - pivot;
    const octaves = Math.floor(diff / 12);
    const semitone = (diff % 12 + 12) % 12;

    // Find closest scale step
    let degree = -1;
    let minErr = 99;
    MAJOR_SCALE_STEPS.forEach((s, i) => {
        if (Math.abs(s - semitone) < minErr) { 
            minErr = Math.abs(s - semitone); 
            degree = i; 
        }
    });

    // Invert the degree index relative to 0 (root)
    const absDegree = (octaves * 7) + degree;
    const invAbsDegree = -absDegree;

    const invOctaves = Math.floor(invAbsDegree / 7);
    const invIndex = (invAbsDegree % 7 + 7) % 7;

    return pivot + (invOctaves * 12) + MAJOR_SCALE_STEPS[invIndex];
}

// Determines if any dissonance exists in a set of pitches
function analyzeVerticalSlice(pitches: number[]): { isDissonant: boolean; label: string } {
    if (pitches.length < 2) return { isDissonant: false, label: '' };

    const sorted = [...pitches].sort((a,b) => a-b);
    const bass = sorted[0];

    for (let i = 0; i < sorted.length; i++) {
        for (let j = i + 1; j < sorted.length; j++) {
            const p1 = sorted[i];
            const p2 = sorted[j];
            const interval = Math.abs(p1 - p2);
            const ic = interval % 12;

            const isBassPair = (p1 === bass || p2 === bass);
            let isDiss = DISSONANT_INTERVALS.includes(ic);
            if (ic === 5 && isBassPair) isDiss = true; // P4 against bass

            if (isDiss) {
                // Prioritize displaying the "crunchiest" interval
                return { isDissonant: true, label: getIntervalLabel(interval) };
            }
        }
    }

    // If no dissonance, return first interval label or generic
    const firstInt = Math.abs(sorted[1] - sorted[0]);
    return { isDissonant: false, label: getIntervalLabel(firstInt) };
}

// Special function for Dyad inference (2 pitch classes)
function analyzeDyad(pc1: number, pc2: number): { name: string; root: number; quality: string } | null {
    const diff = (pc2 - pc1 + 12) % 12; // Assuming pc1 is bass for interval calc

    // 3rd (Major or Minor) -> Root is bottom
    if (diff === 3) return { name: "Min (no 5)", root: pc1, quality: "Min" };
    if (diff === 4) return { name: "Maj (no 5)", root: pc1, quality: "Maj" };

    // 6th (Inverted 3rd) -> Root is top
    if (diff === 8) return { name: "Maj (no 5)", root: pc2, quality: "Maj" }; // m6 -> Inverted Maj3
    if (diff === 9) return { name: "Min (no 5)", root: pc2, quality: "Min" }; // M6 -> Inverted min3

    // Perfect 5th -> Power Chord
    if (diff === 7) return { name: "5", root: pc1, quality: "5" };

    // Tritone -> Diminished (no 3rd) - Usually implies dim triad or dim7
    if (diff === 6) return { name: "Dim (no 3)", root: pc1, quality: "Dim" };

    // P4, 2nds, 7ths are treated as Intervals, not Chords here
    return null;
}

// Helper to identify chord and return quality + NCT count
// Prioritizes shapes where the chord root matches the actual bass note
function identifyChordWithNCT(pitches: number[]): { name: string, quality: string, nct: number, chordTones: number[], rootPC: number } | null {
    if (pitches.length < 2) return null;
    const uniquePCs = Array.from(new Set(pitches.map(p => p % 12)));

    // Dyad/Cluster handling for 2 unique PCs (even if multiple octaves)
    if (uniquePCs.length === 2) {
        const sortedPCs = [...uniquePCs].sort((a,b) => a-b);
        const sortedInput = [...pitches].sort((a,b) => a-b);
        const bassPC = sortedInput[0] % 12;
        const otherPC = uniquePCs.find(p => p !== bassPC) || bassPC;

        const dyadAnalysis = analyzeDyad(bassPC, otherPC);
        if (dyadAnalysis) {
            return {
                name: `${getStrictPitchName(dyadAnalysis.root).replace(/\d/g, '')} ${dyadAnalysis.name}`,
                quality: dyadAnalysis.quality,
                nct: 0,
                chordTones: uniquePCs,
                rootPC: dyadAnalysis.root
            };
        } else {
            // It's an interval (P4, 2nd, 7th)
            return null;
        }
    }

    // 3+ Unique PCs -> Standard Shape Matching
    const sorted = [...pitches].sort((a,b) => a-b);
    const bassPC = sorted[0] % 12;

    let bestMatch = null;
    let bestScore = -Infinity;

    for (const root of uniquePCs) {
        const intervals = uniquePCs.map(pc => (pc - root + 12) % 12);
        for (const shape of CHORD_SHAPES) {
            const matchedIntervals = intervals.filter(i => shape.intervals.includes(i));
            const nctCount = intervals.length - matchedIntervals.length;

            // Basic heuristic: Must match at least 2 notes of the shape
            if (matchedIntervals.length < 2) continue;

            // --- CONSTRAINT: Extension Existence ---
            if (shape.intervals.length > 3) {
                const extensionInterval = shape.intervals[shape.intervals.length - 1];
                if (!matchedIntervals.includes(extensionInterval)) {
                    continue; // Skip this shape, it's invalid (e.g. Maj7 without 7)
                }
            }

            // --- SCORING LOGIC v3 ---
            let missingPenalty = 0;
            const missingIntervals = shape.intervals.filter(i => !matchedIntervals.includes(i));

            missingIntervals.forEach(int => {
                if (int === 3 || int === 4) {
                    missingPenalty += 30; // Missing 3rd is expensive
                } else if (int === 7 || int === 6 || int === 8) {
                    missingPenalty += 10; // Missing 5th is cheap
                } else {
                    missingPenalty += 10; 
                }
            });

            let score = (matchedIntervals.length * 100) 
                      - (nctCount * 500) 
                      - missingPenalty;

            if (root === bassPC) score += 5;

            if (score > bestScore) {
                bestScore = score;
                const rootName = getStrictPitchName(root).replace(/\d/g, '');

                // Identify which PCs are Chord Tones
                const chordTones = uniquePCs.filter(pc => {
                    const int = (pc - root + 12) % 12;
                    return shape.intervals.includes(int);
                });

                bestMatch = { 
                    name: `${rootName} ${shape.name}`, 
                    quality: shape.name, 
                    nct: nctCount,
                    chordTones: chordTones,
                    rootPC: root
                };
            }
        }
    }
    return bestMatch;
}

export function generatePolyphonicHarmonicRegions(notes: RawNote[], keyRoot: number = 0): HarmonicRegion[] {
    if (notes.length === 0) return [];

    // 1. Collect all time boundaries
    const timePoints = new Set<number>();
    notes.forEach(n => {
        timePoints.add(n.ticks);
        timePoints.add(n.ticks + n.durationTicks);
    });
    const sortedPoints = Array.from(timePoints).sort((a,b) => a-b);

    const regions: HarmonicRegion[] = [];
    let consecutiveDissonanceCount = 0;

    for (let i = 0; i < sortedPoints.length - 1; i++) {
        const start = sortedPoints[i];
        const end = sortedPoints[i+1];
        const mid = start + (end - start) / 2; // Sample middle to avoid boundary edge cases

        // Active notes in this slice
        const active = notes.filter(n => n.ticks <= mid && (n.ticks + n.durationTicks) > mid);
        if (active.length < 2) {
            consecutiveDissonanceCount = 0; // Reset on rest/monophony
            continue;
        }

        const pitches = active.map(n => n.midi);
        const chordMatch = identifyChordWithNCT(pitches);
        const { isDissonant, label } = analyzeVerticalSlice(pitches);

        let type: HarmonicRegion['type'] = 'consonant_stable';

        let detailedInfo: NonNullable<HarmonicRegion['detailedInfo']> = {
            chordName: "",
            allNotes: active.map(n => getPitchName(n.midi, keyRoot)),
            noteDetails: [],
            chordTones: [],
            ncts: []
        };

        if (chordMatch) {
            const { quality, nct, name, chordTones, rootPC } = chordMatch;
            const isConsonantChord = CONSONANT_QUALITIES.has(quality);

            detailedInfo.chordName = name;
            detailedInfo.quality = quality;

            const ctSet = new Set(chordTones);
            const isAug = quality.toLowerCase().includes('aug');

            active.forEach(n => {
                const pc = n.midi % 12;
                const interval = (pc - rootPC + 12) % 12;
                const noteName = getPitchName(n.midi, keyRoot);

                let role: NoteRole['role'] = 'NCT';

                if (ctSet.has(pc)) {
                    detailedInfo.chordTones.push(noteName);

                    if (interval === 0) role = 'Root';
                    else if (interval === 3 || interval === 4) role = '3rd';
                    else if (interval === 7) role = '5th';
                    else if (interval === 6) role = 'Ext'; // Dim 5 / Tritone
                    else if (interval === 8) {
                        // 8 is Min 6th or Aug 5th.
                        // If chord quality is Aug, treat as 5th (Augmented)
                        role = isAug ? '5th' : 'Ext'; 
                    }
                    else role = 'Ext'; // 7th, 6th, etc.
                } else {
                    detailedInfo.ncts.push(noteName);
                    role = 'NCT';
                }

                detailedInfo.noteDetails.push({
                    name: noteName,
                    midi: n.midi,
                    role: role
                });
            });

            // Case 5: 2+ NCTs -> Red
            if (nct >= 2) {
                type = 'dissonant_severe';
                consecutiveDissonanceCount++; 
            } 
            // 1 NCT cases
            else if (nct === 1) {
                if (isConsonantChord) {
                    type = 'dissonant_secondary'; 
                } else {
                    type = 'dissonant_tertiary'; 
                }
                consecutiveDissonanceCount++;
            }
            // Clean Chords (0 NCT)
            else {
                if (isConsonantChord) {
                    type = 'consonant_stable'; 
                    consecutiveDissonanceCount = 0; 
                } else {
                    type = 'dissonant_primary'; 
                    consecutiveDissonanceCount++;
                }
            }
        } else {
            // No Chord Detected -> Interval Logic
            detailedInfo.chordName = `Interval: ${label}`;

            // For Intervals, we treat them as 'Chord Tones' but they don't have harmonic roles
            // We'll mark them as Ext to give them Purple color or maybe Root/5th if P5?
            // Let's just default to 'Root' for bass and 'Ext' for others to show color variety?
            // Actually, user spec is specific for Harmonic breakdown. For intervals, maybe just use NCT (Orange) or Ext (Purple).
            // Let's fallback to Ext (Purple) for clarity.
            const sortedActive = [...active].sort((a,b)=>a.midi - b.midi);
            sortedActive.forEach((n, i) => {
                detailedInfo.noteDetails.push({
                    name: getPitchName(n.midi, keyRoot),
                    midi: n.midi,
                    role: i === 0 ? 'Root' : 'Ext' // Arbitrary visual assignment for raw intervals
                });
            });
            detailedInfo.chordTones = detailedInfo.allNotes; 

            if (isDissonant) {
                consecutiveDissonanceCount++;
                if (consecutiveDissonanceCount === 1) {
                    type = 'dissonant_primary'; 
                } else if (consecutiveDissonanceCount === 2) {
                    type = 'dissonant_secondary'; 
                } else {
                    type = 'dissonant_tertiary'; 
                }
            } else {
                type = 'consonant_stable'; 
                consecutiveDissonanceCount = 0; 
            }
        }

        regions.push({
            startTick: start,
            endTick: end,
            type: type,
            intervalLabel: detailedInfo.chordName, // Short label
            description: detailedInfo.ncts.length > 0 ? `NCTs: ${detailedInfo.ncts.join(', ')}` : undefined,
            detailedInfo
        });
    }

    return regions;
}

function isStrongBeat(tick: number, ppq: number, tsNum: number, tsDenom: number): boolean {
    const ticksPerMeasure = ppq * tsNum * (4 / tsDenom);
    const pos = tick % ticksPerMeasure;
    if (pos === 0) return true; 
    if (tsNum === 4 && tsDenom === 4 && pos === (ticksPerMeasure / 2)) return true;
    return false; 
}

export function analyzeStrettoCandidate(
    subject: RawNote[], 
    intervalSemis: number, 
    delayTicks: number, 
    ppq: number,
    ts: { num: number, den: number },
    isInverted: boolean = false,
    pivotMidi: number = 60,
    useChromaticInversion: boolean = false,
    keyRoot: number = 0 // New param for spelling
): StrettoCandidate {

    if (subject.length === 0) {
        return {
            id: `empty`, intervalSemis, intervalLabel: 'N/A', delayBeats: 0, delayTicks,
            grade: 'INVALID', errors: [], notes: [], dissonanceRatio: 0, pairDissonanceScore: 0, endsOnDissonance: true
        };
    }

    const subjectEntryPitch = subject[0].midi;

    const answer: RawNote[] = subject.map(n => {
        if (!n) return null as any;
        let newMidi: number;

        if (isInverted) {
            const rawInverted = invertPitch(n.midi, pivotMidi, useChromaticInversion);
            const invertedStart = invertPitch(subjectEntryPitch, pivotMidi, useChromaticInversion);
            const targetStart = subjectEntryPitch + intervalSemis;
            const shift = targetStart - invertedStart;
            newMidi = rawInverted + shift;
        } else {
            newMidi = n.midi + intervalSemis;
        }

        return {
            ...n,
            ticks: n.ticks + delayTicks,
            midi: newMidi,
            name: getPitchName(newMidi, keyRoot),
            voiceIndex: 1
        };
    }).filter(n => !!n);

    const allNotes = [...subject, ...answer];

    // Generate Regions using Polyphonic Logic with Key Root
    const harmonicRegions = generatePolyphonicHarmonicRegions(allNotes, keyRoot);

    // Calculate Metrics
    let totalOverlapTicks = 0;
    let dissonantTicks = 0;
    let endsOnDissonance = false;

    harmonicRegions.forEach((r, idx) => {
        const dur = r.endTick - r.startTick;
        totalOverlapTicks += dur;
        if (r.type !== 'consonant_stable') {
            dissonantTicks += dur;
            if (idx === harmonicRegions.length - 1) endsOnDissonance = true;
        }
    });

    const dissonanceRatio = totalOverlapTicks > 0 ? (dissonantTicks / totalOverlapTicks) : 0;

    let pairDissonanceScore = 0;
    harmonicRegions.forEach(r => {
        const mid = r.startTick + (r.endTick - r.startTick)/2;
        const active = allNotes.filter(n => n.ticks <= mid && (n.ticks + n.durationTicks) > mid);
        if (active.length < 2) return;

        const sorted = active.map(n => n.midi).sort((a,b) => a-b);
        const bass = sorted[0];
        let pairDissCount = 0;

        for(let i=0; i<sorted.length; i++) {
            for(let j=i+1; j<sorted.length; j++) {
                const interval = Math.abs(sorted[i] - sorted[j]);
                const ic = interval % 12;
                const isBassPair = (sorted[i] === bass || sorted[j] === bass);
                let isDiss = DISSONANT_INTERVALS.includes(ic);
                if (ic === 5 && isBassPair) isDiss = true;

                if (isDiss) pairDissCount++;
            }
        }

        const durBeats = (r.endTick - r.startTick) / ppq;
        pairDissonanceScore += (durBeats * pairDissCount);
    });

    const errors: StrettoError[] = [];

    let prevP1: number | null = null;
    let prevP2: number | null = null;

    const timePoints = new Set<number>();
    allNotes.forEach(n => { timePoints.add(n.ticks); timePoints.add(n.ticks+n.durationTicks); });
    const tPoints = Array.from(timePoints).sort((a,b)=>a-b);

    for(let i=0; i<tPoints.length-1; i++) {
        const t = tPoints[i];
        const n1 = subject.find(n => n.ticks <= t && (n.ticks+n.durationTicks) > t);
        const n2 = answer.find(n => n.ticks <= t && (n.ticks+n.durationTicks) > t);

        if (n1 && n2) {
            const p1 = n1.midi;
            const p2 = n2.midi;

            if (prevP1 !== null && prevP2 !== null) {
                if (prevP1 !== p1 && prevP2 !== p2) { 
                    const int1 = Math.abs(prevP1 - prevP2) % 12;
                    const int2 = Math.abs(p1 - p2) % 12;
                    const isPerfect = int2 === 0 || int2 === 7;
                    if (isPerfect && int1 === int2) {
                        const timeStr = getFormattedTime(t, ppq, ts.num, ts.den);
                        const isStrong = isStrongBeat(t, ppq, ts.num, ts.den);
                        errors.push({
                            tick: t, timeFormatted: timeStr,
                            type: int2 === 7 ? 'Parallel 5th' : 'Parallel 8ve',
                            details: 'Parallel Perfect Interval',
                            severity: isStrong ? 'fatal' : 'warning'
                        });
                    }
                }
            }
            prevP1 = p1; prevP2 = p2;
        } else {
            prevP1 = null; prevP2 = null;
        }
    }

    let grade: StrettoGrade = 'STRONG';
    if (errors.some(e => e.severity === 'fatal')) grade = 'INVALID';
    else if (errors.length > 0) grade = 'VIABLE';

    let intLabel = getIntervalLabel(intervalSemis);
    if (isInverted) intLabel += " (Inv)";

    const delayBeats = delayTicks / (ppq * (4 / ts.den));

    return {
        id: `${intLabel}@${delayBeats.toFixed(1)}${isInverted?'i':''}`,
        intervalSemis,
        intervalLabel: intLabel,
        delayBeats: parseFloat(delayBeats.toFixed(2)),
        delayTicks,
        grade,
        errors,
        notes: allNotes,
        regions: harmonicRegions,
        dissonanceRatio,
        pairDissonanceScore: parseFloat(pairDissonanceScore.toFixed(1)),
        endsOnDissonance
    };
}

import React, { useState, useMemo, useEffect } from 'react';
import { RawNote, StrettoCandidate, StrettoSearchOptions, StrettoChainResult, HarmonicRegion, StrettoSearchReport, StrettoGrade } from '../types';
import { parseSimpleAbc } from './services/abcBridge';
import { analyzeStrettoCandidate, generatePolyphonicHarmonicRegions } from './services/strettoCore';
import { searchStrettoChains } from './services/strettoGenerator'; 
import { getStrictPitchName } from './services/midiSpelling';
import { downloadStrettoCandidate, downloadStrettoSelection } from './services/strettoExport';
import { Spinner, DocumentTextIcon } from './Icons';
import { playSequence, stopPlayback } from './midiPlaybackService';
import { useStrettoAssembly } from '../hooks/useStrettoAssembly';
import { predictKey } from './services/analysis/keyPrediction'; // Robust key finding

import StrettoConfig, { SearchResolution } from './stretto/StrettoConfig';
import StrettoList from './stretto/StrettoList';
import StrettoInspector from './stretto/StrettoInspector';
import StrettoFooter from './stretto/StrettoFooter';
import StrettoChainView from './stretto/StrettoChainView'; 

interface StrettoViewProps {
    notes: RawNote[]; 
    ppq: number;
    ts: { num: number, den: number };
    voiceNames?: Record<number, string>;
    setVoiceNames?: (names: Record<number, string>) => void;
}

interface SavedSubject {
    id: string;
    name: string;
    data: string;
}

export default function StrettoView({ notes: initialNotes, ppq, ts, voiceNames, setVoiceNames }: StrettoViewProps) {
    const [mode, setMode] = useState<'midi' | 'abc'>(initialNotes.length > 0 ? 'midi' : 'abc');
    const [abcInput, setAbcInput] = useState<string>("M:4/4\nL:1/4\nQ:120\nK:C\nc2 G c d e f g3 a b c'2");
    const [viewMode, setViewMode] = useState<'pairwise' | 'chain'>('chain'); 

    const [gradeFilter, setGradeFilter] = useState<Record<StrettoGrade, boolean>>({
        'STRONG': true,
        'VIABLE': true,
        'INVALID': false
    });

    const [savedSubjects, setSavedSubjects] = useState<SavedSubject[]>([]);
    const [saveName, setSaveName] = useState('');
    const [showLibrary, setShowLibrary] = useState(false);

    const [configIntervals, setConfigIntervals] = useState<number[]>([0, 12, -12, 7, -7, 5, -5, 24, -24]);
    const [includeExtensions, setIncludeExtensions] = useState(false);
    const [includeInversions, setIncludeInversions] = useState(false);
    const [searchRes, setSearchRes] = useState<SearchResolution>('full');
    const [selectedCandidate, setSelectedCandidate] = useState<StrettoCandidate | null>(null);
    const [checkedIds, setCheckedIds] = useState<Set<string>>(new Set());

    // Master Transposition State (Post-processing)
    const [masterTransposition, setMasterTransposition] = useState<number>(0);

    const [searchOptions, setSearchOptions] = useState<StrettoSearchOptions>({
        ensembleTotal: 4,
        targetChainLength: 8,
        subjectVoiceIndex: 2, 
        truncationMode: 'None', 
        truncationTargetBeats: 4,
        inversionMode: 'Max 1', 
        useChromaticInversion: false, 
        thirdSixthMode: 'Max 1', 
        pivotMidi: 60, // Placeholder, updated in effect
        requireConsonantEnd: true,
        disallowComplexExceptions: false
    });

    const [chainResults, setChainResults] = useState<StrettoChainResult[]>([]);
    const [searchReport, setSearchReport] = useState<StrettoSearchReport | null>(null);
    const [isSearching, setIsSearching] = useState(false);
    const [selectedChain, setSelectedChain] = useState<StrettoChainResult | null>(null);

    const [isPlaying, setIsPlaying] = useState(false);

    useEffect(() => {
        const saved = localStorage.getItem('stretto_subject_library');
        if (saved) {
            try { setSavedSubjects(JSON.parse(saved)); } catch (e) { console.error(e); }
        }
    }, []);

    const subjectNotes = useMemo(() => {
        if (mode === 'abc') return parseSimpleAbc(abcInput, ppq || 480);
        return initialNotes; 
    }, [mode, abcInput, initialNotes, ppq]);

    // Intelligent Pivot Initialization using Key Prediction
    useEffect(() => {
        if (subjectNotes && subjectNotes.length > 0) {
            // 1. Generate Histogram
            const histogram: Record<number, number> = {};
            for (let i = 0; i < 12; i++) histogram[i] = 0;
            subjectNotes.forEach(n => histogram[n.midi % 12]++);

            // 2. Predict Key to find the Tonic Pitch Class
            const predictions = predictKey(histogram, subjectNotes.length);
            const predictedRoot = predictions.length > 0 ? predictions[0].winner.root : subjectNotes[0].midi % 12;

            // 3. Find the best octave for the pivot
            // We want the tonic instance that sits comfortably within the subject's range
            // or closest to the starting note to preserve register intent.
            const startMidi = subjectNotes[0].midi;

            // Candidates: Root in same octave, octave below, octave above
            const candidates = [
                predictedRoot + (Math.floor(startMidi / 12) - 1) * 12,
                predictedRoot + (Math.floor(startMidi / 12)) * 12,
                predictedRoot + (Math.floor(startMidi / 12) + 1) * 12,
            ];

            // Choose the one closest to the start note
            let closest = candidates[0];
            let minDiff = Math.abs(candidates[0] - startMidi);

            for (let i=1; i<candidates.length; i++) {
                const diff = Math.abs(candidates[i] - startMidi);
                if (diff < minDiff) {
                    minDiff = diff;
                    closest = candidates[i];
                }
            }

            const validPivot = Math.max(0, Math.min(127, closest));

            setSearchOptions(prev => ({ ...prev, pivotMidi: validPivot }));
        }
    }, [subjectNotes]);

    const handleSaveSubject = () => {
        if (!saveName.trim() || !abcInput.trim()) return;
        const newSubject: SavedSubject = { id: Date.now().toString(), name: saveName.trim(), data: abcInput };
        const updated = [...savedSubjects, newSubject];
        setSavedSubjects(updated);
        localStorage.setItem('stretto_subject_library', JSON.stringify(updated));
        setSaveName('');
    };

    const handleDeleteSubject = (id: string) => {
        const updated = savedSubjects.filter(s => s.id !== id);
        setSavedSubjects(updated);
        localStorage.setItem('stretto_subject_library', JSON.stringify(updated));
    };

    const handleLoadSubject = (data: string) => { setAbcInput(data); };

    const { 
        isAssembling, assemblyStatus, assemblyResult, assemblyLog, 
        setAssemblyResult, runAssembly 
    } = useStrettoAssembly({ notes: subjectNotes, ppq: ppq || 480, ts });

    const pairwiseResults = useMemo(() => {
        if (subjectNotes.length === 0 || viewMode !== 'pairwise') return [];
        const candidates: StrettoCandidate[] = [];
        const validNotes = subjectNotes.filter(n => !!n);
        if (validNotes.length === 0) return [];

        const durationTicks = Math.max(...validNotes.map(n => n.ticks + n.durationTicks));
        const maxDelay = durationTicks * (2/3); 
        const currentPpq = ppq || 480;
        let stepTicks = currentPpq; 
        if (searchRes === 'half') stepTicks = currentPpq / 2;
        else if (searchRes === 'double') stepTicks = currentPpq * 2;

        let intervalsToCheck = [...configIntervals];
        if (includeExtensions) {
            const exts = [3, 4, 8, 9, -3, -4, -8, -9];
            exts.forEach(e => { if (!intervalsToCheck.includes(e)) intervalsToCheck.push(e); });
        }

        intervalsToCheck.forEach(interval => {
            for (let d = stepTicks; d <= maxDelay; d += stepTicks) {
                // PASS pivotMidi as keyRoot
                candidates.push(analyzeStrettoCandidate(validNotes, interval, Math.round(d), currentPpq, ts, false, searchOptions.pivotMidi, searchOptions.useChromaticInversion, searchOptions.pivotMidi));
                if (includeInversions) {
                    candidates.push(analyzeStrettoCandidate(validNotes, interval, Math.round(d), currentPpq, ts, true, searchOptions.pivotMidi, searchOptions.useChromaticInversion, searchOptions.pivotMidi));
                }
            }
        });
        return candidates;
    }, [subjectNotes, configIntervals, includeExtensions, includeInversions, ppq, ts, searchRes, viewMode, searchOptions.pivotMidi, searchOptions.useChromaticInversion]);

    const processedDiscoveryResults = useMemo(() => {
        return pairwiseResults.filter(r => gradeFilter[r.grade]);
    }, [pairwiseResults, gradeFilter]);

    const getSelectedCandidates = () => pairwiseResults.filter(r => checkedIds.has(r.id));

    const handleChainSearch = async () => {
        setIsSearching(true); setChainResults([]); setSearchReport(null); setSelectedChain(null);
        setTimeout(async () => {
            try {
                const report = await searchStrettoChains(subjectNotes.filter(n => !!n), { ...searchOptions, voiceNames }, ppq || 480);
                setChainResults(report.results); setSearchReport(report);
            } catch (e) { alert("Search failed."); } finally { setIsSearching(false); }
        }, 100);
    };

    const chainToCandidate = useMemo((): StrettoCandidate | null => {
        if (!selectedChain) return null;
        let allNotes: RawNote[] = [];
        const validSubjectNotes = subjectNotes.filter(n => !!n);
        const currentPpq = ppq || 480;
        if (validSubjectNotes.length === 0) return null;
        const sortedSubj = [...validSubjectNotes].sort((a,b)=>a.ticks-b.ticks);
        const startTick = sortedSubj[0].ticks;

        const SCALE_STEPS = [0, 2, 4, 5, 7, 9, 11];
        const invertPitchDiatonic = (pitch: number, pivot: number) => {
            const diff = pitch - pivot;
            const oct = Math.floor(diff / 12);
            const semi = (diff % 12 + 12) % 12;
            let degree = -1;
            let minErr = 99;
            SCALE_STEPS.forEach((s, i) => {
                if (Math.abs(s - semi) < minErr) { minErr = Math.abs(s - semi); degree = i; }
            });
            const absDegree = (oct * 7) + degree;
            const invAbsDegree = -absDegree;
            const invOct = Math.floor(invAbsDegree / 7);
            const invIndex = (invAbsDegree % 7 + 7) % 7;
            return pivot + (invOct * 12) + SCALE_STEPS[invIndex];
        };

        const invertPitchChromatic = (pitch: number, pivot: number) => {
            return pivot - (pitch - pivot);
        }

        selectedChain.entries.forEach((entry) => {
            const entryStartTick = Math.round(entry.startBeat * currentPpq);
            const transformed = sortedSubj.map(n => {
                let pitch = n.midi;

                if (entry.type === 'I') {
                    const rawInverted = searchOptions.useChromaticInversion 
                        ? invertPitchChromatic(n.midi, searchOptions.pivotMidi)
                        : invertPitchDiatonic(n.midi, searchOptions.pivotMidi);

                    const subjectFirst = sortedSubj[0].midi;
                    const invertedFirst = searchOptions.useChromaticInversion 
                        ? invertPitchChromatic(subjectFirst, searchOptions.pivotMidi)
                        : invertPitchDiatonic(subjectFirst, searchOptions.pivotMidi);

                    const targetStart = subjectFirst + entry.transposition;
                    const shift = targetStart - invertedFirst;
                    pitch = rawInverted + shift;

                } else {
                    pitch += entry.transposition;
                }

                pitch += masterTransposition;

                return { ...n, ticks: (n.ticks - startTick) + entryStartTick, midi: pitch, name: getStrictPitchName(pitch), voiceIndex: entry.voiceIndex };
            });
            const entryEnd = entryStartTick + (entry.length * (currentPpq/4));
            const clipped = transformed.filter(n => n.ticks < entryEnd).map(n => ({ ...n, durationTicks: Math.min(n.durationTicks, entryEnd - n.ticks) }));
            allNotes = [...allNotes, ...clipped];
        });

        // Pass pivotMidi as keyRoot
        const chainRegions = generatePolyphonicHarmonicRegions(allNotes, searchOptions.pivotMidi);

        return { id: selectedChain.id, intervalLabel: "Chain", intervalSemis: 0, delayBeats: 0, delayTicks: 0, grade: 'STRONG', errors: [], notes: allNotes, regions: chainRegions, dissonanceRatio: 0, pairDissonanceScore: 0, endsOnDissonance: false };
    }, [selectedChain, subjectNotes, ppq, searchOptions.pivotMidi, searchOptions.useChromaticInversion, masterTransposition]);

    const handlePlay = (notes: RawNote[]) => {
        if (isPlaying) { stopPlayback(); setIsPlaying(false); return; }
        setIsPlaying(true);
        const currentPpq = ppq || 480;
        playSequence(notes.filter(n => !!n).map(n => ({ 
            midi: n.midi, 
            name: n.name, 
            time: n.ticks * (0.5 / currentPpq), 
            duration: n.durationTicks * (0.5 / currentPpq), 
            velocity: n.velocity 
        })), () => setIsPlaying(false));
    };

    const toggleCheck = (id: string) => {
        setCheckedIds(prev => {
            const next = new Set(prev);
            if (next.has(id)) next.delete(id); else next.add(id);
            const cand = pairwiseResults.find(r => r.id === id);
            if (cand) setSelectedCandidate(cand);
            return next;
        });
    };

    return (
        <div className="w-full bg-gray-dark p-6 rounded-2xl border border-gray-medium animate-slide-up pb-32 relative">
            <div className="flex justify-between items-center mb-6">
                <h2 className="text-2xl font-bold text-gray-light">Stretto Assembly Lab</h2>
                {isAssembling && (
                    <div className="flex items-center gap-2 bg-brand-primary/20 px-4 py-2 rounded-full border border-brand-primary/40 animate-pulse">
                        <Spinner className="w-4 h-4 text-brand-primary" />
                        <span className="text-xs font-bold text-brand-primary">{assemblyStatus}</span>
                    </div>
                )}
            </div>

            <div className="flex flex-col md:flex-row gap-4 mb-6 p-4 bg-gray-800 rounded-lg border border-gray-700 justify-between">
                <div className="flex gap-2 items-center">
                    <span className="text-xs font-bold text-gray-500 mr-2">INPUT:</span>
                    <button onClick={() => setMode('midi')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${mode === 'midi' ? 'bg-brand-primary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Selected MIDI</button>
                    <button onClick={() => setMode('abc')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${mode === 'abc' ? 'bg-brand-primary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>ABC Notation</button>
                </div>
                <div className="flex gap-2 items-center border-l border-gray-600 pl-4">
                    <span className="text-xs font-bold text-gray-500 mr-2">MODE:</span>
                    <button onClick={() => setViewMode('pairwise')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${viewMode === 'pairwise' ? 'bg-brand-secondary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Pairwise Discovery</button>
                    <button onClick={() => setViewMode('chain')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${viewMode === 'chain' ? 'bg-brand-secondary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Algorithmic Chain</button>
                </div>
            </div>

            {mode === 'abc' && (
                <div className="mb-6 space-y-4">
                    <div className="flex justify-between items-center">
                        <label className="block text-sm text-gray-400 font-bold uppercase tracking-wider">Subject ABC</label>
                        <button onClick={() => setShowLibrary(!showLibrary)} className="text-xs bg-gray-800 hover:bg-gray-700 text-brand-primary border border-brand-primary/30 px-3 py-1 rounded flex items-center gap-2 transition-colors">
                            <DocumentTextIcon className="w-3 h-3" /> {showLibrary ? "Hide Library" : "Subject Library"}
                        </button>
                    </div>
                    {showLibrary && (
                        <div className="bg-gray-800 p-4 rounded-lg border border-gray-700 animate-fade-in">
                            <div className="flex gap-2 mb-4 border-b border-gray-700 pb-4">
                                <input type="text" placeholder="Subject Name..." value={saveName} onChange={(e) => setSaveName(e.target.value)} className="flex-grow bg-gray-900 border border-gray-600 rounded px-3 py-1 text-sm text-white outline-none" />
                                <button onClick={handleSaveSubject} disabled={!saveName.trim()} className="bg-brand-primary hover:bg-brand-secondary text-white px-4 py-1 rounded text-sm font-bold transition-colors disabled:bg-gray-600">Save</button>
                            </div>
                            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-2 max-h-48 overflow-y-auto">
                                {savedSubjects.length > 0 ? savedSubjects.map(s => (
                                    <div key={s.id} className="flex justify-between items-center bg-gray-900 p-2 rounded border border-gray-700 group">
                                        <span className="text-sm font-bold text-gray-300 truncate mr-2">{s.name}</span>
                                        <div className="flex gap-1 opacity-50 group-hover:opacity-100">
                                            <button onClick={() => handleLoadSubject(s.data)} className="text-[10px] bg-brand-secondary/50 px-2 py-0.5 rounded">Load</button>
                                            <button onClick={() => handleDeleteSubject(s.id)} className="text-[10px] bg-red-900/50 px-2 py-0.5 rounded">×</button>
                                        </div>
                                    </div>
                                )) : <p className="text-xs text-gray-500 col-span-full text-center py-2">Library empty.</p>}
                            </div>
                        </div>
                    )}
                    <textarea value={abcInput} onChange={e => setAbcInput(e.target.value)} className="w-full bg-gray-900 border border-gray-700 rounded p-3 text-white font-mono h-24 outline-none focus:border-brand-primary" />
                </div>
            )}

            {viewMode === 'pairwise' ? (
                <>
                    <StrettoConfig 
                        selectedIntervals={configIntervals} 
                        setSelectedIntervals={setConfigIntervals} 
                        searchRes={searchRes} 
                        setSearchRes={setSearchRes} 
                        includeInversions={includeInversions} 
                        setIncludeInversions={setIncludeInversions} 
                        includeExtensions={includeExtensions} 
                        setIncludeExtensions={setIncludeExtensions} 
                        pivotMidi={searchOptions.pivotMidi}
                        setPivotMidi={(val) => setSearchOptions({...searchOptions, pivotMidi: val})}
                    />

                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
                        <StrettoList 
                            candidates={pairwiseResults} 
                            processedResults={processedDiscoveryResults}
                            gradeFilter={gradeFilter}
                            setGradeFilter={setGradeFilter}
                            selectedId={selectedCandidate?.id || null} 
                            onSelect={setSelectedCandidate} 
                            checkedIds={checkedIds} 
                            onToggleCheck={toggleCheck} 
                        />
                        <StrettoInspector candidate={selectedCandidate} ppq={ppq || 480} ts={ts} isPlaying={isPlaying} onPlay={handlePlay} assemblyResult={assemblyResult} assemblyLog={assemblyLog} onClearAssembly={() => setAssemblyResult('')} onDownloadChain={() => selectedCandidate && downloadStrettoCandidate(selectedCandidate, ppq || 480, voiceNames)} />
                    </div>
                    <StrettoFooter selectedCandidates={getSelectedCandidates()} onDownloadMidi={() => downloadStrettoSelection(getSelectedCandidates(), ppq || 480, voiceNames)} onAssemble={() => runAssembly(checkedIds.size > 0 ? getSelectedCandidates() : (selectedCandidate ? [selectedCandidate] : []), abcInput)} isAssembling={isAssembling} onRemoveCandidate={toggleCheck} />
                </>
            ) : (
                <StrettoChainView 
                    searchOptions={searchOptions} 
                    setSearchOptions={setSearchOptions} 
                    onSearch={handleChainSearch} 
                    isSearching={isSearching} 
                    chainResults={chainResults} 
                    selectedChain={selectedChain} 
                    setSelectedChain={setSelectedChain} 
                    voiceNames={voiceNames} 
                    setVoiceNames={setVoiceNames} 
                    chainToCandidate={chainToCandidate} 
                    ppq={ppq || 480} 
                    ts={ts} 
                    isPlaying={isPlaying} 
                    onPlay={handlePlay} 
                    onDownloadChain={() => chainToCandidate && downloadStrettoCandidate(chainToCandidate, ppq || 480, voiceNames)} 
                    searchReport={searchReport}
                    masterTransposition={masterTransposition}
                    setMasterTransposition={setMasterTransposition}
                    subjectNotes={subjectNotes} 
                />
            )}
        </div>
    );
}

import React, { useMemo } from 'react';
import { StrettoCandidate, PianoRollTrackData, HarmonicRegion, RawNote } from '../../types';
import { PlayIcon, StopIcon, DocumentTextIcon, DownloadIcon } from '../Icons';
import PianoRoll from '../PianoRoll';
import { playSpecificNotes } from '../midiPlaybackService';
import { getFormattedTime } from '../services/midiHarmony';

interface StrettoInspectorProps {
    candidate: StrettoCandidate | null;
    ppq: number;
    ts: { num: number, den: number };
    isPlaying: boolean;
    onPlay: (notes: RawNote[]) => void;
    assemblyResult: string;
    assemblyLog: string[];
    onClearAssembly: () => void;
    onDownloadChain: () => void;
}

export default function StrettoInspector({ 
    candidate, ppq, ts, isPlaying, onPlay, 
    assemblyResult, assemblyLog, onClearAssembly, onDownloadChain 
}: StrettoInspectorProps) {

    const pianoRollData: PianoRollTrackData | null = useMemo(() => {
        if (!candidate) return null;
        return {
            name: `Stretto ${candidate.intervalLabel}`,
            ppq,
            timeSignature: { numerator: ts.num, denominator: ts.den },
            notes: candidate.notes.map(n => ({
                midi: n.midi,
                ticks: n.ticks,
                durationTicks: n.durationTicks,
                velocity: n.velocity,
                name: n.name,
                voiceIndex: n.voiceIndex ?? 0, 
                isOrnament: false
            })),
            harmonicRegions: candidate.regions 
        };
    }, [candidate, ppq, ts]);

    const handleRegionClick = (region: HarmonicRegion) => {
        if (!candidate) return;
        const activeNotes = candidate.notes.filter(n => 
            n.ticks < region.endTick && (n.ticks + n.durationTicks) > region.startTick
        );
        if (activeNotes.length > 0) {
            const notesToPlay = activeNotes.map(n => ({
                midi: n.midi, 
                duration: n.durationTicks * (0.5 / ppq), 
                velocity: n.velocity
            }));
            playSpecificNotes(notesToPlay);
        }
    };

    const handleExportAnalysis = () => {
        if (!candidate) return;
        let text = `STRETTO ANALYSIS REPORT\nCandidate ID: ${candidate.id}\nInterval: ${candidate.intervalLabel}\nDelay: ${candidate.delayBeats} Beats\n`;
        text += `\nMETRICS\n`;
        text += `Dissonant Time: ${Math.round(candidate.dissonanceRatio * 100)}%\n`;
        text += `Grade: ${candidate.grade}\n`;
        text += `Errors: ${candidate.errors.length}\n`;

        text += `\nHARMONIC SEGMENTS\n`;
        text += `Time | Chord/Interval | Notes | NCTs\n`;
        text += `---|---|---|---\n`;

        candidate.regions?.forEach(r => {
            const time = getFormattedTime(r.startTick, ppq, ts.num, ts.den);
            const notes = r.detailedInfo?.allNotes.join(', ') || '';
            const ncts = r.detailedInfo?.ncts.join(', ') || '-';
            text += `${time} | ${r.detailedInfo?.chordName || ''} | ${notes} | ${ncts}\n`;
        });

        const blob = new Blob([text], { type: 'text/plain' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `Analysis_${candidate.id}.txt`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
    };

    const getStatusColor = (type: HarmonicRegion['type']) => {
        switch(type) {
            case 'consonant_stable': return 'text-green-400';
            case 'dissonant_primary': return 'text-purple-400';
            case 'dissonant_secondary': return 'text-amber-400';
            case 'dissonant_tertiary': return 'text-orange-500';
            case 'dissonant_severe': return 'text-red-500';
            default: return 'text-gray-400';
        }
    };

    const getRoleColor = (role: string) => {
        switch(role) {
            case 'Root': return 'text-blue-400';
            case '3rd': return 'text-lime-400';
            case '5th': return 'text-teal-400';
            case 'Ext': return 'text-purple-400';
            case 'NCT': return 'text-orange-400';
            default: return 'text-gray-300';
        }
    };

    return (
        <div className="bg-gray-800 border border-gray-700 rounded p-4 flex flex-col h-[700px] shadow-lg relative overflow-hidden">
            {/* Gemini Assembly Overlay */}
            {assemblyResult && (
                <div className="absolute inset-0 bg-gray-800 z-30 p-4 flex flex-col animate-fade-in">
                    <div className="flex justify-between items-center mb-4 border-b border-gray-700 pb-2">
                        <h3 className="font-bold text-brand-primary">Gemini Stretto Chain</h3>
                        <button onClick={onClearAssembly} className="text-gray-500 hover:text-white">✕ Close</button>
                    </div>
                    <div className="flex-grow flex flex-col gap-4 overflow-hidden">
                        <div className="flex-1 bg-black rounded p-3 font-mono text-xs text-gray-300 overflow-auto border border-gray-700 whitespace-pre-wrap">
                            {assemblyResult}
                        </div>
                        <div className="grid grid-cols-2 gap-2">
                            <button onClick={onDownloadChain} className="w-full py-2 bg-brand-secondary text-white font-bold rounded flex items-center justify-center gap-2 hover:bg-brand-primary transition-colors">
                                <DownloadIcon className="w-4 h-4"/> Download Chain MIDI
                            </button>
                            <button onClick={() => { navigator.clipboard.writeText(assemblyResult); alert("ABC Chain copied to clipboard!"); }} className="w-full py-2 bg-gray-700 text-white font-bold rounded hover:bg-gray-600 transition-colors">
                                Copy ABC Text
                            </button>
                        </div>
                        <div className="h-24 bg-gray-900 rounded p-2 border border-gray-700 overflow-auto text-[10px]">
                            <h4 className="font-bold text-gray-500 uppercase mb-1">Verification History</h4>
                            {assemblyLog.map((log, i) => (
                                <div key={i} className="border-l border-gray-700 pl-2 mb-1 text-gray-400">{log}</div>
                            ))}
                        </div>
                    </div>
                </div>
            )}

            {candidate && pianoRollData ? (
                <>
                    <div className="flex justify-between items-start mb-4">
                        <div>
                            <h3 className="text-xl font-bold text-white">
                                Stretto: {candidate.intervalLabel} @ {candidate.delayBeats}B
                            </h3>
                            <div className="flex items-center gap-4 mt-1">
                                <div className="flex items-center gap-1 text-[10px] bg-black/30 px-2 py-1 rounded">
                                    <span className="text-gray-400">Time Diss:</span>
                                    <span className={`${candidate.dissonanceRatio > 0.4 ? 'text-red-400' : 'text-green-400'} font-bold`}>
                                        {Math.round(candidate.dissonanceRatio * 100)}%
                                    </span>
                                </div>
                                <span className={`text-xs font-bold ${candidate.grade === 'STRONG' ? 'text-green-400' : candidate.grade === 'VIABLE' ? 'text-yellow-400' : 'text-red-400'}`}>
                                    {candidate.grade}
                                </span>
                            </div>
                        </div>
                        <div className="flex gap-2">
                            <button onClick={handleExportAnalysis} className="p-2 bg-gray-700 rounded-full hover:bg-gray-600 transition-colors text-white" title="Export Analysis Report">
                                <DocumentTextIcon className="w-5 h-5"/>
                            </button>
                            <button onClick={() => onPlay(candidate.notes)} className="bg-brand-primary p-2 rounded-full hover:bg-brand-secondary transition-transform active:scale-95 shadow-md">
                                {isPlaying ? <StopIcon className="w-5 h-5 text-white"/> : <PlayIcon className="w-5 h-5 text-white"/>}
                            </button>
                        </div>
                    </div>

                    <div className="h-64 flex-shrink-0 bg-gray-900 rounded border border-gray-700 mb-2 overflow-hidden shadow-inner relative">
                        <PianoRoll trackData={pianoRollData} onRegionClick={handleRegionClick} />
                    </div>

                    {/* Detailed Analysis Table */}
                    <div className="flex-grow bg-gray-900/50 rounded p-2 border border-gray-700 flex flex-col overflow-hidden relative">
                        <div className="flex justify-between items-center mb-2 px-1">
                            <h4 className="text-xs font-bold text-gray-400 uppercase">Harmonic Breakdown</h4>
                            <span className="text-[10px] text-gray-500">Tap row to audition</span>
                        </div>

                        <div className="flex-grow overflow-auto rounded border border-gray-800 pb-8">
                            <table className="w-full text-left text-[10px] text-gray-300">
                                <thead className="bg-gray-800 text-gray-500 uppercase sticky top-0 z-10">
                                    <tr>
                                        <th className="px-2 py-1.5 w-16">Time</th>
                                        <th className="px-2 py-1.5 w-24">Chord / Int</th>
                                        <th className="px-2 py-1.5">Active Notes</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-gray-800">
                                    {candidate.regions?.map((r, i) => (
                                        <tr 
                                            key={i} 
                                            onClick={() => handleRegionClick(r)}
                                            className="hover:bg-gray-700/50 cursor-pointer transition-colors"
                                        >
                                            <td className="px-2 py-1.5 font-mono text-gray-500">
                                                {getFormattedTime(r.startTick, ppq, ts.num, ts.den)}
                                            </td>
                                            <td className={`px-2 py-1.5 font-bold ${getStatusColor(r.type)}`}>
                                                {r.detailedInfo?.chordName}
                                            </td>
                                            <td className="px-2 py-1.5 flex flex-wrap gap-1">
                                                {r.detailedInfo?.noteDetails.map((n, idx) => (
                                                    <span key={idx} className={`${getRoleColor(n.role)} font-bold`}>
                                                        {n.name}
                                                    </span>
                                                ))}
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>

                        {/* LEGEND */}
                        <div className="absolute bottom-0 left-0 right-0 bg-gray-900 border-t border-gray-700 p-2 flex justify-between text-[9px] font-bold">
                            <span className="text-blue-400">Root</span>
                            <span className="text-lime-400">3rd</span>
                            <span className="text-teal-400">5th</span>
                            <span className="text-purple-400">6th/7th/Dim5</span>
                            <span className="text-orange-400">NCT</span>
                        </div>
                    </div>
                </>
            ) : (
                <div className="flex flex-col items-center justify-center h-full text-gray-500">
                    <span className="text-4xl mb-4 opacity-50">🎹</span>
                    <p className="font-bold text-gray-400">Select a candidate to visualize.</p>
                </div>
            )}
        </div>
    );
}

