    'DB': { 'f': 1,  'F': 1, 'c': 1, 'C': 1, 'g': 1, 'G': 1, 'd': 1, 'D': 1, 'a': 1, 'A': 1, 'e': 1, 'E': 1, 'b': 1, 'B': 1 }, // Enharmonic C#
