import React, { useState, useMemo, useEffect } from 'react';
import { RawNote, StrettoCandidate, StrettoSearchOptions, StrettoChainResult, HarmonicRegion, StrettoSearchReport, StrettoGrade } from '../types';
import { parseSimpleAbc } from './services/abcBridge';
import { analyzeStrettoCandidate, generatePolyphonicHarmonicRegions } from './services/strettoCore';
import { searchStrettoChains } from './services/strettoGenerator'; 
import { getStrictPitchName } from './services/midiSpelling';
import { downloadStrettoCandidate, downloadStrettoSelection } from './services/strettoExport';
import { Spinner, DocumentTextIcon } from './Icons';
import { playSequence, stopPlayback } from './midiPlaybackService';
import { useStrettoAssembly } from '../hooks/useStrettoAssembly';
import { predictKey } from './services/analysis/keyPrediction'; 
import { NOTE_NAMES } from './services/midiCore';

import StrettoConfig, { SearchResolution } from './stretto/StrettoConfig';
import StrettoList from './stretto/StrettoList';
import StrettoInspector from './stretto/StrettoInspector';
import StrettoFooter from './stretto/StrettoFooter';
import StrettoChainView from './stretto/StrettoChainView'; 

interface StrettoViewProps {
    notes: RawNote[]; 
    ppq: number;
    ts: { num: number, den: number };
    voiceNames?: Record<number, string>;
    setVoiceNames?: (names: Record<number, string>) => void;
}

interface SavedSubject {
    id: string;
    name: string;
    data: string;
}

export default function StrettoView({ notes: initialNotes, ppq, ts, voiceNames, setVoiceNames }: StrettoViewProps) {
    const [mode, setMode] = useState<'midi' | 'abc'>(initialNotes.length > 0 ? 'midi' : 'abc');
    // Default ABC is now empty to allow clean pasting
    const [abcInput, setAbcInput] = useState<string>(""); 
    const [viewMode, setViewMode] = useState<'pairwise' | 'chain'>('chain'); 

    const [gradeFilter, setGradeFilter] = useState<Record<StrettoGrade, boolean>>({
        'STRONG': true,
        'VIABLE': true,
        'INVALID': false
    });

    const [savedSubjects, setSavedSubjects] = useState<SavedSubject[]>([]);
    const [saveName, setSaveName] = useState('');
    const [showLibrary, setShowLibrary] = useState(false);

    const [detectedKey, setDetectedKey] = useState<string>('');

    const [configIntervals, setConfigIntervals] = useState<number[]>([0, 12, -12, 7, -7, 5, -5, 24, -24]);
    const [includeExtensions, setIncludeExtensions] = useState(false);
    const [includeInversions, setIncludeInversions] = useState(false);
    const [searchRes, setSearchRes] = useState<SearchResolution>('full');
    const [selectedCandidate, setSelectedCandidate] = useState<StrettoCandidate | null>(null);
    const [checkedIds, setCheckedIds] = useState<Set<string>>(new Set());

    // Master Transposition State (Post-processing)
    const [masterTransposition, setMasterTransposition] = useState<number>(0);

    const [searchOptions, setSearchOptions] = useState<StrettoSearchOptions>({
        ensembleTotal: 4,
        targetChainLength: 8,
        subjectVoiceIndex: 2, 
        truncationMode: 'None', 
        truncationTargetBeats: 4,
        inversionMode: 'Max 1', 
        useChromaticInversion: false, 
        thirdSixthMode: 'Max 1', 
        pivotMidi: 60, 
        requireConsonantEnd: true,
        disallowComplexExceptions: false
    });

    const [chainResults, setChainResults] = useState<StrettoChainResult[]>([]);
    const [searchReport, setSearchReport] = useState<StrettoSearchReport | null>(null);
    const [isSearching, setIsSearching] = useState(false);
    const [selectedChain, setSelectedChain] = useState<StrettoChainResult | null>(null);

    const [isPlaying, setIsPlaying] = useState(false);

    useEffect(() => {
        const saved = localStorage.getItem('stretto_subject_library');
        if (saved) {
            try { setSavedSubjects(JSON.parse(saved)); } catch (e) { console.error(e); }
        }
    }, []);

    const subjectNotes = useMemo(() => {
        if (mode === 'abc') return parseSimpleAbc(abcInput, ppq || 480);
        return initialNotes; 
    }, [mode, abcInput, initialNotes, ppq]);

    // Intelligent Pivot Initialization using Key Prediction
    useEffect(() => {
        if (subjectNotes && subjectNotes.length > 0) {
            // 1. Generate Pitch Class Histogram
            const histogram: Record<number, number> = {};
            for (let i = 0; i < 12; i++) histogram[i] = 0;
            subjectNotes.forEach(n => histogram[n.midi % 12]++);

            // 2. Predict Key to find the Tonic Pitch Class
            const predictions = predictKey(histogram, subjectNotes.length);
            const winner = predictions.length > 0 ? predictions[0].winner : null;
            const predictedRoot = winner ? winner.root : subjectNotes[0].midi % 12;

            if (winner) {
                setDetectedKey(`${NOTE_NAMES[winner.root]} ${winner.mode}`);
            } else {
                setDetectedKey('');
            }

            // 3. Find the best octave for the pivot (Average Pitch Centroid)
            const sumMidi = subjectNotes.reduce((sum, n) => sum + n.midi, 0);
            const avgMidi = sumMidi / subjectNotes.length;

            // Candidates: Root in octave below, same, above the centroid
            const baseOctave = Math.floor(avgMidi / 12);
            const candidates = [
                predictedRoot + (baseOctave - 1) * 12,
                predictedRoot + (baseOctave) * 12,
                predictedRoot + (baseOctave + 1) * 12,
            ];

            // Choose the one closest to the Average Pitch
            let closest = candidates[0];
            let minDiff = Math.abs(candidates[0] - avgMidi);

            for (let i=1; i<candidates.length; i++) {
                const diff = Math.abs(candidates[i] - avgMidi);
                if (diff < minDiff) {
                    minDiff = diff;
                    closest = candidates[i];
                }
            }

            const validPivot = Math.max(0, Math.min(127, closest));

            setSearchOptions(prev => ({ ...prev, pivotMidi: validPivot }));
        } else {
            setDetectedKey('');
        }
    }, [subjectNotes]);

    const handleSaveSubject = () => {
        if (!saveName.trim() || !abcInput.trim()) return;
        const newSubject: SavedSubject = { id: Date.now().toString(), name: saveName.trim(), data: abcInput };
        const updated = [...savedSubjects, newSubject];
        setSavedSubjects(updated);
        localStorage.setItem('stretto_subject_library', JSON.stringify(updated));
        setSaveName('');
    };

    const handleDeleteSubject = (id: string) => {
        const updated = savedSubjects.filter(s => s.id !== id);
        setSavedSubjects(updated);
        localStorage.setItem('stretto_subject_library', JSON.stringify(updated));
    };

    const handleLoadSubject = (data: string) => { setAbcInput(data); };

    const { 
        isAssembling, assemblyStatus, assemblyResult, assemblyLog, 
        setAssemblyResult, runAssembly 
    } = useStrettoAssembly({ notes: subjectNotes, ppq: ppq || 480, ts });

    const pairwiseResults = useMemo(() => {
        if (subjectNotes.length === 0 || viewMode !== 'pairwise') return [];
        const candidates: StrettoCandidate[] = [];
        const validNotes = subjectNotes.filter(n => !!n);
        if (validNotes.length === 0) return [];

        const durationTicks = Math.max(...validNotes.map(n => n.ticks + n.durationTicks));
        const maxDelay = durationTicks * (2/3); 
        const currentPpq = ppq || 480;
        let stepTicks = currentPpq; 
        if (searchRes === 'half') stepTicks = currentPpq / 2;
        else if (searchRes === 'double') stepTicks = currentPpq * 2;

        let intervalsToCheck = [...configIntervals];
        if (includeExtensions) {
            const exts = [3, 4, 8, 9, -3, -4, -8, -9];
            exts.forEach(e => { if (!intervalsToCheck.includes(e)) intervalsToCheck.push(e); });
        }

        intervalsToCheck.forEach(interval => {
            for (let d = stepTicks; d <= maxDelay; d += stepTicks) {
                // PASS pivotMidi as keyRoot
                candidates.push(analyzeStrettoCandidate(validNotes, interval, Math.round(d), currentPpq, ts, false, searchOptions.pivotMidi, searchOptions.useChromaticInversion, searchOptions.pivotMidi));
                if (includeInversions) {
                    candidates.push(analyzeStrettoCandidate(validNotes, interval, Math.round(d), currentPpq, ts, true, searchOptions.pivotMidi, searchOptions.useChromaticInversion, searchOptions.pivotMidi));
                }
            }
        });
        return candidates;
    }, [subjectNotes, configIntervals, includeExtensions, includeInversions, ppq, ts, searchRes, viewMode, searchOptions.pivotMidi, searchOptions.useChromaticInversion]);

    const processedDiscoveryResults = useMemo(() => {
        return pairwiseResults.filter(r => gradeFilter[r.grade]);
    }, [pairwiseResults, gradeFilter]);

    const getSelectedCandidates = () => pairwiseResults.filter(r => checkedIds.has(r.id));

    const handleChainSearch = async () => {
        setIsSearching(true); setChainResults([]); setSearchReport(null); setSelectedChain(null);
        setTimeout(async () => {
            try {
                const report = await searchStrettoChains(subjectNotes.filter(n => !!n), { ...searchOptions, voiceNames }, ppq || 480);
                setChainResults(report.results); setSearchReport(report);
            } catch (e) { alert("Search failed."); } finally { setIsSearching(false); }
        }, 100);
    };

    const chainToCandidate = useMemo((): StrettoCandidate | null => {
        if (!selectedChain) return null;
        let allNotes: RawNote[] = [];
        const validSubjectNotes = subjectNotes.filter(n => !!n);
        const currentPpq = ppq || 480;
        if (validSubjectNotes.length === 0) return null;
        const sortedSubj = [...validSubjectNotes].sort((a,b)=>a.ticks-b.ticks);
        const startTick = sortedSubj[0].ticks;

        const SCALE_STEPS = [0, 2, 4, 5, 7, 9, 11];
        const invertPitchDiatonic = (pitch: number, pivot: number) => {
            const diff = pitch - pivot;
            const oct = Math.floor(diff / 12);
            const semi = (diff % 12 + 12) % 12;
            let degree = -1;
            let minErr = 99;
            SCALE_STEPS.forEach((s, i) => {
                if (Math.abs(s - semi) < minErr) { minErr = Math.abs(s - semi); degree = i; }
            });
            const absDegree = (oct * 7) + degree;
            const invAbsDegree = -absDegree;
            const invOct = Math.floor(invAbsDegree / 7);
            const invIndex = (invAbsDegree % 7 + 7) % 7;
            return pivot + (invOct * 12) + SCALE_STEPS[invIndex];
        };

        const invertPitchChromatic = (pitch: number, pivot: number) => {
            return pivot - (pitch - pivot);
        }

        selectedChain.entries.forEach((entry) => {
            const entryStartTick = Math.round(entry.startBeat * currentPpq);
            const transformed = sortedSubj.map(n => {
                let pitch = n.midi;

                if (entry.type === 'I') {
                    const rawInverted = searchOptions.useChromaticInversion 
                        ? invertPitchChromatic(n.midi, searchOptions.pivotMidi)
                        : invertPitchDiatonic(n.midi, searchOptions.pivotMidi);

                    const subjectFirst = sortedSubj[0].midi;
                    const invertedFirst = searchOptions.useChromaticInversion 
                        ? invertPitchChromatic(subjectFirst, searchOptions.pivotMidi)
                        : invertPitchDiatonic(subjectFirst, searchOptions.pivotMidi);

                    const targetStart = subjectFirst + entry.transposition;
                    const shift = targetStart - invertedFirst;
                    pitch = rawInverted + shift;

                } else {
                    pitch += entry.transposition;
                }

                pitch += masterTransposition;

                return { ...n, ticks: (n.ticks - startTick) + entryStartTick, midi: pitch, name: getStrictPitchName(pitch), voiceIndex: entry.voiceIndex };
            });
            const entryEnd = entryStartTick + (entry.length * (currentPpq/4));
            const clipped = transformed.filter(n => n.ticks < entryEnd).map(n => ({ ...n, durationTicks: Math.min(n.durationTicks, entryEnd - n.ticks) }));
            allNotes = [...allNotes, ...clipped];
        });

        // Pass pivotMidi as keyRoot
        const chainRegions = generatePolyphonicHarmonicRegions(allNotes, searchOptions.pivotMidi);

        return { id: selectedChain.id, intervalLabel: "Chain", intervalSemis: 0, delayBeats: 0, delayTicks: 0, grade: 'STRONG', errors: [], notes: allNotes, regions: chainRegions, dissonanceRatio: 0, pairDissonanceScore: 0, endsOnDissonance: false };
    }, [selectedChain, subjectNotes, ppq, searchOptions.pivotMidi, searchOptions.useChromaticInversion, masterTransposition]);

    const handlePlay = (notes: RawNote[]) => {
        if (isPlaying) { stopPlayback(); setIsPlaying(false); return; }
        setIsPlaying(true);
        const currentPpq = ppq || 480;
        playSequence(notes.filter(n => !!n).map(n => ({ 
            midi: n.midi, 
            name: n.name, 
            time: n.ticks * (0.5 / currentPpq), 
            duration: n.durationTicks * (0.5 / currentPpq), 
            velocity: n.velocity 
        })), () => setIsPlaying(false));
    };

    const toggleCheck = (id: string) => {
        setCheckedIds(prev => {
            const next = new Set(prev);
            if (next.has(id)) next.delete(id); else next.add(id);
            const cand = pairwiseResults.find(r => r.id === id);
            if (cand) setSelectedCandidate(cand);
            return next;
        });
    };

    return (
        <div className="w-full bg-gray-dark p-6 rounded-2xl border border-gray-medium animate-slide-up pb-32 relative">
            <div className="flex justify-between items-center mb-6">
                <h2 className="text-2xl font-bold text-gray-light">Stretto Assembly Lab</h2>
                {isAssembling && (
                    <div className="flex items-center gap-2 bg-brand-primary/20 px-4 py-2 rounded-full border border-brand-primary/40 animate-pulse">
                        <Spinner className="w-4 h-4 text-brand-primary" />
                        <span className="text-xs font-bold text-brand-primary">{assemblyStatus}</span>
                    </div>
                )}
            </div>

            <div className="flex flex-col md:flex-row gap-4 mb-6 p-4 bg-gray-800 rounded-lg border border-gray-700 justify-between">
                <div className="flex gap-2 items-center">
                    <span className="text-xs font-bold text-gray-500 mr-2">INPUT:</span>
                    <button onClick={() => setMode('midi')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${mode === 'midi' ? 'bg-brand-primary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Selected MIDI</button>
                    <button onClick={() => setMode('abc')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${mode === 'abc' ? 'bg-brand-primary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>ABC Notation</button>
                </div>
                <div className="flex gap-2 items-center border-l border-gray-600 pl-4">
                    <span className="text-xs font-bold text-gray-500 mr-2">MODE:</span>
                    <button onClick={() => setViewMode('pairwise')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${viewMode === 'pairwise' ? 'bg-brand-secondary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Pairwise Discovery</button>
                    <button onClick={() => setViewMode('chain')} className={`px-4 py-2 text-sm rounded transition-colors font-bold ${viewMode === 'chain' ? 'bg-brand-secondary text-white' : 'bg-gray-900 text-gray-400 hover:bg-gray-700'}`}>Algorithmic Chain</button>
                </div>
            </div>

            {mode === 'abc' && (
                <div className="mb-6 space-y-4">
                    <div className="flex justify-between items-center">
                        <div className="flex items-center gap-3">
                            <label className="block text-sm text-gray-400 font-bold uppercase tracking-wider">Subject ABC</label>
                            {detectedKey && (
                                <span className="text-xs bg-brand-primary/20 text-brand-primary border border-brand-primary/50 px-2 py-0.5 rounded font-bold">
                                    Detected: {detectedKey}
                                </span>
                            )}
                        </div>
                        <button onClick={() => setShowLibrary(!showLibrary)} className="text-xs bg-gray-800 hover:bg-gray-700 text-brand-primary border border-brand-primary/30 px-3 py-1 rounded flex items-center gap-2 transition-colors">
                            <DocumentTextIcon className="w-3 h-3" /> {showLibrary ? "Hide Library" : "Subject Library"}
                        </button>
                    </div>
                    {showLibrary && (
                        <div className="bg-gray-800 p-4 rounded-lg border border-gray-700 animate-fade-in">
                            <div className="flex gap-2 mb-4 border-b border-gray-700 pb-4">
                                <input type="text" placeholder="Subject Name..." value={saveName} onChange={(e) => setSaveName(e.target.value)} className="flex-grow bg-gray-900 border border-gray-600 rounded px-3 py-1 text-sm text-white outline-none" />
                                <button onClick={handleSaveSubject} disabled={!saveName.trim()} className="bg-brand-primary hover:bg-brand-secondary text-white px-4 py-1 rounded text-sm font-bold transition-colors disabled:bg-gray-600">Save</button>
                            </div>
                            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-2 max-h-48 overflow-y-auto">
                                {savedSubjects.length > 0 ? savedSubjects.map(s => (
                                    <div key={s.id} className="flex justify-between items-center bg-gray-900 p-2 rounded border border-gray-700 group">
                                        <span className="text-sm font-bold text-gray-300 truncate mr-2">{s.name}</span>
                                        <div className="flex gap-1 opacity-50 group-hover:opacity-100">
                                            <button onClick={() => handleLoadSubject(s.data)} className="text-[10px] bg-brand-secondary/50 px-2 py-0.5 rounded">Load</button>
                                            <button onClick={() => handleDeleteSubject(s.id)} className="text-[10px] bg-red-900/50 px-2 py-0.5 rounded">×</button>
                                        </div>
                                    </div>
                                )) : <p className="text-xs text-gray-500 col-span-full text-center py-2">Library empty.</p>}
                            </div>
                        </div>
                    )}
                    <textarea 
                        value={abcInput} 
                        onChange={e => setAbcInput(e.target.value)} 
                        placeholder="Paste ABC notation here..."
                        className="w-full bg-gray-900 border border-gray-700 rounded p-3 text-white font-mono h-24 outline-none focus:border-brand-primary" 
                    />
                </div>
            )}

            {viewMode === 'pairwise' ? (
                <>
                    <StrettoConfig 
                        selectedIntervals={configIntervals} 
                        setSelectedIntervals={setConfigIntervals} 
                        searchRes={searchRes} 
                        setSearchRes={setSearchRes} 
                        includeInversions={includeInversions} 
                        setIncludeInversions={setIncludeInversions} 
                        includeExtensions={includeExtensions} 
                        setIncludeExtensions={setIncludeExtensions} 
                        pivotMidi={searchOptions.pivotMidi}
                        setPivotMidi={(val) => setSearchOptions({...searchOptions, pivotMidi: val})}
                        subjectNotes={subjectNotes}
                    />

                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
                        <StrettoList 
                            candidates={pairwiseResults} 
                            processedResults={processedDiscoveryResults}
                            gradeFilter={gradeFilter}
                            setGradeFilter={setGradeFilter}
                            selectedId={selectedCandidate?.id || null} 
                            onSelect={setSelectedCandidate} 
                            checkedIds={checkedIds} 
                            onToggleCheck={toggleCheck} 
                        />
                        <StrettoInspector candidate={selectedCandidate} ppq={ppq || 480} ts={ts} isPlaying={isPlaying} onPlay={handlePlay} assemblyResult={assemblyResult} assemblyLog={assemblyLog} onClearAssembly={() => setAssemblyResult('')} onDownloadChain={() => selectedCandidate && downloadStrettoCandidate(selectedCandidate, ppq || 480, voiceNames)} />
                    </div>
                    <StrettoFooter selectedCandidates={getSelectedCandidates()} onDownloadMidi={() => downloadStrettoSelection(getSelectedCandidates(), ppq || 480, voiceNames)} onAssemble={() => runAssembly(checkedIds.size > 0 ? getSelectedCandidates() : (selectedCandidate ? [selectedCandidate] : []), abcInput)} isAssembling={isAssembling} onRemoveCandidate={toggleCheck} />
                </>
            ) : (
                <StrettoChainView 
                    searchOptions={searchOptions} 
                    setSearchOptions={setSearchOptions} 
                    onSearch={handleChainSearch} 
                    isSearching={isSearching} 
                    chainResults={chainResults} 
                    selectedChain={selectedChain} 
                    setSelectedChain={setSelectedChain} 
                    voiceNames={voiceNames} 
                    setVoiceNames={setVoiceNames} 
                    chainToCandidate={chainToCandidate} 
                    ppq={ppq || 480} 
                    ts={ts} 
                    isPlaying={isPlaying} 
                    onPlay={handlePlay} 
                    onDownloadChain={() => chainToCandidate && downloadStrettoCandidate(chainToCandidate, ppq || 480, voiceNames)} 
                    searchReport={searchReport}
                    masterTransposition={masterTransposition}
                    setMasterTransposition={setMasterTransposition}
                    subjectNotes={subjectNotes} 
                />
            )}
        </div>
    );
}

import React, { useMemo } from 'react';
import { getStrictPitchName } from '../services/midiSpelling';
import { RawNote } from '../../types';

const INTERVAL_OPTIONS = [
    { label: 'Unison (P1)', val: 0 },
    { label: '+ Perf 5th', val: 7 },
    { label: '- Perf 5th', val: -7 },
    { label: '+ Perf 4th', val: 5 },
    { label: '- Perf 4th', val: -5 },
    { label: '+1 Octave (P8)', val: 12 },
    { label: '-1 Octave (P8)', val: -12 },
    { label: '+2 Octaves (P15)', val: 24 },
    { label: '-2 Octaves (P15)', val: -24 },
];

export type SearchResolution = 'half' | 'full' | 'double';

interface StrettoConfigProps {
    selectedIntervals: number[];
    setSelectedIntervals: (vals: number[]) => void;
    searchRes: SearchResolution;
    setSearchRes: (res: SearchResolution) => void;
    includeInversions: boolean;
    setIncludeInversions: (val: boolean) => void;
    includeExtensions: boolean;
    setIncludeExtensions: (val: boolean) => void;
    pivotMidi: number;
    setPivotMidi: (val: number) => void;
    subjectNotes?: RawNote[];
}

export default function StrettoConfig({ 
    selectedIntervals, setSelectedIntervals, 
    searchRes, setSearchRes,
    includeInversions, setIncludeInversions,
    includeExtensions, setIncludeExtensions,
    pivotMidi, setPivotMidi,
    subjectNotes
}: StrettoConfigProps) {

    const toggleInterval = (val: number, checked: boolean) => {
        if (checked) {
            if (!selectedIntervals.includes(val)) setSelectedIntervals([...selectedIntervals, val]);
        } else {
            setSelectedIntervals(selectedIntervals.filter(c => c !== val));
        }
    };

    const pivotOptions = useMemo(() => {
        let min = 48; // C3
        let max = 72; // C5

        if (subjectNotes && subjectNotes.length > 0) {
            const midis = subjectNotes.map(n => n.midi);
            min = Math.min(...midis);
            max = Math.max(...midis);
        }

        // Expand range by an octave on either side
        const start = Math.floor((min - 12) / 12) * 12;
        const end = Math.ceil((max + 12) / 12) * 12;

        const options = [];
        for (let i = start; i <= end; i++) {
            options.push(i);
        }

        // Ensure current selected pivot is included
        if (!options.includes(pivotMidi)) {
            options.push(pivotMidi);
            options.sort((a,b) => a - b);
        }

        return options;
    }, [subjectNotes, pivotMidi]);

    return (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
            <div className="p-4 bg-gray-800 rounded border border-gray-700 shadow-sm">
                <div className="flex justify-between items-center mb-3">
                    <h3 className="text-xs font-bold text-gray-400 uppercase tracking-widest text-brand-primary">Functional Discovery Intervals</h3>
                    {includeInversions && (
                        <div className="flex items-center gap-2 bg-gray-900 px-2 py-1 rounded border border-gray-700 animate-fade-in">
                            <span className="text-[9px] text-gray-500 font-bold uppercase">Pivot:</span>
                            <select 
                                value={pivotMidi}
                                onChange={(e) => setPivotMidi(parseInt(e.target.value))}
                                className="bg-transparent text-[10px] text-brand-primary font-bold focus:outline-none max-w-[80px]"
                            >
                                {pivotOptions.map((m) => (
                                    <option key={m} value={m} className="bg-gray-800">{getStrictPitchName(m)}</option>
                                ))}
                            </select>
                        </div>
                    )}
                </div>
                <div className="grid grid-cols-3 gap-2 mb-3">
                    {INTERVAL_OPTIONS.map(opt => (
                        <label key={opt.val} className={`flex items-center justify-center px-2 py-1.5 rounded cursor-pointer border transition-all ${selectedIntervals.includes(opt.val) ? 'bg-brand-primary/20 border-brand-primary text-brand-primary' : 'bg-gray-900 border-gray-700 text-gray-400 hover:border-gray-500'}`}>
                            <input 
                                type="checkbox" 
                                checked={selectedIntervals.includes(opt.val)}
                                onChange={e => toggleInterval(opt.val, e.target.checked)}
                                className="sr-only"
                            />
                            <span className="text-[10px] font-bold text-center">{opt.label}</span>
                        </label>
                    ))}
                </div>
                <div className="flex flex-wrap gap-2 border-t border-gray-700 pt-3">
                     <label className={`flex items-center px-3 py-1.5 rounded cursor-pointer border transition-all ${includeExtensions ? 'bg-brand-secondary/20 border-brand-secondary text-brand-secondary' : 'bg-gray-900 border-gray-700 text-gray-400 hover:border-gray-500'}`}>
                        <input 
                            type="checkbox" 
                            checked={includeExtensions}
                            onChange={e => setIncludeExtensions(e.target.checked)}
                            className="sr-only"
                        />
                        <span className="text-xs font-bold">+ 3rds & 6ths</span>
                    </label>
                    <label className={`flex items-center px-3 py-1.5 rounded cursor-pointer border transition-all ${includeInversions ? 'bg-blue-900/30 border-blue-500 text-blue-300' : 'bg-gray-900 border-gray-700 text-gray-400 hover:border-gray-500'}`}>
                        <input 
                            type="checkbox" 
                            checked={includeInversions}
                            onChange={e => setIncludeInversions(e.target.checked)}
                            className="sr-only"
                        />
                        <span className="text-xs font-bold">+ Inversions</span>
                    </label>
                </div>
            </div>

            <div className="p-4 bg-gray-800 rounded border border-gray-700 shadow-sm">
                <h3 className="text-xs font-bold text-gray-400 mb-3 uppercase tracking-widest">Entry Resolution</h3>
                <div className="grid grid-cols-3 gap-2">
                    {(['half', 'full', 'double'] as SearchResolution[]).map(res => (
                        <button 
                            key={res}
                            onClick={() => setSearchRes(res)}
                            className={`px-2 py-2 rounded text-xs font-bold border transition-all ${searchRes === res ? 'bg-brand-primary text-white border-brand-primary shadow-lg' : 'bg-gray-900 border-gray-700 text-gray-500 hover:bg-gray-800'}`}
                        >
                            {res === 'half' ? '1/2 Beat' : res === 'full' ? 'Beat' : '2 Beats'}
                        </button>
                    ))}
                </div>
                <p className="text-[10px] text-gray-500 mt-2">
                    Defines how frequently the algorithm checks for entry points.
                </p>
            </div>
        </div>
    );
}

import React, { useMemo, useState } from 'react';
import { StrettoSearchOptions, StrettoConstraintMode, RawNote } from '../../types';
import { getStrictPitchName } from '../services/midiSpelling';
import { getVoiceLabel } from '../services/midiVoices';

interface StrettoSearchPanelProps {
    options: StrettoSearchOptions;
    setOptions: (opt: StrettoSearchOptions) => void;
    onSearch: () => void;
    isSearching: boolean;
    voiceNames?: Record<number, string>;
    setVoiceNames?: (names: Record<number, string>) => void;
    subjectNotes: RawNote[];
    ppq: number;
}

export default function StrettoSearchPanel({ 
    options, setOptions, onSearch, isSearching, 
    voiceNames, setVoiceNames, subjectNotes, ppq 
}: StrettoSearchPanelProps) {

    const [showVoiceConfig, setShowVoiceConfig] = useState(false);

    const handleChange = (field: keyof StrettoSearchOptions, val: any) => {
        setOptions({ ...options, [field]: val });
    };

    const handleVoiceNameChange = (idx: number, name: string) => {
        if (setVoiceNames && voiceNames) {
            setVoiceNames({ ...voiceNames, [idx]: name });
        }
    };

    const pivotOptions = useMemo(() => {
        let min = 48; // C3
        let max = 72; // C5

        if (subjectNotes && subjectNotes.length > 0) {
            const midis = subjectNotes.map(n => n.midi);
            min = Math.min(...midis);
            max = Math.max(...midis);
        }

        // Expand range by an octave on either side
        const start = Math.floor((min - 12) / 12) * 12;
        const end = Math.ceil((max + 12) / 12) * 12;

        const opts = [];
        for (let i = start; i <= end; i++) {
            opts.push(i);
        }

        // Ensure current selected pivot is included
        if (!opts.includes(options.pivotMidi)) {
            opts.push(options.pivotMidi);
            opts.sort((a,b) => a - b);
        }

        return opts;
    }, [subjectNotes, options.pivotMidi]);

    const renderConstraintSelector = (label: string, field: keyof StrettoSearchOptions, value: StrettoConstraintMode) => (
        <div className="bg-gray-900 p-2 rounded border border-gray-700">
            <label className="block text-[10px] font-bold text-gray-400 mb-2 uppercase">{label}</label>
            <div className="flex gap-1">
                {['None', 'Max 1', 'Unlimited'].map((mode) => (
                    <button
                        key={mode}
                        onClick={() => handleChange(field, mode as StrettoConstraintMode)}
                        className={`flex-1 py-1 text-[10px] rounded border transition-colors ${value === mode ? 'bg-brand-primary text-white border-brand-primary' : 'bg-gray-800 text-gray-500 border-gray-600 hover:border-gray-500'}`}
                    >
                        {mode}
                    </button>
                ))}
            </div>
        </div>
    );

    const availableAbove = options.subjectVoiceIndex; 
    const availableBelow = (options.ensembleTotal - 1) - options.subjectVoiceIndex;

    // Truncation Visualization Logic
    const truncationVisual = useMemo(() => {
        if (subjectNotes.length === 0) return null;

        const sorted = [...subjectNotes].sort((a,b) => a.ticks - b.ticks);
        const startTick = sorted[0].ticks;
        const totalDuration = Math.max(...sorted.map(n => n.ticks + n.durationTicks)) - startTick;

        const targetTicks = Math.round(options.truncationTargetBeats * ppq);
        const minMidi = Math.min(...sorted.map(n => n.midi));
        const maxMidi = Math.max(...sorted.map(n => n.midi));
        const range = maxMidi - minMidi + 12; // Buffer

        return (
            <div className="w-full h-16 bg-gray-900 border border-gray-700 rounded mt-2 relative overflow-hidden select-none">
                <svg className="w-full h-full" preserveAspectRatio="none" viewBox={`0 0 ${totalDuration} ${range}`}>
                    {/* Background Grid (Beats) */}
                    {Array.from({ length: Math.ceil(totalDuration / ppq) }).map((_, i) => (
                        <line 
                            key={i} 
                            x1={i * ppq} y1={0} 
                            x2={i * ppq} y2={range} 
                            stroke="#333" 
                            strokeWidth={i % 4 === 0 ? 2 : 1}
                            vectorEffect="non-scaling-stroke" 
                        />
                    ))}

                    {/* Notes */}
                    {sorted.map((n, i) => {
                        const relStart = n.ticks - startTick;
                        const relEnd = relStart + n.durationTicks;

                        // Check if note is cut
                        let isKept = true;
                        let opacity = 1.0;
                        let fill = "#14b8a6"; // brand-primary

                        if (relStart >= targetTicks) {
                            isKept = false;
                            opacity = 0.3;
                            fill = "#4b5563"; // gray-600
                        } else if (relEnd > targetTicks) {
                            // Split note visualization?
                            fill = "#f59e0b"; // amber for clipped
                        }

                        // Invert Y for SVG
                        const y = range - (n.midi - minMidi) - 6;

                        return (
                            <rect 
                                key={i}
                                x={relStart}
                                y={y}
                                width={n.durationTicks}
                                height={4} // Note height
                                fill={fill}
                                opacity={opacity}
                                rx={2}
                            />
                        );
                    })}

                    {/* Cut Line */}
                    <line 
                        x1={targetTicks} y1={0} 
                        x2={targetTicks} y2={range} 
                        stroke="#ef4444" 
                        strokeWidth={2} 
                        strokeDasharray="4,4"
                        vectorEffect="non-scaling-stroke"
                    />
                </svg>
                <div className="absolute top-1 right-1 text-[9px] bg-black/50 px-1 rounded text-gray-400">
                    {options.truncationTargetBeats} Beats / {(totalDuration/ppq).toFixed(1)} Total
                </div>
            </div>
        );
    }, [subjectNotes, options.truncationTargetBeats, ppq]);

    return (
        <div className="bg-gray-800 border border-gray-700 rounded p-4 mb-6 shadow-sm">
            <div className="flex justify-between items-center mb-4 border-b border-gray-700 pb-2">
                <h3 className="text-sm font-bold text-gray-300 uppercase tracking-wider">Algorithmic Chain Finder</h3>
                {isSearching && <span className="text-xs text-brand-primary animate-pulse">Searching...</span>}
            </div>

            {/* Ensemble & Voice Naming Configuration (Collapsible) */}
            <div className="mb-6 bg-black/20 rounded border border-gray-700 overflow-hidden">
                <button 
                    onClick={() => setShowVoiceConfig(!showVoiceConfig)}
                    className="w-full flex justify-between items-center p-3 text-[10px] font-bold text-gray-400 uppercase tracking-widest hover:bg-white/5 transition-colors"
                >
                    <span>Voice Configuration (SATB)</span>
                    <span>{showVoiceConfig ? '▲' : '▼'}</span>
                </button>

                {showVoiceConfig && (
                    <div className="grid grid-cols-1 md:grid-cols-4 gap-4 p-4 pt-0 animate-fade-in border-t border-gray-700 mt-2">
                        {Array.from({ length: options.ensembleTotal }).map((_, idx) => {
